INSERT INTO sections (id, work_id, sequence, act, scene, scene_title, line_count, word_count, est_read_minutes) VALUES ('henry_v_prologue', 'henry-v', 1, NULL, NULL, 'Prologue', 34, 244, 1);
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act1_scene1', 1, 0, 'CANTERBURY', 'My lord, I’ll tell you; that self bill is urged,'), ('henry_v_act1_scene1', 2, 1, 'CANTERBURY', 'Which in the eleventh year of the last king’s reign'), ('henry_v_act1_scene1', 3, 2, 'CANTERBURY', 'Was like, and had indeed against us pass’d,'), ('henry_v_act1_scene1', 4, 3, 'CANTERBURY', 'But that the scambling and unquiet time'), ('henry_v_act1_scene1', 5, 4, 'CANTERBURY', 'Did push it out of farther question.'), ('henry_v_act1_scene1', 6, 5, 'ELY', 'But how, my lord, shall we resist it now?'), ('henry_v_act1_scene1', 7, 6, 'CANTERBURY', 'It must be thought on. If it pass against us,'), ('henry_v_act1_scene1', 8, 7, 'CANTERBURY', 'We lose the better half of our possession:'), ('henry_v_act1_scene1', 9, 8, 'CANTERBURY', 'For all the temporal lands which men devout'), ('henry_v_act1_scene1', 10, 9, 'CANTERBURY', 'By testament have given to the church'), ('henry_v_act1_scene1', 11, 10, 'CANTERBURY', 'Would they strip from us; being valued thus:'), ('henry_v_act1_scene1', 12, 11, 'CANTERBURY', 'As much as would maintain, to the King’s honour,'), ('henry_v_act1_scene1', 13, 12, 'CANTERBURY', 'Full fifteen earls and fifteen hundred knights,'), ('henry_v_act1_scene1', 14, 13, 'CANTERBURY', 'Six thousand and two hundred good esquires;'), ('henry_v_act1_scene1', 15, 14, 'CANTERBURY', 'And, to relief of lazars and weak age,'), ('henry_v_act1_scene1', 16, 15, 'CANTERBURY', 'Of indigent faint souls past corporal toil,'), ('henry_v_act1_scene1', 17, 16, 'CANTERBURY', 'A hundred almshouses right well supplied;'), ('henry_v_act1_scene1', 18, 17, 'CANTERBURY', 'And to the coffers of the King beside,'), ('henry_v_act1_scene1', 19, 18, 'CANTERBURY', 'A thousand pounds by the year: thus runs the bill.'), ('henry_v_act1_scene1', 20, 19, 'ELY', 'This would drink deep.'), ('henry_v_act1_scene1', 20, 20, 'CANTERBURY', '’Twould drink the cup and all.'), ('henry_v_act1_scene1', 21, 21, 'ELY', 'But what prevention?'), ('henry_v_act1_scene1', 22, 22, 'CANTERBURY', 'The King is full of grace and fair regard.'), ('henry_v_act1_scene1', 23, 23, 'ELY', 'And a true lover of the holy church.'), ('henry_v_act1_scene1', 24, 24, 'CANTERBURY', 'The courses of his youth promised it not.'), ('henry_v_act1_scene1', 25, 25, 'CANTERBURY', 'The breath no sooner left his father’s body,'), ('henry_v_act1_scene1', 26, 26, 'CANTERBURY', 'But that his wildness, mortified in him,'), ('henry_v_act1_scene1', 27, 27, 'CANTERBURY', 'Seem’d to die too; yea, at that very moment'), ('henry_v_act1_scene1', 28, 28, 'CANTERBURY', 'Consideration, like an angel, came'), ('henry_v_act1_scene1', 29, 29, 'CANTERBURY', 'And whipped the offending Adam out of him,'), ('henry_v_act1_scene1', 30, 30, 'CANTERBURY', 'Leaving his body as a paradise,'), ('henry_v_act1_scene1', 31, 31, 'CANTERBURY', 'To envelope and contain celestial spirits.'), ('henry_v_act1_scene1', 32, 32, 'CANTERBURY', 'Never was such a sudden scholar made;'), ('henry_v_act1_scene1', 33, 33, 'CANTERBURY', 'Never came reformation in a flood,'), ('henry_v_act1_scene1', 34, 34, 'CANTERBURY', 'With such a heady currance, scouring faults;'), ('henry_v_act1_scene1', 35, 35, 'CANTERBURY', 'Nor never Hydra-headed wilfulness'), ('henry_v_act1_scene1', 36, 36, 'CANTERBURY', 'So soon did lose his seat and all at once'), ('henry_v_act1_scene1', 37, 37, 'CANTERBURY', 'As in this king.'), ('henry_v_act1_scene1', 37, 38, 'ELY', 'We are blessed in the change.'), ('henry_v_act1_scene1', 38, 39, 'CANTERBURY', 'Hear him but reason in divinity,'), ('henry_v_act1_scene1', 39, 40, 'CANTERBURY', 'And, all-admiring with an inward wish'), ('henry_v_act1_scene1', 40, 41, 'CANTERBURY', 'You would desire the king were made a prelate:'), ('henry_v_act1_scene1', 41, 42, 'CANTERBURY', 'Hear him debate of commonwealth affairs,'), ('henry_v_act1_scene1', 42, 43, 'CANTERBURY', 'You would say it hath been all in all his study:'), ('henry_v_act1_scene1', 43, 44, 'CANTERBURY', 'List his discourse of war, and you shall hear'), ('henry_v_act1_scene1', 44, 45, 'CANTERBURY', 'A fearful battle render’d you in music:'), ('henry_v_act1_scene1', 45, 46, 'CANTERBURY', 'Turn him to any cause of policy,'), ('henry_v_act1_scene1', 46, 47, 'CANTERBURY', 'The Gordian knot of it he will unloose,'), ('henry_v_act1_scene1', 47, 48, 'CANTERBURY', 'Familiar as his garter: that, when he speaks,'), ('henry_v_act1_scene1', 48, 49, 'CANTERBURY', 'The air, a charter’d libertine, is still,'), ('henry_v_act1_scene1', 49, 50, 'CANTERBURY', 'And the mute wonder lurketh in men’s ears,'), ('henry_v_act1_scene1', 50, 51, 'CANTERBURY', 'To steal his sweet and honey’d sentences;'), ('henry_v_act1_scene1', 51, 52, 'CANTERBURY', 'So that the art and practic part of life'), ('henry_v_act1_scene1', 52, 53, 'CANTERBURY', 'Must be the mistress to this theoric:'), ('henry_v_act1_scene1', 53, 54, 'CANTERBURY', 'Which is a wonder how his grace should glean it,'), ('henry_v_act1_scene1', 54, 55, 'CANTERBURY', 'Since his addiction was to courses vain,'), ('henry_v_act1_scene1', 55, 56, 'CANTERBURY', 'His companies unletter’d, rude and shallow,'), ('henry_v_act1_scene1', 56, 57, 'CANTERBURY', 'His hours fill’d up with riots, banquets sports,'), ('henry_v_act1_scene1', 57, 58, 'CANTERBURY', 'And never noted in him any study,'), ('henry_v_act1_scene1', 58, 59, 'CANTERBURY', 'Any retirement, any sequestration'), ('henry_v_act1_scene1', 59, 60, 'CANTERBURY', 'From open haunts and popularity.'), ('henry_v_act1_scene1', 59, 61, 'ELY', 'The strawberry grows underneath the nettle'), ('henry_v_act1_scene1', 60, 62, 'ELY', 'And wholesome berries thrive and ripen best'), ('henry_v_act1_scene1', 61, 63, 'ELY', 'Neighbour’d by fruit of baser quality:'), ('henry_v_act1_scene1', 62, 64, 'ELY', 'And so the prince obscured his contemplation'), ('henry_v_act1_scene1', 63, 65, 'ELY', 'Under the veil of wildness; which, no doubt,'), ('henry_v_act1_scene1', 64, 66, 'ELY', 'Grew like the summer grass, fastest by night,'), ('henry_v_act1_scene1', 65, 67, 'ELY', 'Unseen, yet crescive in his faculty.'), ('henry_v_act1_scene1', 66, 68, 'CANTERBURY', 'It must be so; for miracles are ceased;'), ('henry_v_act1_scene1', 67, 69, 'CANTERBURY', 'And therefore we must needs admit the means'), ('henry_v_act1_scene1', 68, 70, 'CANTERBURY', 'How things are perfected.'), ('henry_v_act1_scene1', 68, 71, 'ELY', 'But, my good lord,'), ('henry_v_act1_scene1', 69, 72, 'ELY', 'How now for mitigation of this bill'), ('henry_v_act1_scene1', 70, 73, 'ELY', 'Urged by the commons? Doth his majesty'), ('henry_v_act1_scene1', 71, 74, 'ELY', 'Incline to it, or no?'), ('henry_v_act1_scene1', 71, 75, 'CANTERBURY', 'He seems indifferent,'), ('henry_v_act1_scene1', 72, 76, 'CANTERBURY', 'Or rather swaying more upon our part'), ('henry_v_act1_scene1', 73, 77, 'CANTERBURY', 'Than cherishing the exhibitors against us;'), ('henry_v_act1_scene1', 74, 78, 'CANTERBURY', 'For I have made an offer to his majesty,'), ('henry_v_act1_scene1', 75, 79, 'CANTERBURY', 'Upon our spiritual convocation'), ('henry_v_act1_scene1', 76, 80, 'CANTERBURY', 'And in regard of causes now in hand,'), ('henry_v_act1_scene1', 77, 81, 'CANTERBURY', 'Which I have open’d to his grace at large,'), ('henry_v_act1_scene1', 78, 82, 'CANTERBURY', 'As touching France, to give a greater sum'), ('henry_v_act1_scene1', 79, 83, 'CANTERBURY', 'Than ever at one time the clergy yet'), ('henry_v_act1_scene1', 80, 84, 'CANTERBURY', 'Did to his predecessors part withal.'), ('henry_v_act1_scene1', 81, 85, 'ELY', 'How did this offer seem received, my lord?'), ('henry_v_act1_scene1', 82, 86, 'CANTERBURY', 'With good acceptance of his majesty;'), ('henry_v_act1_scene1', 83, 87, 'CANTERBURY', 'Save that there was not time enough to hear,'), ('henry_v_act1_scene1', 84, 88, 'CANTERBURY', 'As I perceived his grace would fain have done,'), ('henry_v_act1_scene1', 85, 89, 'CANTERBURY', 'The severals and unhidden passages'), ('henry_v_act1_scene1', 86, 90, 'CANTERBURY', 'Of his true titles to some certain dukedoms'), ('henry_v_act1_scene1', 87, 91, 'CANTERBURY', 'And generally to the crown and seat of France'), ('henry_v_act1_scene1', 88, 92, 'CANTERBURY', 'Derived from Edward, his great-grandfather.'), ('henry_v_act1_scene1', 89, 93, 'ELY', 'What was the impediment that broke this off?'), ('henry_v_act1_scene1', 90, 94, 'CANTERBURY', 'The French ambassador upon that instant'), ('henry_v_act1_scene1', 91, 95, 'CANTERBURY', 'Craved audience; and the hour, I think, is come'), ('henry_v_act1_scene1', 92, 96, 'CANTERBURY', 'To give him hearing: is it four o’clock?'), ('henry_v_act1_scene1', 93, 97, 'ELY', 'It is.'), ('henry_v_act1_scene1', 94, 98, 'CANTERBURY', 'Then go we in, to know his embassy;'), ('henry_v_act1_scene1', 95, 99, 'CANTERBURY', 'Which I could with a ready guess declare,');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act1_scene1', 96, 100, 'CANTERBURY', 'Before the Frenchman speak a word of it.'), ('henry_v_act1_scene1', 97, 101, 'ELY', 'I’ll wait upon you, and I long to hear it.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act1_scene2', 1, 0, 'KING HENRY', 'Where is my gracious Lord of Canterbury?'), ('henry_v_act1_scene2', 2, 1, 'EXETER', 'Not here in presence.'), ('henry_v_act1_scene2', 2, 2, 'KING HENRY', 'Send for him, good uncle.'), ('henry_v_act1_scene2', 3, 3, 'WESTMORELAND', 'Shall we call in the ambassador, my liege?'), ('henry_v_act1_scene2', 4, 4, 'KING HENRY', 'Not yet, my cousin: we would be resolved,'), ('henry_v_act1_scene2', 5, 5, 'KING HENRY', 'Before we hear him, of some things of weight'), ('henry_v_act1_scene2', 6, 6, 'KING HENRY', 'That task our thoughts, concerning us and France.'), ('henry_v_act1_scene2', 7, 7, 'CANTERBURY', 'God and his angels guard your sacred throne'), ('henry_v_act1_scene2', 8, 8, 'CANTERBURY', 'And make you long become it!'), ('henry_v_act1_scene2', 8, 9, 'KING HENRY', 'Sure, we thank you.'), ('henry_v_act1_scene2', 9, 10, 'KING HENRY', 'My learned lord, we pray you to proceed'), ('henry_v_act1_scene2', 10, 11, 'KING HENRY', 'And justly and religiously unfold'), ('henry_v_act1_scene2', 11, 12, 'KING HENRY', 'Why the law Salique that they have in France'), ('henry_v_act1_scene2', 12, 13, 'KING HENRY', 'Or should, or should not, bar us in our claim:'), ('henry_v_act1_scene2', 13, 14, 'KING HENRY', 'And God forbid, my dear and faithful lord,'), ('henry_v_act1_scene2', 14, 15, 'KING HENRY', 'That you should fashion, wrest, or bow your reading,'), ('henry_v_act1_scene2', 15, 16, 'KING HENRY', 'Or nicely charge your understanding soul'), ('henry_v_act1_scene2', 16, 17, 'KING HENRY', 'With opening titles miscreate, whose right'), ('henry_v_act1_scene2', 17, 18, 'KING HENRY', 'Suits not in native colours with the truth;'), ('henry_v_act1_scene2', 18, 19, 'KING HENRY', 'For God doth know how many now in health'), ('henry_v_act1_scene2', 19, 20, 'KING HENRY', 'Shall drop their blood in approbation'), ('henry_v_act1_scene2', 20, 21, 'KING HENRY', 'Of what your reverence shall incite us to.'), ('henry_v_act1_scene2', 21, 22, 'KING HENRY', 'Therefore take heed how you impawn our person,'), ('henry_v_act1_scene2', 22, 23, 'KING HENRY', 'How you awake our sleeping sword of war:'), ('henry_v_act1_scene2', 23, 24, 'KING HENRY', 'We charge you, in the name of God, take heed;'), ('henry_v_act1_scene2', 24, 25, 'KING HENRY', 'For never two such kingdoms did contend'), ('henry_v_act1_scene2', 25, 26, 'KING HENRY', 'Without much fall of blood; whose guiltless drops'), ('henry_v_act1_scene2', 26, 27, 'KING HENRY', 'Are every one a woe, a sore complaint'), ('henry_v_act1_scene2', 27, 28, 'KING HENRY', '’Gainst him whose wrongs gives edge unto the swords'), ('henry_v_act1_scene2', 28, 29, 'KING HENRY', 'That makes such waste in brief mortality.'), ('henry_v_act1_scene2', 29, 30, 'KING HENRY', 'Under this conjuration speak, my lord;'), ('henry_v_act1_scene2', 30, 31, 'KING HENRY', 'For we will hear, note and believe in heart'), ('henry_v_act1_scene2', 31, 32, 'KING HENRY', 'That what you speak is in your conscience wash’d'), ('henry_v_act1_scene2', 32, 33, 'KING HENRY', 'As pure as sin with baptism.'), ('henry_v_act1_scene2', 33, 34, 'CANTERBURY', 'Then hear me, gracious sovereign, and you peers,'), ('henry_v_act1_scene2', 34, 35, 'CANTERBURY', 'That owe yourselves, your lives and services'), ('henry_v_act1_scene2', 35, 36, 'CANTERBURY', 'To this imperial throne. There is no bar'), ('henry_v_act1_scene2', 36, 37, 'CANTERBURY', 'To make against your highness’ claim to France'), ('henry_v_act1_scene2', 37, 38, 'CANTERBURY', 'But this, which they produce from Pharamond,'), ('henry_v_act1_scene2', 38, 39, 'CANTERBURY', '“In terram Salicam mulieres ne succedant:”'), ('henry_v_act1_scene2', 39, 40, 'CANTERBURY', '“No woman shall succeed in Salique land:”'), ('henry_v_act1_scene2', 40, 41, 'CANTERBURY', 'Which Salique land the French unjustly glose'), ('henry_v_act1_scene2', 41, 42, 'CANTERBURY', 'To be the realm of France, and Pharamond'), ('henry_v_act1_scene2', 42, 43, 'CANTERBURY', 'The founder of this law and female bar.'), ('henry_v_act1_scene2', 43, 44, 'CANTERBURY', 'Yet their own authors faithfully affirm'), ('henry_v_act1_scene2', 44, 45, 'CANTERBURY', 'That the land Salique is in Germany,'), ('henry_v_act1_scene2', 45, 46, 'CANTERBURY', 'Between the floods of Sala and of Elbe;'), ('henry_v_act1_scene2', 46, 47, 'CANTERBURY', 'Where Charles the Great, having subdued the Saxons,'), ('henry_v_act1_scene2', 47, 48, 'CANTERBURY', 'There left behind and settled certain French;'), ('henry_v_act1_scene2', 48, 49, 'CANTERBURY', 'Who, holding in disdain the German women'), ('henry_v_act1_scene2', 49, 50, 'CANTERBURY', 'For some dishonest manners of their life,'), ('henry_v_act1_scene2', 50, 51, 'CANTERBURY', 'Establish’d then this law; to wit, no female'), ('henry_v_act1_scene2', 51, 52, 'CANTERBURY', 'Should be inheritrix in Salique land:'), ('henry_v_act1_scene2', 52, 53, 'CANTERBURY', 'Which Salique, as I said, ’twixt Elbe and Sala,'), ('henry_v_act1_scene2', 53, 54, 'CANTERBURY', 'Is at this day in Germany call’d Meissen.'), ('henry_v_act1_scene2', 54, 55, 'CANTERBURY', 'Then doth it well appear the Salique law'), ('henry_v_act1_scene2', 55, 56, 'CANTERBURY', 'Was not devised for the realm of France;'), ('henry_v_act1_scene2', 56, 57, 'CANTERBURY', 'Nor did the French possess the Salique land'), ('henry_v_act1_scene2', 57, 58, 'CANTERBURY', 'Until four hundred one and twenty years'), ('henry_v_act1_scene2', 58, 59, 'CANTERBURY', 'After defunction of King Pharamond,'), ('henry_v_act1_scene2', 59, 60, 'CANTERBURY', 'Idly supposed the founder of this law;'), ('henry_v_act1_scene2', 60, 61, 'CANTERBURY', 'Who died within the year of our redemption'), ('henry_v_act1_scene2', 61, 62, 'CANTERBURY', 'Four hundred twenty-six; and Charles the Great'), ('henry_v_act1_scene2', 62, 63, 'CANTERBURY', 'Subdued the Saxons, and did seat the French'), ('henry_v_act1_scene2', 63, 64, 'CANTERBURY', 'Beyond the river Sala, in the year'), ('henry_v_act1_scene2', 64, 65, 'CANTERBURY', 'Eight hundred five. Besides, their writers say,'), ('henry_v_act1_scene2', 65, 66, 'CANTERBURY', 'King Pepin, which deposed Childeric,'), ('henry_v_act1_scene2', 66, 67, 'CANTERBURY', 'Did, as heir general, being descended'), ('henry_v_act1_scene2', 67, 68, 'CANTERBURY', 'Of Blithild, which was daughter to King Clothair,'), ('henry_v_act1_scene2', 68, 69, 'CANTERBURY', 'Make claim and title to the crown of France.'), ('henry_v_act1_scene2', 69, 70, 'CANTERBURY', 'Hugh Capet also, who usurp’d the crown'), ('henry_v_act1_scene2', 70, 71, 'CANTERBURY', 'Of Charles the duke of Lorraine, sole heir male'), ('henry_v_act1_scene2', 71, 72, 'CANTERBURY', 'Of the true line and stock of Charles the Great,'), ('henry_v_act1_scene2', 72, 73, 'CANTERBURY', 'To find his title with some shows of truth,'), ('henry_v_act1_scene2', 73, 74, 'CANTERBURY', 'Though, in pure truth, it was corrupt and naught,'), ('henry_v_act1_scene2', 74, 75, 'CANTERBURY', 'Convey’d himself as the heir to the Lady Lingare,'), ('henry_v_act1_scene2', 75, 76, 'CANTERBURY', 'Daughter to Charlemain, who was the son'), ('henry_v_act1_scene2', 76, 77, 'CANTERBURY', 'To Lewis the emperor, and Lewis the son'), ('henry_v_act1_scene2', 77, 78, 'CANTERBURY', 'Of Charles the Great. Also King Lewis the Tenth,'), ('henry_v_act1_scene2', 78, 79, 'CANTERBURY', 'Who was sole heir to the usurper Capet,'), ('henry_v_act1_scene2', 79, 80, 'CANTERBURY', 'Could not keep quiet in his conscience,'), ('henry_v_act1_scene2', 80, 81, 'CANTERBURY', 'Wearing the crown of France, till satisfied'), ('henry_v_act1_scene2', 81, 82, 'CANTERBURY', 'That fair Queen Isabel, his grandmother,'), ('henry_v_act1_scene2', 82, 83, 'CANTERBURY', 'Was lineal of the Lady Ermengare,'), ('henry_v_act1_scene2', 83, 84, 'CANTERBURY', 'Daughter to Charles the foresaid duke of Lorraine:'), ('henry_v_act1_scene2', 84, 85, 'CANTERBURY', 'By the which marriage the line of Charles the Great'), ('henry_v_act1_scene2', 85, 86, 'CANTERBURY', 'Was reunited to the crown of France.'), ('henry_v_act1_scene2', 86, 87, 'CANTERBURY', 'So that, as clear as is the summer’s sun,'), ('henry_v_act1_scene2', 87, 88, 'CANTERBURY', 'King Pepin’s title and Hugh Capet’s claim,'), ('henry_v_act1_scene2', 88, 89, 'CANTERBURY', 'King Lewis his satisfaction, all appear'), ('henry_v_act1_scene2', 89, 90, 'CANTERBURY', 'To hold in right and title of the female:'), ('henry_v_act1_scene2', 90, 91, 'CANTERBURY', 'So do the kings of France unto this day;'), ('henry_v_act1_scene2', 91, 92, 'CANTERBURY', 'Howbeit they would hold up this Salique law'), ('henry_v_act1_scene2', 92, 93, 'CANTERBURY', 'To bar your highness claiming from the female,'), ('henry_v_act1_scene2', 93, 94, 'CANTERBURY', 'And rather choose to hide them in a net'), ('henry_v_act1_scene2', 94, 95, 'CANTERBURY', 'Than amply to imbar their crooked titles'), ('henry_v_act1_scene2', 95, 96, 'CANTERBURY', 'Usurp’d from you and your progenitors.'), ('henry_v_act1_scene2', 96, 97, 'KING HENRY', 'May I with right and conscience make this claim?'), ('henry_v_act1_scene2', 97, 98, 'CANTERBURY', 'The sin upon my head, dread sovereign!'), ('henry_v_act1_scene2', 98, 99, 'CANTERBURY', 'For in the Book of Numbers is it writ,');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act1_scene2', 99, 100, 'CANTERBURY', 'When the man dies, let the inheritance'), ('henry_v_act1_scene2', 100, 101, 'CANTERBURY', 'Descend unto the daughter. Gracious lord,'), ('henry_v_act1_scene2', 101, 102, 'CANTERBURY', 'Stand for your own; unwind your bloody flag;'), ('henry_v_act1_scene2', 102, 103, 'CANTERBURY', 'Look back into your mighty ancestors:'), ('henry_v_act1_scene2', 103, 104, 'CANTERBURY', 'Go, my dread lord, to your great-grandsire’s tomb,'), ('henry_v_act1_scene2', 104, 105, 'CANTERBURY', 'From whom you claim; invoke his warlike spirit,'), ('henry_v_act1_scene2', 105, 106, 'CANTERBURY', 'And your great-uncle’s, Edward the Black Prince,'), ('henry_v_act1_scene2', 106, 107, 'CANTERBURY', 'Who on the French ground play’d a tragedy,'), ('henry_v_act1_scene2', 107, 108, 'CANTERBURY', 'Making defeat on the full power of France,'), ('henry_v_act1_scene2', 108, 109, 'CANTERBURY', 'Whiles his most mighty father on a hill'), ('henry_v_act1_scene2', 109, 110, 'CANTERBURY', 'Stood smiling to behold his lion’s whelp'), ('henry_v_act1_scene2', 110, 111, 'CANTERBURY', 'Forage in blood of French nobility.'), ('henry_v_act1_scene2', 111, 112, 'CANTERBURY', 'O noble English, that could entertain'), ('henry_v_act1_scene2', 112, 113, 'CANTERBURY', 'With half their forces the full pride of France'), ('henry_v_act1_scene2', 113, 114, 'CANTERBURY', 'And let another half stand laughing by,'), ('henry_v_act1_scene2', 114, 115, 'CANTERBURY', 'All out of work and cold for action!'), ('henry_v_act1_scene2', 115, 116, 'ELY', 'Awake remembrance of these valiant dead'), ('henry_v_act1_scene2', 116, 117, 'ELY', 'And with your puissant arm renew their feats:'), ('henry_v_act1_scene2', 117, 118, 'ELY', 'You are their heir; you sit upon their throne;'), ('henry_v_act1_scene2', 118, 119, 'ELY', 'The blood and courage that renowned them'), ('henry_v_act1_scene2', 119, 120, 'ELY', 'Runs in your veins; and my thrice-puissant liege'), ('henry_v_act1_scene2', 120, 121, 'ELY', 'Is in the very May-morn of his youth,'), ('henry_v_act1_scene2', 121, 122, 'ELY', 'Ripe for exploits and mighty enterprises.'), ('henry_v_act1_scene2', 122, 123, 'EXETER', 'Your brother kings and monarchs of the earth'), ('henry_v_act1_scene2', 123, 124, 'EXETER', 'Do all expect that you should rouse yourself,'), ('henry_v_act1_scene2', 124, 125, 'EXETER', 'As did the former lions of your blood.'), ('henry_v_act1_scene2', 125, 126, 'WESTMORELAND', 'They know your grace hath cause and means and might;'), ('henry_v_act1_scene2', 126, 127, 'WESTMORELAND', 'So hath your highness; never king of England'), ('henry_v_act1_scene2', 127, 128, 'WESTMORELAND', 'Had nobles richer and more loyal subjects,'), ('henry_v_act1_scene2', 128, 129, 'WESTMORELAND', 'Whose hearts have left their bodies here in England'), ('henry_v_act1_scene2', 129, 130, 'WESTMORELAND', 'And lie pavilion’d in the fields of France.'), ('henry_v_act1_scene2', 130, 131, 'CANTERBURY', 'O, let their bodies follow, my dear liege,'), ('henry_v_act1_scene2', 131, 132, 'CANTERBURY', 'With blood and sword and fire to win your right;'), ('henry_v_act1_scene2', 132, 133, 'CANTERBURY', 'In aid whereof we of the spiritualty'), ('henry_v_act1_scene2', 133, 134, 'CANTERBURY', 'Will raise your highness such a mighty sum'), ('henry_v_act1_scene2', 134, 135, 'CANTERBURY', 'As never did the clergy at one time'), ('henry_v_act1_scene2', 135, 136, 'CANTERBURY', 'Bring in to any of your ancestors.'), ('henry_v_act1_scene2', 136, 137, 'KING HENRY', 'We must not only arm to invade the French,'), ('henry_v_act1_scene2', 137, 138, 'KING HENRY', 'But lay down our proportions to defend'), ('henry_v_act1_scene2', 138, 139, 'KING HENRY', 'Against the Scot, who will make road upon us'), ('henry_v_act1_scene2', 139, 140, 'KING HENRY', 'With all advantages.'), ('henry_v_act1_scene2', 139, 141, 'CANTERBURY', 'They of those marches, gracious sovereign,'), ('henry_v_act1_scene2', 140, 142, 'CANTERBURY', 'Shall be a wall sufficient to defend'), ('henry_v_act1_scene2', 141, 143, 'CANTERBURY', 'Our inland from the pilfering borderers.'), ('henry_v_act1_scene2', 142, 144, 'KING HENRY', 'We do not mean the coursing snatchers only,'), ('henry_v_act1_scene2', 143, 145, 'KING HENRY', 'But fear the main intendment of the Scot,'), ('henry_v_act1_scene2', 144, 146, 'KING HENRY', 'Who hath been still a giddy neighbour to us;'), ('henry_v_act1_scene2', 145, 147, 'KING HENRY', 'For you shall read that my great-grandfather'), ('henry_v_act1_scene2', 146, 148, 'KING HENRY', 'Never went with his forces into France'), ('henry_v_act1_scene2', 147, 149, 'KING HENRY', 'But that the Scot on his unfurnish’d kingdom'), ('henry_v_act1_scene2', 148, 150, 'KING HENRY', 'Came pouring, like the tide into a breach,'), ('henry_v_act1_scene2', 149, 151, 'KING HENRY', 'With ample and brim fullness of his force,'), ('henry_v_act1_scene2', 150, 152, 'KING HENRY', 'Galling the gleaned land with hot assays,'), ('henry_v_act1_scene2', 151, 153, 'KING HENRY', 'Girdling with grievous siege castles and towns;'), ('henry_v_act1_scene2', 152, 154, 'KING HENRY', 'That England, being empty of defence,'), ('henry_v_act1_scene2', 153, 155, 'KING HENRY', 'Hath shook and trembled at the ill neighbourhood.'), ('henry_v_act1_scene2', 154, 156, 'CANTERBURY', 'She hath been then more fear’d than harm’d, my liege;'), ('henry_v_act1_scene2', 155, 157, 'CANTERBURY', 'For hear her but exampled by herself:'), ('henry_v_act1_scene2', 156, 158, 'CANTERBURY', 'When all her chivalry hath been in France'), ('henry_v_act1_scene2', 157, 159, 'CANTERBURY', 'And she a mourning widow of her nobles,'), ('henry_v_act1_scene2', 158, 160, 'CANTERBURY', 'She hath herself not only well defended'), ('henry_v_act1_scene2', 159, 161, 'CANTERBURY', 'But taken and impounded as a stray'), ('henry_v_act1_scene2', 160, 162, 'CANTERBURY', 'The King of Scots; whom she did send to France,'), ('henry_v_act1_scene2', 161, 163, 'CANTERBURY', 'To fill King Edward’s fame with prisoner kings'), ('henry_v_act1_scene2', 162, 164, 'CANTERBURY', 'And make her chronicle as rich with praise'), ('henry_v_act1_scene2', 163, 165, 'CANTERBURY', 'As is the ooze and bottom of the sea'), ('henry_v_act1_scene2', 164, 166, 'CANTERBURY', 'With sunken wreck and sumless treasuries.'), ('henry_v_act1_scene2', 165, 167, 'WESTMORELAND', 'But there’s a saying very old and true,'), ('henry_v_act1_scene2', 166, 168, 'WESTMORELAND', '“If that you will France win,'), ('henry_v_act1_scene2', 167, 169, 'WESTMORELAND', 'Then with Scotland first begin:”'), ('henry_v_act1_scene2', 168, 170, 'WESTMORELAND', 'For once the eagle England being in prey,'), ('henry_v_act1_scene2', 169, 171, 'WESTMORELAND', 'To her unguarded nest the weasel Scot'), ('henry_v_act1_scene2', 170, 172, 'WESTMORELAND', 'Comes sneaking and so sucks her princely eggs,'), ('henry_v_act1_scene2', 171, 173, 'WESTMORELAND', 'Playing the mouse in absence of the cat,'), ('henry_v_act1_scene2', 172, 174, 'WESTMORELAND', 'To tear and havoc more than she can eat.'), ('henry_v_act1_scene2', 173, 175, 'EXETER', 'It follows then the cat must stay at home:'), ('henry_v_act1_scene2', 174, 176, 'EXETER', 'Yet that is but a crush’d necessity,'), ('henry_v_act1_scene2', 175, 177, 'EXETER', 'Since we have locks to safeguard necessaries,'), ('henry_v_act1_scene2', 176, 178, 'EXETER', 'And pretty traps to catch the petty thieves.'), ('henry_v_act1_scene2', 177, 179, 'EXETER', 'While that the armed hand doth fight abroad,'), ('henry_v_act1_scene2', 178, 180, 'EXETER', 'The advised head defends itself at home;'), ('henry_v_act1_scene2', 179, 181, 'EXETER', 'For government, though high and low and lower,'), ('henry_v_act1_scene2', 180, 182, 'EXETER', 'Put into parts, doth keep in one consent,'), ('henry_v_act1_scene2', 181, 183, 'EXETER', 'Congreeing in a full and natural close,'), ('henry_v_act1_scene2', 182, 184, 'EXETER', 'Like music.'), ('henry_v_act1_scene2', 182, 185, 'CANTERBURY', 'Therefore doth heaven divide'), ('henry_v_act1_scene2', 183, 186, 'CANTERBURY', 'The state of man in divers functions,'), ('henry_v_act1_scene2', 184, 187, 'CANTERBURY', 'Setting endeavour in continual motion;'), ('henry_v_act1_scene2', 185, 188, 'CANTERBURY', 'To which is fixed, as an aim or butt,'), ('henry_v_act1_scene2', 186, 189, 'CANTERBURY', 'Obedience: for so work the honeybees,'), ('henry_v_act1_scene2', 187, 190, 'CANTERBURY', 'Creatures that by a rule in nature teach'), ('henry_v_act1_scene2', 188, 191, 'CANTERBURY', 'The act of order to a peopled kingdom.'), ('henry_v_act1_scene2', 189, 192, 'CANTERBURY', 'They have a king and officers of sorts;'), ('henry_v_act1_scene2', 190, 193, 'CANTERBURY', 'Where some, like magistrates, correct at home,'), ('henry_v_act1_scene2', 191, 194, 'CANTERBURY', 'Others, like merchants, venture trade abroad,'), ('henry_v_act1_scene2', 192, 195, 'CANTERBURY', 'Others, like soldiers, armed in their stings,'), ('henry_v_act1_scene2', 193, 196, 'CANTERBURY', 'Make boot upon the summer’s velvet buds,'), ('henry_v_act1_scene2', 194, 197, 'CANTERBURY', 'Which pillage they with merry march bring home'), ('henry_v_act1_scene2', 195, 198, 'CANTERBURY', 'To the tent-royal of their emperor;'), ('henry_v_act1_scene2', 196, 199, 'CANTERBURY', 'Who, busied in his majesty, surveys');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act1_scene2', 197, 200, 'CANTERBURY', 'The singing masons building roofs of gold,'), ('henry_v_act1_scene2', 198, 201, 'CANTERBURY', 'The civil citizens kneading up the honey,'), ('henry_v_act1_scene2', 199, 202, 'CANTERBURY', 'The poor mechanic porters crowding in'), ('henry_v_act1_scene2', 200, 203, 'CANTERBURY', 'Their heavy burdens at his narrow gate,'), ('henry_v_act1_scene2', 201, 204, 'CANTERBURY', 'The sad-eyed justice, with his surly hum,'), ('henry_v_act1_scene2', 202, 205, 'CANTERBURY', 'Delivering o’er to executors pale'), ('henry_v_act1_scene2', 203, 206, 'CANTERBURY', 'The lazy yawning drone. I this infer,'), ('henry_v_act1_scene2', 204, 207, 'CANTERBURY', 'That many things, having full reference'), ('henry_v_act1_scene2', 205, 208, 'CANTERBURY', 'To one consent, may work contrariously:'), ('henry_v_act1_scene2', 206, 209, 'CANTERBURY', 'As many arrows, loosed several ways,'), ('henry_v_act1_scene2', 207, 210, 'CANTERBURY', 'Come to one mark; as many ways meet in one town;'), ('henry_v_act1_scene2', 208, 211, 'CANTERBURY', 'As many fresh streams meet in one salt sea;'), ('henry_v_act1_scene2', 209, 212, 'CANTERBURY', 'As many lines close in the dial’s centre;'), ('henry_v_act1_scene2', 210, 213, 'CANTERBURY', 'So many a thousand actions, once afoot,'), ('henry_v_act1_scene2', 211, 214, 'CANTERBURY', 'End in one purpose, and be all well borne'), ('henry_v_act1_scene2', 212, 215, 'CANTERBURY', 'Without defeat. Therefore to France, my liege.'), ('henry_v_act1_scene2', 213, 216, 'CANTERBURY', 'Divide your happy England into four;'), ('henry_v_act1_scene2', 214, 217, 'CANTERBURY', 'Whereof take you one quarter into France,'), ('henry_v_act1_scene2', 215, 218, 'CANTERBURY', 'And you withal shall make all Gallia shake.'), ('henry_v_act1_scene2', 216, 219, 'CANTERBURY', 'If we, with thrice such powers left at home,'), ('henry_v_act1_scene2', 217, 220, 'CANTERBURY', 'Cannot defend our own doors from the dog,'), ('henry_v_act1_scene2', 218, 221, 'CANTERBURY', 'Let us be worried and our nation lose'), ('henry_v_act1_scene2', 219, 222, 'CANTERBURY', 'The name of hardiness and policy.'), ('henry_v_act1_scene2', 220, 223, 'KING HENRY', 'Call in the messengers sent from the Dauphin.'), ('henry_v_act1_scene2', 221, 224, 'KING HENRY', 'Now are we well resolved; and, by God’s help,'), ('henry_v_act1_scene2', 222, 225, 'KING HENRY', 'And yours, the noble sinews of our power,'), ('henry_v_act1_scene2', 223, 226, 'KING HENRY', 'France being ours, we’ll bend it to our awe,'), ('henry_v_act1_scene2', 224, 227, 'KING HENRY', 'Or break it all to pieces: or there we’ll sit,'), ('henry_v_act1_scene2', 225, 228, 'KING HENRY', 'Ruling in large and ample empery'), ('henry_v_act1_scene2', 226, 229, 'KING HENRY', 'O’er France and all her almost kingly dukedoms,'), ('henry_v_act1_scene2', 227, 230, 'KING HENRY', 'Or lay these bones in an unworthy urn,'), ('henry_v_act1_scene2', 228, 231, 'KING HENRY', 'Tombless, with no remembrance over them:'), ('henry_v_act1_scene2', 229, 232, 'KING HENRY', 'Either our history shall with full mouth'), ('henry_v_act1_scene2', 230, 233, 'KING HENRY', 'Speak freely of our acts, or else our grave,'), ('henry_v_act1_scene2', 231, 234, 'KING HENRY', 'Like Turkish mute, shall have a tongueless mouth,'), ('henry_v_act1_scene2', 232, 235, 'KING HENRY', 'Not worshipp’d with a waxen epitaph.'), ('henry_v_act1_scene2', 233, 236, 'FIRST AMBASSADOR', 'May’t please your majesty to give us leave'), ('henry_v_act1_scene2', 234, 237, 'FIRST AMBASSADOR', 'Freely to render what we have in charge;'), ('henry_v_act1_scene2', 235, 238, 'FIRST AMBASSADOR', 'Or shall we sparingly show you far off'), ('henry_v_act1_scene2', 236, 239, 'FIRST AMBASSADOR', 'The Dauphin’s meaning and our embassy?'), ('henry_v_act1_scene2', 237, 240, 'KING HENRY', 'We are no tyrant, but a Christian king;'), ('henry_v_act1_scene2', 238, 241, 'KING HENRY', 'Unto whose grace our passion is as subject'), ('henry_v_act1_scene2', 239, 242, 'KING HENRY', 'As are our wretches fetter’d in our prisons:'), ('henry_v_act1_scene2', 240, 243, 'KING HENRY', 'Therefore with frank and with uncurbed plainness'), ('henry_v_act1_scene2', 241, 244, 'KING HENRY', 'Tell us the Dauphin’s mind.'), ('henry_v_act1_scene2', 241, 245, 'AMBASSADOR', 'Thus, then, in few.'), ('henry_v_act1_scene2', 242, 246, 'AMBASSADOR', 'Your highness, lately sending into France,'), ('henry_v_act1_scene2', 243, 247, 'AMBASSADOR', 'Did claim some certain dukedoms, in the right'), ('henry_v_act1_scene2', 244, 248, 'AMBASSADOR', 'Of your great predecessor, King Edward the Third.'), ('henry_v_act1_scene2', 245, 249, 'AMBASSADOR', 'In answer of which claim, the prince our master'), ('henry_v_act1_scene2', 246, 250, 'AMBASSADOR', 'Says that you savour too much of your youth,'), ('henry_v_act1_scene2', 247, 251, 'AMBASSADOR', 'And bids you be advised there’s nought in France'), ('henry_v_act1_scene2', 248, 252, 'AMBASSADOR', 'That can be with a nimble galliard won;'), ('henry_v_act1_scene2', 249, 253, 'AMBASSADOR', 'You cannot revel into dukedoms there.'), ('henry_v_act1_scene2', 250, 254, 'AMBASSADOR', 'He therefore sends you, meeter for your spirit,'), ('henry_v_act1_scene2', 251, 255, 'AMBASSADOR', 'This tun of treasure; and, in lieu of this,'), ('henry_v_act1_scene2', 252, 256, 'AMBASSADOR', 'Desires you let the dukedoms that you claim'), ('henry_v_act1_scene2', 253, 257, 'AMBASSADOR', 'Hear no more of you. This the Dauphin speaks.'), ('henry_v_act1_scene2', 254, 258, 'KING HENRY', 'What treasure, uncle?'), ('henry_v_act1_scene2', 254, 259, 'EXETER', 'Tennis-balls, my liege.'), ('henry_v_act1_scene2', 255, 260, 'KING HENRY', 'We are glad the Dauphin is so pleasant with us;'), ('henry_v_act1_scene2', 256, 261, 'KING HENRY', 'His present and your pains we thank you for:'), ('henry_v_act1_scene2', 257, 262, 'KING HENRY', 'When we have match’d our rackets to these balls,'), ('henry_v_act1_scene2', 258, 263, 'KING HENRY', 'We will, in France, by God’s grace, play a set'), ('henry_v_act1_scene2', 259, 264, 'KING HENRY', 'Shall strike his father’s crown into the hazard.'), ('henry_v_act1_scene2', 260, 265, 'KING HENRY', 'Tell him he hath made a match with such a wrangler'), ('henry_v_act1_scene2', 261, 266, 'KING HENRY', 'That all the courts of France will be disturb’d'), ('henry_v_act1_scene2', 262, 267, 'KING HENRY', 'With chases. And we understand him well,'), ('henry_v_act1_scene2', 263, 268, 'KING HENRY', 'How he comes o’er us with our wilder days,'), ('henry_v_act1_scene2', 264, 269, 'KING HENRY', 'Not measuring what use we made of them.'), ('henry_v_act1_scene2', 265, 270, 'KING HENRY', 'We never valued this poor seat of England;'), ('henry_v_act1_scene2', 266, 271, 'KING HENRY', 'And therefore, living hence, did give ourself'), ('henry_v_act1_scene2', 267, 272, 'KING HENRY', 'To barbarous licence; as ’tis ever common'), ('henry_v_act1_scene2', 268, 273, 'KING HENRY', 'That men are merriest when they are from home.'), ('henry_v_act1_scene2', 269, 274, 'KING HENRY', 'But tell the Dauphin I will keep my state,'), ('henry_v_act1_scene2', 270, 275, 'KING HENRY', 'Be like a king and show my sail of greatness'), ('henry_v_act1_scene2', 271, 276, 'KING HENRY', 'When I do rouse me in my throne of France:'), ('henry_v_act1_scene2', 272, 277, 'KING HENRY', 'For that I have laid by my majesty'), ('henry_v_act1_scene2', 273, 278, 'KING HENRY', 'And plodded like a man for working-days,'), ('henry_v_act1_scene2', 274, 279, 'KING HENRY', 'But I will rise there with so full a glory'), ('henry_v_act1_scene2', 275, 280, 'KING HENRY', 'That I will dazzle all the eyes of France,'), ('henry_v_act1_scene2', 276, 281, 'KING HENRY', 'Yea, strike the Dauphin blind to look on us.'), ('henry_v_act1_scene2', 277, 282, 'KING HENRY', 'And tell the pleasant prince this mock of his'), ('henry_v_act1_scene2', 278, 283, 'KING HENRY', 'Hath turn’d his balls to gun-stones; and his soul'), ('henry_v_act1_scene2', 279, 284, 'KING HENRY', 'Shall stand sore charged for the wasteful vengeance'), ('henry_v_act1_scene2', 280, 285, 'KING HENRY', 'That shall fly with them: for many a thousand widows'), ('henry_v_act1_scene2', 281, 286, 'KING HENRY', 'Shall this his mock mock out of their dear husbands;'), ('henry_v_act1_scene2', 282, 287, 'KING HENRY', 'Mock mothers from their sons, mock castles down;'), ('henry_v_act1_scene2', 283, 288, 'KING HENRY', 'And some are yet ungotten and unborn'), ('henry_v_act1_scene2', 284, 289, 'KING HENRY', 'That shall have cause to curse the Dauphin’s scorn.'), ('henry_v_act1_scene2', 285, 290, 'KING HENRY', 'But this lies all within the will of God,'), ('henry_v_act1_scene2', 286, 291, 'KING HENRY', 'To whom I do appeal; and in whose name'), ('henry_v_act1_scene2', 287, 292, 'KING HENRY', 'Tell you the Dauphin I am coming on,'), ('henry_v_act1_scene2', 288, 293, 'KING HENRY', 'To venge me as I may and to put forth'), ('henry_v_act1_scene2', 289, 294, 'KING HENRY', 'My rightful hand in a well-hallow’d cause.'), ('henry_v_act1_scene2', 290, 295, 'KING HENRY', 'So get you hence in peace; and tell the Dauphin'), ('henry_v_act1_scene2', 291, 296, 'KING HENRY', 'His jest will savour but of shallow wit,'), ('henry_v_act1_scene2', 292, 297, 'KING HENRY', 'When thousands weep more than did laugh at it.'), ('henry_v_act1_scene2', 293, 298, 'KING HENRY', 'Convey them with safe conduct. Fare you well.'), ('henry_v_act1_scene2', 294, 299, 'EXETER', 'This was a merry message.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act1_scene2', 295, 300, 'KING HENRY', 'We hope to make the sender blush at it.'), ('henry_v_act1_scene2', 296, 301, 'KING HENRY', 'Therefore, my lords, omit no happy hour'), ('henry_v_act1_scene2', 297, 302, 'KING HENRY', 'That may give furtherance to our expedition;'), ('henry_v_act1_scene2', 298, 303, 'KING HENRY', 'For we have now no thought in us but France,'), ('henry_v_act1_scene2', 299, 304, 'KING HENRY', 'Save those to God, that run before our business.'), ('henry_v_act1_scene2', 300, 305, 'KING HENRY', 'Therefore let our proportions for these wars'), ('henry_v_act1_scene2', 301, 306, 'KING HENRY', 'Be soon collected and all things thought upon'), ('henry_v_act1_scene2', 302, 307, 'KING HENRY', 'That may with reasonable swiftness add'), ('henry_v_act1_scene2', 303, 308, 'KING HENRY', 'More feathers to our wings; for, God before,'), ('henry_v_act1_scene2', 304, 309, 'KING HENRY', 'We’ll chide this Dauphin at his father’s door.'), ('henry_v_act1_scene2', 305, 310, 'KING HENRY', 'Therefore let every man now task his thought,'), ('henry_v_act1_scene2', 306, 311, 'KING HENRY', 'That this fair action may on foot be brought.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act2_chorus', 1, 0, 'CHORUS', 'Now all the youth of England are on fire,'), ('henry_v_act2_chorus', 2, 1, 'CHORUS', 'And silken dalliance in the wardrobe lies:'), ('henry_v_act2_chorus', 3, 2, 'CHORUS', 'Now thrive the armourers, and honour’s thought'), ('henry_v_act2_chorus', 4, 3, 'CHORUS', 'Reigns solely in the breast of every man:'), ('henry_v_act2_chorus', 5, 4, 'CHORUS', 'They sell the pasture now to buy the horse,'), ('henry_v_act2_chorus', 6, 5, 'CHORUS', 'Following the mirror of all Christian kings,'), ('henry_v_act2_chorus', 7, 6, 'CHORUS', 'With winged heels, as English Mercuries.'), ('henry_v_act2_chorus', 8, 7, 'CHORUS', 'For now sits Expectation in the air,'), ('henry_v_act2_chorus', 9, 8, 'CHORUS', 'And hides a sword from hilts unto the point'), ('henry_v_act2_chorus', 10, 9, 'CHORUS', 'With crowns imperial, crowns and coronets,'), ('henry_v_act2_chorus', 11, 10, 'CHORUS', 'Promised to Harry and his followers.'), ('henry_v_act2_chorus', 12, 11, 'CHORUS', 'The French, advised by good intelligence'), ('henry_v_act2_chorus', 13, 12, 'CHORUS', 'Of this most dreadful preparation,'), ('henry_v_act2_chorus', 14, 13, 'CHORUS', 'Shake in their fear and with pale policy'), ('henry_v_act2_chorus', 15, 14, 'CHORUS', 'Seek to divert the English purposes.'), ('henry_v_act2_chorus', 16, 15, 'CHORUS', 'O England! model to thy inward greatness,'), ('henry_v_act2_chorus', 17, 16, 'CHORUS', 'Like little body with a mighty heart,'), ('henry_v_act2_chorus', 18, 17, 'CHORUS', 'What mightst thou do, that honour would thee do,'), ('henry_v_act2_chorus', 19, 18, 'CHORUS', 'Were all thy children kind and natural!'), ('henry_v_act2_chorus', 20, 19, 'CHORUS', 'But see thy fault! France hath in thee found out'), ('henry_v_act2_chorus', 21, 20, 'CHORUS', 'A nest of hollow bosoms, which he fills'), ('henry_v_act2_chorus', 22, 21, 'CHORUS', 'With treacherous crowns; and three corrupted men,'), ('henry_v_act2_chorus', 23, 22, 'CHORUS', 'One, Richard Earl of Cambridge, and the second,'), ('henry_v_act2_chorus', 24, 23, 'CHORUS', 'Henry Lord Scroop of Masham, and the third,'), ('henry_v_act2_chorus', 25, 24, 'CHORUS', 'Sir Thomas Grey, knight, of Northumberland,'), ('henry_v_act2_chorus', 26, 25, 'CHORUS', 'Have, for the gilt of France—O guilt indeed!—'), ('henry_v_act2_chorus', 27, 26, 'CHORUS', 'Confirm’d conspiracy with fearful France;'), ('henry_v_act2_chorus', 28, 27, 'CHORUS', 'And by their hands this grace of kings must die,'), ('henry_v_act2_chorus', 29, 28, 'CHORUS', 'If hell and treason hold their promises,'), ('henry_v_act2_chorus', 30, 29, 'CHORUS', 'Ere he take ship for France, and in Southampton.'), ('henry_v_act2_chorus', 31, 30, 'CHORUS', 'Linger your patience on; and we’ll digest'), ('henry_v_act2_chorus', 32, 31, 'CHORUS', 'The abuse of distance; force a play:'), ('henry_v_act2_chorus', 33, 32, 'CHORUS', 'The sum is paid; the traitors are agreed;'), ('henry_v_act2_chorus', 34, 33, 'CHORUS', 'The king is set from London; and the scene'), ('henry_v_act2_chorus', 35, 34, 'CHORUS', 'Is now transported, gentles, to Southampton.'), ('henry_v_act2_chorus', 36, 35, 'CHORUS', 'There is the playhouse now, there must you sit:'), ('henry_v_act2_chorus', 37, 36, 'CHORUS', 'And thence to France shall we convey you safe,'), ('henry_v_act2_chorus', 38, 37, 'CHORUS', 'And bring you back, charming the narrow seas'), ('henry_v_act2_chorus', 39, 38, 'CHORUS', 'To give you gentle pass; for, if we may,'), ('henry_v_act2_chorus', 40, 39, 'CHORUS', 'We’ll not offend one stomach with our play.'), ('henry_v_act2_chorus', 41, 40, 'CHORUS', 'But, till the king come forth, and not till then,'), ('henry_v_act2_chorus', 42, 41, 'CHORUS', 'Unto Southampton do we shift our scene.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act2_scene1', 1, 0, 'BARDOLPH', 'Well met, Corporal Nym.'), ('henry_v_act2_scene1', 1, 1, 'NYM', 'Good morrow, Lieutenant Bardolph.'), ('henry_v_act2_scene1', 2, 2, 'BARDOLPH', 'What, are Ancient Pistol and you friends yet?'), ('henry_v_act2_scene1', 3, 3, 'NYM', 'For my part, I care not: I say little; but when time'), ('henry_v_act2_scene1', 4, 4, 'NYM', 'shall serve, there shall be smiles; but that shall be as it'), ('henry_v_act2_scene1', 5, 5, 'NYM', 'may. I dare not fight; but I will wink and hold out'), ('henry_v_act2_scene1', 6, 6, 'NYM', 'mine iron: it is a simple one; but what though? it will'), ('henry_v_act2_scene1', 7, 7, 'NYM', 'toast cheese, and it will endure cold as another man’s sword will:'), ('henry_v_act2_scene1', 8, 8, 'NYM', 'and there’s an end.'), ('henry_v_act2_scene1', 9, 9, 'BARDOLPH', 'I will bestow a breakfast to make you friends; and we’ll be'), ('henry_v_act2_scene1', 10, 10, 'BARDOLPH', 'all three sworn brothers to France: let it be so, good Corporal'), ('henry_v_act2_scene1', 11, 11, 'BARDOLPH', 'Nym.'), ('henry_v_act2_scene1', 12, 12, 'NYM', 'Faith, I will live so long as I may, that’s the certain'), ('henry_v_act2_scene1', 13, 13, 'NYM', 'of it; and when I cannot live any longer, I will do'), ('henry_v_act2_scene1', 14, 14, 'NYM', 'as I may: that is my rest, that is the rendezvous of'), ('henry_v_act2_scene1', 15, 15, 'NYM', 'it.'), ('henry_v_act2_scene1', 16, 16, 'BARDOLPH', 'It is certain, corporal, that he is married to Nell Quickly; and'), ('henry_v_act2_scene1', 17, 17, 'BARDOLPH', 'certainly she did you wrong; for you were troth-plight to her.'), ('henry_v_act2_scene1', 18, 18, 'NYM', 'I cannot tell: things must be as they may: men may sleep,'), ('henry_v_act2_scene1', 19, 19, 'NYM', 'and they may have their throats about them at that time; and'), ('henry_v_act2_scene1', 20, 20, 'NYM', 'some say knives have edges. It must be as it may: though'), ('henry_v_act2_scene1', 21, 21, 'NYM', 'patience be a tired mare, yet she will plod. There must be'), ('henry_v_act2_scene1', 22, 22, 'NYM', 'conclusions. Well, I cannot tell.'), ('henry_v_act2_scene1', 23, 23, 'BARDOLPH', 'Here comes Ancient Pistol and his wife: good corporal, be patient here.'), ('henry_v_act2_scene1', 24, 24, 'BARDOLPH', 'How now, mine host Pistol!'), ('henry_v_act2_scene1', 24, 25, 'PISTOL', 'Base tike, call’st thou me host?'), ('henry_v_act2_scene1', 25, 26, 'PISTOL', 'Now, by this hand, I swear, I scorn the term;'), ('henry_v_act2_scene1', 26, 27, 'PISTOL', 'Nor shall my Nell keep lodgers.'), ('henry_v_act2_scene1', 27, 28, 'HOSTESS', 'No, by my troth, not long; for we cannot lodge and board'), ('henry_v_act2_scene1', 28, 29, 'HOSTESS', 'a dozen or fourteen gentlewomen that live honestly by the prick of'), ('henry_v_act2_scene1', 29, 30, 'HOSTESS', 'their needles, but it will be thought we keep a bawdy house'), ('henry_v_act2_scene1', 30, 31, 'HOSTESS', 'straight. Nym and Pistol draw. O well a day, Lady, if he'), ('henry_v_act2_scene1', 31, 32, 'HOSTESS', 'be not drawn now! we shall see wilful adultery and murder committed.'), ('henry_v_act2_scene1', 32, 33, 'BARDOLPH', 'Good lieutenant! good corporal! offer nothing here.'), ('henry_v_act2_scene1', 33, 34, 'NYM', 'Pish!'), ('henry_v_act2_scene1', 34, 35, 'PISTOL', 'Pish for thee, Iceland dog! thou prick-ear’d cur of Iceland!'), ('henry_v_act2_scene1', 35, 36, 'HOSTESS', 'Good Corporal Nym, show thy valour, and put up your sword.'), ('henry_v_act2_scene1', 36, 37, 'NYM', 'Will you shog off? I would have you solus.'), ('henry_v_act2_scene1', 37, 38, 'PISTOL', '“Solus,” egregious dog! O viper vile!'), ('henry_v_act2_scene1', 38, 39, 'PISTOL', 'The “solus” in thy most mervailous face;'), ('henry_v_act2_scene1', 39, 40, 'PISTOL', 'The “solus” in thy teeth, and in thy throat,'), ('henry_v_act2_scene1', 40, 41, 'PISTOL', 'And in thy hateful lungs, yea, in thy maw, perdy,'), ('henry_v_act2_scene1', 41, 42, 'PISTOL', 'And, which is worse, within thy nasty mouth!'), ('henry_v_act2_scene1', 42, 43, 'PISTOL', 'I do retort the “solus” in thy bowels;'), ('henry_v_act2_scene1', 43, 44, 'PISTOL', 'For I can take, and Pistol’s cock is up,'), ('henry_v_act2_scene1', 44, 45, 'PISTOL', 'And flashing fire will follow.'), ('henry_v_act2_scene1', 45, 46, 'NYM', 'I am not Barbason; you cannot conjure me. I have an humour'), ('henry_v_act2_scene1', 46, 47, 'NYM', 'to knock you indifferently well. If you grow foul with me, Pistol,'), ('henry_v_act2_scene1', 47, 48, 'NYM', 'I will scour you with my rapier, as I may, in fair'), ('henry_v_act2_scene1', 48, 49, 'NYM', 'terms: if you would walk off, I would prick your guts a'), ('henry_v_act2_scene1', 49, 50, 'NYM', 'little, in good terms, as I may: and that’s the humour of'), ('henry_v_act2_scene1', 50, 51, 'NYM', 'it.'), ('henry_v_act2_scene1', 51, 52, 'PISTOL', 'O braggart vile and damned furious wight!'), ('henry_v_act2_scene1', 52, 53, 'PISTOL', 'The grave doth gape, and doting death is near;'), ('henry_v_act2_scene1', 53, 54, 'PISTOL', 'Therefore exhale.'), ('henry_v_act2_scene1', 54, 55, 'BARDOLPH', 'Hear me, hear me what I say: he that strikes the first'), ('henry_v_act2_scene1', 55, 56, 'BARDOLPH', 'stroke, I’ll run him up to the hilts, as I am a'), ('henry_v_act2_scene1', 56, 57, 'BARDOLPH', 'soldier.'), ('henry_v_act2_scene1', 57, 58, 'PISTOL', 'An oath of mickle might; and fury shall abate.'), ('henry_v_act2_scene1', 58, 59, 'PISTOL', 'Give me thy fist, thy fore-foot to me give:'), ('henry_v_act2_scene1', 59, 60, 'PISTOL', 'Thy spirits are most tall.'), ('henry_v_act2_scene1', 60, 61, 'NYM', 'I will cut thy throat, one time or other, in fair terms:'), ('henry_v_act2_scene1', 61, 62, 'NYM', 'that is the humour of it.'), ('henry_v_act2_scene1', 61, 63, 'PISTOL', '“Couple a gorge!”'), ('henry_v_act2_scene1', 62, 64, 'PISTOL', 'That is the word. I thee defy again.'), ('henry_v_act2_scene1', 63, 65, 'PISTOL', 'O hound of Crete, think’st thou my spouse to get?'), ('henry_v_act2_scene1', 64, 66, 'PISTOL', 'No; to the spital go,'), ('henry_v_act2_scene1', 65, 67, 'PISTOL', 'And from the powdering-tub of infamy'), ('henry_v_act2_scene1', 66, 68, 'PISTOL', 'Fetch forth the lazar kite of Cressid’s kind,'), ('henry_v_act2_scene1', 67, 69, 'PISTOL', 'Doll Tearsheet she by name, and her espouse:'), ('henry_v_act2_scene1', 68, 70, 'PISTOL', 'I have, and I will hold, the quondam Quickly'), ('henry_v_act2_scene1', 69, 71, 'PISTOL', 'For the only she; and—pauca, there’s enough.'), ('henry_v_act2_scene1', 70, 72, 'PISTOL', 'Go to.'), ('henry_v_act2_scene1', 71, 73, 'BOY', 'Mine host Pistol, you must come to my master, and you, hostess:'), ('henry_v_act2_scene1', 72, 74, 'BOY', 'he is very sick, and would to bed. Good Bardolph, put thy'), ('henry_v_act2_scene1', 73, 75, 'BOY', 'face between his sheets, and do the office of a warming-pan. Faith,'), ('henry_v_act2_scene1', 74, 76, 'BOY', 'he’s very ill.'), ('henry_v_act2_scene1', 74, 77, 'BARDOLPH', 'Away, you rogue!'), ('henry_v_act2_scene1', 75, 78, 'HOSTESS', 'By my troth, he’ll yield the crow a pudding one of these'), ('henry_v_act2_scene1', 76, 79, 'HOSTESS', 'days. The king has killed his heart. Good husband, come home presently.'), ('henry_v_act2_scene1', 77, 80, 'BARDOLPH', 'Come, shall I make you two friends? We must to France together:'), ('henry_v_act2_scene1', 78, 81, 'BARDOLPH', 'why the devil should we keep knives to cut one another’s throats?'), ('henry_v_act2_scene1', 79, 82, 'PISTOL', 'Let floods o’erswell, and fiends for food howl on!'), ('henry_v_act2_scene1', 80, 83, 'NYM', 'You’ll pay me the eight shillings I won of you at betting?'), ('henry_v_act2_scene1', 81, 84, 'PISTOL', 'Base is the slave that pays.'), ('henry_v_act2_scene1', 82, 85, 'NYM', 'That now I will have: that’s the humour of it.'), ('henry_v_act2_scene1', 83, 86, 'PISTOL', 'As manhood shall compound: push home.They draw.'), ('henry_v_act2_scene1', 84, 87, 'BARDOLPH', 'By this sword, he that makes the first thrust, I’ll kill him;'), ('henry_v_act2_scene1', 85, 88, 'BARDOLPH', 'by this sword, I will.'), ('henry_v_act2_scene1', 86, 89, 'PISTOL', 'Sword is an oath, and oaths must have their course.'), ('henry_v_act2_scene1', 87, 90, 'BARDOLPH', 'Corporal Nym, and thou wilt be friends, be friends: an thou wilt'), ('henry_v_act2_scene1', 88, 91, 'BARDOLPH', 'not, why, then, be enemies with me too. Prithee, put up.'), ('henry_v_act2_scene1', 89, 92, 'NYM', 'I shall have my eight shillings I won from you at betting?'), ('henry_v_act2_scene1', 90, 93, 'PISTOL', 'A noble shalt thou have, and present pay;'), ('henry_v_act2_scene1', 91, 94, 'PISTOL', 'And liquor likewise will I give to thee,'), ('henry_v_act2_scene1', 92, 95, 'PISTOL', 'And friendship shall combine, and brotherhood:'), ('henry_v_act2_scene1', 93, 96, 'PISTOL', 'I’ll live by Nym, and Nym shall live by me;'), ('henry_v_act2_scene1', 94, 97, 'PISTOL', 'Is not this just? for I shall sutler be'), ('henry_v_act2_scene1', 95, 98, 'PISTOL', 'Unto the camp, and profits will accrue.'), ('henry_v_act2_scene1', 96, 99, 'PISTOL', 'Give me thy hand.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act2_scene1', 96, 100, 'NYM', 'I shall have my noble?'), ('henry_v_act2_scene1', 97, 101, 'PISTOL', 'In cash most justly paid.'), ('henry_v_act2_scene1', 97, 102, 'NYM', 'Well, then, that’s the humour of’t.'), ('henry_v_act2_scene1', 98, 103, 'HOSTESS', 'As ever you come of women, come in quickly to Sir John.'), ('henry_v_act2_scene1', 99, 104, 'HOSTESS', 'Ah, poor heart! he is so shaked of a burning quotidian tertian,'), ('henry_v_act2_scene1', 100, 105, 'HOSTESS', 'that it is most lamentable to behold. Sweet men, come to him.'), ('henry_v_act2_scene1', 101, 106, 'NYM', 'The king hath run bad humours on the knight; that’s the even of it.'), ('henry_v_act2_scene1', 102, 107, 'PISTOL', 'Nym, thou hast spoke the right;'), ('henry_v_act2_scene1', 103, 108, 'PISTOL', 'His heart is fracted and corroborate.'), ('henry_v_act2_scene1', 104, 109, 'NYM', 'The king is a good king: but it must be as it'), ('henry_v_act2_scene1', 105, 110, 'NYM', 'may; he passes some humours and careers.'), ('henry_v_act2_scene1', 106, 111, 'PISTOL', 'Let us condole the knight; for, lambkins, we will live.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act2_scene2', 1, 0, 'BEDFORD', '’Fore God, his grace is bold, to trust these traitors.'), ('henry_v_act2_scene2', 2, 1, 'EXETER', 'They shall be apprehended by and by.'), ('henry_v_act2_scene2', 3, 2, 'WESTMORELAND', 'How smooth and even they do bear themselves!'), ('henry_v_act2_scene2', 4, 3, 'WESTMORELAND', 'As if allegiance in their bosoms sat,'), ('henry_v_act2_scene2', 5, 4, 'WESTMORELAND', 'Crowned with faith and constant loyalty.'), ('henry_v_act2_scene2', 6, 5, 'BEDFORD', 'The king hath note of all that they intend,'), ('henry_v_act2_scene2', 7, 6, 'BEDFORD', 'By interception which they dream not of.'), ('henry_v_act2_scene2', 8, 7, 'EXETER', 'Nay, but the man that was his bedfellow,'), ('henry_v_act2_scene2', 9, 8, 'EXETER', 'Whom he hath dull’d and cloy’d with gracious favours,'), ('henry_v_act2_scene2', 10, 9, 'EXETER', 'That he should, for a foreign purse, so sell'), ('henry_v_act2_scene2', 11, 10, 'EXETER', 'His sovereign’s life to death and treachery.'), ('henry_v_act2_scene2', 12, 11, 'KING HENRY', 'Now sits the wind fair, and we will aboard.'), ('henry_v_act2_scene2', 13, 12, 'KING HENRY', 'My Lord of Cambridge, and my kind Lord of Masham,'), ('henry_v_act2_scene2', 14, 13, 'KING HENRY', 'And you, my gentle knight, give me your thoughts:'), ('henry_v_act2_scene2', 15, 14, 'KING HENRY', 'Think you not that the powers we bear with us'), ('henry_v_act2_scene2', 16, 15, 'KING HENRY', 'Will cut their passage through the force of France,'), ('henry_v_act2_scene2', 17, 16, 'KING HENRY', 'Doing the execution and the act'), ('henry_v_act2_scene2', 18, 17, 'KING HENRY', 'For which we have in head assembled them?'), ('henry_v_act2_scene2', 19, 18, 'SCROOP', 'No doubt, my liege, if each man do his best.'), ('henry_v_act2_scene2', 20, 19, 'KING HENRY', 'I doubt not that; since we are well persuaded'), ('henry_v_act2_scene2', 21, 20, 'KING HENRY', 'We carry not a heart with us from hence'), ('henry_v_act2_scene2', 22, 21, 'KING HENRY', 'That grows not in a fair consent with ours,'), ('henry_v_act2_scene2', 23, 22, 'KING HENRY', 'Nor leave not one behind that doth not wish'), ('henry_v_act2_scene2', 24, 23, 'KING HENRY', 'Success and conquest to attend on us.'), ('henry_v_act2_scene2', 25, 24, 'CAMBRIDGE', 'Never was monarch better fear’d and loved'), ('henry_v_act2_scene2', 26, 25, 'CAMBRIDGE', 'Than is your majesty: there’s not, I think, a subject'), ('henry_v_act2_scene2', 27, 26, 'CAMBRIDGE', 'That sits in heart-grief and uneasiness'), ('henry_v_act2_scene2', 28, 27, 'CAMBRIDGE', 'Under the sweet shade of your government.'), ('henry_v_act2_scene2', 29, 28, 'GREY', 'True: those that were your father’s enemies'), ('henry_v_act2_scene2', 30, 29, 'GREY', 'Have steep’d their galls in honey and do serve you'), ('henry_v_act2_scene2', 31, 30, 'GREY', 'With hearts create of duty and of zeal.'), ('henry_v_act2_scene2', 32, 31, 'KING HENRY', 'We therefore have great cause of thankfulness;'), ('henry_v_act2_scene2', 33, 32, 'KING HENRY', 'And shall forget the office of our hand,'), ('henry_v_act2_scene2', 34, 33, 'KING HENRY', 'Sooner than quittance of desert and merit'), ('henry_v_act2_scene2', 35, 34, 'KING HENRY', 'According to the weight and worthiness.'), ('henry_v_act2_scene2', 36, 35, 'SCROOP', 'So service shall with steeled sinews toil,'), ('henry_v_act2_scene2', 37, 36, 'SCROOP', 'And labour shall refresh itself with hope,'), ('henry_v_act2_scene2', 38, 37, 'SCROOP', 'To do your grace incessant services.'), ('henry_v_act2_scene2', 39, 38, 'KING HENRY', 'We judge no less. Uncle of Exeter,'), ('henry_v_act2_scene2', 40, 39, 'KING HENRY', 'Enlarge the man committed yesterday,'), ('henry_v_act2_scene2', 41, 40, 'KING HENRY', 'That rail’d against our person: we consider'), ('henry_v_act2_scene2', 42, 41, 'KING HENRY', 'It was excess of wine that set him on;'), ('henry_v_act2_scene2', 43, 42, 'KING HENRY', 'And on his more advice we pardon him.'), ('henry_v_act2_scene2', 44, 43, 'SCROOP', 'That’s mercy, but too much security:'), ('henry_v_act2_scene2', 45, 44, 'SCROOP', 'Let him be punish’d, sovereign, lest example'), ('henry_v_act2_scene2', 46, 45, 'SCROOP', 'Breed, by his sufferance, more of such a kind.'), ('henry_v_act2_scene2', 47, 46, 'KING HENRY', 'O, let us yet be merciful.'), ('henry_v_act2_scene2', 48, 47, 'CAMBRIDGE', 'So may your highness, and yet punish too.'), ('henry_v_act2_scene2', 49, 48, 'GREY', 'Sir,'), ('henry_v_act2_scene2', 50, 49, 'GREY', 'You show great mercy, if you give him life,'), ('henry_v_act2_scene2', 51, 50, 'GREY', 'After the taste of much correction.'), ('henry_v_act2_scene2', 52, 51, 'KING HENRY', 'Alas, your too much love and care of me'), ('henry_v_act2_scene2', 53, 52, 'KING HENRY', 'Are heavy orisons ’gainst this poor wretch!'), ('henry_v_act2_scene2', 54, 53, 'KING HENRY', 'If little faults, proceeding on distemper,'), ('henry_v_act2_scene2', 55, 54, 'KING HENRY', 'Shall not be wink’d at, how shall we stretch our eye'), ('henry_v_act2_scene2', 56, 55, 'KING HENRY', 'When capital crimes, chew’d, swallow’d and digested,'), ('henry_v_act2_scene2', 57, 56, 'KING HENRY', 'Appear before us? We’ll yet enlarge that man,'), ('henry_v_act2_scene2', 58, 57, 'KING HENRY', 'Though Cambridge, Scroop and Grey, in their dear care'), ('henry_v_act2_scene2', 59, 58, 'KING HENRY', 'And tender preservation of our person,'), ('henry_v_act2_scene2', 60, 59, 'KING HENRY', 'Would have him punish’d. And now to our French causes:'), ('henry_v_act2_scene2', 61, 60, 'KING HENRY', 'Who are the late commissioners?'), ('henry_v_act2_scene2', 61, 61, 'CAMBRIDGE', 'I one, my lord:'), ('henry_v_act2_scene2', 62, 62, 'CAMBRIDGE', 'Your highness bade me ask for it today.'), ('henry_v_act2_scene2', 63, 63, 'SCROOP', 'So did you me, my liege.'), ('henry_v_act2_scene2', 63, 64, 'GREY', 'And I, my royal sovereign.'), ('henry_v_act2_scene2', 64, 65, 'KING HENRY', 'Then, Richard Earl of Cambridge, there is yours;'), ('henry_v_act2_scene2', 65, 66, 'KING HENRY', 'There yours, Lord Scroop of Masham; and, sir knight,'), ('henry_v_act2_scene2', 66, 67, 'KING HENRY', 'Grey of Northumberland, this same is yours:'), ('henry_v_act2_scene2', 67, 68, 'KING HENRY', 'Read them; and know, I know your worthiness.'), ('henry_v_act2_scene2', 68, 69, 'KING HENRY', 'My Lord of Westmoreland, and uncle Exeter,'), ('henry_v_act2_scene2', 69, 70, 'KING HENRY', 'We will aboard tonight. Why, how now, gentlemen!'), ('henry_v_act2_scene2', 70, 71, 'KING HENRY', 'What see you in those papers that you lose'), ('henry_v_act2_scene2', 71, 72, 'KING HENRY', 'So much complexion? Look ye, how they change!'), ('henry_v_act2_scene2', 72, 73, 'KING HENRY', 'Their cheeks are paper. Why, what read you there,'), ('henry_v_act2_scene2', 73, 74, 'KING HENRY', 'That have so cowarded and chased your blood'), ('henry_v_act2_scene2', 74, 75, 'KING HENRY', 'Out of appearance?'), ('henry_v_act2_scene2', 74, 76, 'CAMBRIDGE', 'I do confess my fault;'), ('henry_v_act2_scene2', 75, 77, 'CAMBRIDGE', 'And do submit me to your highness’ mercy.'), ('henry_v_act2_scene2', 76, 78, 'GREY AND SCROOP', 'To which we all appeal.'), ('henry_v_act2_scene2', 77, 79, 'KING HENRY', 'The mercy that was quick in us but late,'), ('henry_v_act2_scene2', 78, 80, 'KING HENRY', 'By your own counsel is suppress’d and kill’d:'), ('henry_v_act2_scene2', 79, 81, 'KING HENRY', 'You must not dare, for shame, to talk of mercy;'), ('henry_v_act2_scene2', 80, 82, 'KING HENRY', 'For your own reasons turn into your bosoms,'), ('henry_v_act2_scene2', 81, 83, 'KING HENRY', 'As dogs upon their masters, worrying you.'), ('henry_v_act2_scene2', 82, 84, 'KING HENRY', 'See you, my princes and my noble peers,'), ('henry_v_act2_scene2', 83, 85, 'KING HENRY', 'These English monsters! My Lord of Cambridge here,'), ('henry_v_act2_scene2', 84, 86, 'KING HENRY', 'You know how apt our love was to accord'), ('henry_v_act2_scene2', 85, 87, 'KING HENRY', 'To furnish him with an appertinents'), ('henry_v_act2_scene2', 86, 88, 'KING HENRY', 'Belonging to his honour; and this man'), ('henry_v_act2_scene2', 87, 89, 'KING HENRY', 'Hath, for a few light crowns, lightly conspired,'), ('henry_v_act2_scene2', 88, 90, 'KING HENRY', 'And sworn unto the practices of France,'), ('henry_v_act2_scene2', 89, 91, 'KING HENRY', 'To kill us here in Hampton: to the which'), ('henry_v_act2_scene2', 90, 92, 'KING HENRY', 'This knight, no less for bounty bound to us'), ('henry_v_act2_scene2', 91, 93, 'KING HENRY', 'Than Cambridge is, hath likewise sworn. But, O,'), ('henry_v_act2_scene2', 92, 94, 'KING HENRY', 'What shall I say to thee, Lord Scroop? thou cruel,'), ('henry_v_act2_scene2', 93, 95, 'KING HENRY', 'Ingrateful, savage and inhuman creature!'), ('henry_v_act2_scene2', 94, 96, 'KING HENRY', 'Thou that didst bear the key of all my counsels,'), ('henry_v_act2_scene2', 95, 97, 'KING HENRY', 'That knew’st the very bottom of my soul,'), ('henry_v_act2_scene2', 96, 98, 'KING HENRY', 'That almost mightst have coin’d me into gold,'), ('henry_v_act2_scene2', 97, 99, 'KING HENRY', 'Wouldst thou have practised on me for thy use!');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act2_scene2', 98, 100, 'KING HENRY', 'May it be possible, that foreign hire'), ('henry_v_act2_scene2', 99, 101, 'KING HENRY', 'Could out of thee extract one spark of evil'), ('henry_v_act2_scene2', 100, 102, 'KING HENRY', 'That might annoy my finger? ’tis so strange,'), ('henry_v_act2_scene2', 101, 103, 'KING HENRY', 'That, though the truth of it stands off as gross'), ('henry_v_act2_scene2', 102, 104, 'KING HENRY', 'As black and white, my eye will scarcely see it.'), ('henry_v_act2_scene2', 103, 105, 'KING HENRY', 'Treason and murder ever kept together,'), ('henry_v_act2_scene2', 104, 106, 'KING HENRY', 'As two yoke-devils sworn to either’s purpose,'), ('henry_v_act2_scene2', 105, 107, 'KING HENRY', 'Working so grossly in a natural cause,'), ('henry_v_act2_scene2', 106, 108, 'KING HENRY', 'That admiration did not whoop at them:'), ('henry_v_act2_scene2', 107, 109, 'KING HENRY', 'But thou, ’gainst all proportion, didst bring in'), ('henry_v_act2_scene2', 108, 110, 'KING HENRY', 'Wonder to wait on treason and on murder:'), ('henry_v_act2_scene2', 109, 111, 'KING HENRY', 'And whatsoever cunning fiend it was'), ('henry_v_act2_scene2', 110, 112, 'KING HENRY', 'That wrought upon thee so preposterously'), ('henry_v_act2_scene2', 111, 113, 'KING HENRY', 'Hath got the voice in hell for excellence:'), ('henry_v_act2_scene2', 112, 114, 'KING HENRY', 'And other devils that suggest by treasons'), ('henry_v_act2_scene2', 113, 115, 'KING HENRY', 'Do botch and bungle up damnation'), ('henry_v_act2_scene2', 114, 116, 'KING HENRY', 'With patches, colours and with forms being fetch’d'), ('henry_v_act2_scene2', 115, 117, 'KING HENRY', 'From glistering semblances of piety;'), ('henry_v_act2_scene2', 116, 118, 'KING HENRY', 'But he that temper’d thee bade thee stand up,'), ('henry_v_act2_scene2', 117, 119, 'KING HENRY', 'Gave thee no instance why thou shouldst do treason,'), ('henry_v_act2_scene2', 118, 120, 'KING HENRY', 'Unless to dub thee with the name of traitor.'), ('henry_v_act2_scene2', 119, 121, 'KING HENRY', 'If that same demon that hath gull’d thee thus'), ('henry_v_act2_scene2', 120, 122, 'KING HENRY', 'Should with his lion gait walk the whole world,'), ('henry_v_act2_scene2', 121, 123, 'KING HENRY', 'He might return to vasty Tartar back,'), ('henry_v_act2_scene2', 122, 124, 'KING HENRY', 'And tell the legions “I can never win'), ('henry_v_act2_scene2', 123, 125, 'KING HENRY', 'A soul so easy as that Englishman’s.”'), ('henry_v_act2_scene2', 124, 126, 'KING HENRY', 'O, how hast thou with jealousy infected'), ('henry_v_act2_scene2', 125, 127, 'KING HENRY', 'The sweetness of affiance! Show men dutiful?'), ('henry_v_act2_scene2', 126, 128, 'KING HENRY', 'Why, so didst thou: seem they grave and learned?'), ('henry_v_act2_scene2', 127, 129, 'KING HENRY', 'Why, so didst thou: come they of noble family?'), ('henry_v_act2_scene2', 128, 130, 'KING HENRY', 'Why, so didst thou: seem they religious?'), ('henry_v_act2_scene2', 129, 131, 'KING HENRY', 'Why, so didst thou: or are they spare in diet,'), ('henry_v_act2_scene2', 130, 132, 'KING HENRY', 'Free from gross passion or of mirth or anger,'), ('henry_v_act2_scene2', 131, 133, 'KING HENRY', 'Constant in spirit, not swerving with the blood,'), ('henry_v_act2_scene2', 132, 134, 'KING HENRY', 'Garnish’d and deck’d in modest complement,'), ('henry_v_act2_scene2', 133, 135, 'KING HENRY', 'Not working with the eye without the ear,'), ('henry_v_act2_scene2', 134, 136, 'KING HENRY', 'And but in purged judgement trusting neither?'), ('henry_v_act2_scene2', 135, 137, 'KING HENRY', 'Such and so finely bolted didst thou seem:'), ('henry_v_act2_scene2', 136, 138, 'KING HENRY', 'And thus thy fall hath left a kind of blot,'), ('henry_v_act2_scene2', 137, 139, 'KING HENRY', 'To mark the full-fraught man and best indued'), ('henry_v_act2_scene2', 138, 140, 'KING HENRY', 'With some suspicion. I will weep for thee;'), ('henry_v_act2_scene2', 139, 141, 'KING HENRY', 'For this revolt of thine, methinks, is like'), ('henry_v_act2_scene2', 140, 142, 'KING HENRY', 'Another fall of man. Their faults are open:'), ('henry_v_act2_scene2', 141, 143, 'KING HENRY', 'Arrest them to the answer of the law;'), ('henry_v_act2_scene2', 142, 144, 'KING HENRY', 'And God acquit them of their practices!'), ('henry_v_act2_scene2', 143, 145, 'EXETER', 'I arrest thee of high treason, by the name of Richard Earl of Cambridge.'), ('henry_v_act2_scene2', 144, 146, 'EXETER', 'I arrest thee of high treason, by the name of Henry Lord Scroop of Masham.'), ('henry_v_act2_scene2', 145, 147, 'EXETER', 'I arrest thee of high treason, by the name of Thomas Grey, knight, of Northumberland.'), ('henry_v_act2_scene2', 146, 148, 'SCROOP', 'Our purposes God justly hath discover’d;'), ('henry_v_act2_scene2', 147, 149, 'SCROOP', 'And I repent my fault more than my death;'), ('henry_v_act2_scene2', 148, 150, 'SCROOP', 'Which I beseech your highness to forgive,'), ('henry_v_act2_scene2', 149, 151, 'SCROOP', 'Although my body pay the price of it.'), ('henry_v_act2_scene2', 150, 152, 'CAMBRIDGE', 'For me, the gold of France did not seduce;'), ('henry_v_act2_scene2', 151, 153, 'CAMBRIDGE', 'Although I did admit it as a motive'), ('henry_v_act2_scene2', 152, 154, 'CAMBRIDGE', 'The sooner to effect what I intended:'), ('henry_v_act2_scene2', 153, 155, 'CAMBRIDGE', 'But God be thanked for prevention;'), ('henry_v_act2_scene2', 154, 156, 'CAMBRIDGE', 'Which I in sufferance heartily will rejoice,'), ('henry_v_act2_scene2', 155, 157, 'CAMBRIDGE', 'Beseeching God and you to pardon me.'), ('henry_v_act2_scene2', 156, 158, 'GREY', 'Never did faithful subject more rejoice'), ('henry_v_act2_scene2', 157, 159, 'GREY', 'At the discovery of most dangerous treason'), ('henry_v_act2_scene2', 158, 160, 'GREY', 'Than I do at this hour joy o’er myself,'), ('henry_v_act2_scene2', 159, 161, 'GREY', 'Prevented from a damned enterprise:'), ('henry_v_act2_scene2', 160, 162, 'GREY', 'My fault, but not my body, pardon, sovereign.'), ('henry_v_act2_scene2', 161, 163, 'KING HENRY', 'God quit you in his mercy! Hear your sentence.'), ('henry_v_act2_scene2', 162, 164, 'KING HENRY', 'You have conspired against our royal person,'), ('henry_v_act2_scene2', 163, 165, 'KING HENRY', 'Join’d with an enemy proclaim’d and from his coffers'), ('henry_v_act2_scene2', 164, 166, 'KING HENRY', 'Received the golden earnest of our death;'), ('henry_v_act2_scene2', 165, 167, 'KING HENRY', 'Wherein you would have sold your king to slaughter,'), ('henry_v_act2_scene2', 166, 168, 'KING HENRY', 'His princes and his peers to servitude,'), ('henry_v_act2_scene2', 167, 169, 'KING HENRY', 'His subjects to oppression and contempt'), ('henry_v_act2_scene2', 168, 170, 'KING HENRY', 'And his whole kingdom into desolation.'), ('henry_v_act2_scene2', 169, 171, 'KING HENRY', 'Touching our person seek we no revenge;'), ('henry_v_act2_scene2', 170, 172, 'KING HENRY', 'But we our kingdom’s safety must so tender,'), ('henry_v_act2_scene2', 171, 173, 'KING HENRY', 'Whose ruin you have sought, that to her laws'), ('henry_v_act2_scene2', 172, 174, 'KING HENRY', 'We do deliver you. Get you therefore hence,'), ('henry_v_act2_scene2', 173, 175, 'KING HENRY', 'Poor miserable wretches, to your death:'), ('henry_v_act2_scene2', 174, 176, 'KING HENRY', 'The taste whereof, God of his mercy give'), ('henry_v_act2_scene2', 175, 177, 'KING HENRY', 'You patience to endure, and true repentance'), ('henry_v_act2_scene2', 176, 178, 'KING HENRY', 'Of all your dear offences! Bear them hence.'), ('henry_v_act2_scene2', 177, 179, 'KING HENRY', 'Now, lords, for France; the enterprise whereof'), ('henry_v_act2_scene2', 178, 180, 'KING HENRY', 'Shall be to you, as us, like glorious.'), ('henry_v_act2_scene2', 179, 181, 'KING HENRY', 'We doubt not of a fair and lucky war,'), ('henry_v_act2_scene2', 180, 182, 'KING HENRY', 'Since God so graciously hath brought to light'), ('henry_v_act2_scene2', 181, 183, 'KING HENRY', 'This dangerous treason lurking in our way'), ('henry_v_act2_scene2', 182, 184, 'KING HENRY', 'To hinder our beginnings. We doubt not now'), ('henry_v_act2_scene2', 183, 185, 'KING HENRY', 'But every rub is smoothed on our way.'), ('henry_v_act2_scene2', 184, 186, 'KING HENRY', 'Then forth, dear countrymen: let us deliver'), ('henry_v_act2_scene2', 185, 187, 'KING HENRY', 'Our puissance into the hand of God,'), ('henry_v_act2_scene2', 186, 188, 'KING HENRY', 'Putting it straight in expedition.'), ('henry_v_act2_scene2', 187, 189, 'KING HENRY', 'Cheerly to sea; the signs of war advance:'), ('henry_v_act2_scene2', 188, 190, 'KING HENRY', 'No king of England, if not king of France.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act2_scene3', 1, 0, 'HOSTESS', 'Prithee, honey-sweet husband, let me bring thee to Staines.'), ('henry_v_act2_scene3', 2, 1, 'PISTOL', 'No; for my manly heart doth yearn.'), ('henry_v_act2_scene3', 3, 2, 'PISTOL', 'Bardolph, be blithe: Nym, rouse thy vaunting veins:'), ('henry_v_act2_scene3', 4, 3, 'PISTOL', 'Boy, bristle thy courage up; for Falstaff he is dead,'), ('henry_v_act2_scene3', 5, 4, 'PISTOL', 'And we must yearn therefore.'), ('henry_v_act2_scene3', 6, 5, 'BARDOLPH', 'Would I were with him, wheresome’er he is, either in heaven or in hell!'), ('henry_v_act2_scene3', 7, 6, 'HOSTESS', 'Nay, sure, he’s not in hell: he’s in Arthur’s bosom, if ever'), ('henry_v_act2_scene3', 8, 7, 'HOSTESS', 'man went to Arthur’s bosom. A’ made a finer end and went'), ('henry_v_act2_scene3', 9, 8, 'HOSTESS', 'away an it had been any christom child; a’ parted even just'), ('henry_v_act2_scene3', 10, 9, 'HOSTESS', 'between twelve and one, even at the turning o’ the tide: for'), ('henry_v_act2_scene3', 11, 10, 'HOSTESS', 'after I saw him fumble with the sheets and play with flowers'), ('henry_v_act2_scene3', 12, 11, 'HOSTESS', 'and smile upon his fingers’ ends, I knew there was but one'), ('henry_v_act2_scene3', 13, 12, 'HOSTESS', 'way; for his nose was as sharp as a pen, and a’'), ('henry_v_act2_scene3', 14, 13, 'HOSTESS', 'babbled of green fields. “How now, Sir John!” quoth I: “what, man!'), ('henry_v_act2_scene3', 15, 14, 'HOSTESS', 'be o’ good cheer.” So a’ cried out, “God, God, God!” three'), ('henry_v_act2_scene3', 16, 15, 'HOSTESS', 'or four times. Now I, to comfort him, bid him a’ should'), ('henry_v_act2_scene3', 17, 16, 'HOSTESS', 'not think of God; I hoped there was no need to trouble'), ('henry_v_act2_scene3', 18, 17, 'HOSTESS', 'himself with any such thoughts yet. So a’ bade me lay more'), ('henry_v_act2_scene3', 19, 18, 'HOSTESS', 'clothes on his feet: I put my hand into the bed and'), ('henry_v_act2_scene3', 20, 19, 'HOSTESS', 'felt them, and they were as cold as any stone; then I'), ('henry_v_act2_scene3', 21, 20, 'HOSTESS', 'felt to his knees, and they were as cold as any stone,'), ('henry_v_act2_scene3', 22, 21, 'HOSTESS', 'and so upward and upward, and all was as cold as any'), ('henry_v_act2_scene3', 23, 22, 'HOSTESS', 'stone.'), ('henry_v_act2_scene3', 24, 23, 'NYM', 'They say he cried out of sack.'), ('henry_v_act2_scene3', 25, 24, 'HOSTESS', 'Ay, that a’ did.'), ('henry_v_act2_scene3', 25, 25, 'BARDOLPH', 'And of women.'), ('henry_v_act2_scene3', 26, 26, 'HOSTESS', 'Nay, that a’ did not.'), ('henry_v_act2_scene3', 27, 27, 'BOY', 'Yes, that a’ did; and said they were devils incarnate.'), ('henry_v_act2_scene3', 28, 28, 'HOSTESS', 'A’ could never abide carnation; ’twas a colour he never liked.'), ('henry_v_act2_scene3', 29, 29, 'BOY', 'A’ said once, the devil would have him about women.'), ('henry_v_act2_scene3', 30, 30, 'HOSTESS', 'A’ did in some sort, indeed, handle women; but then he was'), ('henry_v_act2_scene3', 31, 31, 'HOSTESS', 'rheumatic, and talk’d of the whore of Babylon.'), ('henry_v_act2_scene3', 32, 32, 'BOY', 'Do you not remember, a’ saw a flea stick upon Bardolph’s nose,'), ('henry_v_act2_scene3', 33, 33, 'BOY', 'and a’ said it was a black soul burning in hellfire?'), ('henry_v_act2_scene3', 34, 34, 'BARDOLPH', 'Well, the fuel is gone that maintained that fire: that’s all the'), ('henry_v_act2_scene3', 35, 35, 'BARDOLPH', 'riches I got in his service.'), ('henry_v_act2_scene3', 36, 36, 'NYM', 'Shall we shog? the king will be gone from Southampton.'), ('henry_v_act2_scene3', 37, 37, 'PISTOL', 'Come, let’s away. My love, give me thy lips.'), ('henry_v_act2_scene3', 38, 38, 'PISTOL', 'Look to my chattels and my movables:'), ('henry_v_act2_scene3', 39, 39, 'PISTOL', 'Let senses rule; the word is “Pitch and Pay:”'), ('henry_v_act2_scene3', 40, 40, 'PISTOL', 'Trust none;'), ('henry_v_act2_scene3', 41, 41, 'PISTOL', 'For oaths are straws, men’s faiths are wafer-cakes,'), ('henry_v_act2_scene3', 42, 42, 'PISTOL', 'And holdfast is the only dog, my duck:'), ('henry_v_act2_scene3', 43, 43, 'PISTOL', 'Therefore, Caveto be thy counsellor.'), ('henry_v_act2_scene3', 44, 44, 'PISTOL', 'Go, clear thy crystals. Yoke-fellows in arms,'), ('henry_v_act2_scene3', 45, 45, 'PISTOL', 'Let us to France; like horse-leeches, my boys,'), ('henry_v_act2_scene3', 46, 46, 'PISTOL', 'To suck, to suck, the very blood to suck!'), ('henry_v_act2_scene3', 47, 47, 'BOY', 'And that’s but unwholesome food, they say.'), ('henry_v_act2_scene3', 48, 48, 'PISTOL', 'Touch her soft mouth, and march.'), ('henry_v_act2_scene3', 48, 49, 'BARDOLPH', 'Farewell, hostess. Kissing her.'), ('henry_v_act2_scene3', 49, 50, 'NYM', 'I cannot kiss, that is the humour of it; but, adieu.'), ('henry_v_act2_scene3', 50, 51, 'PISTOL', 'Let housewifery appear: keep close, I thee command.'), ('henry_v_act2_scene3', 51, 52, 'HOSTESS', 'Farewell; adieu.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act2_scene4', 1, 0, 'FRENCH KING', 'Thus comes the English with full power upon us;'), ('henry_v_act2_scene4', 2, 1, 'FRENCH KING', 'And more than carefully it us concerns'), ('henry_v_act2_scene4', 3, 2, 'FRENCH KING', 'To answer royally in our defences.'), ('henry_v_act2_scene4', 4, 3, 'FRENCH KING', 'Therefore the Dukes of Berri and of Brittagne,'), ('henry_v_act2_scene4', 5, 4, 'FRENCH KING', 'Of Brabant and of Orleans, shall make forth,'), ('henry_v_act2_scene4', 6, 5, 'FRENCH KING', 'And you, Prince Dauphin, with all swift dispatch,'), ('henry_v_act2_scene4', 7, 6, 'FRENCH KING', 'To line and new repair our towns of war'), ('henry_v_act2_scene4', 8, 7, 'FRENCH KING', 'With men of courage and with means defendant;'), ('henry_v_act2_scene4', 9, 8, 'FRENCH KING', 'For England his approaches makes as fierce'), ('henry_v_act2_scene4', 10, 9, 'FRENCH KING', 'As waters to the sucking of a gulf.'), ('henry_v_act2_scene4', 11, 10, 'FRENCH KING', 'It fits us then to be as provident'), ('henry_v_act2_scene4', 12, 11, 'FRENCH KING', 'As fears may teach us out of late examples'), ('henry_v_act2_scene4', 13, 12, 'FRENCH KING', 'Left by the fatal and neglected English'), ('henry_v_act2_scene4', 14, 13, 'FRENCH KING', 'Upon our fields.'), ('henry_v_act2_scene4', 14, 14, 'DAUPHIN', 'My most redoubted father,'), ('henry_v_act2_scene4', 15, 15, 'DAUPHIN', 'It is most meet we arm us ’gainst the foe;'), ('henry_v_act2_scene4', 16, 16, 'DAUPHIN', 'For peace itself should not so dull a kingdom,'), ('henry_v_act2_scene4', 17, 17, 'DAUPHIN', 'Though war nor no known quarrel were in question,'), ('henry_v_act2_scene4', 18, 18, 'DAUPHIN', 'But that defences, musters, preparations,'), ('henry_v_act2_scene4', 19, 19, 'DAUPHIN', 'Should be maintain’d, assembled and collected,'), ('henry_v_act2_scene4', 20, 20, 'DAUPHIN', 'As were a war in expectation.'), ('henry_v_act2_scene4', 21, 21, 'DAUPHIN', 'Therefore, I say, ’tis meet we all go forth'), ('henry_v_act2_scene4', 22, 22, 'DAUPHIN', 'To view the sick and feeble parts of France:'), ('henry_v_act2_scene4', 23, 23, 'DAUPHIN', 'And let us do it with no show of fear;'), ('henry_v_act2_scene4', 24, 24, 'DAUPHIN', 'No, with no more than if we heard that England'), ('henry_v_act2_scene4', 25, 25, 'DAUPHIN', 'Were busied with a Whitsun morris-dance:'), ('henry_v_act2_scene4', 26, 26, 'DAUPHIN', 'For, my good liege, she is so idly king’d,'), ('henry_v_act2_scene4', 27, 27, 'DAUPHIN', 'Her sceptre so fantastically borne'), ('henry_v_act2_scene4', 28, 28, 'DAUPHIN', 'By a vain, giddy, shallow, humorous youth,'), ('henry_v_act2_scene4', 29, 29, 'DAUPHIN', 'That fear attends her not.'), ('henry_v_act2_scene4', 29, 30, 'CONSTABLE', 'O peace, Prince Dauphin!'), ('henry_v_act2_scene4', 30, 31, 'CONSTABLE', 'You are too much mistaken in this king:'), ('henry_v_act2_scene4', 31, 32, 'CONSTABLE', 'Question your grace the late ambassadors,'), ('henry_v_act2_scene4', 32, 33, 'CONSTABLE', 'With what great state he heard their embassy,'), ('henry_v_act2_scene4', 33, 34, 'CONSTABLE', 'How well supplied with noble counsellors,'), ('henry_v_act2_scene4', 34, 35, 'CONSTABLE', 'How modest in exception, and withal'), ('henry_v_act2_scene4', 35, 36, 'CONSTABLE', 'How terrible in constant resolution,'), ('henry_v_act2_scene4', 36, 37, 'CONSTABLE', 'And you shall find his vanities forespent'), ('henry_v_act2_scene4', 37, 38, 'CONSTABLE', 'Were but the outside of the Roman Brutus,'), ('henry_v_act2_scene4', 38, 39, 'CONSTABLE', 'Covering discretion with a coat of folly;'), ('henry_v_act2_scene4', 39, 40, 'CONSTABLE', 'As gardeners do with ordure hide those roots'), ('henry_v_act2_scene4', 40, 41, 'CONSTABLE', 'That shall first spring and be most delicate.'), ('henry_v_act2_scene4', 41, 42, 'DAUPHIN', 'Well, ’tis not so, my lord high constable;'), ('henry_v_act2_scene4', 42, 43, 'DAUPHIN', 'But though we think it so, it is no matter:'), ('henry_v_act2_scene4', 43, 44, 'DAUPHIN', 'In cases of defence ’tis best to weigh'), ('henry_v_act2_scene4', 44, 45, 'DAUPHIN', 'The enemy more mighty than he seems:'), ('henry_v_act2_scene4', 45, 46, 'DAUPHIN', 'So the proportions of defence are fill’d;'), ('henry_v_act2_scene4', 46, 47, 'DAUPHIN', 'Which of a weak and niggardly projection'), ('henry_v_act2_scene4', 47, 48, 'DAUPHIN', 'Doth, like a miser, spoil his coat with scanting'), ('henry_v_act2_scene4', 48, 49, 'DAUPHIN', 'A little cloth.'), ('henry_v_act2_scene4', 48, 50, 'FRENCH KING', 'Think we King Harry strong;'), ('henry_v_act2_scene4', 49, 51, 'FRENCH KING', 'And, princes, look you strongly arm to meet him.'), ('henry_v_act2_scene4', 50, 52, 'FRENCH KING', 'The kindred of him hath been flesh’d upon us;'), ('henry_v_act2_scene4', 51, 53, 'FRENCH KING', 'And he is bred out of that bloody strain'), ('henry_v_act2_scene4', 52, 54, 'FRENCH KING', 'That haunted us in our familiar paths:'), ('henry_v_act2_scene4', 53, 55, 'FRENCH KING', 'Witness our too much memorable shame'), ('henry_v_act2_scene4', 54, 56, 'FRENCH KING', 'When Cressy battle fatally was struck,'), ('henry_v_act2_scene4', 55, 57, 'FRENCH KING', 'And all our princes captiv’d by the hand'), ('henry_v_act2_scene4', 56, 58, 'FRENCH KING', 'Of that black name, Edward, Black Prince of Wales;'), ('henry_v_act2_scene4', 57, 59, 'FRENCH KING', 'Whiles that his mountain sire, on mountain standing,'), ('henry_v_act2_scene4', 58, 60, 'FRENCH KING', 'Up in the air, crown’d with the golden sun,'), ('henry_v_act2_scene4', 59, 61, 'FRENCH KING', 'Saw his heroical seed, and smiled to see him,'), ('henry_v_act2_scene4', 60, 62, 'FRENCH KING', 'Mangle the work of nature and deface'), ('henry_v_act2_scene4', 61, 63, 'FRENCH KING', 'The patterns that by God and by French fathers'), ('henry_v_act2_scene4', 62, 64, 'FRENCH KING', 'Had twenty years been made. This is a stem'), ('henry_v_act2_scene4', 63, 65, 'FRENCH KING', 'Of that victorious stock; and let us fear'), ('henry_v_act2_scene4', 64, 66, 'FRENCH KING', 'The native mightiness and fate of him.'), ('henry_v_act2_scene4', 65, 67, 'MESSENGER', 'Ambassadors from Harry King of England'), ('henry_v_act2_scene4', 66, 68, 'MESSENGER', 'Do crave admittance to your majesty.'), ('henry_v_act2_scene4', 67, 69, 'FRENCH KING', 'We’ll give them present audience. Go, and bring them.'), ('henry_v_act2_scene4', 68, 70, 'FRENCH KING', 'You see this chase is hotly follow’d, friends.'), ('henry_v_act2_scene4', 69, 71, 'DAUPHIN', 'Turn head, and stop pursuit; for coward dogs'), ('henry_v_act2_scene4', 70, 72, 'DAUPHIN', 'Most spend their mouths when what they seem to threaten'), ('henry_v_act2_scene4', 71, 73, 'DAUPHIN', 'Runs far before them. Good my sovereign,'), ('henry_v_act2_scene4', 72, 74, 'DAUPHIN', 'Take up the English short, and let them know'), ('henry_v_act2_scene4', 73, 75, 'DAUPHIN', 'Of what a monarchy you are the head:'), ('henry_v_act2_scene4', 74, 76, 'DAUPHIN', 'Self-love, my liege, is not so vile a sin'), ('henry_v_act2_scene4', 75, 77, 'DAUPHIN', 'As self-neglecting.'), ('henry_v_act2_scene4', 75, 78, 'FRENCH KING', 'From our brother England?'), ('henry_v_act2_scene4', 76, 79, 'EXETER', 'From him; and thus he greets your majesty.'), ('henry_v_act2_scene4', 77, 80, 'EXETER', 'He wills you, in the name of God Almighty,'), ('henry_v_act2_scene4', 78, 81, 'EXETER', 'That you divest yourself, and lay apart'), ('henry_v_act2_scene4', 79, 82, 'EXETER', 'The borrow’d glories that by gift of heaven,'), ('henry_v_act2_scene4', 80, 83, 'EXETER', 'By law of nature and of nations, ’long'), ('henry_v_act2_scene4', 81, 84, 'EXETER', 'To him and to his heirs; namely, the crown'), ('henry_v_act2_scene4', 82, 85, 'EXETER', 'And all wide-stretched honours that pertain'), ('henry_v_act2_scene4', 83, 86, 'EXETER', 'By custom and the ordinance of times'), ('henry_v_act2_scene4', 84, 87, 'EXETER', 'Unto the crown of France. That you may know'), ('henry_v_act2_scene4', 85, 88, 'EXETER', '’Tis no sinister nor no awkward claim,'), ('henry_v_act2_scene4', 86, 89, 'EXETER', 'Pick’d from the wormholes of long-vanish’d days,'), ('henry_v_act2_scene4', 87, 90, 'EXETER', 'Nor from the dust of old oblivion raked,'), ('henry_v_act2_scene4', 88, 91, 'EXETER', 'He sends you this most memorable line,'), ('henry_v_act2_scene4', 89, 92, 'EXETER', 'In every branch truly demonstrative;'), ('henry_v_act2_scene4', 90, 93, 'EXETER', 'Willing you overlook this pedigree:'), ('henry_v_act2_scene4', 91, 94, 'EXETER', 'And when you find him evenly derived'), ('henry_v_act2_scene4', 92, 95, 'EXETER', 'From his most famed of famous ancestors,'), ('henry_v_act2_scene4', 93, 96, 'EXETER', 'Edward the Third, he bids you then resign'), ('henry_v_act2_scene4', 94, 97, 'EXETER', 'Your crown and kingdom, indirectly held'), ('henry_v_act2_scene4', 95, 98, 'EXETER', 'From him the native and true challenger.'), ('henry_v_act2_scene4', 96, 99, 'FRENCH KING', 'Or else what follows?');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act2_scene4', 97, 100, 'EXETER', 'Bloody constraint; for if you hide the crown'), ('henry_v_act2_scene4', 98, 101, 'EXETER', 'Even in your hearts, there will he rake for it:'), ('henry_v_act2_scene4', 99, 102, 'EXETER', 'Therefore in fierce tempest is he coming,'), ('henry_v_act2_scene4', 100, 103, 'EXETER', 'In thunder and in earthquake, like a Jove,'), ('henry_v_act2_scene4', 101, 104, 'EXETER', 'That, if requiring fail, he will compel;'), ('henry_v_act2_scene4', 102, 105, 'EXETER', 'And bids you, in the bowels of the Lord,'), ('henry_v_act2_scene4', 103, 106, 'EXETER', 'Deliver up the crown, and to take mercy'), ('henry_v_act2_scene4', 104, 107, 'EXETER', 'On the poor souls for whom this hungry war'), ('henry_v_act2_scene4', 105, 108, 'EXETER', 'Opens his vasty jaws; and on your head'), ('henry_v_act2_scene4', 106, 109, 'EXETER', 'Turning the widows’ tears, the orphans’ cries,'), ('henry_v_act2_scene4', 107, 110, 'EXETER', 'The dead men’s blood, the pining maidens’ groans,'), ('henry_v_act2_scene4', 108, 111, 'EXETER', 'For husbands, fathers and betrothed lovers,'), ('henry_v_act2_scene4', 109, 112, 'EXETER', 'That shall be swallow’d in this controversy.'), ('henry_v_act2_scene4', 110, 113, 'EXETER', 'This is his claim, his threatening and my message;'), ('henry_v_act2_scene4', 111, 114, 'EXETER', 'Unless the Dauphin be in presence here,'), ('henry_v_act2_scene4', 112, 115, 'EXETER', 'To whom expressly I bring greeting too.'), ('henry_v_act2_scene4', 113, 116, 'FRENCH KING', 'For us, we will consider of this further:'), ('henry_v_act2_scene4', 114, 117, 'FRENCH KING', 'Tomorrow shall you bear our full intent'), ('henry_v_act2_scene4', 115, 118, 'FRENCH KING', 'Back to our brother of England.'), ('henry_v_act2_scene4', 115, 119, 'DAUPHIN', 'For the Dauphin,'), ('henry_v_act2_scene4', 116, 120, 'DAUPHIN', 'I stand here for him: what to him from England?'), ('henry_v_act2_scene4', 117, 121, 'EXETER', 'Scorn and defiance: slight regard, contempt,'), ('henry_v_act2_scene4', 118, 122, 'EXETER', 'And anything that may not misbecome'), ('henry_v_act2_scene4', 119, 123, 'EXETER', 'The mighty sender, doth he prize you at.'), ('henry_v_act2_scene4', 120, 124, 'EXETER', 'Thus says my king; an if your father’s highness'), ('henry_v_act2_scene4', 121, 125, 'EXETER', 'Do not, in grant of all demands at large,'), ('henry_v_act2_scene4', 122, 126, 'EXETER', 'Sweeten the bitter mock you sent his majesty,'), ('henry_v_act2_scene4', 123, 127, 'EXETER', 'He’ll call you to so hot an answer of it,'), ('henry_v_act2_scene4', 124, 128, 'EXETER', 'That caves and womby vaultages of France'), ('henry_v_act2_scene4', 125, 129, 'EXETER', 'Shall chide your trespass and return your mock'), ('henry_v_act2_scene4', 126, 130, 'EXETER', 'In second accent of his ordinance.'), ('henry_v_act2_scene4', 127, 131, 'DAUPHIN', 'Say, if my father render fair return,'), ('henry_v_act2_scene4', 128, 132, 'DAUPHIN', 'It is against my will; for I desire'), ('henry_v_act2_scene4', 129, 133, 'DAUPHIN', 'Nothing but odds with England: to that end,'), ('henry_v_act2_scene4', 130, 134, 'DAUPHIN', 'As matching to his youth and vanity,'), ('henry_v_act2_scene4', 131, 135, 'DAUPHIN', 'I did present him with the Paris balls.'), ('henry_v_act2_scene4', 132, 136, 'EXETER', 'He’ll make your Paris Louvre shake for it,'), ('henry_v_act2_scene4', 133, 137, 'EXETER', 'Were it the mistress-court of mighty Europe:'), ('henry_v_act2_scene4', 134, 138, 'EXETER', 'And, be assured, you’ll find a difference,'), ('henry_v_act2_scene4', 135, 139, 'EXETER', 'As we his subjects have in wonder found,'), ('henry_v_act2_scene4', 136, 140, 'EXETER', 'Between the promise of his greener days'), ('henry_v_act2_scene4', 137, 141, 'EXETER', 'And these he masters now: now he weighs time'), ('henry_v_act2_scene4', 138, 142, 'EXETER', 'Even to the utmost grain: that you shall read'), ('henry_v_act2_scene4', 139, 143, 'EXETER', 'In your own losses, if he stay in France.'), ('henry_v_act2_scene4', 140, 144, 'FRENCH KING', 'Tomorrow shall you know our mind at full.'), ('henry_v_act2_scene4', 141, 145, 'EXETER', 'Dispatch us with all speed, lest that our king'), ('henry_v_act2_scene4', 142, 146, 'EXETER', 'Come here himself to question our delay;'), ('henry_v_act2_scene4', 143, 147, 'EXETER', 'For he is footed in this land already.'), ('henry_v_act2_scene4', 144, 148, 'FRENCH KING', 'You shall be soon dispatch’d with fair conditions:'), ('henry_v_act2_scene4', 145, 149, 'FRENCH KING', 'A night is but small breath and little pause'), ('henry_v_act2_scene4', 146, 150, 'FRENCH KING', 'To answer matters of this consequence.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_chorus', 1, 0, 'CHORUS', 'Thus with imagined wing our swift scene flies'), ('henry_v_act3_chorus', 2, 1, 'CHORUS', 'In motion of no less celerity'), ('henry_v_act3_chorus', 3, 2, 'CHORUS', 'Than that of thought. Suppose that you have seen'), ('henry_v_act3_chorus', 4, 3, 'CHORUS', 'The well-appointed king at Hampton pier'), ('henry_v_act3_chorus', 5, 4, 'CHORUS', 'Embark his royalty; and his brave fleet'), ('henry_v_act3_chorus', 6, 5, 'CHORUS', 'With silken streamers the young Phoebus fanning:'), ('henry_v_act3_chorus', 7, 6, 'CHORUS', 'Play with your fancies, and in them behold'), ('henry_v_act3_chorus', 8, 7, 'CHORUS', 'Upon the hempen tackle ship-boys climbing;'), ('henry_v_act3_chorus', 9, 8, 'CHORUS', 'Hear the shrill whistle which doth order give'), ('henry_v_act3_chorus', 10, 9, 'CHORUS', 'To sounds confused; behold the threaden sails,'), ('henry_v_act3_chorus', 11, 10, 'CHORUS', 'Borne with the invisible and creeping wind,'), ('henry_v_act3_chorus', 12, 11, 'CHORUS', 'Draw the huge bottoms through the furrow’d sea,'), ('henry_v_act3_chorus', 13, 12, 'CHORUS', 'Breasting the lofty surge: O, do but think'), ('henry_v_act3_chorus', 14, 13, 'CHORUS', 'You stand upon the rivage and behold'), ('henry_v_act3_chorus', 15, 14, 'CHORUS', 'A city on the inconstant billows dancing;'), ('henry_v_act3_chorus', 16, 15, 'CHORUS', 'For so appears this fleet majestical,'), ('henry_v_act3_chorus', 17, 16, 'CHORUS', 'Holding due course to Harfleur. Follow, follow:'), ('henry_v_act3_chorus', 18, 17, 'CHORUS', 'Grapple your minds to sternage of this navy,'), ('henry_v_act3_chorus', 19, 18, 'CHORUS', 'And leave your England, as dead midnight still,'), ('henry_v_act3_chorus', 20, 19, 'CHORUS', 'Guarded with grandsires, babies and old women,'), ('henry_v_act3_chorus', 21, 20, 'CHORUS', 'Either past or not arrived to pith and puissance;'), ('henry_v_act3_chorus', 22, 21, 'CHORUS', 'For who is he, whose chin is but enrich’d'), ('henry_v_act3_chorus', 23, 22, 'CHORUS', 'With one appearing hair, that will not follow'), ('henry_v_act3_chorus', 24, 23, 'CHORUS', 'These cull’d and choice-drawn cavaliers to France?'), ('henry_v_act3_chorus', 25, 24, 'CHORUS', 'Work, work your thoughts, and therein see a siege;'), ('henry_v_act3_chorus', 26, 25, 'CHORUS', 'Behold the ordnance on their carriages,'), ('henry_v_act3_chorus', 27, 26, 'CHORUS', 'With fatal mouths gaping on girded Harfleur.'), ('henry_v_act3_chorus', 28, 27, 'CHORUS', 'Suppose the ambassador from the French comes back;'), ('henry_v_act3_chorus', 29, 28, 'CHORUS', 'Tells Harry that the king doth offer him'), ('henry_v_act3_chorus', 30, 29, 'CHORUS', 'Katharine his daughter, and with her, to dowry,'), ('henry_v_act3_chorus', 31, 30, 'CHORUS', 'Some petty and unprofitable dukedoms.'), ('henry_v_act3_chorus', 32, 31, 'CHORUS', 'The offer likes not: and the nimble gunner'), ('henry_v_act3_chorus', 33, 32, 'CHORUS', 'With linstock now the devilish cannon touches,'), ('henry_v_act3_chorus', 34, 33, 'CHORUS', 'And down goes all before them. Still be kind,'), ('henry_v_act3_chorus', 35, 34, 'CHORUS', 'And eke out our performance with your mind.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_scene1', 1, 0, 'KING HENRY', 'Once more unto the breach, dear friends, once more;'), ('henry_v_act3_scene1', 2, 1, 'KING HENRY', 'Or close the wall up with our English dead.'), ('henry_v_act3_scene1', 3, 2, 'KING HENRY', 'In peace there’s nothing so becomes a man'), ('henry_v_act3_scene1', 4, 3, 'KING HENRY', 'As modest stillness and humility:'), ('henry_v_act3_scene1', 5, 4, 'KING HENRY', 'But when the blast of war blows in our ears,'), ('henry_v_act3_scene1', 6, 5, 'KING HENRY', 'Then imitate the action of the tiger;'), ('henry_v_act3_scene1', 7, 6, 'KING HENRY', 'Stiffen the sinews, summon up the blood,'), ('henry_v_act3_scene1', 8, 7, 'KING HENRY', 'Disguise fair nature with hard-favour’d rage;'), ('henry_v_act3_scene1', 9, 8, 'KING HENRY', 'Then lend the eye a terrible aspect;'), ('henry_v_act3_scene1', 10, 9, 'KING HENRY', 'Let it pry through the portage of the head'), ('henry_v_act3_scene1', 11, 10, 'KING HENRY', 'Like the brass cannon; let the brow o’erwhelm it'), ('henry_v_act3_scene1', 12, 11, 'KING HENRY', 'As fearfully as doth a galled rock'), ('henry_v_act3_scene1', 13, 12, 'KING HENRY', 'O’erhang and jutty his confounded base,'), ('henry_v_act3_scene1', 14, 13, 'KING HENRY', 'Swill’d with the wild and wasteful ocean.'), ('henry_v_act3_scene1', 15, 14, 'KING HENRY', 'Now set the teeth and stretch the nostril wide,'), ('henry_v_act3_scene1', 16, 15, 'KING HENRY', 'Hold hard the breath and bend up every spirit'), ('henry_v_act3_scene1', 17, 16, 'KING HENRY', 'To his full height. On, on, you noblest English,'), ('henry_v_act3_scene1', 18, 17, 'KING HENRY', 'Whose blood is fet from fathers of war-proof!'), ('henry_v_act3_scene1', 19, 18, 'KING HENRY', 'Fathers that, like so many Alexanders,'), ('henry_v_act3_scene1', 20, 19, 'KING HENRY', 'Have in these parts from morn till even fought'), ('henry_v_act3_scene1', 21, 20, 'KING HENRY', 'And sheathed their swords for lack of argument:'), ('henry_v_act3_scene1', 22, 21, 'KING HENRY', 'Dishonour not your mothers; now attest'), ('henry_v_act3_scene1', 23, 22, 'KING HENRY', 'That those whom you call’d fathers did beget you.'), ('henry_v_act3_scene1', 24, 23, 'KING HENRY', 'Be copy now to men of grosser blood,'), ('henry_v_act3_scene1', 25, 24, 'KING HENRY', 'And teach them how to war. And you, good yeomen,'), ('henry_v_act3_scene1', 26, 25, 'KING HENRY', 'Whose limbs were made in England, show us here'), ('henry_v_act3_scene1', 27, 26, 'KING HENRY', 'The mettle of your pasture; let us swear'), ('henry_v_act3_scene1', 28, 27, 'KING HENRY', 'That you are worth your breeding; which I doubt not;'), ('henry_v_act3_scene1', 29, 28, 'KING HENRY', 'For there is none of you so mean and base,'), ('henry_v_act3_scene1', 30, 29, 'KING HENRY', 'That hath not noble lustre in your eyes.'), ('henry_v_act3_scene1', 31, 30, 'KING HENRY', 'I see you stand like greyhounds in the slips,'), ('henry_v_act3_scene1', 32, 31, 'KING HENRY', 'Straining upon the start. The game’s afoot:'), ('henry_v_act3_scene1', 33, 32, 'KING HENRY', 'Follow your spirit, and upon this charge'), ('henry_v_act3_scene1', 34, 33, 'KING HENRY', 'Cry, “God for Harry, England, and Saint George!”');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_scene2', 1, 0, 'BARDOLPH', 'On, on, on, on, on! to the breach, to the breach!'), ('henry_v_act3_scene2', 2, 1, 'NYM', 'Pray thee, corporal, stay: the knocks are too hot; and, for mine'), ('henry_v_act3_scene2', 3, 2, 'NYM', 'own part, I have not a case of lives: the humour of'), ('henry_v_act3_scene2', 4, 3, 'NYM', 'it is too hot, that is the very plainsong of it.'), ('henry_v_act3_scene2', 5, 4, 'PISTOL', 'The plain-song is most just; for humours do abound:'), ('henry_v_act3_scene2', 6, 5, 'PISTOL', 'Knocks go and come; God’s vassals drop and die;'), ('henry_v_act3_scene2', 7, 6, 'PISTOL', 'And sword and shield,'), ('henry_v_act3_scene2', 8, 7, 'PISTOL', 'In bloody field,'), ('henry_v_act3_scene2', 9, 8, 'PISTOL', 'Doth win immortal fame.'), ('henry_v_act3_scene2', 10, 9, 'BOY', 'Would I were in an alehouse in London! I would give all'), ('henry_v_act3_scene2', 11, 10, 'BOY', 'my fame for a pot of ale and safety.'), ('henry_v_act3_scene2', 12, 11, 'PISTOL', 'And I:'), ('henry_v_act3_scene2', 13, 12, 'PISTOL', 'If wishes would prevail with me,'), ('henry_v_act3_scene2', 14, 13, 'PISTOL', 'My purpose should not fail with me,'), ('henry_v_act3_scene2', 15, 14, 'PISTOL', 'But thither would I hie.'), ('henry_v_act3_scene2', 15, 15, 'BOY', 'As duly, but not as truly,'), ('henry_v_act3_scene2', 16, 16, 'BOY', 'As bird doth sing on bough.'), ('henry_v_act3_scene2', 17, 17, 'FLUELLEN', 'Up to the breach, you dogs! avaunt, you cullions! Driving them forward.'), ('henry_v_act3_scene2', 18, 18, 'PISTOL', 'Be merciful, great duke, to men of mould.'), ('henry_v_act3_scene2', 19, 19, 'PISTOL', 'Abate thy rage, abate thy manly rage,'), ('henry_v_act3_scene2', 20, 20, 'PISTOL', 'Abate thy rage, great duke!'), ('henry_v_act3_scene2', 21, 21, 'PISTOL', 'Good bawcock, bate thy rage; use lenity, sweet chuck!'), ('henry_v_act3_scene2', 22, 22, 'NYM', 'These be good humours! your honour wins bad humours.'), ('henry_v_act3_scene2', 23, 23, 'BOY', 'As young as I am, I have observ’d these three swashers. I'), ('henry_v_act3_scene2', 24, 24, 'BOY', 'am boy to them all three: but all they three, though they'), ('henry_v_act3_scene2', 25, 25, 'BOY', 'would serve me, could not be man to me; for indeed three'), ('henry_v_act3_scene2', 26, 26, 'BOY', 'such antics do not amount to a man. For Bardolph, he is'), ('henry_v_act3_scene2', 27, 27, 'BOY', 'white-livered and red-faced; by the means whereof a’ faces it out, but'), ('henry_v_act3_scene2', 28, 28, 'BOY', 'fights not. For Pistol, he hath a killing tongue and a quiet'), ('henry_v_act3_scene2', 29, 29, 'BOY', 'sword; by the means whereof a’ breaks words, and keeps whole weapons.'), ('henry_v_act3_scene2', 30, 30, 'BOY', 'For Nym, he hath heard that men of few words are the'), ('henry_v_act3_scene2', 31, 31, 'BOY', 'best men; and therefore he scorns to say his prayers, lest a’'), ('henry_v_act3_scene2', 32, 32, 'BOY', 'should be thought a coward: but his few bad words are matched'), ('henry_v_act3_scene2', 33, 33, 'BOY', 'with as few good deeds; for a’ never broke any man’s head'), ('henry_v_act3_scene2', 34, 34, 'BOY', 'but his own, and that was against a post when he was'), ('henry_v_act3_scene2', 35, 35, 'BOY', 'drunk. They will steal anything, and call it purchase. Bardolph stole a'), ('henry_v_act3_scene2', 36, 36, 'BOY', 'lute-case, bore it twelve leagues, and sold it for three half-pence. Nym'), ('henry_v_act3_scene2', 37, 37, 'BOY', 'and Bardolph are sworn brothers in filching, and in Calais they stole'), ('henry_v_act3_scene2', 38, 38, 'BOY', 'a fire-shovel: I knew by that piece of service the men would'), ('henry_v_act3_scene2', 39, 39, 'BOY', 'carry coals. They would have me as familiar with men’s pockets as'), ('henry_v_act3_scene2', 40, 40, 'BOY', 'their gloves or their handkerchers: which makes much against my manhood, if'), ('henry_v_act3_scene2', 41, 41, 'BOY', 'I should take from another’s pocket to put into mine; for it'), ('henry_v_act3_scene2', 42, 42, 'BOY', 'is plain pocketing up of wrongs. I must leave them, and seek'), ('henry_v_act3_scene2', 43, 43, 'BOY', 'some better service: their villainy goes against my weak stomach, and therefore'), ('henry_v_act3_scene2', 44, 44, 'BOY', 'I must cast it up.'), ('henry_v_act3_scene2', 45, 45, 'GOWER', 'Captain Fluellen, you must come presently to the mines; the Duke of'), ('henry_v_act3_scene2', 46, 46, 'GOWER', 'Gloucester would speak with you.'), ('henry_v_act3_scene2', 47, 47, 'FLUELLEN', 'To the mines! tell you the duke, it is not so good'), ('henry_v_act3_scene2', 48, 48, 'FLUELLEN', 'to come to the mines; for, look you, the mines is not'), ('henry_v_act3_scene2', 49, 49, 'FLUELLEN', 'according to the disciplines of the war: the concavities of it is'), ('henry_v_act3_scene2', 50, 50, 'FLUELLEN', 'not sufficient; for, look you, th’ athversary, you may discuss unto the'), ('henry_v_act3_scene2', 51, 51, 'FLUELLEN', 'duke, look you, is digt himself four yard under the countermines: by'), ('henry_v_act3_scene2', 52, 52, 'FLUELLEN', 'Cheshu, I think a’ will plow up all, if there is not'), ('henry_v_act3_scene2', 53, 53, 'FLUELLEN', 'better directions.'), ('henry_v_act3_scene2', 54, 54, 'GOWER', 'The Duke of Gloucester, to whom the order of the siege is'), ('henry_v_act3_scene2', 55, 55, 'GOWER', 'given, is altogether directed by an Irishman, a very valiant gentleman, i’'), ('henry_v_act3_scene2', 56, 56, 'GOWER', 'faith.'), ('henry_v_act3_scene2', 57, 57, 'FLUELLEN', 'It is Captain Macmorris, is it not?'), ('henry_v_act3_scene2', 58, 58, 'GOWER', 'I think it be.'), ('henry_v_act3_scene2', 59, 59, 'FLUELLEN', 'By Cheshu, he is an ass, as in the world: I will'), ('henry_v_act3_scene2', 60, 60, 'FLUELLEN', 'verify as much in his beard: he has no more directions in'), ('henry_v_act3_scene2', 61, 61, 'FLUELLEN', 'the true disciplines of the wars, look you, of the Roman disciplines,'), ('henry_v_act3_scene2', 62, 62, 'FLUELLEN', 'than is a puppy-dog.'), ('henry_v_act3_scene2', 63, 63, 'GOWER', 'Here a’ comes; and the Scots captain, Captain Jamy, with him.'), ('henry_v_act3_scene2', 64, 64, 'FLUELLEN', 'Captain Jamy is a marvellous falorous gentleman, that is certain; and of'), ('henry_v_act3_scene2', 65, 65, 'FLUELLEN', 'great expedition and knowledge in th’ aunchient wars, upon my particular knowledge'), ('henry_v_act3_scene2', 66, 66, 'FLUELLEN', 'of his directions: by Cheshu, he will maintain his argument as well'), ('henry_v_act3_scene2', 67, 67, 'FLUELLEN', 'as any military man in the world, in the disciplines of the'), ('henry_v_act3_scene2', 68, 68, 'FLUELLEN', 'pristine wars of the Romans.'), ('henry_v_act3_scene2', 68, 69, 'JAMY', 'I say gud-day, Captain Fluellen.'), ('henry_v_act3_scene2', 69, 70, 'FLUELLEN', 'God-den to your worship, good Captain James.'), ('henry_v_act3_scene2', 70, 71, 'GOWER', 'How now, Captain Macmorris! have you quit the mines? have the pioneers given o’er?'), ('henry_v_act3_scene2', 71, 72, 'MACMORRIS', 'By Chrish, la! tish ill done: the work ish give over, the'), ('henry_v_act3_scene2', 72, 73, 'MACMORRIS', 'trompet sound the retreat. By my hand, I swear, and my father’s'), ('henry_v_act3_scene2', 73, 74, 'MACMORRIS', 'soul, the work ish ill done; it ish give over: I would'), ('henry_v_act3_scene2', 74, 75, 'MACMORRIS', 'have blowed up the town, so Chrish save me, la! in an'), ('henry_v_act3_scene2', 75, 76, 'MACMORRIS', 'hour: O, tish ill done, tish ill done; by my hand, tish'), ('henry_v_act3_scene2', 76, 77, 'MACMORRIS', 'ill done!'), ('henry_v_act3_scene2', 77, 78, 'FLUELLEN', 'Captain Macmorris, I beseech you now, will you voutsafe me, look you,'), ('henry_v_act3_scene2', 78, 79, 'FLUELLEN', 'a few disputations with you, as partly touching or concerning the disciplines'), ('henry_v_act3_scene2', 79, 80, 'FLUELLEN', 'of the war, the Roman wars, in the way of argument, look'), ('henry_v_act3_scene2', 80, 81, 'FLUELLEN', 'you, and friendly communication; partly to satisfy my opinion, and partly for'), ('henry_v_act3_scene2', 81, 82, 'FLUELLEN', 'the satisfaction, look you, of my mind, as touching the direction of'), ('henry_v_act3_scene2', 82, 83, 'FLUELLEN', 'the military discipline; that is the point.'), ('henry_v_act3_scene2', 83, 84, 'JAMY', 'It sall be vary gud, gud feith, gud captains bath: and I'), ('henry_v_act3_scene2', 84, 85, 'JAMY', 'sall quit you with gud leve, as I may pick occasion; that'), ('henry_v_act3_scene2', 85, 86, 'JAMY', 'sall I, marry.'), ('henry_v_act3_scene2', 86, 87, 'MACMORRIS', 'It is no time to discourse, so Chrish save me: the day'), ('henry_v_act3_scene2', 87, 88, 'MACMORRIS', 'is hot, and the weather, and the wars, and the king, and'), ('henry_v_act3_scene2', 88, 89, 'MACMORRIS', 'the dukes: it is no time to discourse. The town is beseeched,'), ('henry_v_act3_scene2', 89, 90, 'MACMORRIS', 'and the trumpet call us to the breach; and we talk, and,'), ('henry_v_act3_scene2', 90, 91, 'MACMORRIS', 'be Chrish, do nothing: ’tis shame for us all: so God sa’'), ('henry_v_act3_scene2', 91, 92, 'MACMORRIS', 'me, ’tis shame to stand still; it is shame, by my hand:'), ('henry_v_act3_scene2', 92, 93, 'MACMORRIS', 'and there is throats to be cut, and works to be done;'), ('henry_v_act3_scene2', 93, 94, 'MACMORRIS', 'and there ish nothing done, so Chrish sa’ me, la!'), ('henry_v_act3_scene2', 94, 95, 'JAMY', 'By the mess, ere theise eyes of mine take themselves to slomber,'), ('henry_v_act3_scene2', 95, 96, 'JAMY', 'ay’ll de gud service, or ay’ll lig i’ the grund for it;'), ('henry_v_act3_scene2', 96, 97, 'JAMY', 'ay, or go to death; and ay’ll pay’t as valorously as I'), ('henry_v_act3_scene2', 97, 98, 'JAMY', 'may, that sall I suerly do, that is the breff and the'), ('henry_v_act3_scene2', 98, 99, 'JAMY', 'long. Marry, I wad full fain heard some question ’tween you tway.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_scene2', 99, 100, 'FLUELLEN', 'Captain Macmorris, I think, look you, under your correction, there is not'), ('henry_v_act3_scene2', 100, 101, 'FLUELLEN', 'many of your nation—'), ('henry_v_act3_scene2', 101, 102, 'MACMORRIS', 'Of my nation! What ish my nation? Ish a villain, and a'), ('henry_v_act3_scene2', 102, 103, 'MACMORRIS', 'bastard, and a knave, and a rascal—What ish my nation? Who talks'), ('henry_v_act3_scene2', 103, 104, 'MACMORRIS', 'of my nation?'), ('henry_v_act3_scene2', 104, 105, 'FLUELLEN', 'Look you, if you take the matter otherwise than is meant, Captain'), ('henry_v_act3_scene2', 105, 106, 'FLUELLEN', 'Macmorris, peradventure I shall think you do not use me with that'), ('henry_v_act3_scene2', 106, 107, 'FLUELLEN', 'affability as in discretion you ought to use me, look you; being'), ('henry_v_act3_scene2', 107, 108, 'FLUELLEN', 'as good a man as yourself, both in the disciplines of war,'), ('henry_v_act3_scene2', 108, 109, 'FLUELLEN', 'and in the derivation of my birth, and in other particularities.'), ('henry_v_act3_scene2', 109, 110, 'MACMORRIS', 'I do not know you so good a man as myself: so'), ('henry_v_act3_scene2', 110, 111, 'MACMORRIS', 'Chrish save me, I will cut off your head.'), ('henry_v_act3_scene2', 111, 112, 'GOWER', 'Gentlemen both, you will mistake each other.'), ('henry_v_act3_scene2', 112, 113, 'JAMY', 'A! that’s a foul fault. A parley sounded.'), ('henry_v_act3_scene2', 113, 114, 'GOWER', 'The town sounds a parley.'), ('henry_v_act3_scene2', 114, 115, 'FLUELLEN', 'Captain Macmorris, when there is more better opportunity to be required, look'), ('henry_v_act3_scene2', 115, 116, 'FLUELLEN', 'you, I will be so bold as to tell you I know'), ('henry_v_act3_scene2', 116, 117, 'FLUELLEN', 'the disciplines of war; and there is an end.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_scene3', 1, 0, 'KING HENRY', 'How yet resolves the governor of the town?'), ('henry_v_act3_scene3', 2, 1, 'KING HENRY', 'This is the latest parle we will admit:'), ('henry_v_act3_scene3', 3, 2, 'KING HENRY', 'Therefore to our best mercy give yourselves;'), ('henry_v_act3_scene3', 4, 3, 'KING HENRY', 'Or like to men proud of destruction'), ('henry_v_act3_scene3', 5, 4, 'KING HENRY', 'Defy us to our worst: for, as I am a soldier,'), ('henry_v_act3_scene3', 6, 5, 'KING HENRY', 'A name that in my thoughts becomes me best,'), ('henry_v_act3_scene3', 7, 6, 'KING HENRY', 'If I begin the battery once again,'), ('henry_v_act3_scene3', 8, 7, 'KING HENRY', 'I will not leave the half-achieved Harfleur'), ('henry_v_act3_scene3', 9, 8, 'KING HENRY', 'Till in her ashes she lie buried.'), ('henry_v_act3_scene3', 10, 9, 'KING HENRY', 'The gates of mercy shall be all shut up,'), ('henry_v_act3_scene3', 11, 10, 'KING HENRY', 'And the flesh’d soldier, rough and hard of heart,'), ('henry_v_act3_scene3', 12, 11, 'KING HENRY', 'In liberty of bloody hand shall range'), ('henry_v_act3_scene3', 13, 12, 'KING HENRY', 'With conscience wide as hell, mowing like grass'), ('henry_v_act3_scene3', 14, 13, 'KING HENRY', 'Your fresh-fair virgins and your flowering infants.'), ('henry_v_act3_scene3', 15, 14, 'KING HENRY', 'What is it then to me, if impious War,'), ('henry_v_act3_scene3', 16, 15, 'KING HENRY', 'Array’d in flames like to the prince of fiends,'), ('henry_v_act3_scene3', 17, 16, 'KING HENRY', 'Do, with his smirch’d complexion, all fell feats'), ('henry_v_act3_scene3', 18, 17, 'KING HENRY', 'Enlink’d to waste and desolation?'), ('henry_v_act3_scene3', 19, 18, 'KING HENRY', 'What is’t to me, when you yourselves are cause,'), ('henry_v_act3_scene3', 20, 19, 'KING HENRY', 'If your pure maidens fall into the hand'), ('henry_v_act3_scene3', 21, 20, 'KING HENRY', 'Of hot and forcing violation?'), ('henry_v_act3_scene3', 22, 21, 'KING HENRY', 'What rein can hold licentious wickedness'), ('henry_v_act3_scene3', 23, 22, 'KING HENRY', 'When down the hill he holds his fierce career?'), ('henry_v_act3_scene3', 24, 23, 'KING HENRY', 'We may as bootless spend our vain command'), ('henry_v_act3_scene3', 25, 24, 'KING HENRY', 'Upon the enraged soldiers in their spoil'), ('henry_v_act3_scene3', 26, 25, 'KING HENRY', 'As send precepts to the leviathan'), ('henry_v_act3_scene3', 27, 26, 'KING HENRY', 'To come ashore. Therefore, you men of Harfleur,'), ('henry_v_act3_scene3', 28, 27, 'KING HENRY', 'Take pity of your town and of your people,'), ('henry_v_act3_scene3', 29, 28, 'KING HENRY', 'Whiles yet my soldiers are in my command;'), ('henry_v_act3_scene3', 30, 29, 'KING HENRY', 'Whiles yet the cool and temperate wind of grace'), ('henry_v_act3_scene3', 31, 30, 'KING HENRY', 'O’erblows the filthy and contagious clouds'), ('henry_v_act3_scene3', 32, 31, 'KING HENRY', 'Of heady murder, spoil and villainy.'), ('henry_v_act3_scene3', 33, 32, 'KING HENRY', 'If not, why, in a moment look to see'), ('henry_v_act3_scene3', 34, 33, 'KING HENRY', 'The blind and bloody soldier with foul hand'), ('henry_v_act3_scene3', 35, 34, 'KING HENRY', 'Defile the locks of your shrill-shrieking daughters;'), ('henry_v_act3_scene3', 36, 35, 'KING HENRY', 'Your fathers taken by the silver beards,'), ('henry_v_act3_scene3', 37, 36, 'KING HENRY', 'And their most reverend heads dash’d to the walls,'), ('henry_v_act3_scene3', 38, 37, 'KING HENRY', 'Your naked infants spitted upon pikes,'), ('henry_v_act3_scene3', 39, 38, 'KING HENRY', 'Whiles the mad mothers with their howls confused'), ('henry_v_act3_scene3', 40, 39, 'KING HENRY', 'Do break the clouds, as did the wives of Jewry'), ('henry_v_act3_scene3', 41, 40, 'KING HENRY', 'At Herod’s bloody-hunting slaughtermen.'), ('henry_v_act3_scene3', 42, 41, 'KING HENRY', 'What say you? will you yield, and this avoid,'), ('henry_v_act3_scene3', 43, 42, 'KING HENRY', 'Or, guilty in defence, be thus destroy’d?'), ('henry_v_act3_scene3', 44, 43, 'GOVERNOR', 'Our expectation hath this day an end:'), ('henry_v_act3_scene3', 45, 44, 'GOVERNOR', 'The Dauphin, whom of succours we entreated,'), ('henry_v_act3_scene3', 46, 45, 'GOVERNOR', 'Returns us that his powers are yet not ready'), ('henry_v_act3_scene3', 47, 46, 'GOVERNOR', 'To raise so great a siege. Therefore, great king,'), ('henry_v_act3_scene3', 48, 47, 'GOVERNOR', 'We yield our town and lives to thy soft mercy.'), ('henry_v_act3_scene3', 49, 48, 'GOVERNOR', 'Enter our gates; dispose of us and ours;'), ('henry_v_act3_scene3', 50, 49, 'GOVERNOR', 'For we no longer are defensible.'), ('henry_v_act3_scene3', 50, 50, 'KING HENRY', 'Open your gates. Come, uncle Exeter,'), ('henry_v_act3_scene3', 51, 51, 'KING HENRY', 'Go you and enter Harfleur; there remain,'), ('henry_v_act3_scene3', 52, 52, 'KING HENRY', 'And fortify it strongly ’gainst the French:'), ('henry_v_act3_scene3', 53, 53, 'KING HENRY', 'Use mercy to them all. For us, dear uncle,'), ('henry_v_act3_scene3', 54, 54, 'KING HENRY', 'The winter coming on and sickness growing'), ('henry_v_act3_scene3', 55, 55, 'KING HENRY', 'Upon our soldiers, we will retire to Calais.'), ('henry_v_act3_scene3', 56, 56, 'KING HENRY', 'Tonight in Harfleur will we be your guest;'), ('henry_v_act3_scene3', 57, 57, 'KING HENRY', 'Tomorrow for the march are we addrest.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_scene4', 1, 0, 'KATHERINE', 'Alice, tu as été en Angleterre, et tu parles bien le langage.'), ('henry_v_act3_scene4', 2, 1, 'ALICE', 'Un peu, madame.'), ('henry_v_act3_scene4', 3, 2, 'KATHERINE', 'Je te prie, m’enseignez; il faut que j’apprenne à parler. Comment appelez-vous'), ('henry_v_act3_scene4', 4, 3, 'KATHERINE', 'la main en Anglois?'), ('henry_v_act3_scene4', 5, 4, 'ALICE', 'La main? elle est appelée de hand.'), ('henry_v_act3_scene4', 6, 5, 'KATHERINE', 'De hand. Et les doigts?'), ('henry_v_act3_scene4', 7, 6, 'ALICE', 'Les doigts? ma foi, j’oublie les doigts; mais je me souviendrai. Les'), ('henry_v_act3_scene4', 8, 7, 'ALICE', 'doigts? je pense qu’ils sont appelés de fingres; oui, de fingres.'), ('henry_v_act3_scene4', 9, 8, 'KATHERINE', 'La main, de hand; les doigts, de fingres. Je pense que je'), ('henry_v_act3_scene4', 10, 9, 'KATHERINE', 'suis le bon écolier; j’ai gagné deux mots d’Anglois vîtement. Comment appelez-vous'), ('henry_v_act3_scene4', 11, 10, 'KATHERINE', 'les ongles?'), ('henry_v_act3_scene4', 12, 11, 'ALICE', 'Les ongles? Nous les appelons de nails.'), ('henry_v_act3_scene4', 13, 12, 'KATHERINE', 'De nails. Écoutez; dites-moi, si je parle bien: de hand, de fingres, et de nails.'), ('henry_v_act3_scene4', 14, 13, 'ALICE', 'C’est bien dit, madame; il est fort bon Anglois.'), ('henry_v_act3_scene4', 15, 14, 'KATHERINE', 'Dites-moi l’Anglois pour le bras.'), ('henry_v_act3_scene4', 15, 15, 'ALICE', 'De arm, madame.'), ('henry_v_act3_scene4', 16, 16, 'KATHERINE', 'Et le coude?'), ('henry_v_act3_scene4', 16, 17, 'ALICE', 'De elbow.'), ('henry_v_act3_scene4', 17, 18, 'KATHERINE', 'De elbow. Je m’en fais la répétition de tous les mots que'), ('henry_v_act3_scene4', 18, 19, 'KATHERINE', 'vous m’avez appris dès à présent.'), ('henry_v_act3_scene4', 19, 20, 'ALICE', 'Il est trop difficile, madame, comme je pense.'), ('henry_v_act3_scene4', 20, 21, 'KATHERINE', 'Excusez-moi, Alice; écoutez: de hand, de fingres, de nails, de arm, de bilbow.'), ('henry_v_act3_scene4', 21, 22, 'ALICE', 'De elbow, madame.'), ('henry_v_act3_scene4', 22, 23, 'KATHERINE', 'O Seigneur Dieu, je m’en oublie! de elbow. Comment appelez-vous le col?'), ('henry_v_act3_scene4', 23, 24, 'ALICE', 'De neck, madame.'), ('henry_v_act3_scene4', 23, 25, 'KATHERINE', 'De nick. Et le menton?'), ('henry_v_act3_scene4', 24, 26, 'ALICE', 'De chin.'), ('henry_v_act3_scene4', 25, 27, 'KATHERINE', 'De sin. Le col, de nick; le menton, de sin.'), ('henry_v_act3_scene4', 26, 28, 'ALICE', 'Oui. Sauf votre honneur, en vérité, vous prononcez les mots aussi droit'), ('henry_v_act3_scene4', 27, 29, 'ALICE', 'que les natifs d’Angleterre.'), ('henry_v_act3_scene4', 28, 30, 'KATHERINE', 'Je ne doute point d’apprendre, par la grâce de Dieu, et en peu de temps.'), ('henry_v_act3_scene4', 29, 31, 'ALICE', 'N’avez-vous pas déjà oublié ce que je vous ai enseigné?'), ('henry_v_act3_scene4', 30, 32, 'KATHERINE', 'Non, je réciterai à vous promptement: d’hand, de fingres, de mails—'), ('henry_v_act3_scene4', 31, 33, 'ALICE', 'De nails, madame.'), ('henry_v_act3_scene4', 31, 34, 'KATHERINE', 'De nails, de arm, de ilbow.'), ('henry_v_act3_scene4', 32, 35, 'ALICE', 'Sauf votre honneur, de elbow.'), ('henry_v_act3_scene4', 33, 36, 'KATHERINE', 'Ainsi dis-je; de elbow, de nick, et de sin. Comment appelez-vous le'), ('henry_v_act3_scene4', 34, 37, 'KATHERINE', 'pied et la robe?'), ('henry_v_act3_scene4', 34, 38, 'ALICE', 'De foot, madame; et de coun.'), ('henry_v_act3_scene4', 35, 39, 'KATHERINE', 'De foot et de coun! O Seigneur Dieu! ce sont mots de'), ('henry_v_act3_scene4', 36, 40, 'KATHERINE', 'son mauvais, corruptible, gros, et impudique, et non pour les dames d’honneur'), ('henry_v_act3_scene4', 37, 41, 'KATHERINE', 'd’user: je ne voudrais prononcer ces mots devant les seigneurs de France'), ('henry_v_act3_scene4', 38, 42, 'KATHERINE', 'pour tout le monde. Foh! le foot et le coun! Néanmoins, je'), ('henry_v_act3_scene4', 39, 43, 'KATHERINE', 'réciterai une autre fois ma leçon ensemble: d’hand, de fingres, de nails,'), ('henry_v_act3_scene4', 40, 44, 'KATHERINE', 'de arm, de elbow, de nick, de sin, de foot, de coun.'), ('henry_v_act3_scene4', 41, 45, 'ALICE', 'Excellent, madame!'), ('henry_v_act3_scene4', 42, 46, 'KATHERINE', 'C’est assez pour une fois: allons-nous à dîner.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_scene5', 1, 0, 'FRENCH KING', '’Tis certain he hath pass’d the river Somme.'), ('henry_v_act3_scene5', 2, 1, 'CONSTABLE', 'And if he be not fought withal, my lord,'), ('henry_v_act3_scene5', 3, 2, 'CONSTABLE', 'Let us not live in France; let us quit all'), ('henry_v_act3_scene5', 4, 3, 'CONSTABLE', 'And give our vineyards to a barbarous people.'), ('henry_v_act3_scene5', 5, 4, 'DAUPHIN', 'O Dieu vivant! shall a few sprays of us,'), ('henry_v_act3_scene5', 6, 5, 'DAUPHIN', 'The emptying of our fathers’ luxury,'), ('henry_v_act3_scene5', 7, 6, 'DAUPHIN', 'Our scions, put in wild and savage stock,'), ('henry_v_act3_scene5', 8, 7, 'DAUPHIN', 'Spirt up so suddenly into the clouds,'), ('henry_v_act3_scene5', 9, 8, 'DAUPHIN', 'And overlook their grafters?'), ('henry_v_act3_scene5', 9, 9, 'BOURBON', 'Normans, but bastard Normans, Norman bastards!'), ('henry_v_act3_scene5', 10, 10, 'BOURBON', 'Mort de ma vie! if they march along'), ('henry_v_act3_scene5', 11, 11, 'BOURBON', 'Unfought withal, but I will sell my dukedom,'), ('henry_v_act3_scene5', 12, 12, 'BOURBON', 'To buy a slobbery and a dirty farm'), ('henry_v_act3_scene5', 13, 13, 'BOURBON', 'In that nook-shotten isle of Albion.'), ('henry_v_act3_scene5', 14, 14, 'CONSTABLE', 'Dieu de batailles! where have they this mettle?'), ('henry_v_act3_scene5', 15, 15, 'CONSTABLE', 'Is not their climate foggy, raw, and dull,'), ('henry_v_act3_scene5', 16, 16, 'CONSTABLE', 'On whom, as in despite, the sun looks pale,'), ('henry_v_act3_scene5', 17, 17, 'CONSTABLE', 'Killing their fruit with frowns? Can sodden water,'), ('henry_v_act3_scene5', 18, 18, 'CONSTABLE', 'A drench for sur-rein’d jades, their barley-broth,'), ('henry_v_act3_scene5', 19, 19, 'CONSTABLE', 'Decoct their cold blood to such valiant heat?'), ('henry_v_act3_scene5', 20, 20, 'CONSTABLE', 'And shall our quick blood, spirited with wine,'), ('henry_v_act3_scene5', 21, 21, 'CONSTABLE', 'Seem frosty? O, for honour of our land,'), ('henry_v_act3_scene5', 22, 22, 'CONSTABLE', 'Let us not hang like roping icicles'), ('henry_v_act3_scene5', 23, 23, 'CONSTABLE', 'Upon our houses’ thatch, whiles a more frosty people'), ('henry_v_act3_scene5', 24, 24, 'CONSTABLE', 'Sweat drops of gallant youth in our rich fields!'), ('henry_v_act3_scene5', 25, 25, 'CONSTABLE', 'Poor we may call them in their native lords.'), ('henry_v_act3_scene5', 26, 26, 'DAUPHIN', 'By faith and honour,'), ('henry_v_act3_scene5', 27, 27, 'DAUPHIN', 'Our madams mock at us, and plainly say'), ('henry_v_act3_scene5', 28, 28, 'DAUPHIN', 'Our mettle is bred out and they will give'), ('henry_v_act3_scene5', 29, 29, 'DAUPHIN', 'Their bodies to the lust of English youth'), ('henry_v_act3_scene5', 30, 30, 'DAUPHIN', 'To new-store France with bastard warriors.'), ('henry_v_act3_scene5', 31, 31, 'BOURBON', 'They bid us to the English dancing-schools,'), ('henry_v_act3_scene5', 32, 32, 'BOURBON', 'And teach lavoltas high and swift corantos;'), ('henry_v_act3_scene5', 33, 33, 'BOURBON', 'Saying our grace is only in our heels,'), ('henry_v_act3_scene5', 34, 34, 'BOURBON', 'And that we are most lofty runaways.'), ('henry_v_act3_scene5', 35, 35, 'FRENCH KING', 'Where is Montjoy the herald? speed him hence:'), ('henry_v_act3_scene5', 36, 36, 'FRENCH KING', 'Let him greet England with our sharp defiance.'), ('henry_v_act3_scene5', 37, 37, 'FRENCH KING', 'Up, princes! and, with spirit of honour edged'), ('henry_v_act3_scene5', 38, 38, 'FRENCH KING', 'More sharper than your swords, hie to the field:'), ('henry_v_act3_scene5', 39, 39, 'FRENCH KING', 'Charles Delabreth, high constable of France;'), ('henry_v_act3_scene5', 40, 40, 'FRENCH KING', 'You Dukes of Orleans, Bourbon, and of Berri,'), ('henry_v_act3_scene5', 41, 41, 'FRENCH KING', 'Alençon, Brabant, Bar, and Burgundy;'), ('henry_v_act3_scene5', 42, 42, 'FRENCH KING', 'Jacques Chatillon, Rambures, Vaudemont,'), ('henry_v_act3_scene5', 43, 43, 'FRENCH KING', 'Beaumont, Grandpré, Roussi, and Fauconbridge,'), ('henry_v_act3_scene5', 44, 44, 'FRENCH KING', 'Foix, Lestrale, Bouciqualt, and Charolois;'), ('henry_v_act3_scene5', 45, 45, 'FRENCH KING', 'High dukes, great princes, barons, lords and knights,'), ('henry_v_act3_scene5', 46, 46, 'FRENCH KING', 'For your great seats now quit you of great shames.'), ('henry_v_act3_scene5', 47, 47, 'FRENCH KING', 'Bar Harry England, that sweeps through our land'), ('henry_v_act3_scene5', 48, 48, 'FRENCH KING', 'With pennons painted in the blood of Harfleur:'), ('henry_v_act3_scene5', 49, 49, 'FRENCH KING', 'Rush on his host, as doth the melted snow'), ('henry_v_act3_scene5', 50, 50, 'FRENCH KING', 'Upon the valleys, whose low vassal seat'), ('henry_v_act3_scene5', 51, 51, 'FRENCH KING', 'The Alps doth spit and void his rheum upon:'), ('henry_v_act3_scene5', 52, 52, 'FRENCH KING', 'Go down upon him, you have power enough,'), ('henry_v_act3_scene5', 53, 53, 'FRENCH KING', 'And in a captive chariot into Rouen'), ('henry_v_act3_scene5', 54, 54, 'FRENCH KING', 'Bring him our prisoner.'), ('henry_v_act3_scene5', 54, 55, 'CONSTABLE', 'This becomes the great.'), ('henry_v_act3_scene5', 55, 56, 'CONSTABLE', 'Sorry am I his numbers are so few,'), ('henry_v_act3_scene5', 56, 57, 'CONSTABLE', 'His soldiers sick and famish’d in their march,'), ('henry_v_act3_scene5', 57, 58, 'CONSTABLE', 'For I am sure, when he shall see our army,'), ('henry_v_act3_scene5', 58, 59, 'CONSTABLE', 'He’ll drop his heart into the sink of fear'), ('henry_v_act3_scene5', 59, 60, 'CONSTABLE', 'And for achievement offer us his ransom.'), ('henry_v_act3_scene5', 60, 61, 'FRENCH KING', 'Therefore, lord constable, haste on Montjoy,'), ('henry_v_act3_scene5', 61, 62, 'FRENCH KING', 'And let him say to England that we send'), ('henry_v_act3_scene5', 62, 63, 'FRENCH KING', 'To know what willing ransom he will give.'), ('henry_v_act3_scene5', 63, 64, 'FRENCH KING', 'Prince Dauphin, you shall stay with us in Rouen.'), ('henry_v_act3_scene5', 64, 65, 'DAUPHIN', 'Not so, I do beseech your majesty.'), ('henry_v_act3_scene5', 65, 66, 'FRENCH KING', 'Be patient, for you shall remain with us.'), ('henry_v_act3_scene5', 66, 67, 'FRENCH KING', 'Now forth, lord constable and princes all,'), ('henry_v_act3_scene5', 67, 68, 'FRENCH KING', 'And quickly bring us word of England’s fall.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_scene6', 1, 0, 'GOWER', 'How now, Captain Fluellen! come you from the bridge?'), ('henry_v_act3_scene6', 2, 1, 'FLUELLEN', 'I assure you, there is very excellent services committed at the bridge.'), ('henry_v_act3_scene6', 3, 2, 'GOWER', 'Is the Duke of Exeter safe?'), ('henry_v_act3_scene6', 4, 3, 'FLUELLEN', 'The Duke of Exeter is as magnanimous as Agamemnon; and a man'), ('henry_v_act3_scene6', 5, 4, 'FLUELLEN', 'that I love and honour with my soul, and my heart, and'), ('henry_v_act3_scene6', 6, 5, 'FLUELLEN', 'my duty, and my life, and my living, and my uttermost power:'), ('henry_v_act3_scene6', 7, 6, 'FLUELLEN', 'he is not—God be praised and blessed!—any hurt in the world; but'), ('henry_v_act3_scene6', 8, 7, 'FLUELLEN', 'keeps the bridge most valiantly, with excellent discipline. There is an aunchient'), ('henry_v_act3_scene6', 9, 8, 'FLUELLEN', 'lieutenant there at the pridge, I think in my very conscience he'), ('henry_v_act3_scene6', 10, 9, 'FLUELLEN', 'is as valiant a man as Mark Antony; and he is a'), ('henry_v_act3_scene6', 11, 10, 'FLUELLEN', 'man of no estimation in the world; but I did see him'), ('henry_v_act3_scene6', 12, 11, 'FLUELLEN', 'do as gallant service.'), ('henry_v_act3_scene6', 12, 12, 'GOWER', 'What do you call him?'), ('henry_v_act3_scene6', 13, 13, 'FLUELLEN', 'He is call’d Aunchient Pistol.'), ('henry_v_act3_scene6', 13, 14, 'GOWER', 'I know him not.'), ('henry_v_act3_scene6', 14, 15, 'FLUELLEN', 'Here is the man.'), ('henry_v_act3_scene6', 15, 16, 'PISTOL', 'Captain, I thee beseech to do me favours:'), ('henry_v_act3_scene6', 16, 17, 'PISTOL', 'The Duke of Exeter doth love thee well.'), ('henry_v_act3_scene6', 17, 18, 'FLUELLEN', 'Ay, I praise God; and I have merited some love at his hands.'), ('henry_v_act3_scene6', 18, 19, 'PISTOL', 'Bardolph, a soldier, firm and sound of heart,'), ('henry_v_act3_scene6', 19, 20, 'PISTOL', 'And of buxom valour, hath by cruel fate,'), ('henry_v_act3_scene6', 20, 21, 'PISTOL', 'And giddy Fortune’s furious fickle wheel,'), ('henry_v_act3_scene6', 21, 22, 'PISTOL', 'That goddess blind,'), ('henry_v_act3_scene6', 22, 23, 'PISTOL', 'That stands upon the rolling restless stone—'), ('henry_v_act3_scene6', 23, 24, 'FLUELLEN', 'By your patience, Aunchient Pistol. Fortune is painted blind, with a muffler'), ('henry_v_act3_scene6', 24, 25, 'FLUELLEN', 'afore his eyes, to signify to you that Fortune is blind; and'), ('henry_v_act3_scene6', 25, 26, 'FLUELLEN', 'she is painted also with a wheel, to signify to you, which'), ('henry_v_act3_scene6', 26, 27, 'FLUELLEN', 'is the moral of it, that she is turning, and inconstant, and'), ('henry_v_act3_scene6', 27, 28, 'FLUELLEN', 'mutability, and variation: and her foot, look you, is fixed upon a'), ('henry_v_act3_scene6', 28, 29, 'FLUELLEN', 'spherical stone, which rolls, and rolls, and rolls: in good truth, the'), ('henry_v_act3_scene6', 29, 30, 'FLUELLEN', 'poet makes a most excellent description of it: Fortune is an excellent'), ('henry_v_act3_scene6', 30, 31, 'FLUELLEN', 'moral.'), ('henry_v_act3_scene6', 31, 32, 'PISTOL', 'Fortune is Bardolph’s foe, and frowns on him;'), ('henry_v_act3_scene6', 32, 33, 'PISTOL', 'For he hath stolen a pax, and hanged must a’ be:'), ('henry_v_act3_scene6', 33, 34, 'PISTOL', 'A damned death!'), ('henry_v_act3_scene6', 34, 35, 'PISTOL', 'Let gallows gape for dog; let man go free'), ('henry_v_act3_scene6', 35, 36, 'PISTOL', 'And let not hemp his windpipe suffocate:'), ('henry_v_act3_scene6', 36, 37, 'PISTOL', 'But Exeter hath given the doom of death'), ('henry_v_act3_scene6', 37, 38, 'PISTOL', 'For pax of little price.'), ('henry_v_act3_scene6', 38, 39, 'PISTOL', 'Therefore, go speak: the duke will hear thy voice;'), ('henry_v_act3_scene6', 39, 40, 'PISTOL', 'And let not Bardolph’s vital thread be cut'), ('henry_v_act3_scene6', 40, 41, 'PISTOL', 'With edge of penny cord and vile reproach:'), ('henry_v_act3_scene6', 41, 42, 'PISTOL', 'Speak, captain, for his life, and I will thee requite.'), ('henry_v_act3_scene6', 42, 43, 'FLUELLEN', 'Aunchient Pistol, I do partly understand your meaning.'), ('henry_v_act3_scene6', 43, 44, 'PISTOL', 'Why then, rejoice therefore.'), ('henry_v_act3_scene6', 44, 45, 'FLUELLEN', 'Certainly, aunchient, it is not a thing to rejoice at: for if,'), ('henry_v_act3_scene6', 45, 46, 'FLUELLEN', 'look you, he were my brother, I would desire the duke to'), ('henry_v_act3_scene6', 46, 47, 'FLUELLEN', 'use his good pleasure, and put him to execution; for discipline ought'), ('henry_v_act3_scene6', 47, 48, 'FLUELLEN', 'to be used.'), ('henry_v_act3_scene6', 48, 49, 'PISTOL', 'Die and be damned! and figo for thy friendship!'), ('henry_v_act3_scene6', 49, 50, 'FLUELLEN', 'It is well.'), ('henry_v_act3_scene6', 49, 51, 'PISTOL', 'The fig of Spain!'), ('henry_v_act3_scene6', 50, 52, 'FLUELLEN', 'Very good.'), ('henry_v_act3_scene6', 51, 53, 'GOWER', 'Why, this is an arrant counterfeit rascal; I remember him now; a bawd, a cutpurse.'), ('henry_v_act3_scene6', 52, 54, 'FLUELLEN', 'I’ll assure you, a’ uttered as prave words at the pridge as'), ('henry_v_act3_scene6', 53, 55, 'FLUELLEN', 'you shall see in a summer’s day. But it is very well;'), ('henry_v_act3_scene6', 54, 56, 'FLUELLEN', 'what he has spoke to me, that is well, I warrant you,'), ('henry_v_act3_scene6', 55, 57, 'FLUELLEN', 'when time is serve.'), ('henry_v_act3_scene6', 56, 58, 'GOWER', 'Why, ’tis a gull, a fool, a rogue, that now and then'), ('henry_v_act3_scene6', 57, 59, 'GOWER', 'goes to the wars, to grace himself at his return into London'), ('henry_v_act3_scene6', 58, 60, 'GOWER', 'under the form of a soldier. And such fellows are perfect in'), ('henry_v_act3_scene6', 59, 61, 'GOWER', 'the great commanders’ names: and they will learn you by rote where'), ('henry_v_act3_scene6', 60, 62, 'GOWER', 'services were done; at such and such a sconce, at such a'), ('henry_v_act3_scene6', 61, 63, 'GOWER', 'breach, at such a convoy; who came off bravely, who was shot,'), ('henry_v_act3_scene6', 62, 64, 'GOWER', 'who disgraced, what terms the enemy stood on; and this they con'), ('henry_v_act3_scene6', 63, 65, 'GOWER', 'perfectly in the phrase of war, which they trick up with new-tuned'), ('henry_v_act3_scene6', 64, 66, 'GOWER', 'oaths: and what a beard of the general’s cut and a horrid'), ('henry_v_act3_scene6', 65, 67, 'GOWER', 'suit of the camp will do among foaming bottles and ale-washed wits,'), ('henry_v_act3_scene6', 66, 68, 'GOWER', 'is wonderful to be thought on. But you must learn to know'), ('henry_v_act3_scene6', 67, 69, 'GOWER', 'such slanders of the age, or else you may be marvellously mistook.'), ('henry_v_act3_scene6', 68, 70, 'FLUELLEN', 'I tell you what, Captain Gower; I do perceive he is not'), ('henry_v_act3_scene6', 69, 71, 'FLUELLEN', 'the man that he would gladly make show to the world he'), ('henry_v_act3_scene6', 70, 72, 'FLUELLEN', 'is: if I find a hole in his coat, I will tell'), ('henry_v_act3_scene6', 71, 73, 'FLUELLEN', 'him my mind. Hark you, the king is coming, and I must'), ('henry_v_act3_scene6', 72, 74, 'FLUELLEN', 'speak with him from the pridge.'), ('henry_v_act3_scene6', 73, 75, 'KING HENRY', 'How now, Fluellen! camest thou from the bridge?'), ('henry_v_act3_scene6', 74, 76, 'FLUELLEN', 'Ay, so please your majesty. The Duke of Exeter has very gallantly'), ('henry_v_act3_scene6', 75, 77, 'FLUELLEN', 'maintained the pridge: the French is gone off, look you; and there'), ('henry_v_act3_scene6', 76, 78, 'FLUELLEN', 'is gallant and most prave passages; marry, th’ athversary was have possession'), ('henry_v_act3_scene6', 77, 79, 'FLUELLEN', 'of the pridge; but he is enforced to retire, and the Duke'), ('henry_v_act3_scene6', 78, 80, 'FLUELLEN', 'of Exeter is master of the pridge: I can tell your majesty,'), ('henry_v_act3_scene6', 79, 81, 'FLUELLEN', 'the duke is a prave man.'), ('henry_v_act3_scene6', 79, 82, 'KING HENRY', 'What men have you lost, Fluellen?'), ('henry_v_act3_scene6', 80, 83, 'FLUELLEN', 'The perdition of th’ athversary hath been very great, reasonable great: marry,'), ('henry_v_act3_scene6', 81, 84, 'FLUELLEN', 'for my part, I think the duke hath lost never a man,'), ('henry_v_act3_scene6', 82, 85, 'FLUELLEN', 'but one that is like to be executed for robbing a church,'), ('henry_v_act3_scene6', 83, 86, 'FLUELLEN', 'one Bardolph, if your majesty know the man: his face is all'), ('henry_v_act3_scene6', 84, 87, 'FLUELLEN', 'bubukles, and whelks, and knobs, and flames o’ fire: and his lips'), ('henry_v_act3_scene6', 85, 88, 'FLUELLEN', 'blows at his nose, and it is like a coal of fire,'), ('henry_v_act3_scene6', 86, 89, 'FLUELLEN', 'sometimes plue and sometimes red; but his nose is executed, and his'), ('henry_v_act3_scene6', 87, 90, 'FLUELLEN', 'fire’s out.'), ('henry_v_act3_scene6', 88, 91, 'KING HENRY', 'We would have all such offenders so cut off: and we give'), ('henry_v_act3_scene6', 89, 92, 'KING HENRY', 'express charge, that in our marches through the country, there be nothing'), ('henry_v_act3_scene6', 90, 93, 'KING HENRY', 'compelled from the villages, nothing taken but paid for, none of the'), ('henry_v_act3_scene6', 91, 94, 'KING HENRY', 'French upbraided or abused in disdainful language; for when lenity and cruelty'), ('henry_v_act3_scene6', 92, 95, 'KING HENRY', 'play for a kingdom, the gentler gamester is the soonest winner.'), ('henry_v_act3_scene6', 93, 96, 'MONTJOY', 'You know me by my habit.'), ('henry_v_act3_scene6', 94, 97, 'KING HENRY', 'Well then I know thee: what shall I know of thee?'), ('henry_v_act3_scene6', 95, 98, 'MONTJOY', 'My master’s mind.'), ('henry_v_act3_scene6', 95, 99, 'KING HENRY', 'Unfold it.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_scene6', 96, 100, 'MONTJOY', 'Thus says my king: Say thou to Harry of England: Though we'), ('henry_v_act3_scene6', 97, 101, 'MONTJOY', 'seemed dead, we did but sleep: advantage is a better soldier than'), ('henry_v_act3_scene6', 98, 102, 'MONTJOY', 'rashness. Tell him we could have rebuked him at Harfleur, but that'), ('henry_v_act3_scene6', 99, 103, 'MONTJOY', 'we thought not good to bruise an injury till it were full'), ('henry_v_act3_scene6', 100, 104, 'MONTJOY', 'ripe: now we speak upon our cue, and our voice is imperial:'), ('henry_v_act3_scene6', 101, 105, 'MONTJOY', 'England shall repent his folly, see his weakness, and admire our sufferance.'), ('henry_v_act3_scene6', 102, 106, 'MONTJOY', 'Bid him therefore consider of his ransom; which must proportion the losses'), ('henry_v_act3_scene6', 103, 107, 'MONTJOY', 'we have borne, the subjects we have lost, the disgrace we have'), ('henry_v_act3_scene6', 104, 108, 'MONTJOY', 'digested; which in weight to re-answer, his pettiness would bow under. For'), ('henry_v_act3_scene6', 105, 109, 'MONTJOY', 'our losses, his exchequer is too poor; for the effusion of our'), ('henry_v_act3_scene6', 106, 110, 'MONTJOY', 'blood, the muster of his kingdom too faint a number; and for'), ('henry_v_act3_scene6', 107, 111, 'MONTJOY', 'our disgrace, his own person, kneeling at our feet, but a weak'), ('henry_v_act3_scene6', 108, 112, 'MONTJOY', 'and worthless satisfaction. To this add defiance: and tell him, for conclusion,'), ('henry_v_act3_scene6', 109, 113, 'MONTJOY', 'he hath betrayed his followers, whose condemnation is pronounced. So far my'), ('henry_v_act3_scene6', 110, 114, 'MONTJOY', 'king and master; so much my office.'), ('henry_v_act3_scene6', 111, 115, 'KING HENRY', 'What is thy name? I know thy quality.'), ('henry_v_act3_scene6', 112, 116, 'MONTJOY', 'Montjoy.'), ('henry_v_act3_scene6', 113, 117, 'KING HENRY', 'Thou dost thy office fairly. Turn thee back,'), ('henry_v_act3_scene6', 114, 118, 'KING HENRY', 'And tell thy king I do not seek him now;'), ('henry_v_act3_scene6', 115, 119, 'KING HENRY', 'But could be willing to march on to Calais'), ('henry_v_act3_scene6', 116, 120, 'KING HENRY', 'Without impeachment: for, to say the sooth,'), ('henry_v_act3_scene6', 117, 121, 'KING HENRY', 'Though ’tis no wisdom to confess so much'), ('henry_v_act3_scene6', 118, 122, 'KING HENRY', 'Unto an enemy of craft and vantage,'), ('henry_v_act3_scene6', 119, 123, 'KING HENRY', 'My people are with sickness much enfeebled,'), ('henry_v_act3_scene6', 120, 124, 'KING HENRY', 'My numbers lessened, and those few I have'), ('henry_v_act3_scene6', 121, 125, 'KING HENRY', 'Almost no better than so many French;'), ('henry_v_act3_scene6', 122, 126, 'KING HENRY', 'Who when they were in health, I tell thee, herald,'), ('henry_v_act3_scene6', 123, 127, 'KING HENRY', 'I thought upon one pair of English legs'), ('henry_v_act3_scene6', 124, 128, 'KING HENRY', 'Did march three Frenchmen. Yet, forgive me, God,'), ('henry_v_act3_scene6', 125, 129, 'KING HENRY', 'That I do brag thus! This your air of France'), ('henry_v_act3_scene6', 126, 130, 'KING HENRY', 'Hath blown that vice in me; I must repent.'), ('henry_v_act3_scene6', 127, 131, 'KING HENRY', 'Go therefore, tell thy master here I am;'), ('henry_v_act3_scene6', 128, 132, 'KING HENRY', 'My ransom is this frail and worthless trunk,'), ('henry_v_act3_scene6', 129, 133, 'KING HENRY', 'My army but a weak and sickly guard;'), ('henry_v_act3_scene6', 130, 134, 'KING HENRY', 'Yet, God before, tell him we will come on,'), ('henry_v_act3_scene6', 131, 135, 'KING HENRY', 'Though France himself and such another neighbour'), ('henry_v_act3_scene6', 132, 136, 'KING HENRY', 'Stand in our way. There’s for thy labour, Montjoy.'), ('henry_v_act3_scene6', 133, 137, 'KING HENRY', 'Go, bid thy master well advise himself:'), ('henry_v_act3_scene6', 134, 138, 'KING HENRY', 'If we may pass, we will; if we be hinder’d,'), ('henry_v_act3_scene6', 135, 139, 'KING HENRY', 'We shall your tawny ground with your red blood'), ('henry_v_act3_scene6', 136, 140, 'KING HENRY', 'Discolour; and so, Montjoy, fare you well.'), ('henry_v_act3_scene6', 137, 141, 'KING HENRY', 'The sum of all our answer is but this:'), ('henry_v_act3_scene6', 138, 142, 'KING HENRY', 'We would not seek a battle, as we are;'), ('henry_v_act3_scene6', 139, 143, 'KING HENRY', 'Nor, as we are, we say we will not shun it:'), ('henry_v_act3_scene6', 140, 144, 'KING HENRY', 'So tell your master.'), ('henry_v_act3_scene6', 141, 145, 'MONTJOY', 'I shall deliver so. Thanks to your highness.'), ('henry_v_act3_scene6', 142, 146, 'GLOUCESTER', 'I hope they will not come upon us now.'), ('henry_v_act3_scene6', 143, 147, 'KING HENRY', 'We are in God’s hands, brother, not in theirs.'), ('henry_v_act3_scene6', 144, 148, 'KING HENRY', 'March to the bridge; it now draws toward night:'), ('henry_v_act3_scene6', 145, 149, 'KING HENRY', 'Beyond the river we’ll encamp ourselves,'), ('henry_v_act3_scene6', 146, 150, 'KING HENRY', 'And on tomorrow bid them march away.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_scene7', 1, 0, 'CONSTABLE', 'Tut! I have the best armour of the world. Would it were day!'), ('henry_v_act3_scene7', 2, 1, 'ORLEANS', 'You have an excellent armour; but let my horse have his due.'), ('henry_v_act3_scene7', 3, 2, 'CONSTABLE', 'It is the best horse of Europe.'), ('henry_v_act3_scene7', 4, 3, 'ORLEANS', 'Will it never be morning?'), ('henry_v_act3_scene7', 5, 4, 'DAUPHIN', 'My Lord of Orleans, and my lord high constable, you talk of horse and armour?'), ('henry_v_act3_scene7', 6, 5, 'ORLEANS', 'You are as well provided of both as any prince in the world.'), ('henry_v_act3_scene7', 7, 6, 'DAUPHIN', 'What a long night is this! I will not change my horse'), ('henry_v_act3_scene7', 8, 7, 'DAUPHIN', 'with any that treads but on four pasterns. Ça, ha! he bounds'), ('henry_v_act3_scene7', 9, 8, 'DAUPHIN', 'from the earth, as if his entrails were hairs; le cheval volant,'), ('henry_v_act3_scene7', 10, 9, 'DAUPHIN', 'the Pegasus, qui a les narines de feu! When I bestride him,'), ('henry_v_act3_scene7', 11, 10, 'DAUPHIN', 'I soar, I am a hawk: he trots the air; the earth'), ('henry_v_act3_scene7', 12, 11, 'DAUPHIN', 'sings when he touches it; the basest horn of his hoof is'), ('henry_v_act3_scene7', 13, 12, 'DAUPHIN', 'more musical than the pipe of Hermes.'), ('henry_v_act3_scene7', 14, 13, 'ORLEANS', 'He’s of the colour of the nutmeg.'), ('henry_v_act3_scene7', 15, 14, 'DAUPHIN', 'And of the heat of the ginger. It is a beast for'), ('henry_v_act3_scene7', 16, 15, 'DAUPHIN', 'Perseus: he is pure air and fire; and the dull elements of'), ('henry_v_act3_scene7', 17, 16, 'DAUPHIN', 'earth and water never appear in him, but only in patient stillness'), ('henry_v_act3_scene7', 18, 17, 'DAUPHIN', 'while his rider mounts him: he is indeed a horse; and all'), ('henry_v_act3_scene7', 19, 18, 'DAUPHIN', 'other jades you may call beasts.'), ('henry_v_act3_scene7', 20, 19, 'CONSTABLE', 'Indeed, my lord, it is a most absolute and excellent horse.'), ('henry_v_act3_scene7', 21, 20, 'DAUPHIN', 'It is the prince of palfreys; his neigh is like the bidding'), ('henry_v_act3_scene7', 22, 21, 'DAUPHIN', 'of a monarch and his countenance enforces homage.'), ('henry_v_act3_scene7', 23, 22, 'ORLEANS', 'No more, cousin.'), ('henry_v_act3_scene7', 24, 23, 'DAUPHIN', 'Nay, the man hath no wit that cannot, from the rising of'), ('henry_v_act3_scene7', 25, 24, 'DAUPHIN', 'the lark to the lodging of the lamb, vary deserved praise on'), ('henry_v_act3_scene7', 26, 25, 'DAUPHIN', 'my palfrey: it is a theme as fluent as the sea: turn'), ('henry_v_act3_scene7', 27, 26, 'DAUPHIN', 'the sands into eloquent tongues, and my horse is argument for them'), ('henry_v_act3_scene7', 28, 27, 'DAUPHIN', 'all: ’tis a subject for a sovereign to reason on, and for'), ('henry_v_act3_scene7', 29, 28, 'DAUPHIN', 'a sovereign’s sovereign to ride on; and for the world, familiar to'), ('henry_v_act3_scene7', 30, 29, 'DAUPHIN', 'us and unknown, to lay apart their particular functions and wonder at'), ('henry_v_act3_scene7', 31, 30, 'DAUPHIN', 'him. I once writ a sonnet in his praise and began thus:'), ('henry_v_act3_scene7', 32, 31, 'DAUPHIN', '“Wonder of nature,”—'), ('henry_v_act3_scene7', 33, 32, 'ORLEANS', 'I have heard a sonnet begin so to one’s mistress.'), ('henry_v_act3_scene7', 34, 33, 'DAUPHIN', 'Then did they imitate that which I composed to my courser, for'), ('henry_v_act3_scene7', 35, 34, 'DAUPHIN', 'my horse is my mistress.'), ('henry_v_act3_scene7', 35, 35, 'ORLEANS', 'Your mistress bears well.'), ('henry_v_act3_scene7', 36, 36, 'DAUPHIN', 'Me well; which is the prescript praise and perfection of a good and particular mistress.'), ('henry_v_act3_scene7', 37, 37, 'CONSTABLE', 'Nay, for methought yesterday your mistress shrewdly shook your back.'), ('henry_v_act3_scene7', 38, 38, 'DAUPHIN', 'So perhaps did yours.'), ('henry_v_act3_scene7', 38, 39, 'CONSTABLE', 'Mine was not bridled.'), ('henry_v_act3_scene7', 39, 40, 'DAUPHIN', 'O then belike she was old and gentle; and you rode, like'), ('henry_v_act3_scene7', 40, 41, 'DAUPHIN', 'a kern of Ireland, your French hose off, and in your strait'), ('henry_v_act3_scene7', 41, 42, 'DAUPHIN', 'strossers.'), ('henry_v_act3_scene7', 41, 43, 'CONSTABLE', 'You have good judgment in horsemanship.'), ('henry_v_act3_scene7', 42, 44, 'DAUPHIN', 'Be warned by me, then: they that ride so and ride not'), ('henry_v_act3_scene7', 43, 45, 'DAUPHIN', 'warily, fall into foul bogs. I had rather have my horse to'), ('henry_v_act3_scene7', 44, 46, 'DAUPHIN', 'my mistress.'), ('henry_v_act3_scene7', 45, 47, 'CONSTABLE', 'I had as lief have my mistress a jade.'), ('henry_v_act3_scene7', 46, 48, 'DAUPHIN', 'I tell thee, constable, my mistress wears his own hair.'), ('henry_v_act3_scene7', 47, 49, 'CONSTABLE', 'I could make as true a boast as that, if I had'), ('henry_v_act3_scene7', 48, 50, 'CONSTABLE', 'a sow to my mistress.'), ('henry_v_act3_scene7', 49, 51, 'DAUPHIN', '“Le chien est retourné à son propre vomissement, et la truie lavée'), ('henry_v_act3_scene7', 50, 52, 'DAUPHIN', 'au bourbier:” thou makest use of anything.'), ('henry_v_act3_scene7', 51, 53, 'CONSTABLE', 'Yet do I not use my horse for my mistress, or any'), ('henry_v_act3_scene7', 52, 54, 'CONSTABLE', 'such proverb so little kin to the purpose.'), ('henry_v_act3_scene7', 53, 55, 'RAMBURES', 'My lord constable, the armour that I saw in your tent tonight,'), ('henry_v_act3_scene7', 54, 56, 'RAMBURES', 'are those stars or suns upon it?'), ('henry_v_act3_scene7', 55, 57, 'CONSTABLE', 'Stars, my lord.'), ('henry_v_act3_scene7', 56, 58, 'DAUPHIN', 'Some of them will fall tomorrow, I hope.'), ('henry_v_act3_scene7', 57, 59, 'CONSTABLE', 'And yet my sky shall not want.'), ('henry_v_act3_scene7', 58, 60, 'DAUPHIN', 'That may be, for you bear a many superfluously, and ’twere more'), ('henry_v_act3_scene7', 59, 61, 'DAUPHIN', 'honour some were away.'), ('henry_v_act3_scene7', 60, 62, 'CONSTABLE', 'Even as your horse bears your praises; who would trot as well,'), ('henry_v_act3_scene7', 61, 63, 'CONSTABLE', 'were some of your brags dismounted.'), ('henry_v_act3_scene7', 62, 64, 'DAUPHIN', 'Would I were able to load him with his desert! Will it'), ('henry_v_act3_scene7', 63, 65, 'DAUPHIN', 'never be day? I will trot tomorrow a mile, and my way'), ('henry_v_act3_scene7', 64, 66, 'DAUPHIN', 'shall be paved with English faces.'), ('henry_v_act3_scene7', 65, 67, 'CONSTABLE', 'I will not say so, for fear I should be faced out'), ('henry_v_act3_scene7', 66, 68, 'CONSTABLE', 'of my way: but I would it were morning; for I would'), ('henry_v_act3_scene7', 67, 69, 'CONSTABLE', 'fain be about the ears of the English.'), ('henry_v_act3_scene7', 68, 70, 'RAMBURES', 'Who will go to hazard with me for twenty prisoners?'), ('henry_v_act3_scene7', 69, 71, 'CONSTABLE', 'You must first go yourself to hazard, ere you have them.'), ('henry_v_act3_scene7', 70, 72, 'DAUPHIN', '’Tis midnight; I’ll go arm myself.'), ('henry_v_act3_scene7', 70, 73, 'ORLEANS', 'The Dauphin longs for morning.'), ('henry_v_act3_scene7', 71, 74, 'RAMBURES', 'He longs to eat the English.'), ('henry_v_act3_scene7', 72, 75, 'CONSTABLE', 'I think he will eat all he kills.'), ('henry_v_act3_scene7', 73, 76, 'ORLEANS', 'By the white hand of my lady, he’s a gallant prince.'), ('henry_v_act3_scene7', 74, 77, 'CONSTABLE', 'Swear by her foot, that she may tread out the oath.'), ('henry_v_act3_scene7', 75, 78, 'ORLEANS', 'He is simply the most active gentleman of France.'), ('henry_v_act3_scene7', 76, 79, 'CONSTABLE', 'Doing is activity; and he will still be doing.'), ('henry_v_act3_scene7', 77, 80, 'ORLEANS', 'He never did harm, that I heard of.'), ('henry_v_act3_scene7', 78, 81, 'CONSTABLE', 'Nor will do none tomorrow: he will keep that good name still.'), ('henry_v_act3_scene7', 79, 82, 'ORLEANS', 'I know him to be valiant.'), ('henry_v_act3_scene7', 80, 83, 'CONSTABLE', 'I was told that by one that knows him better than you.'), ('henry_v_act3_scene7', 81, 84, 'ORLEANS', 'What’s he?'), ('henry_v_act3_scene7', 82, 85, 'CONSTABLE', 'Marry, he told me so himself; and he said he cared not who knew it.'), ('henry_v_act3_scene7', 83, 86, 'ORLEANS', 'He needs not; it is no hidden virtue in him.'), ('henry_v_act3_scene7', 84, 87, 'CONSTABLE', 'By my faith, sir, but it is; never anybody saw it but'), ('henry_v_act3_scene7', 85, 88, 'CONSTABLE', 'his lackey: ’tis a hooded valour; and when it appears, it will'), ('henry_v_act3_scene7', 86, 89, 'CONSTABLE', 'bate.'), ('henry_v_act3_scene7', 86, 90, 'ORLEANS', 'Ill will never said well.'), ('henry_v_act3_scene7', 87, 91, 'CONSTABLE', 'I will cap that proverb with “There is flattery in friendship.”'), ('henry_v_act3_scene7', 88, 92, 'ORLEANS', 'And I will take up that with “Give the devil his due.”'), ('henry_v_act3_scene7', 89, 93, 'CONSTABLE', 'Well placed: there stands your friend for the devil: have at the'), ('henry_v_act3_scene7', 90, 94, 'CONSTABLE', 'very eye of that proverb with “A pox of the devil.”'), ('henry_v_act3_scene7', 91, 95, 'ORLEANS', 'You are the better at proverbs, by how much “A fool’s bolt is soon shot.”'), ('henry_v_act3_scene7', 92, 96, 'CONSTABLE', 'You have shot over.'), ('henry_v_act3_scene7', 93, 97, 'ORLEANS', '’Tis not the first time you were overshot.'), ('henry_v_act3_scene7', 94, 98, 'MESSENGER', 'My lord high constable, the English lie within fifteen hundred paces of your tents.'), ('henry_v_act3_scene7', 95, 99, 'CONSTABLE', 'Who hath measured the ground?');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act3_scene7', 95, 100, 'MESSENGER', 'The Lord Grandpré.'), ('henry_v_act3_scene7', 96, 101, 'CONSTABLE', 'A valiant and most expert gentleman. Would it were day! Alas, poor'), ('henry_v_act3_scene7', 97, 102, 'CONSTABLE', 'Harry of England! he longs not for the dawning as we do.'), ('henry_v_act3_scene7', 98, 103, 'ORLEANS', 'What a wretched and peevish fellow is this king of England, to'), ('henry_v_act3_scene7', 99, 104, 'ORLEANS', 'mope with his fat-brained followers so far out of his knowledge!'), ('henry_v_act3_scene7', 100, 105, 'CONSTABLE', 'If the English had any apprehension, they would run away.'), ('henry_v_act3_scene7', 101, 106, 'ORLEANS', 'That they lack; for if their heads had any intellectual armour, they'), ('henry_v_act3_scene7', 102, 107, 'ORLEANS', 'could never wear such heavy headpieces.'), ('henry_v_act3_scene7', 103, 108, 'RAMBURES', 'That island of England breeds very valiant creatures; their mastiffs are of unmatchable courage.'), ('henry_v_act3_scene7', 104, 109, 'ORLEANS', 'Foolish curs, that run winking into the mouth of a Russian bear'), ('henry_v_act3_scene7', 105, 110, 'ORLEANS', 'and have their heads crushed like rotten apples! You may as well'), ('henry_v_act3_scene7', 106, 111, 'ORLEANS', 'say, that’s a valiant flea that dare eat his breakfast on the'), ('henry_v_act3_scene7', 107, 112, 'ORLEANS', 'lip of a lion.'), ('henry_v_act3_scene7', 108, 113, 'CONSTABLE', 'Just, just; and the men do sympathize with the mastiffs in robustious'), ('henry_v_act3_scene7', 109, 114, 'CONSTABLE', 'and rough coming on, leaving their wits with their wives: and then'), ('henry_v_act3_scene7', 110, 115, 'CONSTABLE', 'give them great meals of beef and iron and steel, they will'), ('henry_v_act3_scene7', 111, 116, 'CONSTABLE', 'eat like wolves and fight like devils.'), ('henry_v_act3_scene7', 112, 117, 'ORLEANS', 'Ay, but these English are shrewdly out of beef.'), ('henry_v_act3_scene7', 113, 118, 'CONSTABLE', 'Then shall we find tomorrow they have only stomachs to eat and'), ('henry_v_act3_scene7', 114, 119, 'CONSTABLE', 'none to fight. Now is it time to arm: come, shall we'), ('henry_v_act3_scene7', 115, 120, 'CONSTABLE', 'about it?'), ('henry_v_act3_scene7', 116, 121, 'ORLEANS', 'It is now two o’clock: but, let me see, by ten'), ('henry_v_act3_scene7', 117, 122, 'ORLEANS', 'We shall have each a hundred Englishmen.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_chorus', 1, 0, 'CHORUS', 'Now entertain conjecture of a time'), ('henry_v_act4_chorus', 2, 1, 'CHORUS', 'When creeping murmur and the poring dark'), ('henry_v_act4_chorus', 3, 2, 'CHORUS', 'Fills the wide vessel of the universe.'), ('henry_v_act4_chorus', 4, 3, 'CHORUS', 'From camp to camp through the foul womb of night'), ('henry_v_act4_chorus', 5, 4, 'CHORUS', 'The hum of either army stilly sounds,'), ('henry_v_act4_chorus', 6, 5, 'CHORUS', 'That the fix’d sentinels almost receive'), ('henry_v_act4_chorus', 7, 6, 'CHORUS', 'The secret whispers of each other’s watch:'), ('henry_v_act4_chorus', 8, 7, 'CHORUS', 'Fire answers fire, and through their paly flames'), ('henry_v_act4_chorus', 9, 8, 'CHORUS', 'Each battle sees the other’s umber’d face;'), ('henry_v_act4_chorus', 10, 9, 'CHORUS', 'Steed threatens steed, in high and boastful neighs'), ('henry_v_act4_chorus', 11, 10, 'CHORUS', 'Piercing the night’s dull ear; and from the tents'), ('henry_v_act4_chorus', 12, 11, 'CHORUS', 'The armourers, accomplishing the knights,'), ('henry_v_act4_chorus', 13, 12, 'CHORUS', 'With busy hammers closing rivets up,'), ('henry_v_act4_chorus', 14, 13, 'CHORUS', 'Give dreadful note of preparation:'), ('henry_v_act4_chorus', 15, 14, 'CHORUS', 'The country cocks do crow, the clocks do toll,'), ('henry_v_act4_chorus', 16, 15, 'CHORUS', 'And the third hour of drowsy morning name.'), ('henry_v_act4_chorus', 17, 16, 'CHORUS', 'Proud of their numbers and secure in soul,'), ('henry_v_act4_chorus', 18, 17, 'CHORUS', 'The confident and over-lusty French'), ('henry_v_act4_chorus', 19, 18, 'CHORUS', 'Do the low-rated English play at dice;'), ('henry_v_act4_chorus', 20, 19, 'CHORUS', 'And chide the cripple tardy-gaited night'), ('henry_v_act4_chorus', 21, 20, 'CHORUS', 'Who, like a foul and ugly witch, doth limp'), ('henry_v_act4_chorus', 22, 21, 'CHORUS', 'So tediously away. The poor condemned English,'), ('henry_v_act4_chorus', 23, 22, 'CHORUS', 'Like sacrifices, by their watchful fires'), ('henry_v_act4_chorus', 24, 23, 'CHORUS', 'Sit patiently and inly ruminate'), ('henry_v_act4_chorus', 25, 24, 'CHORUS', 'The morning’s danger, and their gesture sad'), ('henry_v_act4_chorus', 26, 25, 'CHORUS', 'Investing lank-lean cheeks and war-worn coats'), ('henry_v_act4_chorus', 27, 26, 'CHORUS', 'Presenteth them unto the gazing moon'), ('henry_v_act4_chorus', 28, 27, 'CHORUS', 'So many horrid ghosts. O now, who will behold'), ('henry_v_act4_chorus', 29, 28, 'CHORUS', 'The royal captain of this ruin’d band'), ('henry_v_act4_chorus', 30, 29, 'CHORUS', 'Walking from watch to watch, from tent to tent,'), ('henry_v_act4_chorus', 31, 30, 'CHORUS', 'Let him cry, “Praise and glory on his head!”'), ('henry_v_act4_chorus', 32, 31, 'CHORUS', 'For forth he goes and visits all his host,'), ('henry_v_act4_chorus', 33, 32, 'CHORUS', 'Bids them good morrow with a modest smile'), ('henry_v_act4_chorus', 34, 33, 'CHORUS', 'And calls them brothers, friends, and countrymen.'), ('henry_v_act4_chorus', 35, 34, 'CHORUS', 'Upon his royal face there is no note'), ('henry_v_act4_chorus', 36, 35, 'CHORUS', 'How dread an army hath enrounded him;'), ('henry_v_act4_chorus', 37, 36, 'CHORUS', 'Nor doth he dedicate one jot of colour'), ('henry_v_act4_chorus', 38, 37, 'CHORUS', 'Unto the weary and all-watched night,'), ('henry_v_act4_chorus', 39, 38, 'CHORUS', 'But freshly looks and overbears attaint'), ('henry_v_act4_chorus', 40, 39, 'CHORUS', 'With cheerful semblance and sweet majesty;'), ('henry_v_act4_chorus', 41, 40, 'CHORUS', 'That every wretch, pining and pale before,'), ('henry_v_act4_chorus', 42, 41, 'CHORUS', 'Beholding him, plucks comfort from his looks:'), ('henry_v_act4_chorus', 43, 42, 'CHORUS', 'A largess universal like the sun'), ('henry_v_act4_chorus', 44, 43, 'CHORUS', 'His liberal eye doth give to everyone,'), ('henry_v_act4_chorus', 45, 44, 'CHORUS', 'Thawing cold fear, that mean and gentle all'), ('henry_v_act4_chorus', 46, 45, 'CHORUS', 'Behold, as may unworthiness define,'), ('henry_v_act4_chorus', 47, 46, 'CHORUS', 'A little touch of Harry in the night.'), ('henry_v_act4_chorus', 48, 47, 'CHORUS', 'And so our scene must to the battle fly;'), ('henry_v_act4_chorus', 49, 48, 'CHORUS', 'Where—O for pity!—we shall much disgrace'), ('henry_v_act4_chorus', 50, 49, 'CHORUS', 'With four or five most vile and ragged foils,'), ('henry_v_act4_chorus', 51, 50, 'CHORUS', 'Right ill-disposed in brawl ridiculous,'), ('henry_v_act4_chorus', 52, 51, 'CHORUS', 'The name of Agincourt. Yet sit and see,'), ('henry_v_act4_chorus', 53, 52, 'CHORUS', 'Minding true things by what their mock’ries be.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene1', 1, 0, 'KING HENRY', 'Gloucester, ’tis true that we are in great danger;'), ('henry_v_act4_scene1', 2, 1, 'KING HENRY', 'The greater therefore should our courage be.'), ('henry_v_act4_scene1', 3, 2, 'KING HENRY', 'Good morrow, brother Bedford. God Almighty!'), ('henry_v_act4_scene1', 4, 3, 'KING HENRY', 'There is some soul of goodness in things evil,'), ('henry_v_act4_scene1', 5, 4, 'KING HENRY', 'Would men observingly distil it out.'), ('henry_v_act4_scene1', 6, 5, 'KING HENRY', 'For our bad neighbour makes us early stirrers,'), ('henry_v_act4_scene1', 7, 6, 'KING HENRY', 'Which is both healthful and good husbandry:'), ('henry_v_act4_scene1', 8, 7, 'KING HENRY', 'Besides, they are our outward consciences,'), ('henry_v_act4_scene1', 9, 8, 'KING HENRY', 'And preachers to us all, admonishing'), ('henry_v_act4_scene1', 10, 9, 'KING HENRY', 'That we should dress us fairly for our end.'), ('henry_v_act4_scene1', 11, 10, 'KING HENRY', 'Thus may we gather honey from the weed,'), ('henry_v_act4_scene1', 12, 11, 'KING HENRY', 'And make a moral of the devil himself.'), ('henry_v_act4_scene1', 13, 12, 'ERPINGHAM', 'Not so, my liege: this lodging likes me better,'), ('henry_v_act4_scene1', 14, 13, 'ERPINGHAM', 'Since I may say “Now lie I like a king.”'), ('henry_v_act4_scene1', 15, 14, 'KING HENRY', '’Tis good for men to love their present pains'), ('henry_v_act4_scene1', 16, 15, 'KING HENRY', 'Upon example; so the spirit is eased:'), ('henry_v_act4_scene1', 17, 16, 'KING HENRY', 'And when the mind is quicken’d, out of doubt,'), ('henry_v_act4_scene1', 18, 17, 'KING HENRY', 'The organs, though defunct and dead before,'), ('henry_v_act4_scene1', 19, 18, 'KING HENRY', 'Break up their drowsy grave and newly move,'), ('henry_v_act4_scene1', 20, 19, 'KING HENRY', 'With casted slough and fresh legerity.'), ('henry_v_act4_scene1', 21, 20, 'KING HENRY', 'Lend me thy cloak, Sir Thomas. Brothers both,'), ('henry_v_act4_scene1', 22, 21, 'KING HENRY', 'Commend me to the princes in our camp;'), ('henry_v_act4_scene1', 23, 22, 'KING HENRY', 'Do my good morrow to them, and anon'), ('henry_v_act4_scene1', 24, 23, 'KING HENRY', 'Desire them all to my pavilion.'), ('henry_v_act4_scene1', 24, 24, 'GLOUCESTER', 'We shall, my liege.'), ('henry_v_act4_scene1', 25, 25, 'ERPINGHAM', 'Shall I attend your grace?'), ('henry_v_act4_scene1', 25, 26, 'KING HENRY', 'No, my good knight;'), ('henry_v_act4_scene1', 26, 27, 'KING HENRY', 'Go with my brothers to my lords of England:'), ('henry_v_act4_scene1', 27, 28, 'KING HENRY', 'I and my bosom must debate a while,'), ('henry_v_act4_scene1', 28, 29, 'KING HENRY', 'And then I would no other company.'), ('henry_v_act4_scene1', 29, 30, 'ERPINGHAM', 'The Lord in heaven bless thee, noble Harry!'), ('henry_v_act4_scene1', 30, 31, 'KING HENRY', 'God-a-mercy, old heart! thou speak’st cheerfully.'), ('henry_v_act4_scene1', 30, 32, 'PISTOL', 'Qui vas là?'), ('henry_v_act4_scene1', 31, 33, 'KING HENRY', 'A friend.'), ('henry_v_act4_scene1', 31, 34, 'PISTOL', 'Discuss unto me; art thou officer?'), ('henry_v_act4_scene1', 32, 35, 'PISTOL', 'Or art thou base, common and popular?'), ('henry_v_act4_scene1', 33, 36, 'KING HENRY', 'I am a gentleman of a company.'), ('henry_v_act4_scene1', 34, 37, 'PISTOL', 'Trail’st thou the puissant pike?'), ('henry_v_act4_scene1', 34, 38, 'KING HENRY', 'Even so. What are you?'), ('henry_v_act4_scene1', 35, 39, 'PISTOL', 'As good a gentleman as the emperor.'), ('henry_v_act4_scene1', 36, 40, 'KING HENRY', 'Then you are a better than the king.'), ('henry_v_act4_scene1', 37, 41, 'PISTOL', 'The king’s a bawcock, and a heart of gold,'), ('henry_v_act4_scene1', 38, 42, 'PISTOL', 'A lad of life, an imp of fame;'), ('henry_v_act4_scene1', 39, 43, 'PISTOL', 'Of parents good, of fist most valiant:'), ('henry_v_act4_scene1', 40, 44, 'PISTOL', 'I kiss his dirty shoe, and from heart-string'), ('henry_v_act4_scene1', 41, 45, 'PISTOL', 'I love the lovely bully. What is thy name?'), ('henry_v_act4_scene1', 42, 46, 'KING HENRY', 'Harry le Roy.'), ('henry_v_act4_scene1', 43, 47, 'PISTOL', 'Le Roy! a Cornish name: art thou of Cornish crew?'), ('henry_v_act4_scene1', 44, 48, 'KING HENRY', 'No, I am a Welshman.'), ('henry_v_act4_scene1', 44, 49, 'PISTOL', 'Know’st thou Fluellen?'), ('henry_v_act4_scene1', 45, 50, 'KING HENRY', 'Yes.'), ('henry_v_act4_scene1', 46, 51, 'PISTOL', 'Tell him I’ll knock his leek about his pate'), ('henry_v_act4_scene1', 47, 52, 'PISTOL', 'Upon Saint Davy’s day.'), ('henry_v_act4_scene1', 48, 53, 'KING HENRY', 'Do not you wear your dagger in your cap that day, lest'), ('henry_v_act4_scene1', 49, 54, 'KING HENRY', 'he knock that about yours.'), ('henry_v_act4_scene1', 49, 55, 'PISTOL', 'Art thou his friend?'), ('henry_v_act4_scene1', 50, 56, 'KING HENRY', 'And his kinsman too.'), ('henry_v_act4_scene1', 50, 57, 'PISTOL', 'The figo for thee, then!'), ('henry_v_act4_scene1', 51, 58, 'KING HENRY', 'I thank you: God be with you!'), ('henry_v_act4_scene1', 52, 59, 'PISTOL', 'My name is Pistol call’d.'), ('henry_v_act4_scene1', 52, 60, 'KING HENRY', 'It sorts well with your fierceness.'), ('henry_v_act4_scene1', 53, 61, 'GOWER', 'Captain Fluellen!'), ('henry_v_act4_scene1', 54, 62, 'FLUELLEN', 'So! in the name of Jesu Christ, speak lower. It is the'), ('henry_v_act4_scene1', 55, 63, 'FLUELLEN', 'greatest admiration in the universal world, when the true and aunchient prerogatifes'), ('henry_v_act4_scene1', 56, 64, 'FLUELLEN', 'and laws of the wars is not kept: if you would take'), ('henry_v_act4_scene1', 57, 65, 'FLUELLEN', 'the pains but to examine the wars of Pompey the Great, you'), ('henry_v_act4_scene1', 58, 66, 'FLUELLEN', 'shall find, I warrant you, that there is no tiddle taddle nor'), ('henry_v_act4_scene1', 59, 67, 'FLUELLEN', 'pibble pabble in Pompey’s camp; I warrant you, you shall find the'), ('henry_v_act4_scene1', 60, 68, 'FLUELLEN', 'ceremonies of the wars, and the cares of it, and the forms'), ('henry_v_act4_scene1', 61, 69, 'FLUELLEN', 'of it, and the sobriety of it, and the modesty of it,'), ('henry_v_act4_scene1', 62, 70, 'FLUELLEN', 'to be otherwise.'), ('henry_v_act4_scene1', 63, 71, 'GOWER', 'Why, the enemy is loud; you hear him all night.'), ('henry_v_act4_scene1', 64, 72, 'FLUELLEN', 'If the enemy is an ass and a fool and a prating'), ('henry_v_act4_scene1', 65, 73, 'FLUELLEN', 'coxcomb, is it meet, think you, that we should also, look you,'), ('henry_v_act4_scene1', 66, 74, 'FLUELLEN', 'be an ass and a fool and a prating coxcomb? in your'), ('henry_v_act4_scene1', 67, 75, 'FLUELLEN', 'own conscience, now?'), ('henry_v_act4_scene1', 67, 76, 'GOWER', 'I will speak lower.'), ('henry_v_act4_scene1', 68, 77, 'FLUELLEN', 'I pray you and beseech you that you will.'), ('henry_v_act4_scene1', 69, 78, 'KING HENRY', 'Though it appear a little out of fashion,'), ('henry_v_act4_scene1', 70, 79, 'KING HENRY', 'There is much care and valour in this Welshman.'), ('henry_v_act4_scene1', 71, 80, 'COURT', 'Brother John Bates, is not that the morning which breaks yonder?'), ('henry_v_act4_scene1', 72, 81, 'BATES', 'I think it be: but we have no great cause to desire'), ('henry_v_act4_scene1', 73, 82, 'BATES', 'the approach of day.'), ('henry_v_act4_scene1', 74, 83, 'WILLIAMS', 'We see yonder the beginning of the day, but I think we'), ('henry_v_act4_scene1', 75, 84, 'WILLIAMS', 'shall never see the end of it. Who goes there?'), ('henry_v_act4_scene1', 76, 85, 'KING HENRY', 'A friend.'), ('henry_v_act4_scene1', 76, 86, 'WILLIAMS', 'Under what captain serve you?'), ('henry_v_act4_scene1', 77, 87, 'KING HENRY', 'Under Sir Thomas Erpingham.'), ('henry_v_act4_scene1', 78, 88, 'WILLIAMS', 'A good old commander and a most kind gentleman: I pray you,'), ('henry_v_act4_scene1', 79, 89, 'WILLIAMS', 'what thinks he of our estate?'), ('henry_v_act4_scene1', 80, 90, 'KING HENRY', 'Even as men wrecked upon a sand, that look to be washed'), ('henry_v_act4_scene1', 81, 91, 'KING HENRY', 'off the next tide.'), ('henry_v_act4_scene1', 82, 92, 'BATES', 'He hath not told his thought to the king?'), ('henry_v_act4_scene1', 83, 93, 'KING HENRY', 'No; nor it is not meet he should. For, though I speak'), ('henry_v_act4_scene1', 84, 94, 'KING HENRY', 'it to you, I think the king is but a man, as'), ('henry_v_act4_scene1', 85, 95, 'KING HENRY', 'I am: the violet smells to him as it doth to me;'), ('henry_v_act4_scene1', 86, 96, 'KING HENRY', 'the element shows to him as it doth to me; all his'), ('henry_v_act4_scene1', 87, 97, 'KING HENRY', 'senses have but human conditions: his ceremonies laid by, in his nakedness'), ('henry_v_act4_scene1', 88, 98, 'KING HENRY', 'he appears but a man; and though his affections are higher mounted'), ('henry_v_act4_scene1', 89, 99, 'KING HENRY', 'than ours, yet, when they stoop, they stoop with the like wing.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene1', 90, 100, 'KING HENRY', 'Therefore when he sees reason of fears, as we do, his fears,'), ('henry_v_act4_scene1', 91, 101, 'KING HENRY', 'out of doubt, be of the same relish as ours are: yet,'), ('henry_v_act4_scene1', 92, 102, 'KING HENRY', 'in reason, no man should possess him with any appearance of fear,'), ('henry_v_act4_scene1', 93, 103, 'KING HENRY', 'lest he, by showing it, should dishearten his army.'), ('henry_v_act4_scene1', 94, 104, 'BATES', 'He may show what outward courage he will; but I believe, as'), ('henry_v_act4_scene1', 95, 105, 'BATES', 'cold a night as ’tis, he could wish himself in Thames up'), ('henry_v_act4_scene1', 96, 106, 'BATES', 'to the neck; and so I would he were, and I by'), ('henry_v_act4_scene1', 97, 107, 'BATES', 'him, at all adventures, so we were quit here.'), ('henry_v_act4_scene1', 98, 108, 'KING HENRY', 'By my troth, I will speak my conscience of the King: I'), ('henry_v_act4_scene1', 99, 109, 'KING HENRY', 'think he would not wish himself anywhere but where he is.'), ('henry_v_act4_scene1', 100, 110, 'BATES', 'Then I would he were here alone; so should he be sure'), ('henry_v_act4_scene1', 101, 111, 'BATES', 'to be ransomed, and a many poor men’s lives saved.'), ('henry_v_act4_scene1', 102, 112, 'KING HENRY', 'I dare say you love him not so ill, to wish him'), ('henry_v_act4_scene1', 103, 113, 'KING HENRY', 'here alone, howsoever you speak this to feel other men’s minds: methinks'), ('henry_v_act4_scene1', 104, 114, 'KING HENRY', 'I could not die anywhere so contented as in the king’s company;'), ('henry_v_act4_scene1', 105, 115, 'KING HENRY', 'his cause being just and his quarrel honourable.'), ('henry_v_act4_scene1', 106, 116, 'WILLIAMS', 'That’s more than we know.'), ('henry_v_act4_scene1', 107, 117, 'BATES', 'Ay, or more than we should seek after; for we know enough,'), ('henry_v_act4_scene1', 108, 118, 'BATES', 'if we know we are the king’s subjects: if his cause be'), ('henry_v_act4_scene1', 109, 119, 'BATES', 'wrong, our obedience to the king wipes the crime of it out'), ('henry_v_act4_scene1', 110, 120, 'BATES', 'of us.'), ('henry_v_act4_scene1', 111, 121, 'WILLIAMS', 'But if the cause be not good, the king himself hath a'), ('henry_v_act4_scene1', 112, 122, 'WILLIAMS', 'heavy reckoning to make, when all those legs and arms and heads,'), ('henry_v_act4_scene1', 113, 123, 'WILLIAMS', 'chopped off in a battle, shall join together at the latter day'), ('henry_v_act4_scene1', 114, 124, 'WILLIAMS', 'and cry all “We died at such a place;” some swearing, some'), ('henry_v_act4_scene1', 115, 125, 'WILLIAMS', 'crying for a surgeon, some upon their wives left poor behind them,'), ('henry_v_act4_scene1', 116, 126, 'WILLIAMS', 'some upon the debts they owe, some upon their children rawly left.'), ('henry_v_act4_scene1', 117, 127, 'WILLIAMS', 'I am afeard there are few die well that die in a'), ('henry_v_act4_scene1', 118, 128, 'WILLIAMS', 'battle; for how can they charitably dispose of anything, when blood is'), ('henry_v_act4_scene1', 119, 129, 'WILLIAMS', 'their argument? Now, if these men do not die well, it will'), ('henry_v_act4_scene1', 120, 130, 'WILLIAMS', 'be a black matter for the king that led them to it;'), ('henry_v_act4_scene1', 121, 131, 'WILLIAMS', 'who to disobey were against all proportion of subjection.'), ('henry_v_act4_scene1', 122, 132, 'KING HENRY', 'So, if a son that is by his father sent about merchandise'), ('henry_v_act4_scene1', 123, 133, 'KING HENRY', 'do sinfully miscarry upon the sea, the imputation of his wickedness, by'), ('henry_v_act4_scene1', 124, 134, 'KING HENRY', 'your rule, should be imposed upon his father that sent him: or'), ('henry_v_act4_scene1', 125, 135, 'KING HENRY', 'if a servant, under his master’s command transporting a sum of money,'), ('henry_v_act4_scene1', 126, 136, 'KING HENRY', 'be assailed by robbers and die in many irreconcil’d iniquities, you may'), ('henry_v_act4_scene1', 127, 137, 'KING HENRY', 'call the business of the master the author of the servant’s damnation:'), ('henry_v_act4_scene1', 128, 138, 'KING HENRY', 'but this is not so: the king is not bound to answer'), ('henry_v_act4_scene1', 129, 139, 'KING HENRY', 'the particular endings of his soldiers, the father of his son, nor'), ('henry_v_act4_scene1', 130, 140, 'KING HENRY', 'the master of his servant; for they purpose not their death, when'), ('henry_v_act4_scene1', 131, 141, 'KING HENRY', 'they purpose their services. Besides, there is no king, be his cause'), ('henry_v_act4_scene1', 132, 142, 'KING HENRY', 'never so spotless, if it come to the arbitrement of swords, can'), ('henry_v_act4_scene1', 133, 143, 'KING HENRY', 'try it out with all unspotted soldiers: some peradventure have on them'), ('henry_v_act4_scene1', 134, 144, 'KING HENRY', 'the guilt of premeditated and contrived murder; some, of beguiling virgins with'), ('henry_v_act4_scene1', 135, 145, 'KING HENRY', 'the broken seals of perjury; some, making the wars their bulwark, that'), ('henry_v_act4_scene1', 136, 146, 'KING HENRY', 'have before gored the gentle bosom of peace with pillage and robbery.'), ('henry_v_act4_scene1', 137, 147, 'KING HENRY', 'Now, if these men have defeated the law and outrun native punishment,'), ('henry_v_act4_scene1', 138, 148, 'KING HENRY', 'though they can outstrip men, they have no wings to fly from'), ('henry_v_act4_scene1', 139, 149, 'KING HENRY', 'God: war is his beadle, war is his vengeance; so that here'), ('henry_v_act4_scene1', 140, 150, 'KING HENRY', 'men are punished for before-breach of the king’s laws in now the'), ('henry_v_act4_scene1', 141, 151, 'KING HENRY', 'king’s quarrel: where they feared the death, they have borne life away;'), ('henry_v_act4_scene1', 142, 152, 'KING HENRY', 'and where they would be safe, they perish: then if they die'), ('henry_v_act4_scene1', 143, 153, 'KING HENRY', 'unprovided, no more is the king guilty of their damnation than he'), ('henry_v_act4_scene1', 144, 154, 'KING HENRY', 'was before guilty of those impieties for the which they are now'), ('henry_v_act4_scene1', 145, 155, 'KING HENRY', 'visited. Every subject’s duty is the king’s; but every subject’s soul is'), ('henry_v_act4_scene1', 146, 156, 'KING HENRY', 'his own. Therefore should every soldier in the wars do as every'), ('henry_v_act4_scene1', 147, 157, 'KING HENRY', 'sick man in his bed, wash every mote out of his conscience:'), ('henry_v_act4_scene1', 148, 158, 'KING HENRY', 'and dying so, death is to him advantage; or not dying, the'), ('henry_v_act4_scene1', 149, 159, 'KING HENRY', 'time was blessedly lost wherein such preparation was gained: and in him'), ('henry_v_act4_scene1', 150, 160, 'KING HENRY', 'that escapes, it were not sin to think that, making God so'), ('henry_v_act4_scene1', 151, 161, 'KING HENRY', 'free an offer, He let him outlive that day to see His'), ('henry_v_act4_scene1', 152, 162, 'KING HENRY', 'greatness and to teach others how they should prepare.'), ('henry_v_act4_scene1', 153, 163, 'WILLIAMS', '’Tis certain, every man that dies ill, the ill upon his own'), ('henry_v_act4_scene1', 154, 164, 'WILLIAMS', 'head, the king is not to answer for it.'), ('henry_v_act4_scene1', 155, 165, 'BATES', 'I do not desire he should answer for me; and yet I'), ('henry_v_act4_scene1', 156, 166, 'BATES', 'determine to fight lustily for him.'), ('henry_v_act4_scene1', 157, 167, 'KING HENRY', 'I myself heard the king say he would not be ransomed.'), ('henry_v_act4_scene1', 158, 168, 'WILLIAMS', 'Ay, he said so, to make us fight cheerfully: but when our'), ('henry_v_act4_scene1', 159, 169, 'WILLIAMS', 'throats are cut, he may be ransomed, and we ne’er the wiser.'), ('henry_v_act4_scene1', 160, 170, 'KING HENRY', 'If I live to see it, I will never trust his word after.'), ('henry_v_act4_scene1', 161, 171, 'WILLIAMS', 'You pay him then. That’s a perilous shot out of an elder-gun,'), ('henry_v_act4_scene1', 162, 172, 'WILLIAMS', 'that a poor and a private displeasure can do against a monarch!'), ('henry_v_act4_scene1', 163, 173, 'WILLIAMS', 'you may as well go about to turn the sun to ice'), ('henry_v_act4_scene1', 164, 174, 'WILLIAMS', 'with fanning in his face with a peacock’s feather. You’ll never trust'), ('henry_v_act4_scene1', 165, 175, 'WILLIAMS', 'his word after! come, ’tis a foolish saying.'), ('henry_v_act4_scene1', 166, 176, 'KING HENRY', 'Your reproof is something too round: I should be angry with you,'), ('henry_v_act4_scene1', 167, 177, 'KING HENRY', 'if the time were convenient.'), ('henry_v_act4_scene1', 168, 178, 'WILLIAMS', 'Let it be a quarrel between us, if you live.'), ('henry_v_act4_scene1', 169, 179, 'KING HENRY', 'I embrace it.'), ('henry_v_act4_scene1', 169, 180, 'WILLIAMS', 'How shall I know thee again?'), ('henry_v_act4_scene1', 170, 181, 'KING HENRY', 'Give me any gage of thine, and I will wear it in'), ('henry_v_act4_scene1', 171, 182, 'KING HENRY', 'my bonnet: then, if ever thou darest acknowledge it, I will make'), ('henry_v_act4_scene1', 172, 183, 'KING HENRY', 'it my quarrel.'), ('henry_v_act4_scene1', 173, 184, 'WILLIAMS', 'Here’s my glove: give me another of thine.'), ('henry_v_act4_scene1', 174, 185, 'KING HENRY', 'There.'), ('henry_v_act4_scene1', 175, 186, 'WILLIAMS', 'This will I also wear in my cap: if ever thou come'), ('henry_v_act4_scene1', 176, 187, 'WILLIAMS', 'to me and say, after tomorrow, “This is my glove,” by this'), ('henry_v_act4_scene1', 177, 188, 'WILLIAMS', 'hand I will take thee a box on the ear.'), ('henry_v_act4_scene1', 178, 189, 'KING HENRY', 'If ever I live to see it, I will challenge it.'), ('henry_v_act4_scene1', 179, 190, 'WILLIAMS', 'Thou darest as well be hane’d.'), ('henry_v_act4_scene1', 180, 191, 'KING HENRY', 'Well, I will do it, though I take thee in the king’s company.'), ('henry_v_act4_scene1', 181, 192, 'WILLIAMS', 'Keep thy word: fare thee well.'), ('henry_v_act4_scene1', 182, 193, 'BATES', 'Be friends, you English fools, be friends: we have French quarrels enow,'), ('henry_v_act4_scene1', 183, 194, 'BATES', 'if you could tell how to reckon.'), ('henry_v_act4_scene1', 184, 195, 'KING HENRY', 'Indeed, the French may lay twenty French crowns to one, they will'), ('henry_v_act4_scene1', 185, 196, 'KING HENRY', 'beat us; for they bear them on their shoulders: but it is'), ('henry_v_act4_scene1', 186, 197, 'KING HENRY', 'no English treason to cut French crowns, and tomorrow the king himself'), ('henry_v_act4_scene1', 187, 198, 'KING HENRY', 'will be a clipper.'), ('henry_v_act4_scene1', 188, 199, 'ERPINGHAM', 'My lord, your nobles, jealous of your absence,');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene1', 189, 200, 'ERPINGHAM', 'Seek through your camp to find you.'), ('henry_v_act4_scene1', 190, 201, 'KING HENRY', 'Good old knight,'), ('henry_v_act4_scene1', 191, 202, 'KING HENRY', 'Collect them all together at my tent:'), ('henry_v_act4_scene1', 192, 203, 'KING HENRY', 'I’ll be before thee.'), ('henry_v_act4_scene1', 192, 204, 'ERPINGHAM', 'I shall do’t, my lord.'), ('henry_v_act4_scene1', 193, 205, 'KING HENRY', 'O God of battles! steel my soldiers’ hearts;'), ('henry_v_act4_scene1', 194, 206, 'KING HENRY', 'Possess them not with fear; take from them now'), ('henry_v_act4_scene1', 195, 207, 'KING HENRY', 'The sense of reckoning, if the opposed numbers'), ('henry_v_act4_scene1', 196, 208, 'KING HENRY', 'Pluck their hearts from them. Not today, O Lord,'), ('henry_v_act4_scene1', 197, 209, 'KING HENRY', 'O, not today, think not upon the fault'), ('henry_v_act4_scene1', 198, 210, 'KING HENRY', 'My father made in compassing the crown!'), ('henry_v_act4_scene1', 199, 211, 'KING HENRY', 'I Richard’s body have interred new;'), ('henry_v_act4_scene1', 200, 212, 'KING HENRY', 'And on it have bestow’d more contrite tears'), ('henry_v_act4_scene1', 201, 213, 'KING HENRY', 'Than from it issued forced drops of blood:'), ('henry_v_act4_scene1', 202, 214, 'KING HENRY', 'Five hundred poor I have in yearly pay,'), ('henry_v_act4_scene1', 203, 215, 'KING HENRY', 'Who twice a day their wither’d hands hold up'), ('henry_v_act4_scene1', 204, 216, 'KING HENRY', 'Toward heaven, to pardon blood; and I have built'), ('henry_v_act4_scene1', 205, 217, 'KING HENRY', 'Two chantries, where the sad and solemn priests'), ('henry_v_act4_scene1', 206, 218, 'KING HENRY', 'Sing still for Richard’s soul. More will I do;'), ('henry_v_act4_scene1', 207, 219, 'KING HENRY', 'Though all that I can do is nothing worth,'), ('henry_v_act4_scene1', 208, 220, 'KING HENRY', 'Since that my penitence comes after all,'), ('henry_v_act4_scene1', 209, 221, 'KING HENRY', 'Imploring pardon.'), ('henry_v_act4_scene1', 209, 222, 'GLOUCESTER', 'My liege!'), ('henry_v_act4_scene1', 210, 223, 'KING HENRY', 'My brother Gloucester’s voice? Ay;'), ('henry_v_act4_scene1', 211, 224, 'KING HENRY', 'I know thy errand, I will go with thee:'), ('henry_v_act4_scene1', 212, 225, 'KING HENRY', 'The day, my friends and all things stay for me.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene2', 1, 0, 'ORLEANS', 'The sun doth gild our armour; up, my lords!'), ('henry_v_act4_scene2', 2, 1, 'DAUPHIN', 'Monte à cheval! My horse! varlet! laquais! ha!'), ('henry_v_act4_scene2', 3, 2, 'ORLEANS', 'O brave spirit!'), ('henry_v_act4_scene2', 3, 3, 'DAUPHIN', 'Via! les eaux et la terre.'), ('henry_v_act4_scene2', 4, 4, 'ORLEANS', 'Rien puis? l’air et le feu.'), ('henry_v_act4_scene2', 4, 5, 'DAUPHIN', 'Ciel, cousin Orleans.'), ('henry_v_act4_scene2', 5, 6, 'CONSTABLE', 'Hark, how our steeds for present service neigh!'), ('henry_v_act4_scene2', 6, 7, 'DAUPHIN', 'Mount them, and make incision in their hides,'), ('henry_v_act4_scene2', 7, 8, 'DAUPHIN', 'That their hot blood may spin in English eyes,'), ('henry_v_act4_scene2', 8, 9, 'DAUPHIN', 'And dout them with superfluous courage, ha!'), ('henry_v_act4_scene2', 9, 10, 'RAMBURES', 'What, will you have them weep our horses’ blood?'), ('henry_v_act4_scene2', 10, 11, 'RAMBURES', 'How shall we, then, behold their natural tears?'), ('henry_v_act4_scene2', 11, 12, 'MESSENGER', 'The English are embattled, you French peers.'), ('henry_v_act4_scene2', 12, 13, 'CONSTABLE', 'To horse, you gallant princes! straight to horse!'), ('henry_v_act4_scene2', 13, 14, 'CONSTABLE', 'Do but behold yon poor and starved band,'), ('henry_v_act4_scene2', 14, 15, 'CONSTABLE', 'And your fair show shall suck away their souls,'), ('henry_v_act4_scene2', 15, 16, 'CONSTABLE', 'Leaving them but the shales and husks of men.'), ('henry_v_act4_scene2', 16, 17, 'CONSTABLE', 'There is not work enough for all our hands;'), ('henry_v_act4_scene2', 17, 18, 'CONSTABLE', 'Scarce blood enough in all their sickly veins'), ('henry_v_act4_scene2', 18, 19, 'CONSTABLE', 'To give each naked curtle-axe a stain,'), ('henry_v_act4_scene2', 19, 20, 'CONSTABLE', 'That our French gallants shall today draw out,'), ('henry_v_act4_scene2', 20, 21, 'CONSTABLE', 'And sheathe for lack of sport: let us but blow on them,'), ('henry_v_act4_scene2', 21, 22, 'CONSTABLE', 'The vapour of our valour will o’erturn them.'), ('henry_v_act4_scene2', 22, 23, 'CONSTABLE', '’Tis positive ’gainst all exceptions, lords,'), ('henry_v_act4_scene2', 23, 24, 'CONSTABLE', 'That our superfluous lackeys and our peasants,'), ('henry_v_act4_scene2', 24, 25, 'CONSTABLE', 'Who in unnecessary action swarm'), ('henry_v_act4_scene2', 25, 26, 'CONSTABLE', 'About our squares of battle, were enough'), ('henry_v_act4_scene2', 26, 27, 'CONSTABLE', 'To purge this field of such a hilding foe,'), ('henry_v_act4_scene2', 27, 28, 'CONSTABLE', 'Though we upon this mountain’s basis by'), ('henry_v_act4_scene2', 28, 29, 'CONSTABLE', 'Took stand for idle speculation:'), ('henry_v_act4_scene2', 29, 30, 'CONSTABLE', 'But that our honours must not. What’s to say?'), ('henry_v_act4_scene2', 30, 31, 'CONSTABLE', 'A very little little let us do,'), ('henry_v_act4_scene2', 31, 32, 'CONSTABLE', 'And all is done. Then let the trumpets sound'), ('henry_v_act4_scene2', 32, 33, 'CONSTABLE', 'The tucket sonance and the note to mount;'), ('henry_v_act4_scene2', 33, 34, 'CONSTABLE', 'For our approach shall so much dare the field'), ('henry_v_act4_scene2', 34, 35, 'CONSTABLE', 'That England shall crouch down in fear and yield.'), ('henry_v_act4_scene2', 35, 36, 'GRANDPRÉ', 'Why do you stay so long, my lords of France?'), ('henry_v_act4_scene2', 36, 37, 'GRANDPRÉ', 'Yond island carrions, desperate of their bones,'), ('henry_v_act4_scene2', 37, 38, 'GRANDPRÉ', 'Ill-favouredly become the morning field:'), ('henry_v_act4_scene2', 38, 39, 'GRANDPRÉ', 'Their ragged curtains poorly are let loose,'), ('henry_v_act4_scene2', 39, 40, 'GRANDPRÉ', 'And our air shakes them passing scornfully:'), ('henry_v_act4_scene2', 40, 41, 'GRANDPRÉ', 'Big Mars seems bankrupt in their beggar’d host'), ('henry_v_act4_scene2', 41, 42, 'GRANDPRÉ', 'And faintly through a rusty beaver peeps:'), ('henry_v_act4_scene2', 42, 43, 'GRANDPRÉ', 'The horsemen sit like fixed candlesticks,'), ('henry_v_act4_scene2', 43, 44, 'GRANDPRÉ', 'With torch-staves in their hand; and their poor jades'), ('henry_v_act4_scene2', 44, 45, 'GRANDPRÉ', 'Lob down their heads, drooping the hides and hips,'), ('henry_v_act4_scene2', 45, 46, 'GRANDPRÉ', 'The gum down-roping from their pale-dead eyes,'), ('henry_v_act4_scene2', 46, 47, 'GRANDPRÉ', 'And in their pale dull mouths the gimmal bit'), ('henry_v_act4_scene2', 47, 48, 'GRANDPRÉ', 'Lies foul with chew’d grass, still and motionless;'), ('henry_v_act4_scene2', 48, 49, 'GRANDPRÉ', 'And their executors, the knavish crows,'), ('henry_v_act4_scene2', 49, 50, 'GRANDPRÉ', 'Fly o’er them, all impatient for their hour.'), ('henry_v_act4_scene2', 50, 51, 'GRANDPRÉ', 'Description cannot suit itself in words'), ('henry_v_act4_scene2', 51, 52, 'GRANDPRÉ', 'To demonstrate the life of such a battle'), ('henry_v_act4_scene2', 52, 53, 'GRANDPRÉ', 'In life so lifeless as it shows itself.'), ('henry_v_act4_scene2', 53, 54, 'CONSTABLE', 'They have said their prayers, and they stay for death.'), ('henry_v_act4_scene2', 54, 55, 'DAUPHIN', 'Shall we go send them dinners and fresh suits'), ('henry_v_act4_scene2', 55, 56, 'DAUPHIN', 'And give their fasting horses provender,'), ('henry_v_act4_scene2', 56, 57, 'DAUPHIN', 'And after fight with them?'), ('henry_v_act4_scene2', 57, 58, 'CONSTABLE', 'I stay but for my guidon: to the field!'), ('henry_v_act4_scene2', 58, 59, 'CONSTABLE', 'I will the banner from a trumpet take,'), ('henry_v_act4_scene2', 59, 60, 'CONSTABLE', 'And use it for my haste. Come, come, away!'), ('henry_v_act4_scene2', 60, 61, 'CONSTABLE', 'The sun is high, and we outwear the day.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene3', 1, 0, 'GLOUCESTER', 'Where is the king?'), ('henry_v_act4_scene3', 2, 1, 'BEDFORD', 'The king himself is rode to view their battle.'), ('henry_v_act4_scene3', 3, 2, 'WESTMORELAND', 'Of fighting men they have full threescore thousand.'), ('henry_v_act4_scene3', 4, 3, 'EXETER', 'There’s five to one; besides, they all are fresh.'), ('henry_v_act4_scene3', 5, 4, 'SALISBURY', 'God’s arm strike with us! ’tis a fearful odds.'), ('henry_v_act4_scene3', 6, 5, 'SALISBURY', 'God be wi’ you, princes all; I’ll to my charge:'), ('henry_v_act4_scene3', 7, 6, 'SALISBURY', 'If we no more meet till we meet in heaven,'), ('henry_v_act4_scene3', 8, 7, 'SALISBURY', 'Then, joyfully, my noble Lord of Bedford,'), ('henry_v_act4_scene3', 9, 8, 'SALISBURY', 'My dear Lord Gloucester, and my good Lord Exeter,'), ('henry_v_act4_scene3', 10, 9, 'SALISBURY', 'And my kind kinsman, warriors all, adieu!'), ('henry_v_act4_scene3', 11, 10, 'BEDFORD', 'Farewell, good Salisbury; and good luck go with thee!'), ('henry_v_act4_scene3', 12, 11, 'EXETER', 'Farewell, kind lord; fight valiantly today:'), ('henry_v_act4_scene3', 13, 12, 'EXETER', 'And yet I do thee wrong to mind thee of it,'), ('henry_v_act4_scene3', 14, 13, 'EXETER', 'For thou art framed of the firm truth of valour.'), ('henry_v_act4_scene3', 15, 14, 'BEDFORD', 'He is as full of valour as of kindness;'), ('henry_v_act4_scene3', 16, 15, 'BEDFORD', 'Princely in both.'), ('henry_v_act4_scene3', 16, 16, 'WESTMORELAND', 'O that we now had here'), ('henry_v_act4_scene3', 17, 17, 'WESTMORELAND', 'But one ten thousand of those men in England'), ('henry_v_act4_scene3', 18, 18, 'WESTMORELAND', 'That do no work today!'), ('henry_v_act4_scene3', 18, 19, 'KING HENRY', 'What’s he that wishes so?'), ('henry_v_act4_scene3', 19, 20, 'KING HENRY', 'My cousin Westmoreland? No, my fair cousin:'), ('henry_v_act4_scene3', 20, 21, 'KING HENRY', 'If we are mark’d to die, we are enow'), ('henry_v_act4_scene3', 21, 22, 'KING HENRY', 'To do our country loss; and if to live,'), ('henry_v_act4_scene3', 22, 23, 'KING HENRY', 'The fewer men, the greater share of honour.'), ('henry_v_act4_scene3', 23, 24, 'KING HENRY', 'God’s will! I pray thee, wish not one man more.'), ('henry_v_act4_scene3', 24, 25, 'KING HENRY', 'By Jove, I am not covetous for gold,'), ('henry_v_act4_scene3', 25, 26, 'KING HENRY', 'Nor care I who doth feed upon my cost;'), ('henry_v_act4_scene3', 26, 27, 'KING HENRY', 'It yearns me not if men my garments wear;'), ('henry_v_act4_scene3', 27, 28, 'KING HENRY', 'Such outward things dwell not in my desires:'), ('henry_v_act4_scene3', 28, 29, 'KING HENRY', 'But if it be a sin to covet honour,'), ('henry_v_act4_scene3', 29, 30, 'KING HENRY', 'I am the most offending soul alive.'), ('henry_v_act4_scene3', 30, 31, 'KING HENRY', 'No, faith, my coz, wish not a man from England:'), ('henry_v_act4_scene3', 31, 32, 'KING HENRY', 'God’s peace! I would not lose so great an honour'), ('henry_v_act4_scene3', 32, 33, 'KING HENRY', 'As one man more, methinks, would share from me'), ('henry_v_act4_scene3', 33, 34, 'KING HENRY', 'For the best hope I have. O, do not wish one more!'), ('henry_v_act4_scene3', 34, 35, 'KING HENRY', 'Rather proclaim it, Westmoreland, through my host,'), ('henry_v_act4_scene3', 35, 36, 'KING HENRY', 'That he which hath no stomach to this fight,'), ('henry_v_act4_scene3', 36, 37, 'KING HENRY', 'Let him depart; his passport shall be made'), ('henry_v_act4_scene3', 37, 38, 'KING HENRY', 'And crowns for convoy put into his purse:'), ('henry_v_act4_scene3', 38, 39, 'KING HENRY', 'We would not die in that man’s company'), ('henry_v_act4_scene3', 39, 40, 'KING HENRY', 'That fears his fellowship to die with us.'), ('henry_v_act4_scene3', 40, 41, 'KING HENRY', 'This day is call’d the feast of Crispian:'), ('henry_v_act4_scene3', 41, 42, 'KING HENRY', 'He that outlives this day, and comes safe home,'), ('henry_v_act4_scene3', 42, 43, 'KING HENRY', 'Will stand a tip-toe when this day is named,'), ('henry_v_act4_scene3', 43, 44, 'KING HENRY', 'And rouse him at the name of Crispian.'), ('henry_v_act4_scene3', 44, 45, 'KING HENRY', 'He that shall live this day, and see old age,'), ('henry_v_act4_scene3', 45, 46, 'KING HENRY', 'Will yearly on the vigil feast his neighbours,'), ('henry_v_act4_scene3', 46, 47, 'KING HENRY', 'And say, “Tomorrow is Saint Crispian:”'), ('henry_v_act4_scene3', 47, 48, 'KING HENRY', 'Then will he strip his sleeve and show his scars,'), ('henry_v_act4_scene3', 48, 49, 'KING HENRY', 'And say “These wounds I had on Crispian’s day.”'), ('henry_v_act4_scene3', 49, 50, 'KING HENRY', 'Old men forget; yet all shall be forgot,'), ('henry_v_act4_scene3', 50, 51, 'KING HENRY', 'But he’ll remember with advantages'), ('henry_v_act4_scene3', 51, 52, 'KING HENRY', 'What feats he did that day: then shall our names,'), ('henry_v_act4_scene3', 52, 53, 'KING HENRY', 'Familiar in his mouth as household words,'), ('henry_v_act4_scene3', 53, 54, 'KING HENRY', 'Harry the king, Bedford and Exeter,'), ('henry_v_act4_scene3', 54, 55, 'KING HENRY', 'Warwick and Talbot, Salisbury and Gloucester,'), ('henry_v_act4_scene3', 55, 56, 'KING HENRY', 'Be in their flowing cups freshly remember’d.'), ('henry_v_act4_scene3', 56, 57, 'KING HENRY', 'This story shall the good man teach his son;'), ('henry_v_act4_scene3', 57, 58, 'KING HENRY', 'And Crispin Crispian shall ne’er go by,'), ('henry_v_act4_scene3', 58, 59, 'KING HENRY', 'From this day to the ending of the world,'), ('henry_v_act4_scene3', 59, 60, 'KING HENRY', 'But we in it shall be remembered;'), ('henry_v_act4_scene3', 60, 61, 'KING HENRY', 'We few, we happy few, we band of brothers;'), ('henry_v_act4_scene3', 61, 62, 'KING HENRY', 'For he today that sheds his blood with me'), ('henry_v_act4_scene3', 62, 63, 'KING HENRY', 'Shall be my brother; be he ne’er so vile,'), ('henry_v_act4_scene3', 63, 64, 'KING HENRY', 'This day shall gentle his condition:'), ('henry_v_act4_scene3', 64, 65, 'KING HENRY', 'And gentlemen in England now abed'), ('henry_v_act4_scene3', 65, 66, 'KING HENRY', 'Shall think themselves accursed they were not here,'), ('henry_v_act4_scene3', 66, 67, 'KING HENRY', 'And hold their manhoods cheap whiles any speaks'), ('henry_v_act4_scene3', 67, 68, 'KING HENRY', 'That fought with us upon Saint Crispin’s day.'), ('henry_v_act4_scene3', 68, 69, 'SALISBURY', 'My sovereign lord, bestow yourself with speed:'), ('henry_v_act4_scene3', 69, 70, 'SALISBURY', 'The French are bravely in their battles set,'), ('henry_v_act4_scene3', 70, 71, 'SALISBURY', 'And will with all expedience charge on us.'), ('henry_v_act4_scene3', 71, 72, 'KING HENRY', 'All things are ready, if our minds be so.'), ('henry_v_act4_scene3', 72, 73, 'WESTMORELAND', 'Perish the man whose mind is backward now!'), ('henry_v_act4_scene3', 73, 74, 'KING HENRY', 'Thou dost not wish more help from England, coz?'), ('henry_v_act4_scene3', 74, 75, 'WESTMORELAND', 'God’s will! my liege, would you and I alone,'), ('henry_v_act4_scene3', 75, 76, 'WESTMORELAND', 'Without more help, could fight this royal battle!'), ('henry_v_act4_scene3', 76, 77, 'KING HENRY', 'Why, now thou hast unwish’d five thousand men;'), ('henry_v_act4_scene3', 77, 78, 'KING HENRY', 'Which likes me better than to wish us one.'), ('henry_v_act4_scene3', 78, 79, 'KING HENRY', 'You know your places: God be with you all!'), ('henry_v_act4_scene3', 79, 80, 'MONTJOY', 'Once more I come to know of thee, King Harry,'), ('henry_v_act4_scene3', 80, 81, 'MONTJOY', 'If for thy ransom thou wilt now compound,'), ('henry_v_act4_scene3', 81, 82, 'MONTJOY', 'Before thy most assured overthrow:'), ('henry_v_act4_scene3', 82, 83, 'MONTJOY', 'For certainly thou art so near the gulf,'), ('henry_v_act4_scene3', 83, 84, 'MONTJOY', 'Thou needs must be englutted. Besides, in mercy,'), ('henry_v_act4_scene3', 84, 85, 'MONTJOY', 'The constable desires thee thou wilt mind'), ('henry_v_act4_scene3', 85, 86, 'MONTJOY', 'Thy followers of repentance; that their souls'), ('henry_v_act4_scene3', 86, 87, 'MONTJOY', 'May make a peaceful and a sweet retire'), ('henry_v_act4_scene3', 87, 88, 'MONTJOY', 'From off these fields, where, wretches, their poor bodies'), ('henry_v_act4_scene3', 88, 89, 'MONTJOY', 'Must lie and fester.'), ('henry_v_act4_scene3', 88, 90, 'KING HENRY', 'Who hath sent thee now?'), ('henry_v_act4_scene3', 89, 91, 'MONTJOY', 'The Constable of France.'), ('henry_v_act4_scene3', 90, 92, 'KING HENRY', 'I pray thee, bear my former answer back:'), ('henry_v_act4_scene3', 91, 93, 'KING HENRY', 'Bid them achieve me and then sell my bones.'), ('henry_v_act4_scene3', 92, 94, 'KING HENRY', 'Good God! why should they mock poor fellows thus?'), ('henry_v_act4_scene3', 93, 95, 'KING HENRY', 'The man that once did sell the lion’s skin'), ('henry_v_act4_scene3', 94, 96, 'KING HENRY', 'While the beast lived, was killed with hunting him.'), ('henry_v_act4_scene3', 95, 97, 'KING HENRY', 'A many of our bodies shall no doubt'), ('henry_v_act4_scene3', 96, 98, 'KING HENRY', 'Find native graves; upon the which, I trust,'), ('henry_v_act4_scene3', 97, 99, 'KING HENRY', 'Shall witness live in brass of this day’s work:');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene3', 98, 100, 'KING HENRY', 'And those that leave their valiant bones in France,'), ('henry_v_act4_scene3', 99, 101, 'KING HENRY', 'Dying like men, though buried in your dunghills,'), ('henry_v_act4_scene3', 100, 102, 'KING HENRY', 'They shall be famed; for there the sun shall greet them,'), ('henry_v_act4_scene3', 101, 103, 'KING HENRY', 'And draw their honours reeking up to heaven;'), ('henry_v_act4_scene3', 102, 104, 'KING HENRY', 'Leaving their earthly parts to choke your clime,'), ('henry_v_act4_scene3', 103, 105, 'KING HENRY', 'The smell whereof shall breed a plague in France.'), ('henry_v_act4_scene3', 104, 106, 'KING HENRY', 'Mark then abounding valour in our English,'), ('henry_v_act4_scene3', 105, 107, 'KING HENRY', 'That being dead, like to the bullet’s grazing,'), ('henry_v_act4_scene3', 106, 108, 'KING HENRY', 'Break out into a second course of mischief,'), ('henry_v_act4_scene3', 107, 109, 'KING HENRY', 'Killing in relapse of mortality.'), ('henry_v_act4_scene3', 108, 110, 'KING HENRY', 'Let me speak proudly: tell the constable'), ('henry_v_act4_scene3', 109, 111, 'KING HENRY', 'We are but warriors for the working-day;'), ('henry_v_act4_scene3', 110, 112, 'KING HENRY', 'Our gayness and our gilt are all besmirch’d'), ('henry_v_act4_scene3', 111, 113, 'KING HENRY', 'With rainy marching in the painful field;'), ('henry_v_act4_scene3', 112, 114, 'KING HENRY', 'There’s not a piece of feather in our host—'), ('henry_v_act4_scene3', 113, 115, 'KING HENRY', 'Good argument, I hope, we will not fly—'), ('henry_v_act4_scene3', 114, 116, 'KING HENRY', 'And time hath worn us into slovenry:'), ('henry_v_act4_scene3', 115, 117, 'KING HENRY', 'But, by the mass, our hearts are in the trim;'), ('henry_v_act4_scene3', 116, 118, 'KING HENRY', 'And my poor soldiers tell me, yet ere night'), ('henry_v_act4_scene3', 117, 119, 'KING HENRY', 'They’ll be in fresher robes, or they will pluck'), ('henry_v_act4_scene3', 118, 120, 'KING HENRY', 'The gay new coats o’er the French soldiers’ heads'), ('henry_v_act4_scene3', 119, 121, 'KING HENRY', 'And turn them out of service. If they do this—'), ('henry_v_act4_scene3', 120, 122, 'KING HENRY', 'As, if God please, they shall—my ransom then'), ('henry_v_act4_scene3', 121, 123, 'KING HENRY', 'Will soon be levied. Herald, save thou thy labour;'), ('henry_v_act4_scene3', 122, 124, 'KING HENRY', 'Come thou no more for ransom, gentle herald:'), ('henry_v_act4_scene3', 123, 125, 'KING HENRY', 'They shall have none, I swear, but these my joints;'), ('henry_v_act4_scene3', 124, 126, 'KING HENRY', 'Which if they have as I will leave ’em them,'), ('henry_v_act4_scene3', 125, 127, 'KING HENRY', 'Shall yield them little, tell the constable.'), ('henry_v_act4_scene3', 126, 128, 'MONTJOY', 'I shall, King Harry. And so fare thee well:'), ('henry_v_act4_scene3', 127, 129, 'MONTJOY', 'Thou never shalt hear herald any more.'), ('henry_v_act4_scene3', 128, 130, 'KING HENRY', 'I fear thou’lt once more come again for ransom.'), ('henry_v_act4_scene3', 129, 131, 'YORK', 'My lord, most humbly on my knee I beg'), ('henry_v_act4_scene3', 130, 132, 'YORK', 'The leading of the vaward.'), ('henry_v_act4_scene3', 131, 133, 'KING HENRY', 'Take it, brave York. Now, soldiers, march away:'), ('henry_v_act4_scene3', 132, 134, 'KING HENRY', 'And how thou pleasest, God, dispose the day!');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene4', 1, 0, 'PISTOL', 'Yield, cur!'), ('henry_v_act4_scene4', 2, 1, 'FRENCH SOLDIER', 'Je pense que vous êtes le gentilhomme de bonne qualité.'), ('henry_v_act4_scene4', 3, 2, 'PISTOL', 'Qualité calmie custore me! Art thou a gentleman? What is thy name? Discuss.'), ('henry_v_act4_scene4', 4, 3, 'FRENCH SOLDIER', 'O Seigneur Dieu!'), ('henry_v_act4_scene4', 5, 4, 'PISTOL', 'O, Signieur Dew should be a gentleman:'), ('henry_v_act4_scene4', 6, 5, 'PISTOL', 'Perpend my words, O Signieur Dew, and mark;'), ('henry_v_act4_scene4', 7, 6, 'PISTOL', 'O Signieur Dew, thou diest on point of fox,'), ('henry_v_act4_scene4', 8, 7, 'PISTOL', 'Except, O signieur, thou do give to me'), ('henry_v_act4_scene4', 9, 8, 'PISTOL', 'Egregious ransom.'), ('henry_v_act4_scene4', 10, 9, 'FRENCH SOLDIER', 'O, prenez miséricorde! ayez pitié de moi!'), ('henry_v_act4_scene4', 11, 10, 'PISTOL', 'Moy shall not serve; I will have forty moys;'), ('henry_v_act4_scene4', 12, 11, 'PISTOL', 'Or I will fetch thy rim out at thy throat'), ('henry_v_act4_scene4', 13, 12, 'PISTOL', 'In drops of crimson blood.'), ('henry_v_act4_scene4', 14, 13, 'FRENCH SOLDIER', 'Est-il impossible d’échapper la force de ton bras?'), ('henry_v_act4_scene4', 15, 14, 'PISTOL', 'Brass, cur!'), ('henry_v_act4_scene4', 16, 15, 'PISTOL', 'Thou damned and luxurious mountain goat,'), ('henry_v_act4_scene4', 17, 16, 'PISTOL', 'Offer’st me brass?'), ('henry_v_act4_scene4', 17, 17, 'FRENCH SOLDIER', 'O pardonnez-moi!'), ('henry_v_act4_scene4', 18, 18, 'PISTOL', 'Say’st thou me so? is that a ton of moys?'), ('henry_v_act4_scene4', 19, 19, 'PISTOL', 'Come hither, boy: ask me this slave in French'), ('henry_v_act4_scene4', 20, 20, 'PISTOL', 'What is his name.'), ('henry_v_act4_scene4', 20, 21, 'BOY', 'Écoutez: comment êtes-vous appelé?'), ('henry_v_act4_scene4', 21, 22, 'FRENCH SOLDIER', 'Monsieur le Fer.'), ('henry_v_act4_scene4', 22, 23, 'BOY', 'He says his name is Master Fer.'), ('henry_v_act4_scene4', 23, 24, 'PISTOL', 'Master Fer! I’ll fer him, and firk him, and ferret him: discuss'), ('henry_v_act4_scene4', 24, 25, 'PISTOL', 'the same in French unto him.'), ('henry_v_act4_scene4', 25, 26, 'BOY', 'I do not know the French for fer, and ferret, and firk.'), ('henry_v_act4_scene4', 26, 27, 'PISTOL', 'Bid him prepare; for I will cut his throat.'), ('henry_v_act4_scene4', 27, 28, 'FRENCH SOLDIER', 'Que dit-il, monsieur?'), ('henry_v_act4_scene4', 28, 29, 'BOY', 'Il me commande de vous dire que vous faites vous prêt; car'), ('henry_v_act4_scene4', 29, 30, 'BOY', 'ce soldat ici est disposé tout à cette heure de couper votre'), ('henry_v_act4_scene4', 30, 31, 'BOY', 'gorge.'), ('henry_v_act4_scene4', 30, 32, 'PISTOL', 'Owy, cuppele gorge, permafoy,'), ('henry_v_act4_scene4', 31, 33, 'PISTOL', 'Peasant, unless thou give me crowns, brave crowns;'), ('henry_v_act4_scene4', 32, 34, 'PISTOL', 'Or mangled shalt thou be by this my sword.'), ('henry_v_act4_scene4', 33, 35, 'FRENCH SOLDIER', 'O, je vous supplie, pour l’amour de Dieu, me pardonner! Je suis'), ('henry_v_act4_scene4', 34, 36, 'FRENCH SOLDIER', 'le gentilhomme de bonne maison: gardez ma vie, et je vous donnerai'), ('henry_v_act4_scene4', 35, 37, 'FRENCH SOLDIER', 'deux cents écus.'), ('henry_v_act4_scene4', 35, 38, 'PISTOL', 'What are his words?'), ('henry_v_act4_scene4', 36, 39, 'BOY', 'He prays you to save his life: he is a gentleman of'), ('henry_v_act4_scene4', 37, 40, 'BOY', 'a good house; and for his ransom he will give you two'), ('henry_v_act4_scene4', 38, 41, 'BOY', 'hundred crowns.'), ('henry_v_act4_scene4', 39, 42, 'PISTOL', 'Tell him my fury shall abate, and I'), ('henry_v_act4_scene4', 40, 43, 'PISTOL', 'The crowns will take.'), ('henry_v_act4_scene4', 40, 44, 'FRENCH SOLDIER', 'Petit monsieur, que dit-il?'), ('henry_v_act4_scene4', 41, 45, 'BOY', 'Encore qu’il est contre son jurement de pardonner aucun prisonnier, néanmoins, pour'), ('henry_v_act4_scene4', 42, 46, 'BOY', 'les écus que vous l’avez promis, il est content de vous donner'), ('henry_v_act4_scene4', 43, 47, 'BOY', 'la liberté, le franchisement.'), ('henry_v_act4_scene4', 44, 48, 'FRENCH SOLDIER', 'Sur mes genoux je vous donne mille remercîments; et je m’estime heureux'), ('henry_v_act4_scene4', 45, 49, 'FRENCH SOLDIER', 'que je suis tombé entre les mains d’un chevalier, je pense, le'), ('henry_v_act4_scene4', 46, 50, 'FRENCH SOLDIER', 'plus brave, vaillant, et très distingué seigneur d’Angleterre.'), ('henry_v_act4_scene4', 47, 51, 'PISTOL', 'Expound unto me, boy.'), ('henry_v_act4_scene4', 48, 52, 'BOY', 'He gives you, upon his knees, a thousand thanks; and he esteems'), ('henry_v_act4_scene4', 49, 53, 'BOY', 'himself happy that he hath fallen into the hands of one, as'), ('henry_v_act4_scene4', 50, 54, 'BOY', 'he thinks, the most brave, valorous, and thrice-worthy seigneur of England.'), ('henry_v_act4_scene4', 51, 55, 'PISTOL', 'As I suck blood, I will some mercy show. Follow me!'), ('henry_v_act4_scene4', 52, 56, 'BOY', 'Suivez-vous le grand capitaine. I did never know so full a voice'), ('henry_v_act4_scene4', 53, 57, 'BOY', 'issue from so empty a heart: but the saying is true, “The'), ('henry_v_act4_scene4', 54, 58, 'BOY', 'empty vessel makes the greatest sound.” Bardolph and Nym had ten times'), ('henry_v_act4_scene4', 55, 59, 'BOY', 'more valour than this roaring devil i’ the old play, that everyone'), ('henry_v_act4_scene4', 56, 60, 'BOY', 'may pare his nails with a wooden dagger; and they are both'), ('henry_v_act4_scene4', 57, 61, 'BOY', 'hanged; and so would this be, if he durst steal anything adventurously.'), ('henry_v_act4_scene4', 58, 62, 'BOY', 'I must stay with the lackeys, with the luggage of our camp:'), ('henry_v_act4_scene4', 59, 63, 'BOY', 'the French might have a good prey of us, if he knew'), ('henry_v_act4_scene4', 60, 64, 'BOY', 'of it; for there is none to guard it but boys.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene5', 1, 0, 'CONSTABLE', 'O diable!'), ('henry_v_act4_scene5', 2, 1, 'ORLEANS', 'O seigneur! le jour est perdu, tout est perdu!'), ('henry_v_act4_scene5', 3, 2, 'DAUPHIN', 'Mort de ma vie! all is confounded, all!'), ('henry_v_act4_scene5', 4, 3, 'DAUPHIN', 'Reproach and everlasting shame'), ('henry_v_act4_scene5', 5, 4, 'DAUPHIN', 'Sits mocking in our plumes. O méchante fortune!'), ('henry_v_act4_scene5', 6, 5, 'DAUPHIN', 'Do not run away. A short alarum.'), ('henry_v_act4_scene5', 7, 6, 'CONSTABLE', 'Why, all our ranks are broke.'), ('henry_v_act4_scene5', 7, 7, 'DAUPHIN', 'O perdurable shame! let’s stab ourselves.'), ('henry_v_act4_scene5', 8, 8, 'DAUPHIN', 'Be these the wretches that we play’d at dice for?'), ('henry_v_act4_scene5', 9, 9, 'ORLEANS', 'Is this the king we sent to for his ransom?'), ('henry_v_act4_scene5', 10, 10, 'BOURBON', 'Shame and eternal shame, nothing but shame!'), ('henry_v_act4_scene5', 11, 11, 'BOURBON', 'Let’s die in honour: once more back again;'), ('henry_v_act4_scene5', 12, 12, 'BOURBON', 'And he that will not follow Bourbon now,'), ('henry_v_act4_scene5', 13, 13, 'BOURBON', 'Let him go hence, and with his cap in hand,'), ('henry_v_act4_scene5', 14, 14, 'BOURBON', 'Like a base pandar, hold the chamber-door'), ('henry_v_act4_scene5', 15, 15, 'BOURBON', 'Whilst by a slave, no gentler than my dog,'), ('henry_v_act4_scene5', 16, 16, 'BOURBON', 'His fairest daughter is contaminated.'), ('henry_v_act4_scene5', 17, 17, 'CONSTABLE', 'Disorder, that hath spoil’d us, friend us now!'), ('henry_v_act4_scene5', 18, 18, 'CONSTABLE', 'Let us on heaps go offer up our lives.'), ('henry_v_act4_scene5', 19, 19, 'ORLEANS', 'We are enough yet living in the field'), ('henry_v_act4_scene5', 20, 20, 'ORLEANS', 'To smother up the English in our throngs,'), ('henry_v_act4_scene5', 21, 21, 'ORLEANS', 'If any order might be thought upon.'), ('henry_v_act4_scene5', 22, 22, 'BOURBON', 'The devil take order now! I’ll to the throng;'), ('henry_v_act4_scene5', 23, 23, 'BOURBON', 'Let life be short; else shame will be too long.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene6', 1, 0, 'KING HENRY', 'Well have we done, thrice valiant countrymen:'), ('henry_v_act4_scene6', 2, 1, 'KING HENRY', 'But all’s not done; yet keep the French the field.'), ('henry_v_act4_scene6', 3, 2, 'EXETER', 'The Duke of York commends him to your majesty.'), ('henry_v_act4_scene6', 4, 3, 'KING HENRY', 'Lives he, good uncle? thrice within this hour'), ('henry_v_act4_scene6', 5, 4, 'KING HENRY', 'I saw him down; thrice up again, and fighting;'), ('henry_v_act4_scene6', 6, 5, 'KING HENRY', 'From helmet to the spur all blood he was.'), ('henry_v_act4_scene6', 7, 6, 'EXETER', 'In which array, brave soldier, doth he lie,'), ('henry_v_act4_scene6', 8, 7, 'EXETER', 'Larding the plain; and by his bloody side,'), ('henry_v_act4_scene6', 9, 8, 'EXETER', 'Yoke-fellow to his honour-owing wounds,'), ('henry_v_act4_scene6', 10, 9, 'EXETER', 'The noble Earl of Suffolk also lies.'), ('henry_v_act4_scene6', 11, 10, 'EXETER', 'Suffolk first died: and York, all haggled over,'), ('henry_v_act4_scene6', 12, 11, 'EXETER', 'Comes to him, where in gore he lay insteep’d,'), ('henry_v_act4_scene6', 13, 12, 'EXETER', 'And takes him by the beard; kisses the gashes'), ('henry_v_act4_scene6', 14, 13, 'EXETER', 'That bloodily did yawn upon his face;'), ('henry_v_act4_scene6', 15, 14, 'EXETER', 'He cries aloud “Tarry, my cousin Suffolk!'), ('henry_v_act4_scene6', 16, 15, 'EXETER', 'My soul shall thine keep company to heaven;'), ('henry_v_act4_scene6', 17, 16, 'EXETER', 'Tarry, sweet soul, for mine, then fly abreast,'), ('henry_v_act4_scene6', 18, 17, 'EXETER', 'As in this glorious and well-foughten field'), ('henry_v_act4_scene6', 19, 18, 'EXETER', 'We kept together in our chivalry!”'), ('henry_v_act4_scene6', 20, 19, 'EXETER', 'Upon these words I came and cheer’d him up:'), ('henry_v_act4_scene6', 21, 20, 'EXETER', 'He smiled me in the face, raught me his hand,'), ('henry_v_act4_scene6', 22, 21, 'EXETER', 'And, with a feeble gripe, says, “Dear my lord,'), ('henry_v_act4_scene6', 23, 22, 'EXETER', 'Commend my service to my sovereign.”'), ('henry_v_act4_scene6', 24, 23, 'EXETER', 'So did he turn and over Suffolk’s neck'), ('henry_v_act4_scene6', 25, 24, 'EXETER', 'He threw his wounded arm and kiss’d his lips;'), ('henry_v_act4_scene6', 26, 25, 'EXETER', 'And so espoused to death, with blood he seal’d'), ('henry_v_act4_scene6', 27, 26, 'EXETER', 'A testament of noble-ending love.'), ('henry_v_act4_scene6', 28, 27, 'EXETER', 'The pretty and sweet manner of it forced'), ('henry_v_act4_scene6', 29, 28, 'EXETER', 'Those waters from me which I would have stopp’d;'), ('henry_v_act4_scene6', 30, 29, 'EXETER', 'But I had not so much of man in me,'), ('henry_v_act4_scene6', 31, 30, 'EXETER', 'And all my mother came into mine eyes'), ('henry_v_act4_scene6', 32, 31, 'EXETER', 'And gave me up to tears.'), ('henry_v_act4_scene6', 32, 32, 'KING HENRY', 'I blame you not;'), ('henry_v_act4_scene6', 33, 33, 'KING HENRY', 'For, hearing this, I must perforce compound'), ('henry_v_act4_scene6', 34, 34, 'KING HENRY', 'With mistful eyes, or they will issue too. Alarm.'), ('henry_v_act4_scene6', 35, 35, 'KING HENRY', 'But hark! what new alarum is this same?'), ('henry_v_act4_scene6', 36, 36, 'KING HENRY', 'The French have reinforced their scatter’d men:'), ('henry_v_act4_scene6', 37, 37, 'KING HENRY', 'Then every soldier kill his prisoners;'), ('henry_v_act4_scene6', 38, 38, 'KING HENRY', 'Give the word through.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene7', 1, 0, 'FLUELLEN', 'Kill the poys and the luggage! ’tis expressly against the law of'), ('henry_v_act4_scene7', 2, 1, 'FLUELLEN', 'arms: ’tis as arrant a piece of knavery, mark you now, as'), ('henry_v_act4_scene7', 3, 2, 'FLUELLEN', 'can be offer’t; in your conscience, now, is it not?'), ('henry_v_act4_scene7', 4, 3, 'GOWER', '’Tis certain there’s not a boy left alive; and the cowardly rascals'), ('henry_v_act4_scene7', 5, 4, 'GOWER', 'that ran from the battle ha’ done this slaughter: besides, they have'), ('henry_v_act4_scene7', 6, 5, 'GOWER', 'burned and carried away all that was in the king’s tent; wherefore'), ('henry_v_act4_scene7', 7, 6, 'GOWER', 'the king, most worthily, hath caused every soldier to cut his prisoner’s'), ('henry_v_act4_scene7', 8, 7, 'GOWER', 'throat. O, ’tis a gallant king!'), ('henry_v_act4_scene7', 9, 8, 'FLUELLEN', 'Ay, he was porn at Monmouth, Captain Gower. What call you the'), ('henry_v_act4_scene7', 10, 9, 'FLUELLEN', 'town’s name where Alexander the Pig was born!'), ('henry_v_act4_scene7', 11, 10, 'GOWER', 'Alexander the Great.'), ('henry_v_act4_scene7', 12, 11, 'FLUELLEN', 'Why, I pray you, is not pig great? the pig, or the'), ('henry_v_act4_scene7', 13, 12, 'FLUELLEN', 'great, or the mighty, or the huge, or the magnanimous, are all'), ('henry_v_act4_scene7', 14, 13, 'FLUELLEN', 'one reckonings, save the phrase is a little variations.'), ('henry_v_act4_scene7', 15, 14, 'GOWER', 'I think Alexander the Great was born in Macedon: his father was'), ('henry_v_act4_scene7', 16, 15, 'GOWER', 'called Philip of Macedon, as I take it.'), ('henry_v_act4_scene7', 17, 16, 'FLUELLEN', 'I think it is in Macedon where Alexander is porn. I tell'), ('henry_v_act4_scene7', 18, 17, 'FLUELLEN', 'you, captain, if you look in the maps of the ’orld, I'), ('henry_v_act4_scene7', 19, 18, 'FLUELLEN', 'warrant you sall find, in the comparisons between Macedon and Monmouth, that'), ('henry_v_act4_scene7', 20, 19, 'FLUELLEN', 'the situations, look you, is both alike. There is a river in'), ('henry_v_act4_scene7', 21, 20, 'FLUELLEN', 'Macedon; and there is also moreover a river at Monmouth: it is'), ('henry_v_act4_scene7', 22, 21, 'FLUELLEN', 'called Wye at Monmouth; but it is out of my prains what'), ('henry_v_act4_scene7', 23, 22, 'FLUELLEN', 'is the name of the other river; but ’tis all one, ’tis'), ('henry_v_act4_scene7', 24, 23, 'FLUELLEN', 'alike as my fingers is to my fingers, and there is salmons'), ('henry_v_act4_scene7', 25, 24, 'FLUELLEN', 'in both. If you mark Alexander’s life well, Harry of Monmouth’s life'), ('henry_v_act4_scene7', 26, 25, 'FLUELLEN', 'is come after it indifferent well; for there is figures in all'), ('henry_v_act4_scene7', 27, 26, 'FLUELLEN', 'things. Alexander, God knows, and you know, in his rages, and his'), ('henry_v_act4_scene7', 28, 27, 'FLUELLEN', 'furies, and his wraths, and his cholers, and his moods, and his'), ('henry_v_act4_scene7', 29, 28, 'FLUELLEN', 'displeasures, and his indignations, and also being a little intoxicates in his'), ('henry_v_act4_scene7', 30, 29, 'FLUELLEN', 'prains, did, in his ales and his angers, look you, kill his'), ('henry_v_act4_scene7', 31, 30, 'FLUELLEN', 'best friend, Cleitus.'), ('henry_v_act4_scene7', 32, 31, 'GOWER', 'Our king is not like him in that: he never killed any of his friends.'), ('henry_v_act4_scene7', 33, 32, 'FLUELLEN', 'It is not well done, mark you now, to take the tales'), ('henry_v_act4_scene7', 34, 33, 'FLUELLEN', 'out of my mouth, ere it is made and finished. I speak'), ('henry_v_act4_scene7', 35, 34, 'FLUELLEN', 'but in the figures and comparisons of it: as Alexander killed his'), ('henry_v_act4_scene7', 36, 35, 'FLUELLEN', 'friend Cleitus, being in his ales and his cups; so also Harry'), ('henry_v_act4_scene7', 37, 36, 'FLUELLEN', 'Monmouth, being in his right wits and his good judgements, turned away'), ('henry_v_act4_scene7', 38, 37, 'FLUELLEN', 'the fat knight with the great belly doublet: he was full of'), ('henry_v_act4_scene7', 39, 38, 'FLUELLEN', 'jests, and gipes, and knaveries, and mocks; I have forgot his name.'), ('henry_v_act4_scene7', 40, 39, 'GOWER', 'Sir John Falstaff.'), ('henry_v_act4_scene7', 41, 40, 'FLUELLEN', 'That is he: I’ll tell you there is good men porn at Monmouth.'), ('henry_v_act4_scene7', 42, 41, 'GOWER', 'Here comes his majesty.'), ('henry_v_act4_scene7', 43, 42, 'KING HENRY', 'I was not angry since I came to France'), ('henry_v_act4_scene7', 44, 43, 'KING HENRY', 'Until this instant. Take a trumpet, herald;'), ('henry_v_act4_scene7', 45, 44, 'KING HENRY', 'Ride thou unto the horsemen on yond hill:'), ('henry_v_act4_scene7', 46, 45, 'KING HENRY', 'If they will fight with us, bid them come down,'), ('henry_v_act4_scene7', 47, 46, 'KING HENRY', 'Or void the field; they do offend our sight:'), ('henry_v_act4_scene7', 48, 47, 'KING HENRY', 'If they’ll do neither, we will come to them,'), ('henry_v_act4_scene7', 49, 48, 'KING HENRY', 'And make them skirr away, as swift as stones'), ('henry_v_act4_scene7', 50, 49, 'KING HENRY', 'Enforced from the old Assyrian slings:'), ('henry_v_act4_scene7', 51, 50, 'KING HENRY', 'Besides, we’ll cut the throats of those we have,'), ('henry_v_act4_scene7', 52, 51, 'KING HENRY', 'And not a man of them that we shall take'), ('henry_v_act4_scene7', 53, 52, 'KING HENRY', 'Shall taste our mercy. Go and tell them so.'), ('henry_v_act4_scene7', 54, 53, 'EXETER', 'Here comes the herald of the French, my liege.'), ('henry_v_act4_scene7', 55, 54, 'GLOUCESTER', 'His eyes are humbler than they used to be.'), ('henry_v_act4_scene7', 56, 55, 'KING HENRY', 'How now! what means this, herald? know’st thou not'), ('henry_v_act4_scene7', 57, 56, 'KING HENRY', 'That I have fined these bones of mine for ransom?'), ('henry_v_act4_scene7', 58, 57, 'KING HENRY', 'Comest thou again for ransom?'), ('henry_v_act4_scene7', 58, 58, 'MONTJOY', 'No, great king:'), ('henry_v_act4_scene7', 59, 59, 'MONTJOY', 'I come to thee for charitable license,'), ('henry_v_act4_scene7', 60, 60, 'MONTJOY', 'That we may wander o’er this bloody field'), ('henry_v_act4_scene7', 61, 61, 'MONTJOY', 'To book our dead, and then to bury them;'), ('henry_v_act4_scene7', 62, 62, 'MONTJOY', 'To sort our nobles from our common men.'), ('henry_v_act4_scene7', 63, 63, 'MONTJOY', 'For many of our princes—woe the while!—'), ('henry_v_act4_scene7', 64, 64, 'MONTJOY', 'Lie drown’d and soak’d in mercenary blood;'), ('henry_v_act4_scene7', 65, 65, 'MONTJOY', 'So do our vulgar drench their peasant limbs'), ('henry_v_act4_scene7', 66, 66, 'MONTJOY', 'In blood of princes; and their wounded steeds'), ('henry_v_act4_scene7', 67, 67, 'MONTJOY', 'Fret fetlock deep in gore and with wild rage'), ('henry_v_act4_scene7', 68, 68, 'MONTJOY', 'Yerk out their armed heels at their dead masters,'), ('henry_v_act4_scene7', 69, 69, 'MONTJOY', 'Killing them twice. O, give us leave, great king,'), ('henry_v_act4_scene7', 70, 70, 'MONTJOY', 'To view the field in safety and dispose'), ('henry_v_act4_scene7', 71, 71, 'MONTJOY', 'Of their dead bodies!'), ('henry_v_act4_scene7', 71, 72, 'KING HENRY', 'I tell thee truly, herald,'), ('henry_v_act4_scene7', 72, 73, 'KING HENRY', 'I know not if the day be ours or no;'), ('henry_v_act4_scene7', 73, 74, 'KING HENRY', 'For yet a many of your horsemen peer'), ('henry_v_act4_scene7', 74, 75, 'KING HENRY', 'And gallop o’er the field.'), ('henry_v_act4_scene7', 74, 76, 'MONTJOY', 'The day is yours.'), ('henry_v_act4_scene7', 75, 77, 'KING HENRY', 'Praised be God, and not our strength, for it!'), ('henry_v_act4_scene7', 76, 78, 'KING HENRY', 'What is this castle call’d that stands hard by?'), ('henry_v_act4_scene7', 77, 79, 'MONTJOY', 'They call it Agincourt.'), ('henry_v_act4_scene7', 78, 80, 'KING HENRY', 'Then call we this the field of Agincourt.'), ('henry_v_act4_scene7', 79, 81, 'KING HENRY', 'Fought on the day of Crispin Crispianus.'), ('henry_v_act4_scene7', 80, 82, 'FLUELLEN', 'Your grandfather of famous memory, an’t please your majesty, and your great-uncle'), ('henry_v_act4_scene7', 81, 83, 'FLUELLEN', 'Edward the Plack Prince of Wales, as I have read in the'), ('henry_v_act4_scene7', 82, 84, 'FLUELLEN', 'chronicles, fought a most prave pattle here in France.'), ('henry_v_act4_scene7', 83, 85, 'KING HENRY', 'They did, Fluellen.'), ('henry_v_act4_scene7', 84, 86, 'FLUELLEN', 'Your majesty says very true: if your majesties is remembered of it,'), ('henry_v_act4_scene7', 85, 87, 'FLUELLEN', 'the Welshmen did good service in garden where leeks did grow, wearing'), ('henry_v_act4_scene7', 86, 88, 'FLUELLEN', 'leeks in their Monmouth caps; which, your majesty know, to this hour'), ('henry_v_act4_scene7', 87, 89, 'FLUELLEN', 'is an honourable badge of the service; and I do believe your'), ('henry_v_act4_scene7', 88, 90, 'FLUELLEN', 'majesty takes no scorn to wear the leek upon Saint Tavy’s day.'), ('henry_v_act4_scene7', 89, 91, 'KING HENRY', 'I wear it for a memorable honour;'), ('henry_v_act4_scene7', 90, 92, 'KING HENRY', 'For I am Welsh, you know, good countryman.'), ('henry_v_act4_scene7', 91, 93, 'FLUELLEN', 'All the water in Wye cannot wash your majesty’s Welsh plood out'), ('henry_v_act4_scene7', 92, 94, 'FLUELLEN', 'of your pody, I can tell you that: Got pless it and'), ('henry_v_act4_scene7', 93, 95, 'FLUELLEN', 'preserve it, as long as it pleases his grace, and his majesty'), ('henry_v_act4_scene7', 94, 96, 'FLUELLEN', 'too!'), ('henry_v_act4_scene7', 94, 97, 'KING HENRY', 'Thanks, good my countryman.'), ('henry_v_act4_scene7', 95, 98, 'FLUELLEN', 'By Jeshu, I am your majesty’s countryman, I care not who know'), ('henry_v_act4_scene7', 96, 99, 'FLUELLEN', 'it; I will confess it to all the ’orld: I need not');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene7', 97, 100, 'FLUELLEN', 'be ashamed of your majesty, praised be God, so long as your'), ('henry_v_act4_scene7', 98, 101, 'FLUELLEN', 'majesty is an honest man.'), ('henry_v_act4_scene7', 99, 102, 'KING HENRY', 'God keep me so! Our heralds go with him:'), ('henry_v_act4_scene7', 100, 103, 'KING HENRY', 'Bring me just notice of the numbers dead'), ('henry_v_act4_scene7', 101, 104, 'KING HENRY', 'On both our parts. Call yonder fellow hither.'), ('henry_v_act4_scene7', 102, 105, 'EXETER', 'Soldier, you must come to the king.'), ('henry_v_act4_scene7', 103, 106, 'KING HENRY', 'Soldier, why wearest thou that glove in thy cap?'), ('henry_v_act4_scene7', 104, 107, 'WILLIAMS', 'An’t please your majesty, ’tis the gage of one that I should'), ('henry_v_act4_scene7', 105, 108, 'WILLIAMS', 'fight withal, if he be alive.'), ('henry_v_act4_scene7', 105, 109, 'KING HENRY', 'An Englishman?'), ('henry_v_act4_scene7', 106, 110, 'WILLIAMS', 'An’t please your majesty, a rascal that swaggered with me last night;'), ('henry_v_act4_scene7', 107, 111, 'WILLIAMS', 'who, if alive and ever dare to challenge this glove, I have'), ('henry_v_act4_scene7', 108, 112, 'WILLIAMS', 'sworn to take him a box o’ th’ ear: or if I'), ('henry_v_act4_scene7', 109, 113, 'WILLIAMS', 'can see my glove in his cap, which he swore, as he'), ('henry_v_act4_scene7', 110, 114, 'WILLIAMS', 'was a soldier, he would wear if alive, I will strike it'), ('henry_v_act4_scene7', 111, 115, 'WILLIAMS', 'out soundly.'), ('henry_v_act4_scene7', 112, 116, 'KING HENRY', 'What think you, Captain Fluellen? is it fit this soldier keep his oath?'), ('henry_v_act4_scene7', 113, 117, 'FLUELLEN', 'He is a craven and a villain else, an’t please your majesty, in my conscience.'), ('henry_v_act4_scene7', 114, 118, 'KING HENRY', 'It may be his enemy is a gentlemen of great sort, quite'), ('henry_v_act4_scene7', 115, 119, 'KING HENRY', 'from the answer of his degree.'), ('henry_v_act4_scene7', 116, 120, 'FLUELLEN', 'Though he be as good a gentleman as the devil is, as'), ('henry_v_act4_scene7', 117, 121, 'FLUELLEN', 'Lucifier and Belzebub himself, it is necessary, look your grace, that he'), ('henry_v_act4_scene7', 118, 122, 'FLUELLEN', 'keep his vow and his oath: if he be perjured, see you'), ('henry_v_act4_scene7', 119, 123, 'FLUELLEN', 'now, his reputation is as arrant a villain and a Jacksauce, as'), ('henry_v_act4_scene7', 120, 124, 'FLUELLEN', 'ever his black shoe trod upon God’s ground and his earth, in'), ('henry_v_act4_scene7', 121, 125, 'FLUELLEN', 'my conscience, la!'), ('henry_v_act4_scene7', 122, 126, 'KING HENRY', 'Then keep thy vow, sirrah, when thou meetest the fellow.'), ('henry_v_act4_scene7', 123, 127, 'WILLIAMS', 'So I will, my liege, as I live.'), ('henry_v_act4_scene7', 124, 128, 'KING HENRY', 'Who servest thou under?'), ('henry_v_act4_scene7', 124, 129, 'WILLIAMS', 'Under Captain Gower, my liege.'), ('henry_v_act4_scene7', 125, 130, 'FLUELLEN', 'Gower is a good captain, and is good knowledge and literatured in the wars.'), ('henry_v_act4_scene7', 126, 131, 'KING HENRY', 'Call him hither to me, soldier.'), ('henry_v_act4_scene7', 126, 132, 'WILLIAMS', 'I will, my liege.'), ('henry_v_act4_scene7', 127, 133, 'KING HENRY', 'Here, Fluellen; wear thou this favour for me and stick it in'), ('henry_v_act4_scene7', 128, 134, 'KING HENRY', 'thy cap: when Alençon and myself were down together, I plucked this'), ('henry_v_act4_scene7', 129, 135, 'KING HENRY', 'glove from his helm: if any man challenge this, he is a'), ('henry_v_act4_scene7', 130, 136, 'KING HENRY', 'friend to Alençon, and an enemy to our person; if thou encounter'), ('henry_v_act4_scene7', 131, 137, 'KING HENRY', 'any such, apprehend him, an thou dost me love.'), ('henry_v_act4_scene7', 132, 138, 'FLUELLEN', 'Your grace doo’s me as great honours as can be desired in'), ('henry_v_act4_scene7', 133, 139, 'FLUELLEN', 'the hearts of his subjects: I would fain see the man, that'), ('henry_v_act4_scene7', 134, 140, 'FLUELLEN', 'has but two legs, that shall find himself aggriefed at this glove;'), ('henry_v_act4_scene7', 135, 141, 'FLUELLEN', 'that is all; but I would fain see it once, an please'), ('henry_v_act4_scene7', 136, 142, 'FLUELLEN', 'God of his grace that I might see.'), ('henry_v_act4_scene7', 137, 143, 'KING HENRY', 'Knowest thou Gower?'), ('henry_v_act4_scene7', 138, 144, 'FLUELLEN', 'He is my dear friend, an please you.'), ('henry_v_act4_scene7', 139, 145, 'KING HENRY', 'Pray thee, go seek him, and bring him to my tent.'), ('henry_v_act4_scene7', 140, 146, 'FLUELLEN', 'I will fetch him.'), ('henry_v_act4_scene7', 141, 147, 'KING HENRY', 'My Lord of Warwick, and my brother Gloucester,'), ('henry_v_act4_scene7', 142, 148, 'KING HENRY', 'Follow Fluellen closely at the heels:'), ('henry_v_act4_scene7', 143, 149, 'KING HENRY', 'The glove which I have given him for a favour'), ('henry_v_act4_scene7', 144, 150, 'KING HENRY', 'May haply purchase him a box o’ th’ ear;'), ('henry_v_act4_scene7', 145, 151, 'KING HENRY', 'It is the soldier’s; I by bargain should'), ('henry_v_act4_scene7', 146, 152, 'KING HENRY', 'Wear it myself. Follow, good cousin Warwick:'), ('henry_v_act4_scene7', 147, 153, 'KING HENRY', 'If that the soldier strike him, as I judge'), ('henry_v_act4_scene7', 148, 154, 'KING HENRY', 'By his blunt bearing he will keep his word,'), ('henry_v_act4_scene7', 149, 155, 'KING HENRY', 'Some sudden mischief may arise of it;'), ('henry_v_act4_scene7', 150, 156, 'KING HENRY', 'For I do know Fluellen valiant'), ('henry_v_act4_scene7', 151, 157, 'KING HENRY', 'And, touch’d with choler, hot as gunpowder,'), ('henry_v_act4_scene7', 152, 158, 'KING HENRY', 'And quickly will return an injury:'), ('henry_v_act4_scene7', 153, 159, 'KING HENRY', 'Follow, and see there be no harm between them.'), ('henry_v_act4_scene7', 154, 160, 'KING HENRY', 'Go you with me, uncle of Exeter.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene8', 1, 0, 'WILLIAMS', 'I warrant it is to knight you, captain.'), ('henry_v_act4_scene8', 2, 1, 'FLUELLEN', 'God’s will and his pleasure, captain, I beseech you now, come apace'), ('henry_v_act4_scene8', 3, 2, 'FLUELLEN', 'to the King. There is more good toward you peradventure than is'), ('henry_v_act4_scene8', 4, 3, 'FLUELLEN', 'in your knowledge to dream of.'), ('henry_v_act4_scene8', 4, 4, 'WILLIAMS', 'Sir, know you this glove?'), ('henry_v_act4_scene8', 5, 5, 'FLUELLEN', 'Know the glove! I know the glove is a glove.'), ('henry_v_act4_scene8', 6, 6, 'WILLIAMS', 'I know this; and thus I challenge it.'), ('henry_v_act4_scene8', 7, 7, 'FLUELLEN', '’Sblood! an arrant traitor as any is in the universal world, or'), ('henry_v_act4_scene8', 8, 8, 'FLUELLEN', 'in France, or in England!'), ('henry_v_act4_scene8', 8, 9, 'GOWER', 'How now, sir! you villain!'), ('henry_v_act4_scene8', 9, 10, 'WILLIAMS', 'Do you think I’ll be forsworn?'), ('henry_v_act4_scene8', 10, 11, 'FLUELLEN', 'Stand away, Captain Gower; I will give treason his payment into plows, I warrant you.'), ('henry_v_act4_scene8', 11, 12, 'WILLIAMS', 'I am no traitor.'), ('henry_v_act4_scene8', 12, 13, 'FLUELLEN', 'That’s a lie in thy throat. I charge you in his majesty’s'), ('henry_v_act4_scene8', 13, 14, 'FLUELLEN', 'name, apprehend him: he’s a friend of the Duke Alençon’s.'), ('henry_v_act4_scene8', 14, 15, 'WARWICK', 'How now, how now! what’s the matter?'), ('henry_v_act4_scene8', 15, 16, 'FLUELLEN', 'My lord of Warwick, here is—praised be God for it!—a most contagious'), ('henry_v_act4_scene8', 16, 17, 'FLUELLEN', 'treason come to light, look you, as you shall desire in a'), ('henry_v_act4_scene8', 17, 18, 'FLUELLEN', 'summer’s day. Here is his majesty.'), ('henry_v_act4_scene8', 17, 19, 'KING HENRY', 'How now! what’s the matter?'), ('henry_v_act4_scene8', 18, 20, 'FLUELLEN', 'My liege, here is a villain and a traitor, that, look your'), ('henry_v_act4_scene8', 19, 21, 'FLUELLEN', 'grace, has struck the glove which your majesty is take out of'), ('henry_v_act4_scene8', 20, 22, 'FLUELLEN', 'the helmet of Alençon.'), ('henry_v_act4_scene8', 21, 23, 'WILLIAMS', 'My liege, this was my glove; here is the fellow of it;'), ('henry_v_act4_scene8', 22, 24, 'WILLIAMS', 'and he that I gave it to in change promised to wear'), ('henry_v_act4_scene8', 23, 25, 'WILLIAMS', 'it in his cap: I promised to strike him, if he did:'), ('henry_v_act4_scene8', 24, 26, 'WILLIAMS', 'I met this man with my glove in his cap, and I'), ('henry_v_act4_scene8', 25, 27, 'WILLIAMS', 'have been as good as my word.'), ('henry_v_act4_scene8', 26, 28, 'FLUELLEN', 'Your majesty hear now, saving your majesty’s manhood, what an arrant, rascally,'), ('henry_v_act4_scene8', 27, 29, 'FLUELLEN', 'beggarly, lousy knave it is: I hope your majesty is pear me'), ('henry_v_act4_scene8', 28, 30, 'FLUELLEN', 'testimony and witness, and will avouchment, that this is the glove of'), ('henry_v_act4_scene8', 29, 31, 'FLUELLEN', 'Alençon, that your majesty is give me; in your conscience, now.'), ('henry_v_act4_scene8', 30, 32, 'KING HENRY', 'Give me thy glove, soldier: look, here is the fellow of it.'), ('henry_v_act4_scene8', 31, 33, 'KING HENRY', '’Twas I, indeed, thou promised’st to strike;'), ('henry_v_act4_scene8', 32, 34, 'KING HENRY', 'And thou hast given me most bitter terms.'), ('henry_v_act4_scene8', 33, 35, 'FLUELLEN', 'An it please your majesty, let his neck answer for it, if'), ('henry_v_act4_scene8', 34, 36, 'FLUELLEN', 'there is any martial law in the world.'), ('henry_v_act4_scene8', 35, 37, 'KING HENRY', 'How canst thou make me satisfaction?'), ('henry_v_act4_scene8', 36, 38, 'WILLIAMS', 'All offences, my lord, come from the heart: never came any from'), ('henry_v_act4_scene8', 37, 39, 'WILLIAMS', 'mine that might offend your majesty.'), ('henry_v_act4_scene8', 37, 40, 'KING HENRY', 'It was ourself thou didst abuse.'), ('henry_v_act4_scene8', 38, 41, 'WILLIAMS', 'Your majesty came not like yourself: you appeared to me but as'), ('henry_v_act4_scene8', 39, 42, 'WILLIAMS', 'a common man; witness the night, your garments, your lowliness; and what'), ('henry_v_act4_scene8', 40, 43, 'WILLIAMS', 'your highness suffered under that shape, I beseech you take it for'), ('henry_v_act4_scene8', 41, 44, 'WILLIAMS', 'your own fault and not mine: for had you been as I'), ('henry_v_act4_scene8', 42, 45, 'WILLIAMS', 'took you for, I made no offence; therefore, I beseech your highness,'), ('henry_v_act4_scene8', 43, 46, 'WILLIAMS', 'pardon me.'), ('henry_v_act4_scene8', 44, 47, 'KING HENRY', 'Here, uncle Exeter, fill this glove with crowns,'), ('henry_v_act4_scene8', 45, 48, 'KING HENRY', 'And give it to this fellow. Keep it, fellow;'), ('henry_v_act4_scene8', 46, 49, 'KING HENRY', 'And wear it for an honour in thy cap'), ('henry_v_act4_scene8', 47, 50, 'KING HENRY', 'Till I do challenge it. Give him his crowns:'), ('henry_v_act4_scene8', 48, 51, 'KING HENRY', 'And, captain, you must needs be friends with him.'), ('henry_v_act4_scene8', 49, 52, 'FLUELLEN', 'By this day and this light, the fellow has mettle enough in'), ('henry_v_act4_scene8', 50, 53, 'FLUELLEN', 'his belly. Hold, there is twelve pence for you; and I pray'), ('henry_v_act4_scene8', 51, 54, 'FLUELLEN', 'you to serve God, and keep you out of prawls, and prabbles,'), ('henry_v_act4_scene8', 52, 55, 'FLUELLEN', 'and quarrels, and dissensions, and, I warrant you, it is the better'), ('henry_v_act4_scene8', 53, 56, 'FLUELLEN', 'for you.'), ('henry_v_act4_scene8', 53, 57, 'WILLIAMS', 'I will none of your money.'), ('henry_v_act4_scene8', 54, 58, 'FLUELLEN', 'It is with a good will; I can tell you, it will'), ('henry_v_act4_scene8', 55, 59, 'FLUELLEN', 'serve you to mend your shoes: come, wherefore should you be so'), ('henry_v_act4_scene8', 56, 60, 'FLUELLEN', 'pashful? your shoes is not so good: ’tis a good silling, I'), ('henry_v_act4_scene8', 57, 61, 'FLUELLEN', 'warrant you, or I will change it.'), ('henry_v_act4_scene8', 58, 62, 'KING HENRY', 'Now, herald, are the dead number’d?'), ('henry_v_act4_scene8', 59, 63, 'HERALD', 'Here is the number of the slaughter’d French.'), ('henry_v_act4_scene8', 60, 64, 'KING HENRY', 'What prisoners of good sort are taken, uncle?'), ('henry_v_act4_scene8', 61, 65, 'EXETER', 'Charles Duke of Orleans, nephew to the king;'), ('henry_v_act4_scene8', 62, 66, 'EXETER', 'John Duke of Bourbon, and Lord Bouciqualt:'), ('henry_v_act4_scene8', 63, 67, 'EXETER', 'Of other lords and barons, knights and squires,'), ('henry_v_act4_scene8', 64, 68, 'EXETER', 'Full fifteen hundred, besides common men.'), ('henry_v_act4_scene8', 65, 69, 'KING HENRY', 'This note doth tell me of ten thousand French'), ('henry_v_act4_scene8', 66, 70, 'KING HENRY', 'That in the field lie slain: of princes, in this number,'), ('henry_v_act4_scene8', 67, 71, 'KING HENRY', 'And nobles bearing banners, there lie dead'), ('henry_v_act4_scene8', 68, 72, 'KING HENRY', 'One hundred twenty-six: added to these,'), ('henry_v_act4_scene8', 69, 73, 'KING HENRY', 'Of knights, esquires, and gallant gentlemen,'), ('henry_v_act4_scene8', 70, 74, 'KING HENRY', 'Eight thousand and four hundred; of the which,'), ('henry_v_act4_scene8', 71, 75, 'KING HENRY', 'Five hundred were but yesterday dubb’d knights:'), ('henry_v_act4_scene8', 72, 76, 'KING HENRY', 'So that, in these ten thousand they have lost,'), ('henry_v_act4_scene8', 73, 77, 'KING HENRY', 'There are but sixteen hundred mercenaries;'), ('henry_v_act4_scene8', 74, 78, 'KING HENRY', 'The rest are princes, barons, lords, knights, squires,'), ('henry_v_act4_scene8', 75, 79, 'KING HENRY', 'And gentlemen of blood and quality.'), ('henry_v_act4_scene8', 76, 80, 'KING HENRY', 'The names of those their nobles that lie dead:'), ('henry_v_act4_scene8', 77, 81, 'KING HENRY', 'Charles Delabreth, high constable of France;'), ('henry_v_act4_scene8', 78, 82, 'KING HENRY', 'Jacques of Chatillon, admiral of France;'), ('henry_v_act4_scene8', 79, 83, 'KING HENRY', 'The master of the crossbows, Lord Rambures;'), ('henry_v_act4_scene8', 80, 84, 'KING HENRY', 'Great Master of France, the brave Sir Guichard Dolphin,'), ('henry_v_act4_scene8', 81, 85, 'KING HENRY', 'John, Duke of Alençon, Anthony Duke of Brabant,'), ('henry_v_act4_scene8', 82, 86, 'KING HENRY', 'The brother to the Duke of Burgundy,'), ('henry_v_act4_scene8', 83, 87, 'KING HENRY', 'And Edward Duke of Bar: of lusty earls,'), ('henry_v_act4_scene8', 84, 88, 'KING HENRY', 'Grandpré and Roussi, Fauconberg and Foix,'), ('henry_v_act4_scene8', 85, 89, 'KING HENRY', 'Beaumont and Marle, Vaudemont and Lestrale.'), ('henry_v_act4_scene8', 86, 90, 'KING HENRY', 'Here was a royal fellowship of death!'), ('henry_v_act4_scene8', 87, 91, 'KING HENRY', 'Where is the number of our English dead? Herald shews him another paper.'), ('henry_v_act4_scene8', 88, 92, 'KING HENRY', 'Edward the Duke of York, the Earl of Suffolk,'), ('henry_v_act4_scene8', 89, 93, 'KING HENRY', 'Sir Richard Ketly, Davy Gam, esquire:'), ('henry_v_act4_scene8', 90, 94, 'KING HENRY', 'None else of name; and of all other men'), ('henry_v_act4_scene8', 91, 95, 'KING HENRY', 'But five and twenty. O God, thy arm was here;'), ('henry_v_act4_scene8', 92, 96, 'KING HENRY', 'And not to us, but to thy arm alone,'), ('henry_v_act4_scene8', 93, 97, 'KING HENRY', 'Ascribe we all! When, without stratagem,'), ('henry_v_act4_scene8', 94, 98, 'KING HENRY', 'But in plain shock and even play of battle,'), ('henry_v_act4_scene8', 95, 99, 'KING HENRY', 'Was ever known so great and little loss');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act4_scene8', 96, 100, 'KING HENRY', 'On one part and on the other? Take it, God,'), ('henry_v_act4_scene8', 97, 101, 'KING HENRY', 'For it is none but thine!'), ('henry_v_act4_scene8', 97, 102, 'EXETER', '’Tis wonderful!'), ('henry_v_act4_scene8', 98, 103, 'KING HENRY', 'Come, go we in procession to the village:'), ('henry_v_act4_scene8', 99, 104, 'KING HENRY', 'And be it death proclaimed through our host'), ('henry_v_act4_scene8', 100, 105, 'KING HENRY', 'To boast of this or take that praise from God'), ('henry_v_act4_scene8', 101, 106, 'KING HENRY', 'Which is his only.'), ('henry_v_act4_scene8', 102, 107, 'FLUELLEN', 'Is it not lawful, an please your majesty, to tell how many is killed?'), ('henry_v_act4_scene8', 103, 108, 'KING HENRY', 'Yes, captain; but with this acknowledgment,'), ('henry_v_act4_scene8', 104, 109, 'KING HENRY', 'That God fought for us.'), ('henry_v_act4_scene8', 105, 110, 'FLUELLEN', 'Yes, my conscience, he did us great good.'), ('henry_v_act4_scene8', 106, 111, 'KING HENRY', 'Do we all holy rites;'), ('henry_v_act4_scene8', 107, 112, 'KING HENRY', 'Let there be sung “Non nobis” and “Te Deum;”'), ('henry_v_act4_scene8', 108, 113, 'KING HENRY', 'The dead with charity enclosed in clay:'), ('henry_v_act4_scene8', 109, 114, 'KING HENRY', 'And then to Calais; and to England then;'), ('henry_v_act4_scene8', 110, 115, 'KING HENRY', 'Where ne’er from France arrived more happy men.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act5_chorus', 1, 0, 'CHORUS', 'Vouchsafe to those that have not read the story,'), ('henry_v_act5_chorus', 2, 1, 'CHORUS', 'That I may prompt them: and of such as have,'), ('henry_v_act5_chorus', 3, 2, 'CHORUS', 'I humbly pray them to admit the excuse'), ('henry_v_act5_chorus', 4, 3, 'CHORUS', 'Of time, of numbers and due course of things,'), ('henry_v_act5_chorus', 5, 4, 'CHORUS', 'Which cannot in their huge and proper life'), ('henry_v_act5_chorus', 6, 5, 'CHORUS', 'Be here presented. Now we bear the king'), ('henry_v_act5_chorus', 7, 6, 'CHORUS', 'Toward Calais: grant him there; there seen,'), ('henry_v_act5_chorus', 8, 7, 'CHORUS', 'Heave him away upon your winged thoughts'), ('henry_v_act5_chorus', 9, 8, 'CHORUS', 'Athwart the sea. Behold, the English beach'), ('henry_v_act5_chorus', 10, 9, 'CHORUS', 'Pales in the flood with men, with wives and boys,'), ('henry_v_act5_chorus', 11, 10, 'CHORUS', 'Whose shouts and claps out-voice the deep-mouth’d sea,'), ('henry_v_act5_chorus', 12, 11, 'CHORUS', 'Which like a mighty whiffler ’fore the king'), ('henry_v_act5_chorus', 13, 12, 'CHORUS', 'Seems to prepare his way: so let him land,'), ('henry_v_act5_chorus', 14, 13, 'CHORUS', 'And solemnly see him set on to London.'), ('henry_v_act5_chorus', 15, 14, 'CHORUS', 'So swift a pace hath thought that even now'), ('henry_v_act5_chorus', 16, 15, 'CHORUS', 'You may imagine him upon Blackheath;'), ('henry_v_act5_chorus', 17, 16, 'CHORUS', 'Where that his lords desire him to have borne'), ('henry_v_act5_chorus', 18, 17, 'CHORUS', 'His bruised helmet and his bended sword'), ('henry_v_act5_chorus', 19, 18, 'CHORUS', 'Before him through the city: he forbids it,'), ('henry_v_act5_chorus', 20, 19, 'CHORUS', 'Being free from vainness and self-glorious pride;'), ('henry_v_act5_chorus', 21, 20, 'CHORUS', 'Giving full trophy, signal and ostent'), ('henry_v_act5_chorus', 22, 21, 'CHORUS', 'Quite from himself to God. But now behold,'), ('henry_v_act5_chorus', 23, 22, 'CHORUS', 'In the quick forge and working-house of thought,'), ('henry_v_act5_chorus', 24, 23, 'CHORUS', 'How London doth pour out her citizens!'), ('henry_v_act5_chorus', 25, 24, 'CHORUS', 'The mayor and all his brethren in best sort,'), ('henry_v_act5_chorus', 26, 25, 'CHORUS', 'Like to the senators of the antique Rome,'), ('henry_v_act5_chorus', 27, 26, 'CHORUS', 'With the plebeians swarming at their heels,'), ('henry_v_act5_chorus', 28, 27, 'CHORUS', 'Go forth and fetch their conquering Caesar in:'), ('henry_v_act5_chorus', 29, 28, 'CHORUS', 'As, by a lower but loving likelihood,'), ('henry_v_act5_chorus', 30, 29, 'CHORUS', 'Were now the general of our gracious empress,'), ('henry_v_act5_chorus', 31, 30, 'CHORUS', 'As in good time he may, from Ireland coming,'), ('henry_v_act5_chorus', 32, 31, 'CHORUS', 'Bringing rebellion broached on his sword,'), ('henry_v_act5_chorus', 33, 32, 'CHORUS', 'How many would the peaceful city quit,'), ('henry_v_act5_chorus', 34, 33, 'CHORUS', 'To welcome him! much more, and much more cause,'), ('henry_v_act5_chorus', 35, 34, 'CHORUS', 'Did they this Harry. Now in London place him;'), ('henry_v_act5_chorus', 36, 35, 'CHORUS', 'As yet the lamentation of the French'), ('henry_v_act5_chorus', 37, 36, 'CHORUS', 'Invites the King of England’s stay at home;'), ('henry_v_act5_chorus', 38, 37, 'CHORUS', 'The emperor’s coming in behalf of France,'), ('henry_v_act5_chorus', 39, 38, 'CHORUS', 'To order peace between them; and omit'), ('henry_v_act5_chorus', 40, 39, 'CHORUS', 'All the occurrences, whatever chanced,'), ('henry_v_act5_chorus', 41, 40, 'CHORUS', 'Till Harry’s back-return again to France:'), ('henry_v_act5_chorus', 42, 41, 'CHORUS', 'There must we bring him; and myself have play’d'), ('henry_v_act5_chorus', 43, 42, 'CHORUS', 'The interim, by remembering you ’tis past.'), ('henry_v_act5_chorus', 44, 43, 'CHORUS', 'Then brook abridgement, and your eyes advance,'), ('henry_v_act5_chorus', 45, 44, 'CHORUS', 'After your thoughts, straight back again to France.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act5_scene1', 1, 0, 'GOWER', 'Nay, that’s right; but why wear you your leek today? Saint Davy’s day is past.'), ('henry_v_act5_scene1', 2, 1, 'FLUELLEN', 'There is occasions and causes why and wherefore in all things: I'), ('henry_v_act5_scene1', 3, 2, 'FLUELLEN', 'will tell you, asse my friend, Captain Gower: the rascally, scauld, beggarly,'), ('henry_v_act5_scene1', 4, 3, 'FLUELLEN', 'lousy, pragging knave, Pistol, which you and yourself and all the world'), ('henry_v_act5_scene1', 5, 4, 'FLUELLEN', 'know to be no petter than a fellow, look you now, of'), ('henry_v_act5_scene1', 6, 5, 'FLUELLEN', 'no merits, he is come to me and prings me pread and'), ('henry_v_act5_scene1', 7, 6, 'FLUELLEN', 'salt yesterday, look you, and bid me eat my leek: it was'), ('henry_v_act5_scene1', 8, 7, 'FLUELLEN', 'in a place where I could not breed no contention with him;'), ('henry_v_act5_scene1', 9, 8, 'FLUELLEN', 'but I will be so bold as to wear it in my'), ('henry_v_act5_scene1', 10, 9, 'FLUELLEN', 'cap till I see him once again, and then I will tell'), ('henry_v_act5_scene1', 11, 10, 'FLUELLEN', 'him a little piece of my desires.'), ('henry_v_act5_scene1', 12, 11, 'GOWER', 'Why, here he comes, swelling like a turkey-cock.'), ('henry_v_act5_scene1', 13, 12, 'FLUELLEN', '’Tis no matter for his swellings nor his turkey-cocks. God pless you,'), ('henry_v_act5_scene1', 14, 13, 'FLUELLEN', 'Aunchient Pistol! you scurvy, lousy knave, God pless you!'), ('henry_v_act5_scene1', 15, 14, 'PISTOL', 'Ha! art thou bedlam? dost thou thirst, base Trojan,'), ('henry_v_act5_scene1', 16, 15, 'PISTOL', 'To have me fold up Parca’s fatal web?'), ('henry_v_act5_scene1', 17, 16, 'PISTOL', 'Hence! I am qualmish at the smell of leek.'), ('henry_v_act5_scene1', 18, 17, 'FLUELLEN', 'I peseech you heartily, scurfy, lousy knave, at my desires, and my'), ('henry_v_act5_scene1', 19, 18, 'FLUELLEN', 'requests, and my petitions, to eat, look you, this leek: because, look'), ('henry_v_act5_scene1', 20, 19, 'FLUELLEN', 'you, you do not love it, nor your affections and your appetites'), ('henry_v_act5_scene1', 21, 20, 'FLUELLEN', 'and your digestions doo’s not agree with it, I would desire you'), ('henry_v_act5_scene1', 22, 21, 'FLUELLEN', 'to eat it.'), ('henry_v_act5_scene1', 23, 22, 'PISTOL', 'Not for Cadwallader and all his goats.'), ('henry_v_act5_scene1', 24, 23, 'FLUELLEN', 'There is one goat for you. Will you be so good, scauld'), ('henry_v_act5_scene1', 25, 24, 'FLUELLEN', 'knave, as eat it?'), ('henry_v_act5_scene1', 25, 25, 'PISTOL', 'Base Trojan, thou shalt die.'), ('henry_v_act5_scene1', 26, 26, 'FLUELLEN', 'You say very true, scauld knave, when God’s will is: I will'), ('henry_v_act5_scene1', 27, 27, 'FLUELLEN', 'desire you to live in the meantime, and eat your victuals: come,'), ('henry_v_act5_scene1', 28, 28, 'FLUELLEN', 'there is sauce for it. You called me yesterday mountain-squire; but I'), ('henry_v_act5_scene1', 29, 29, 'FLUELLEN', 'will make you today a squire of low degree. I pray you,'), ('henry_v_act5_scene1', 30, 30, 'FLUELLEN', 'fall to: if you can mock a leek, you can eat a'), ('henry_v_act5_scene1', 31, 31, 'FLUELLEN', 'leek.'), ('henry_v_act5_scene1', 31, 32, 'GOWER', 'Enough, captain: you have astonished him.'), ('henry_v_act5_scene1', 32, 33, 'FLUELLEN', 'I say, I will make him eat some part of my leek,'), ('henry_v_act5_scene1', 33, 34, 'FLUELLEN', 'or I will peat his pate four days. Bite, I pray you;'), ('henry_v_act5_scene1', 34, 35, 'FLUELLEN', 'it is good for your green wound and your ploody coxcomb.'), ('henry_v_act5_scene1', 35, 36, 'PISTOL', 'Must I bite?'), ('henry_v_act5_scene1', 36, 37, 'FLUELLEN', 'Yes, certainly, and out of doubt and out of question too, and ambiguities.'), ('henry_v_act5_scene1', 37, 38, 'PISTOL', 'By this leek, I will most horribly revenge: I eat and eat, I swear—'), ('henry_v_act5_scene1', 38, 39, 'FLUELLEN', 'Eat, I pray you: will you have some more sauce to your'), ('henry_v_act5_scene1', 39, 40, 'FLUELLEN', 'leek? there is not enough leek to swear by.'), ('henry_v_act5_scene1', 40, 41, 'PISTOL', 'Quiet thy cudgel; thou dost see I eat.'), ('henry_v_act5_scene1', 41, 42, 'FLUELLEN', 'Much good do you, scauld knave, heartily. Nay, pray you, throw none'), ('henry_v_act5_scene1', 42, 43, 'FLUELLEN', 'away; the skin is good for your broken coxcomb. When you take'), ('henry_v_act5_scene1', 43, 44, 'FLUELLEN', 'occasions to see leeks hereafter, I pray you, mock at ’em; that'), ('henry_v_act5_scene1', 44, 45, 'FLUELLEN', 'is all.'), ('henry_v_act5_scene1', 44, 46, 'PISTOL', 'Good.'), ('henry_v_act5_scene1', 45, 47, 'FLUELLEN', 'Ay, leeks is good: hold you, there is a groat to heal your pate.'), ('henry_v_act5_scene1', 46, 48, 'PISTOL', 'Me a groat!'), ('henry_v_act5_scene1', 47, 49, 'FLUELLEN', 'Yes, verily and in truth you, shall take it; or I have'), ('henry_v_act5_scene1', 48, 50, 'FLUELLEN', 'another leek in my pocket, which you shall eat.'), ('henry_v_act5_scene1', 49, 51, 'PISTOL', 'I take thy groat in earnest of revenge.'), ('henry_v_act5_scene1', 50, 52, 'FLUELLEN', 'If I owe you anything I will pay you in cudgels: you'), ('henry_v_act5_scene1', 51, 53, 'FLUELLEN', 'shall be a woodmonger, and buy nothing of me but cudgels. God'), ('henry_v_act5_scene1', 52, 54, 'FLUELLEN', 'b’ wi’ you, and keep you, and heal your pate.'), ('henry_v_act5_scene1', 53, 55, 'PISTOL', 'All hell shall stir for this.'), ('henry_v_act5_scene1', 54, 56, 'GOWER', 'Go, go; you are a counterfeit cowardly knave. Will you mock at'), ('henry_v_act5_scene1', 55, 57, 'GOWER', 'an ancient tradition, begun upon an honourable respect, and worn as a'), ('henry_v_act5_scene1', 56, 58, 'GOWER', 'memorable trophy of predeceased valour and dare not avouch in your deeds'), ('henry_v_act5_scene1', 57, 59, 'GOWER', 'any of your words? I have seen you gleeking and galling at'), ('henry_v_act5_scene1', 58, 60, 'GOWER', 'this gentleman twice or thrice. You thought, because he could not speak'), ('henry_v_act5_scene1', 59, 61, 'GOWER', 'English in the native garb, he could not therefore handle an English'), ('henry_v_act5_scene1', 60, 62, 'GOWER', 'cudgel: you find it otherwise; and henceforth let a Welsh correction teach'), ('henry_v_act5_scene1', 61, 63, 'GOWER', 'you a good English condition. Fare ye well.'), ('henry_v_act5_scene1', 62, 64, 'PISTOL', 'Doth Fortune play the huswife with me now?'), ('henry_v_act5_scene1', 63, 65, 'PISTOL', 'News have I, that my Doll is dead i’ the spital'), ('henry_v_act5_scene1', 64, 66, 'PISTOL', 'Of malady of France;'), ('henry_v_act5_scene1', 65, 67, 'PISTOL', 'And there my rendezvous is quite cut off.'), ('henry_v_act5_scene1', 66, 68, 'PISTOL', 'Old I do wax; and from my weary limbs'), ('henry_v_act5_scene1', 67, 69, 'PISTOL', 'Honour is cudgelled. Well, bawd I’ll turn,'), ('henry_v_act5_scene1', 68, 70, 'PISTOL', 'And something lean to cutpurse of quick hand.'), ('henry_v_act5_scene1', 69, 71, 'PISTOL', 'To England will I steal, and there I’ll steal:'), ('henry_v_act5_scene1', 70, 72, 'PISTOL', 'And patches will I get unto these cudgell’d scars,'), ('henry_v_act5_scene1', 71, 73, 'PISTOL', 'And swear I got them in the Gallia wars.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act5_scene2', 1, 0, 'KING HENRY', 'Peace to this meeting, wherefore we are met!'), ('henry_v_act5_scene2', 2, 1, 'KING HENRY', 'Unto our brother France, and to our sister,'), ('henry_v_act5_scene2', 3, 2, 'KING HENRY', 'Health and fair time of day; joy and good wishes'), ('henry_v_act5_scene2', 4, 3, 'KING HENRY', 'To our most fair and princely cousin Katharine;'), ('henry_v_act5_scene2', 5, 4, 'KING HENRY', 'And, as a branch and member of this royalty,'), ('henry_v_act5_scene2', 6, 5, 'KING HENRY', 'By whom this great assembly is contrived,'), ('henry_v_act5_scene2', 7, 6, 'KING HENRY', 'We do salute you, Duke of Burgundy;'), ('henry_v_act5_scene2', 8, 7, 'KING HENRY', 'And, princes French, and peers, health to you all!'), ('henry_v_act5_scene2', 9, 8, 'FRENCH KING', 'Right joyous are we to behold your face,'), ('henry_v_act5_scene2', 10, 9, 'FRENCH KING', 'Most worthy brother England; fairly met:'), ('henry_v_act5_scene2', 11, 10, 'FRENCH KING', 'So are you, princes English, every one.'), ('henry_v_act5_scene2', 12, 11, 'QUEEN ISABEL', 'So happy be the issue, brother England,'), ('henry_v_act5_scene2', 13, 12, 'QUEEN ISABEL', 'Of this good day and of this gracious meeting,'), ('henry_v_act5_scene2', 14, 13, 'QUEEN ISABEL', 'As we are now glad to behold your eyes;'), ('henry_v_act5_scene2', 15, 14, 'QUEEN ISABEL', 'Your eyes, which hitherto have borne in them'), ('henry_v_act5_scene2', 16, 15, 'QUEEN ISABEL', 'Against the French, that met them in their bent,'), ('henry_v_act5_scene2', 17, 16, 'QUEEN ISABEL', 'The fatal balls of murdering basilisks:'), ('henry_v_act5_scene2', 18, 17, 'QUEEN ISABEL', 'The venom of such looks, we fairly hope,'), ('henry_v_act5_scene2', 19, 18, 'QUEEN ISABEL', 'Have lost their quality, and that this day'), ('henry_v_act5_scene2', 20, 19, 'QUEEN ISABEL', 'Shall change all griefs and quarrels into love.'), ('henry_v_act5_scene2', 21, 20, 'KING HENRY', 'To cry amen to that, thus we appear.'), ('henry_v_act5_scene2', 22, 21, 'QUEEN ISABEL', 'You English princes all, I do salute you.'), ('henry_v_act5_scene2', 23, 22, 'BURGUNDY', 'My duty to you both, on equal love,'), ('henry_v_act5_scene2', 24, 23, 'BURGUNDY', 'Great Kings of France and England! That I have labour’d,'), ('henry_v_act5_scene2', 25, 24, 'BURGUNDY', 'With all my wits, my pains and strong endeavours,'), ('henry_v_act5_scene2', 26, 25, 'BURGUNDY', 'To bring your most imperial majesties'), ('henry_v_act5_scene2', 27, 26, 'BURGUNDY', 'Unto this bar and royal interview,'), ('henry_v_act5_scene2', 28, 27, 'BURGUNDY', 'Your mightiness on both parts best can witness.'), ('henry_v_act5_scene2', 29, 28, 'BURGUNDY', 'Since then my office hath so far prevail’d'), ('henry_v_act5_scene2', 30, 29, 'BURGUNDY', 'That, face to face and royal eye to eye,'), ('henry_v_act5_scene2', 31, 30, 'BURGUNDY', 'You have congreeted, let it not disgrace me,'), ('henry_v_act5_scene2', 32, 31, 'BURGUNDY', 'If I demand, before this royal view,'), ('henry_v_act5_scene2', 33, 32, 'BURGUNDY', 'What rub or what impediment there is,'), ('henry_v_act5_scene2', 34, 33, 'BURGUNDY', 'Why that the naked, poor and mangled Peace,'), ('henry_v_act5_scene2', 35, 34, 'BURGUNDY', 'Dear nurse of arts, plenties and joyful births,'), ('henry_v_act5_scene2', 36, 35, 'BURGUNDY', 'Should not in this best garden of the world'), ('henry_v_act5_scene2', 37, 36, 'BURGUNDY', 'Our fertile France, put up her lovely visage?'), ('henry_v_act5_scene2', 38, 37, 'BURGUNDY', 'Alas, she hath from France too long been chased,'), ('henry_v_act5_scene2', 39, 38, 'BURGUNDY', 'And all her husbandry doth lie on heaps,'), ('henry_v_act5_scene2', 40, 39, 'BURGUNDY', 'Corrupting in it own fertility.'), ('henry_v_act5_scene2', 41, 40, 'BURGUNDY', 'Her vine, the merry cheerer of the heart,'), ('henry_v_act5_scene2', 42, 41, 'BURGUNDY', 'Unpruned dies; her hedges even-pleach’d,'), ('henry_v_act5_scene2', 43, 42, 'BURGUNDY', 'Like prisoners wildly overgrown with hair,'), ('henry_v_act5_scene2', 44, 43, 'BURGUNDY', 'Put forth disorder’d twigs; her fallow leas'), ('henry_v_act5_scene2', 45, 44, 'BURGUNDY', 'The darnel, hemlock and rank fumitory'), ('henry_v_act5_scene2', 46, 45, 'BURGUNDY', 'Doth root upon, while that the coulter rusts'), ('henry_v_act5_scene2', 47, 46, 'BURGUNDY', 'That should deracinate such savagery;'), ('henry_v_act5_scene2', 48, 47, 'BURGUNDY', 'The even mead, that erst brought sweetly forth'), ('henry_v_act5_scene2', 49, 48, 'BURGUNDY', 'The freckled cowslip, burnet and green clover,'), ('henry_v_act5_scene2', 50, 49, 'BURGUNDY', 'Wanting the scythe, all uncorrected, rank,'), ('henry_v_act5_scene2', 51, 50, 'BURGUNDY', 'Conceives by idleness, and nothing teems'), ('henry_v_act5_scene2', 52, 51, 'BURGUNDY', 'But hateful docks, rough thistles, kecksies, burs,'), ('henry_v_act5_scene2', 53, 52, 'BURGUNDY', 'Losing both beauty and utility.'), ('henry_v_act5_scene2', 54, 53, 'BURGUNDY', 'And as our vineyards, fallows, meads and hedges,'), ('henry_v_act5_scene2', 55, 54, 'BURGUNDY', 'Defective in their natures, grow to wildness,'), ('henry_v_act5_scene2', 56, 55, 'BURGUNDY', 'Even so our houses and ourselves and children'), ('henry_v_act5_scene2', 57, 56, 'BURGUNDY', 'Have lost, or do not learn for want of time,'), ('henry_v_act5_scene2', 58, 57, 'BURGUNDY', 'The sciences that should become our country;'), ('henry_v_act5_scene2', 59, 58, 'BURGUNDY', 'But grow like savages—as soldiers will'), ('henry_v_act5_scene2', 60, 59, 'BURGUNDY', 'That nothing do but meditate on blood—'), ('henry_v_act5_scene2', 61, 60, 'BURGUNDY', 'To swearing and stern looks, diffused attire'), ('henry_v_act5_scene2', 62, 61, 'BURGUNDY', 'And everything that seems unnatural.'), ('henry_v_act5_scene2', 63, 62, 'BURGUNDY', 'Which to reduce into our former favour'), ('henry_v_act5_scene2', 64, 63, 'BURGUNDY', 'You are assembled: and my speech entreats'), ('henry_v_act5_scene2', 65, 64, 'BURGUNDY', 'That I may know the let, why gentle Peace'), ('henry_v_act5_scene2', 66, 65, 'BURGUNDY', 'Should not expel these inconveniences'), ('henry_v_act5_scene2', 67, 66, 'BURGUNDY', 'And bless us with her former qualities.'), ('henry_v_act5_scene2', 68, 67, 'KING HENRY', 'If, Duke of Burgundy, you would the peace,'), ('henry_v_act5_scene2', 69, 68, 'KING HENRY', 'Whose want gives growth to the imperfections'), ('henry_v_act5_scene2', 70, 69, 'KING HENRY', 'Which you have cited, you must buy that peace'), ('henry_v_act5_scene2', 71, 70, 'KING HENRY', 'With full accord to all our just demands;'), ('henry_v_act5_scene2', 72, 71, 'KING HENRY', 'Whose tenours and particular effects'), ('henry_v_act5_scene2', 73, 72, 'KING HENRY', 'You have enscheduled briefly in your hands.'), ('henry_v_act5_scene2', 74, 73, 'BURGUNDY', 'The king hath heard them; to the which as yet'), ('henry_v_act5_scene2', 75, 74, 'BURGUNDY', 'There is no answer made.'), ('henry_v_act5_scene2', 75, 75, 'KING HENRY', 'Well, then, the peace,'), ('henry_v_act5_scene2', 76, 76, 'KING HENRY', 'Which you before so urged, lies in his answer.'), ('henry_v_act5_scene2', 77, 77, 'FRENCH KING', 'I have but with a cursorary eye'), ('henry_v_act5_scene2', 78, 78, 'FRENCH KING', 'O’erglanced the articles: pleaseth your grace'), ('henry_v_act5_scene2', 79, 79, 'FRENCH KING', 'To appoint some of your council presently'), ('henry_v_act5_scene2', 80, 80, 'FRENCH KING', 'To sit with us once more, with better heed'), ('henry_v_act5_scene2', 81, 81, 'FRENCH KING', 'To resurvey them, we will suddenly'), ('henry_v_act5_scene2', 82, 82, 'FRENCH KING', 'Pass our accept and peremptory answer.'), ('henry_v_act5_scene2', 82, 83, 'KING HENRY', 'Brother, we shall. Go, uncle Exeter,'), ('henry_v_act5_scene2', 83, 84, 'KING HENRY', 'And brother Clarence, and you, brother Gloucester,'), ('henry_v_act5_scene2', 84, 85, 'KING HENRY', 'Warwick and Huntington, go with the king;'), ('henry_v_act5_scene2', 85, 86, 'KING HENRY', 'And take with you free power to ratify,'), ('henry_v_act5_scene2', 86, 87, 'KING HENRY', 'Augment, or alter, as your wisdoms best'), ('henry_v_act5_scene2', 87, 88, 'KING HENRY', 'Shall see advantageable for our dignity,'), ('henry_v_act5_scene2', 88, 89, 'KING HENRY', 'Anything in or out of our demands,'), ('henry_v_act5_scene2', 89, 90, 'KING HENRY', 'And we’ll consign thereto. Will you, fair sister,'), ('henry_v_act5_scene2', 90, 91, 'KING HENRY', 'Go with the princes, or stay here with us?'), ('henry_v_act5_scene2', 91, 92, 'QUEEN ISABEL', 'Our gracious brother, I will go with them:'), ('henry_v_act5_scene2', 92, 93, 'QUEEN ISABEL', 'Haply a woman’s voice may do some good,'), ('henry_v_act5_scene2', 93, 94, 'QUEEN ISABEL', 'When articles too nicely urg’d be stood on.'), ('henry_v_act5_scene2', 94, 95, 'KING HENRY', 'Yet leave our cousin Katharine here with us:'), ('henry_v_act5_scene2', 95, 96, 'KING HENRY', 'She is our capital demand, comprised'), ('henry_v_act5_scene2', 96, 97, 'KING HENRY', 'Within the fore-rank of our articles.'), ('henry_v_act5_scene2', 96, 98, 'QUEEN ISABEL', 'She hath good leave.'), ('henry_v_act5_scene2', 97, 99, 'KING HENRY', 'Fair Katharine, and most fair,');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act5_scene2', 98, 100, 'KING HENRY', 'Will you vouchsafe to teach a soldier terms'), ('henry_v_act5_scene2', 99, 101, 'KING HENRY', 'Such as will enter at a lady’s ear'), ('henry_v_act5_scene2', 100, 102, 'KING HENRY', 'And plead his love-suit to her gentle heart?'), ('henry_v_act5_scene2', 101, 103, 'KATHERINE', 'Your majesty shall mock me; I cannot speak your England.'), ('henry_v_act5_scene2', 102, 104, 'KING HENRY', 'O fair Katharine, if you will love me soundly with your French'), ('henry_v_act5_scene2', 103, 105, 'KING HENRY', 'heart, I will be glad to hear you confess it brokenly with'), ('henry_v_act5_scene2', 104, 106, 'KING HENRY', 'your English tongue. Do you like me, Kate?'), ('henry_v_act5_scene2', 105, 107, 'KATHERINE', 'Pardonnez-moi, I cannot tell vat is “like me.”'), ('henry_v_act5_scene2', 106, 108, 'KING HENRY', 'An angel is like you, Kate, and you are like an angel.'), ('henry_v_act5_scene2', 107, 109, 'KATHERINE', 'Que dit-il? Que je suis semblable à les anges?'), ('henry_v_act5_scene2', 108, 110, 'ALICE', 'Oui, vraiment, sauf votre grâce, ainsi dit-il.'), ('henry_v_act5_scene2', 109, 111, 'KING HENRY', 'I said so, dear Katharine; and I must not blush to affirm it.'), ('henry_v_act5_scene2', 110, 112, 'KATHERINE', 'O bon Dieu! les langues des hommes sont pleines de tromperies.'), ('henry_v_act5_scene2', 111, 113, 'KING HENRY', 'What says she, fair one? that the tongues of men are full of deceits?'), ('henry_v_act5_scene2', 112, 114, 'ALICE', 'Oui, dat de tongues of de mans is be full of deceits:'), ('henry_v_act5_scene2', 113, 115, 'ALICE', 'dat is de princess.'), ('henry_v_act5_scene2', 114, 116, 'KING HENRY', 'The princess is the better Englishwoman. I’ faith, Kate, my wooing is'), ('henry_v_act5_scene2', 115, 117, 'KING HENRY', 'fit for thy understanding: I am glad thou canst speak no better'), ('henry_v_act5_scene2', 116, 118, 'KING HENRY', 'English; for, if thou couldst, thou wouldst find me such a plain'), ('henry_v_act5_scene2', 117, 119, 'KING HENRY', 'king that thou wouldst think I had sold my farm to buy'), ('henry_v_act5_scene2', 118, 120, 'KING HENRY', 'my crown. I know no ways to mince it in love, but'), ('henry_v_act5_scene2', 119, 121, 'KING HENRY', 'directly to say “I love you:” then if you urge me farther'), ('henry_v_act5_scene2', 120, 122, 'KING HENRY', 'than to say “do you in faith?” I wear out my suit.'), ('henry_v_act5_scene2', 121, 123, 'KING HENRY', 'Give me your answer; i’ faith, do: and so clap hands and'), ('henry_v_act5_scene2', 122, 124, 'KING HENRY', 'a bargain: how say you, lady?'), ('henry_v_act5_scene2', 122, 125, 'KATHERINE', 'Sauf votre honneur, me understand vell.'), ('henry_v_act5_scene2', 123, 126, 'KING HENRY', 'Marry, if you would put me to verses or to dance for'), ('henry_v_act5_scene2', 124, 127, 'KING HENRY', 'your sake, Kate, why you undid me: for the one, I have'), ('henry_v_act5_scene2', 125, 128, 'KING HENRY', 'neither words nor measure, and for the other, I have no strength'), ('henry_v_act5_scene2', 126, 129, 'KING HENRY', 'in measure, yet a reasonable measure in strength. If I could win'), ('henry_v_act5_scene2', 127, 130, 'KING HENRY', 'a lady at leap-frog, or by vaulting into my saddle with my'), ('henry_v_act5_scene2', 128, 131, 'KING HENRY', 'armour on my back, under the correction of bragging be it spoken,'), ('henry_v_act5_scene2', 129, 132, 'KING HENRY', 'I should quickly leap into a wife. Or if I might buffet'), ('henry_v_act5_scene2', 130, 133, 'KING HENRY', 'for my love, or bound my horse for her favours, I could'), ('henry_v_act5_scene2', 131, 134, 'KING HENRY', 'lay on like a butcher and sit like a jack-an-apes, never off.'), ('henry_v_act5_scene2', 132, 135, 'KING HENRY', 'But, before God, Kate, I cannot look greenly nor gasp out my'), ('henry_v_act5_scene2', 133, 136, 'KING HENRY', 'eloquence, nor I have no cunning in protestation; only downright oaths, which'), ('henry_v_act5_scene2', 134, 137, 'KING HENRY', 'I never use till urged, nor never break for urging. If thou'), ('henry_v_act5_scene2', 135, 138, 'KING HENRY', 'canst love a fellow of this temper, Kate, whose face is not'), ('henry_v_act5_scene2', 136, 139, 'KING HENRY', 'worth sun-burning, that never looks in his glass for love of anything'), ('henry_v_act5_scene2', 137, 140, 'KING HENRY', 'he sees there, let thine eye be thy cook. I speak to'), ('henry_v_act5_scene2', 138, 141, 'KING HENRY', 'thee plain soldier: if thou canst love me for this, take me;'), ('henry_v_act5_scene2', 139, 142, 'KING HENRY', 'if not, to say to thee that I shall die, is true;'), ('henry_v_act5_scene2', 140, 143, 'KING HENRY', 'but for thy love, by the Lord, no; yet I love thee'), ('henry_v_act5_scene2', 141, 144, 'KING HENRY', 'too. And while thou livest, dear Kate, take a fellow of plain'), ('henry_v_act5_scene2', 142, 145, 'KING HENRY', 'and uncoined constancy; for he perforce must do thee right, because he'), ('henry_v_act5_scene2', 143, 146, 'KING HENRY', 'hath not the gift to woo in other places: for these fellows'), ('henry_v_act5_scene2', 144, 147, 'KING HENRY', 'of infinite tongue, that can rhyme themselves into ladies’ favours, they do'), ('henry_v_act5_scene2', 145, 148, 'KING HENRY', 'always reason themselves out again. What! a speaker is but a prater;'), ('henry_v_act5_scene2', 146, 149, 'KING HENRY', 'a rhyme is but a ballad. A good leg will fall; a'), ('henry_v_act5_scene2', 147, 150, 'KING HENRY', 'straight back will stoop; a black beard will turn white; a curled'), ('henry_v_act5_scene2', 148, 151, 'KING HENRY', 'pate will grow bald; a fair face will wither; a full eye'), ('henry_v_act5_scene2', 149, 152, 'KING HENRY', 'will wax hollow: but a good heart, Kate, is the sun and'), ('henry_v_act5_scene2', 150, 153, 'KING HENRY', 'the moon; or rather the sun and not the moon; for it'), ('henry_v_act5_scene2', 151, 154, 'KING HENRY', 'shines bright and never changes, but keeps his course truly. If thou'), ('henry_v_act5_scene2', 152, 155, 'KING HENRY', 'would have such a one, take me; and take me, take a'), ('henry_v_act5_scene2', 153, 156, 'KING HENRY', 'soldier; take a soldier, take a king. And what sayest thou then'), ('henry_v_act5_scene2', 154, 157, 'KING HENRY', 'to my love? speak, my fair, and fairly, I pray thee.'), ('henry_v_act5_scene2', 155, 158, 'KATHERINE', 'Is it possible dat I sould love de enemy of France?'), ('henry_v_act5_scene2', 156, 159, 'KING HENRY', 'No; it is not possible you should love the enemy of France,'), ('henry_v_act5_scene2', 157, 160, 'KING HENRY', 'Kate: but, in loving me, you should love the friend of France;'), ('henry_v_act5_scene2', 158, 161, 'KING HENRY', 'for I love France so well that I will not part with'), ('henry_v_act5_scene2', 159, 162, 'KING HENRY', 'a village of it; I will have it all mine: and, Kate,'), ('henry_v_act5_scene2', 160, 163, 'KING HENRY', 'when France is mine and I am yours, then yours is France'), ('henry_v_act5_scene2', 161, 164, 'KING HENRY', 'and you are mine.'), ('henry_v_act5_scene2', 161, 165, 'KATHERINE', 'I cannot tell vat is dat.'), ('henry_v_act5_scene2', 162, 166, 'KING HENRY', 'No, Kate? I will tell thee in French; which I am sure'), ('henry_v_act5_scene2', 163, 167, 'KING HENRY', 'will hang upon my tongue like a new-married wife about her husband’s'), ('henry_v_act5_scene2', 164, 168, 'KING HENRY', 'neck, hardly to be shook off. Je quand sur le possession de'), ('henry_v_act5_scene2', 165, 169, 'KING HENRY', 'France, et quand vous avez le possession de moi—let me see, what'), ('henry_v_act5_scene2', 166, 170, 'KING HENRY', 'then? Saint Denis be my speed!—donc votre est France et vous êtes'), ('henry_v_act5_scene2', 167, 171, 'KING HENRY', 'mienne. It is as easy for me, Kate, to conquer the kingdom'), ('henry_v_act5_scene2', 168, 172, 'KING HENRY', 'as to speak so much more French: I shall never move thee'), ('henry_v_act5_scene2', 169, 173, 'KING HENRY', 'in French, unless it be to laugh at me.'), ('henry_v_act5_scene2', 170, 174, 'KATHERINE', 'Sauf votre honneur, le françois que vous parlez, il est meilleur que'), ('henry_v_act5_scene2', 171, 175, 'KATHERINE', 'l’Anglois lequel je parle.'), ('henry_v_act5_scene2', 172, 176, 'KING HENRY', 'No, faith, is’t not, Kate: but thy speaking of my tongue, and'), ('henry_v_act5_scene2', 173, 177, 'KING HENRY', 'I thine, most truly-falsely, must needs be granted to be much at'), ('henry_v_act5_scene2', 174, 178, 'KING HENRY', 'one. But, Kate, dost thou understand thus much English, canst thou love'), ('henry_v_act5_scene2', 175, 179, 'KING HENRY', 'me?'), ('henry_v_act5_scene2', 175, 180, 'KATHERINE', 'I cannot tell.'), ('henry_v_act5_scene2', 176, 181, 'KING HENRY', 'Can any of your neighbours tell, Kate? I’ll ask them. Come, I'), ('henry_v_act5_scene2', 177, 182, 'KING HENRY', 'know thou lovest me: and at night, when you come into your'), ('henry_v_act5_scene2', 178, 183, 'KING HENRY', 'closet, you’ll question this gentlewoman about me; and I know, Kate, you'), ('henry_v_act5_scene2', 179, 184, 'KING HENRY', 'will to her dispraise those parts in me that you love with'), ('henry_v_act5_scene2', 180, 185, 'KING HENRY', 'your heart: but, good Kate, mock me mercifully; the rather, gentle princess,'), ('henry_v_act5_scene2', 181, 186, 'KING HENRY', 'because I love thee cruelly. If ever thou beest mine, Kate, as'), ('henry_v_act5_scene2', 182, 187, 'KING HENRY', 'I have a saving faith within me tells me thou shalt, I'), ('henry_v_act5_scene2', 183, 188, 'KING HENRY', 'get thee with scambling, and thou must therefore needs prove a good'), ('henry_v_act5_scene2', 184, 189, 'KING HENRY', 'soldier-breeder: shall not thou and I, between Saint Denis and Saint George,'), ('henry_v_act5_scene2', 185, 190, 'KING HENRY', 'compound a boy, half French, half English, that shall go to Constantinople'), ('henry_v_act5_scene2', 186, 191, 'KING HENRY', 'and take the Turk by the beard? shall we not? what sayest'), ('henry_v_act5_scene2', 187, 192, 'KING HENRY', 'thou, my fair flower-de-luce?'), ('henry_v_act5_scene2', 187, 193, 'KATHERINE', 'I do not know dat.'), ('henry_v_act5_scene2', 188, 194, 'KING HENRY', 'No; ’tis hereafter to know, but now to promise: do but now'), ('henry_v_act5_scene2', 189, 195, 'KING HENRY', 'promise, Kate, you will endeavour for your French part of such a'), ('henry_v_act5_scene2', 190, 196, 'KING HENRY', 'boy; and for my English moiety take the word of a king'), ('henry_v_act5_scene2', 191, 197, 'KING HENRY', 'and a bachelor. How answer you, la plus belle Katherine du monde,'), ('henry_v_act5_scene2', 192, 198, 'KING HENRY', 'mon très cher et divin déesse?'), ('henry_v_act5_scene2', 193, 199, 'KATHERINE', 'Your majestee ave fausse French enough to deceive de most sage demoiselle');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act5_scene2', 194, 200, 'KATHERINE', 'dat is en France.'), ('henry_v_act5_scene2', 195, 201, 'KING HENRY', 'Now, fie upon my false French! By mine honour, in true English,'), ('henry_v_act5_scene2', 196, 202, 'KING HENRY', 'I love thee, Kate: by which honour I dare not swear thou'), ('henry_v_act5_scene2', 197, 203, 'KING HENRY', 'lovest me; yet my blood begins to flatter me that thou dost,'), ('henry_v_act5_scene2', 198, 204, 'KING HENRY', 'notwithstanding the poor and untempering effect of my visage. Now, beshrew my'), ('henry_v_act5_scene2', 199, 205, 'KING HENRY', 'father’s ambition! he was thinking of civil wars when he got me:'), ('henry_v_act5_scene2', 200, 206, 'KING HENRY', 'therefore was I created with a stubborn outside, with an aspect of'), ('henry_v_act5_scene2', 201, 207, 'KING HENRY', 'iron, that, when I come to woo ladies, I fright them. But,'), ('henry_v_act5_scene2', 202, 208, 'KING HENRY', 'in faith, Kate, the elder I wax, the better I shall appear:'), ('henry_v_act5_scene2', 203, 209, 'KING HENRY', 'my comfort is, that old age, that ill layer up of beauty,'), ('henry_v_act5_scene2', 204, 210, 'KING HENRY', 'can do no more spoil upon my face: thou hast me, if'), ('henry_v_act5_scene2', 205, 211, 'KING HENRY', 'thou hast me, at the worst; and thou shalt wear me, if'), ('henry_v_act5_scene2', 206, 212, 'KING HENRY', 'thou wear me, better and better: and therefore tell me, most fair'), ('henry_v_act5_scene2', 207, 213, 'KING HENRY', 'Katharine, will you have me? Put off your maiden blushes; avouch the'), ('henry_v_act5_scene2', 208, 214, 'KING HENRY', 'thoughts of your heart with the looks of an empress; take me'), ('henry_v_act5_scene2', 209, 215, 'KING HENRY', 'by the hand, and say “Harry of England, I am thine:” which'), ('henry_v_act5_scene2', 210, 216, 'KING HENRY', 'word thou shalt no sooner bless mine ear withal, but I will'), ('henry_v_act5_scene2', 211, 217, 'KING HENRY', 'tell thee aloud “England is thine, Ireland is thine, France is thine,'), ('henry_v_act5_scene2', 212, 218, 'KING HENRY', 'and Henry Plantagenet is thine;” who, though I speak it before his'), ('henry_v_act5_scene2', 213, 219, 'KING HENRY', 'face, if he be not fellow with the best king, thou shalt'), ('henry_v_act5_scene2', 214, 220, 'KING HENRY', 'find the best king of good fellows. Come, your answer in broken'), ('henry_v_act5_scene2', 215, 221, 'KING HENRY', 'music; for thy voice is music and thy English broken; therefore, queen'), ('henry_v_act5_scene2', 216, 222, 'KING HENRY', 'of all, Katharine, break thy mind to me in broken English; wilt'), ('henry_v_act5_scene2', 217, 223, 'KING HENRY', 'thou have me?'), ('henry_v_act5_scene2', 218, 224, 'KATHERINE', 'Dat is as it shall please le roi mon père.'), ('henry_v_act5_scene2', 219, 225, 'KING HENRY', 'Nay, it will please him well, Kate; it shall please him, Kate.'), ('henry_v_act5_scene2', 220, 226, 'KATHERINE', 'Den it sall also content me.'), ('henry_v_act5_scene2', 221, 227, 'KING HENRY', 'Upon that I kiss your hand, and call you my queen.'), ('henry_v_act5_scene2', 222, 228, 'KATHERINE', 'Laissez, mon seigneur, laissez, laissez: ma foi, je ne veux point que'), ('henry_v_act5_scene2', 223, 229, 'KATHERINE', 'vous abaissiez votre grandeur en baisant la main d’une votre seigneurie indigne'), ('henry_v_act5_scene2', 224, 230, 'KATHERINE', 'serviteur: excusez-moi, je vous supplie, mon très-puissant seigneur.'), ('henry_v_act5_scene2', 225, 231, 'KING HENRY', 'Then I will kiss your lips, Kate.'), ('henry_v_act5_scene2', 226, 232, 'KATHERINE', 'Les dames et demoiselles pour être baisées devant leurs noces, il n’est'), ('henry_v_act5_scene2', 227, 233, 'KATHERINE', 'pas la coutume de France.'), ('henry_v_act5_scene2', 227, 234, 'KING HENRY', 'Madame my interpreter, what says she?'), ('henry_v_act5_scene2', 228, 235, 'ALICE', 'Dat it is not be de fashion pour les ladies of France—I'), ('henry_v_act5_scene2', 229, 236, 'ALICE', 'cannot tell vat is baiser en Anglish.'), ('henry_v_act5_scene2', 230, 237, 'KING HENRY', 'To kiss.'), ('henry_v_act5_scene2', 230, 238, 'ALICE', 'Your majestee entend bettre que moi.'), ('henry_v_act5_scene2', 231, 239, 'KING HENRY', 'It is not a fashion for the maids in France to kiss'), ('henry_v_act5_scene2', 232, 240, 'KING HENRY', 'before they are married, would she say?'), ('henry_v_act5_scene2', 233, 241, 'ALICE', 'Oui, vraiment.'), ('henry_v_act5_scene2', 234, 242, 'KING HENRY', 'O Kate, nice customs curtsy to great kings. Dear Kate, you and'), ('henry_v_act5_scene2', 235, 243, 'KING HENRY', 'I cannot be confined within the weak list of a country’s fashion:'), ('henry_v_act5_scene2', 236, 244, 'KING HENRY', 'we are the makers of manners, Kate; and the liberty that follows'), ('henry_v_act5_scene2', 237, 245, 'KING HENRY', 'our places stops the mouth of all find-faults; as I will do'), ('henry_v_act5_scene2', 238, 246, 'KING HENRY', 'yours, for upholding the nice fashion of your country in denying me'), ('henry_v_act5_scene2', 239, 247, 'KING HENRY', 'a kiss: therefore, patiently and yielding. Kissing her. You have witchcraft in'), ('henry_v_act5_scene2', 240, 248, 'KING HENRY', 'your lips, Kate: there is more eloquence in a sugar touch of'), ('henry_v_act5_scene2', 241, 249, 'KING HENRY', 'them than in the tongues of the French council; and they should'), ('henry_v_act5_scene2', 242, 250, 'KING HENRY', 'sooner persuade Harry of England than a general petition of monarchs. Here'), ('henry_v_act5_scene2', 243, 251, 'KING HENRY', 'comes your father.'), ('henry_v_act5_scene2', 244, 252, 'BURGUNDY', 'God save your majesty! my royal cousin, teach you our princess English?'), ('henry_v_act5_scene2', 245, 253, 'KING HENRY', 'I would have her learn, my fair cousin, how perfectly I love'), ('henry_v_act5_scene2', 246, 254, 'KING HENRY', 'her; and that is good English.'), ('henry_v_act5_scene2', 246, 255, 'BURGUNDY', 'Is she not apt?'), ('henry_v_act5_scene2', 247, 256, 'KING HENRY', 'Our tongue is rough, coz, and my condition is not smooth; so'), ('henry_v_act5_scene2', 248, 257, 'KING HENRY', 'that, having neither the voice nor the heart of flattery about me,'), ('henry_v_act5_scene2', 249, 258, 'KING HENRY', 'I cannot so conjure up the spirit of love in her, that'), ('henry_v_act5_scene2', 250, 259, 'KING HENRY', 'he will appear in his true likeness.'), ('henry_v_act5_scene2', 251, 260, 'BURGUNDY', 'Pardon the frankness of my mirth, if I answer you for that.'), ('henry_v_act5_scene2', 252, 261, 'BURGUNDY', 'If you would conjure in her, you must make a circle; if'), ('henry_v_act5_scene2', 253, 262, 'BURGUNDY', 'conjure up love in her in his true likeness, he must appear'), ('henry_v_act5_scene2', 254, 263, 'BURGUNDY', 'naked and blind. Can you blame her then, being a maid yet'), ('henry_v_act5_scene2', 255, 264, 'BURGUNDY', 'ros’d over with the virgin crimson of modesty, if she deny the'), ('henry_v_act5_scene2', 256, 265, 'BURGUNDY', 'appearance of a naked blind boy in her naked seeing self? It'), ('henry_v_act5_scene2', 257, 266, 'BURGUNDY', 'were, my lord, a hard condition for a maid to consign to.'), ('henry_v_act5_scene2', 258, 267, 'KING HENRY', 'Yet they do wink and yield, as love is blind and enforces.'), ('henry_v_act5_scene2', 259, 268, 'BURGUNDY', 'They are then excused, my lord, when they see not what they do.'), ('henry_v_act5_scene2', 260, 269, 'KING HENRY', 'Then, good my lord, teach your cousin to consent winking.'), ('henry_v_act5_scene2', 261, 270, 'BURGUNDY', 'I will wink on her to consent, my lord, if you will'), ('henry_v_act5_scene2', 262, 271, 'BURGUNDY', 'teach her to know my meaning: for maids, well summered and warm'), ('henry_v_act5_scene2', 263, 272, 'BURGUNDY', 'kept, are like flies at Bartholomew-tide, blind, though they have their eyes;'), ('henry_v_act5_scene2', 264, 273, 'BURGUNDY', 'and then they will endure handling, which before would not abide looking'), ('henry_v_act5_scene2', 265, 274, 'BURGUNDY', 'on.'), ('henry_v_act5_scene2', 266, 275, 'KING HENRY', 'This moral ties me over to time and a hot summer; and'), ('henry_v_act5_scene2', 267, 276, 'KING HENRY', 'so I shall catch the fly, your cousin, in the latter end'), ('henry_v_act5_scene2', 268, 277, 'KING HENRY', 'and she must be blind too.'), ('henry_v_act5_scene2', 269, 278, 'BURGUNDY', 'As love is, my lord, before it loves.'), ('henry_v_act5_scene2', 270, 279, 'KING HENRY', 'It is so: and you may, some of you, thank love for'), ('henry_v_act5_scene2', 271, 280, 'KING HENRY', 'my blindness, who cannot see many a fair French city for one'), ('henry_v_act5_scene2', 272, 281, 'KING HENRY', 'fair French maid that stands in my way.'), ('henry_v_act5_scene2', 273, 282, 'FRENCH KING', 'Yes, my lord, you see them perspectively, the cities turned into a'), ('henry_v_act5_scene2', 274, 283, 'FRENCH KING', 'maid; for they are all girdled with maiden walls that no war'), ('henry_v_act5_scene2', 275, 284, 'FRENCH KING', 'hath entered.'), ('henry_v_act5_scene2', 275, 285, 'KING HENRY', 'Shall Kate be my wife?'), ('henry_v_act5_scene2', 276, 286, 'FRENCH KING', 'So please you.'), ('henry_v_act5_scene2', 277, 287, 'KING HENRY', 'I am content; so the maiden cities you talk of may wait'), ('henry_v_act5_scene2', 278, 288, 'KING HENRY', 'on her: so the maid that stood in the way for my'), ('henry_v_act5_scene2', 279, 289, 'KING HENRY', 'wish shall show me the way to my will.'), ('henry_v_act5_scene2', 280, 290, 'FRENCH KING', 'We have consented to all terms of reason.'), ('henry_v_act5_scene2', 281, 291, 'KING HENRY', 'Is’t so, my lords of England?'), ('henry_v_act5_scene2', 281, 292, 'WESTMORELAND', 'The king hath granted every article:'), ('henry_v_act5_scene2', 282, 293, 'WESTMORELAND', 'His daughter first, and then in sequel all,'), ('henry_v_act5_scene2', 283, 294, 'WESTMORELAND', 'According to their firm proposed natures.'), ('henry_v_act5_scene2', 284, 295, 'EXETER', 'Only he hath not yet subscribed this: Where your majesty demands, that'), ('henry_v_act5_scene2', 285, 296, 'EXETER', 'the King of France, having any occasion to write for matter of'), ('henry_v_act5_scene2', 286, 297, 'EXETER', 'grant, shall name your highness in this form and with this addition,'), ('henry_v_act5_scene2', 287, 298, 'EXETER', 'in French, Notre très-cher fils Henri, Roi d’Angleterre, Héritier de France; and'), ('henry_v_act5_scene2', 288, 299, 'EXETER', 'thus in Latin, Praeclarissimus filius noster Henricus, Rex Angliae, et Haeres Franciae.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_act5_scene2', 289, 300, 'FRENCH KING', 'Nor this I have not, brother, so denied'), ('henry_v_act5_scene2', 290, 301, 'FRENCH KING', 'But our request shall make me let it pass.'), ('henry_v_act5_scene2', 291, 302, 'KING HENRY', 'I pray you then, in love and dear alliance,'), ('henry_v_act5_scene2', 292, 303, 'KING HENRY', 'Let that one article rank with the rest;'), ('henry_v_act5_scene2', 293, 304, 'KING HENRY', 'And thereupon give me your daughter.'), ('henry_v_act5_scene2', 294, 305, 'FRENCH KING', 'Take her, fair son, and from her blood raise up'), ('henry_v_act5_scene2', 295, 306, 'FRENCH KING', 'Issue to me; that the contending kingdoms'), ('henry_v_act5_scene2', 296, 307, 'FRENCH KING', 'Of France and England, whose very shores look pale'), ('henry_v_act5_scene2', 297, 308, 'FRENCH KING', 'With envy of each other’s happiness,'), ('henry_v_act5_scene2', 298, 309, 'FRENCH KING', 'May cease their hatred, and this dear conjunction'), ('henry_v_act5_scene2', 299, 310, 'FRENCH KING', 'Plant neighbourhood and Christian-like accord'), ('henry_v_act5_scene2', 300, 311, 'FRENCH KING', 'In their sweet bosoms, that never war advance'), ('henry_v_act5_scene2', 301, 312, 'FRENCH KING', 'His bleeding sword ’twixt England and fair France.'), ('henry_v_act5_scene2', 302, 313, 'ALL', 'Amen!'), ('henry_v_act5_scene2', 303, 314, 'KING HENRY', 'Now, welcome, Kate: and bear me witness all,'), ('henry_v_act5_scene2', 304, 315, 'KING HENRY', 'That here I kiss her as my sovereign queen.'), ('henry_v_act5_scene2', 305, 316, 'QUEEN ISABEL', 'God, the best maker of all marriages,'), ('henry_v_act5_scene2', 306, 317, 'QUEEN ISABEL', 'Combine your hearts in one, your realms in one!'), ('henry_v_act5_scene2', 307, 318, 'QUEEN ISABEL', 'As man and wife, being two, are one in love,'), ('henry_v_act5_scene2', 308, 319, 'QUEEN ISABEL', 'So be there ’twixt your kingdoms such a spousal,'), ('henry_v_act5_scene2', 309, 320, 'QUEEN ISABEL', 'That never may ill office, or fell jealousy,'), ('henry_v_act5_scene2', 310, 321, 'QUEEN ISABEL', 'Which troubles oft the bed of blessed marriage,'), ('henry_v_act5_scene2', 311, 322, 'QUEEN ISABEL', 'Thrust in between the paction of these kingdoms,'), ('henry_v_act5_scene2', 312, 323, 'QUEEN ISABEL', 'To make divorce of their incorporate league;'), ('henry_v_act5_scene2', 313, 324, 'QUEEN ISABEL', 'That English may as French, French Englishmen,'), ('henry_v_act5_scene2', 314, 325, 'QUEEN ISABEL', 'Receive each other. God speak this Amen!'), ('henry_v_act5_scene2', 315, 326, 'ALL', 'Amen!'), ('henry_v_act5_scene2', 316, 327, 'KING HENRY', 'Prepare we for our marriage: on which day,'), ('henry_v_act5_scene2', 317, 328, 'KING HENRY', 'My Lord of Burgundy, we’ll take your oath,'), ('henry_v_act5_scene2', 318, 329, 'KING HENRY', 'And all the peers’, for surety of our leagues.'), ('henry_v_act5_scene2', 319, 330, 'KING HENRY', 'Then shall I swear to Kate, and you to me;'), ('henry_v_act5_scene2', 320, 331, 'KING HENRY', 'And may our oaths well kept and prosperous be! Sennet. Exeunt.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_epilogue', 1, 0, 'CHORUS', 'Thus far, with rough and all-unable pen,'), ('henry_v_epilogue', 2, 1, 'CHORUS', 'Our bending author hath pursued the story,'), ('henry_v_epilogue', 3, 2, 'CHORUS', 'In little room confining mighty men,'), ('henry_v_epilogue', 4, 3, 'CHORUS', 'Mangling by starts the full course of their glory.'), ('henry_v_epilogue', 5, 4, 'CHORUS', 'Small time, but in that small most greatly lived'), ('henry_v_epilogue', 6, 5, 'CHORUS', 'This star of England: Fortune made his sword;'), ('henry_v_epilogue', 7, 6, 'CHORUS', 'By which the world’s best garden he achieved,'), ('henry_v_epilogue', 8, 7, 'CHORUS', 'And of it left his son imperial lord.'), ('henry_v_epilogue', 9, 8, 'CHORUS', 'Henry the Sixth, in infant bands crown’d King'), ('henry_v_epilogue', 10, 9, 'CHORUS', 'Of France and England, did this king succeed;'), ('henry_v_epilogue', 11, 10, 'CHORUS', 'Whose state so many had the managing,'), ('henry_v_epilogue', 12, 11, 'CHORUS', 'That they lost France and made his England bleed:'), ('henry_v_epilogue', 13, 12, 'CHORUS', 'Which oft our stage hath shown; and, for their sake,'), ('henry_v_epilogue', 14, 13, 'CHORUS', 'In your fair minds let this acceptance take.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('henry_v_prologue', 1, 0, 'CHORUS', 'O for a Muse of fire, that would ascend'), ('henry_v_prologue', 2, 1, 'CHORUS', 'The brightest heaven of invention,'), ('henry_v_prologue', 3, 2, 'CHORUS', 'A kingdom for a stage, princes to act'), ('henry_v_prologue', 4, 3, 'CHORUS', 'And monarchs to behold the swelling scene!'), ('henry_v_prologue', 5, 4, 'CHORUS', 'Then should the warlike Harry, like himself,'), ('henry_v_prologue', 6, 5, 'CHORUS', 'Assume the port of Mars; and at his heels,'), ('henry_v_prologue', 7, 6, 'CHORUS', 'Leash’d in like hounds, should famine, sword and fire'), ('henry_v_prologue', 8, 7, 'CHORUS', 'Crouch for employment. But pardon, gentles all,'), ('henry_v_prologue', 9, 8, 'CHORUS', 'The flat unraised spirits that hath dared'), ('henry_v_prologue', 10, 9, 'CHORUS', 'On this unworthy scaffold to bring forth'), ('henry_v_prologue', 11, 10, 'CHORUS', 'So great an object: can this cockpit hold'), ('henry_v_prologue', 12, 11, 'CHORUS', 'The vasty fields of France? or may we cram'), ('henry_v_prologue', 13, 12, 'CHORUS', 'Within this wooden O the very casques'), ('henry_v_prologue', 14, 13, 'CHORUS', 'That did affright the air at Agincourt?'), ('henry_v_prologue', 15, 14, 'CHORUS', 'O pardon! since a crooked figure may'), ('henry_v_prologue', 16, 15, 'CHORUS', 'Attest in little place a million;'), ('henry_v_prologue', 17, 16, 'CHORUS', 'And let us, ciphers to this great accompt,'), ('henry_v_prologue', 18, 17, 'CHORUS', 'On your imaginary forces work.'), ('henry_v_prologue', 19, 18, 'CHORUS', 'Suppose within the girdle of these walls'), ('henry_v_prologue', 20, 19, 'CHORUS', 'Are now confined two mighty monarchies,'), ('henry_v_prologue', 21, 20, 'CHORUS', 'Whose high upreared and abutting fronts'), ('henry_v_prologue', 22, 21, 'CHORUS', 'The perilous narrow ocean parts asunder:'), ('henry_v_prologue', 23, 22, 'CHORUS', 'Piece out our imperfections with your thoughts;'), ('henry_v_prologue', 24, 23, 'CHORUS', 'Into a thousand parts divide one man,'), ('henry_v_prologue', 25, 24, 'CHORUS', 'And make imaginary puissance;'), ('henry_v_prologue', 26, 25, 'CHORUS', 'Think, when we talk of horses, that you see them'), ('henry_v_prologue', 27, 26, 'CHORUS', 'Printing their proud hoofs i’ the receiving earth;'), ('henry_v_prologue', 28, 27, 'CHORUS', 'For ’tis your thoughts that now must deck our kings,'), ('henry_v_prologue', 29, 28, 'CHORUS', 'Carry them here and there; jumping o’er times,'), ('henry_v_prologue', 30, 29, 'CHORUS', 'Turning the accomplishment of many years'), ('henry_v_prologue', 31, 30, 'CHORUS', 'Into an hourglass: for the which supply,'), ('henry_v_prologue', 32, 31, 'CHORUS', 'Admit me Chorus to this history;'), ('henry_v_prologue', 33, 32, 'CHORUS', 'Who prologue-like your humble patience pray,'), ('henry_v_prologue', 34, 33, 'CHORUS', 'Gently to hear, kindly to judge, our play.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act1_scene1', 0, 'Enter the Archbishop of Canterbury, and the Bishop of Ely.'), ('henry_v_act1_scene1', 97, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act1_scene2', 0, 'Enter King Henry, Gloucester, Bedford, Exeter, Warwick, Westmoreland, and Attendants.'), ('henry_v_act1_scene2', 6, 'Enter the Archbishop of Canterbury and the Bishop of Ely.'), ('henry_v_act1_scene2', 220, 'Exeunt some Attendants.'), ('henry_v_act1_scene2', 232, 'Enter Ambassadors of France.'), ('henry_v_act1_scene2', 232, 'Now are we well prepared to know the pleasure Of our fair cousin Dauphin; for we hear Your greeting is from him, not from the king.'), ('henry_v_act1_scene2', 293, 'Exeunt Ambassadors.'), ('henry_v_act1_scene2', 306, 'Exeunt. Flourish.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act2_chorus', 0, 'Flourish. Enter Chorus.'), ('henry_v_act2_chorus', 0, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act2_scene1', 0, 'Enter Corporal Nym and Lieutenant Bardolph.'), ('henry_v_act2_scene1', 22, 'Enter Pistol and Hostess.'), ('henry_v_act2_scene1', 56, 'Draws.'), ('henry_v_act2_scene1', 70, 'Enter the Boy.'), ('henry_v_act2_scene1', 76, 'Exeunt Hostess and Boy.'), ('henry_v_act2_scene1', 97, 'Reenter Hostess.'), ('henry_v_act2_scene1', 106, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act2_scene2', 0, 'Enter Exeter, Bedford and Westmoreland.'), ('henry_v_act2_scene2', 11, 'Trumpets sound. Enter King Henry, Scroop, Cambridge, Grey, and Attendants.'), ('henry_v_act2_scene2', 176, 'Exeunt Cambridge, Scroop and Grey, guarded.'), ('henry_v_act2_scene2', 188, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act2_scene3', 0, 'Enter Pistol, Hostess, Nym, Bardolph and Boy.'), ('henry_v_act2_scene3', 51, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act2_scene4', 0, 'Flourish. Enter the French King, the Dauphin, the Dukes of Berri and Brittagne, the Constable, and others.'), ('henry_v_act2_scene4', 64, 'Enter a Messenger.'), ('henry_v_act2_scene4', 67, 'Exeunt Messenger and certain Lords.'), ('henry_v_act2_scene4', 75, 'Reenter Lords, with Exeter and train.'), ('henry_v_act2_scene4', 146, 'Flourish. Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act3_chorus', 0, 'Enter Chorus.'), ('henry_v_act3_chorus', 0, 'Alarum, and chambers go off.'), ('henry_v_act3_chorus', 0, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act3_scene1', 0, 'Alarum. Enter King Henry, Exeter, Bedford, Gloucester and Soldiers, with scaling-ladders.'), ('henry_v_act3_scene1', 34, 'Exeunt. Alarum, and chambers go off.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act3_scene2', 0, 'Enter Nym, Bardolph, Pistol and Boy.'), ('henry_v_act3_scene2', 16, 'Enter Fluellen.'), ('henry_v_act3_scene2', 22, 'Exeunt all but Boy.'), ('henry_v_act3_scene2', 44, 'Exit.'), ('henry_v_act3_scene2', 44, 'Reenter Fluellen, Gower following.'), ('henry_v_act3_scene2', 62, 'Enter Macmorris and Captain Jamy.'), ('henry_v_act3_scene2', 116, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act3_scene3', 0, 'The Governor and some Citizens on the walls; the English forces below. Enter King Henry and his train.'), ('henry_v_act3_scene3', 57, 'Flourish. The King and his train enter the town.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act3_scene4', 0, 'Enter Katharine and Alice.'), ('henry_v_act3_scene4', 42, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act3_scene5', 0, 'Enter the King of France, the Dauphin, the Duke of Bourbon, the Constable of France, and others.'), ('henry_v_act3_scene5', 67, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act3_scene6', 0, 'Enter Gower and Fluellen, meeting.'), ('henry_v_act3_scene6', 13, 'Enter Pistol.'), ('henry_v_act3_scene6', 49, 'Exit.'), ('henry_v_act3_scene6', 72, 'Drum heard.'), ('henry_v_act3_scene6', 72, 'Drum and colours. Enter King Henry, Gloucester and Soldiers.'), ('henry_v_act3_scene6', 72, 'God bless your majesty!'), ('henry_v_act3_scene6', 92, 'Tucket. Enter Montjoy.'), ('henry_v_act3_scene6', 141, 'Exit.'), ('henry_v_act3_scene6', 146, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act3_scene7', 0, 'Enter the Constable of France, the Lord Rambures, Orleans, Dauphin with others.'), ('henry_v_act3_scene7', 70, 'Exit.'), ('henry_v_act3_scene7', 93, 'Enter a Messenger.'), ('henry_v_act3_scene7', 117, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act4_chorus', 0, 'Enter Chorus.'), ('henry_v_act4_chorus', 0, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act4_scene1', 0, 'Enter King Henry, Bedford, and Gloucester.'), ('henry_v_act4_scene1', 12, 'Enter Erpingham.'), ('henry_v_act4_scene1', 12, 'Good morrow, old Sir Thomas Erpingham: A good soft pillow for that good white head Were better than a churlish turf of France.'), ('henry_v_act4_scene1', 29, 'Exeunt all but King.'), ('henry_v_act4_scene1', 30, 'Enter Pistol.'), ('henry_v_act4_scene1', 52, 'Exit.'), ('henry_v_act4_scene1', 52, 'Enter Fluellen and Gower.'), ('henry_v_act4_scene1', 68, 'Exeunt Gower and Fluellen.'), ('henry_v_act4_scene1', 70, 'Enter three soldiers, John Bates, Alexander Court, and Michael Williams.'), ('henry_v_act4_scene1', 187, 'Exeunt Soldiers.'), ('henry_v_act4_scene1', 187, 'Upon the king! let us our lives, our souls, Our debts, our careful wives, Our children and our sins lay on the king! We must bear all. O hard condition, Twin-born with greatness, subject to the breath Of every fool, whose sense no more can feel But his own wringing! What infinite heart’s-ease Must kings neglect, that private men enjoy! And what have kings, that privates have not too, Save ceremony, save general ceremony? And what art thou, thou idol ceremony? What kind of god art thou, that suffer’st more Of mortal griefs than do thy worshippers? What are thy rents? what are thy comings in? O ceremony, show me but thy worth! What is thy soul of adoration? Art thou aught else but place, degree and form, Creating awe and fear in other men? Wherein thou art less happy being fear’d Than they in fearing. What drink’st thou oft, instead of homage sweet, But poison’d flattery? O, be sick, great greatness, And bid thy ceremony give thee cure! Think’st thou the fiery fever will go out With titles blown from adulation? Will it give place to flexure and low bending? Canst thou, when thou command’st the beggar’s knee, Command the health of it? No, thou proud dream, That play’st so subtly with a king’s repose; I am a king that find thee, and I know ’Tis not the balm, the sceptre and the ball, The sword, the mace, the crown imperial, The intertissued robe of gold and pearl, The farced title running ’fore the king, The throne he sits on, nor the tide of pomp That beats upon the high shore of this world, No, not all these, thrice-gorgeous ceremony, Not all these, laid in bed majestical, Can sleep so soundly as the wretched slave, Who with a body fill’d and vacant mind Gets him to rest, cramm’d with distressful bread; Never sees horrid night, the child of hell, But, like a lackey, from the rise to set Sweats in the eye of Phoebus and all night Sleeps in Elysium; next day after dawn, Doth rise and help Hyperion to his horse, And follows so the ever-running year, With profitable labour, to his grave: And, but for ceremony, such a wretch, Winding up days with toil and nights with sleep, Had the forehand and vantage of a king. The slave, a member of the country’s peace, Enjoys it; but in gross brain little wots What watch the king keeps to maintain the peace, Whose hours the peasant best advantages.'), ('henry_v_act4_scene1', 187, 'Enter Erpingham.'), ('henry_v_act4_scene1', 192, 'Exit.'), ('henry_v_act4_scene1', 209, 'Enter Gloucester.'), ('henry_v_act4_scene1', 212, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act4_scene2', 0, 'Enter the Dauphin, Orleans, Rambures, and others.'), ('henry_v_act4_scene2', 4, 'Enter Constable.'), ('henry_v_act4_scene2', 4, 'Now, my lord constable!'), ('henry_v_act4_scene2', 10, 'Enter a Messenger.'), ('henry_v_act4_scene2', 34, 'Enter Grandpré.'), ('henry_v_act4_scene2', 60, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act4_scene3', 0, 'Enter Gloucester, Bedford, Exeter, Erpingham, with all his host: Salisbury and Westmoreland.'), ('henry_v_act4_scene3', 14, 'Exit Salisbury.'), ('henry_v_act4_scene3', 16, 'Enter the King.'), ('henry_v_act4_scene3', 67, 'Enter Salisbury.'), ('henry_v_act4_scene3', 78, 'Tucket. Enter Montjoy.'), ('henry_v_act4_scene3', 127, 'Exit.'), ('henry_v_act4_scene3', 128, 'Enter York.'), ('henry_v_act4_scene3', 132, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act4_scene4', 0, 'Alarum. Excursions. Enter Pistol, French Soldier, and Boy.'), ('henry_v_act4_scene4', 60, 'Exeunt Pistol and French Soldier.'), ('henry_v_act4_scene4', 60, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act4_scene5', 0, 'Enter Constable, Orleans, Bourbon, Dauphin, and Rambures.'), ('henry_v_act4_scene5', 23, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act4_scene6', 0, 'Alarums. Enter King Henry, and forces, Exeter, and others.'), ('henry_v_act4_scene6', 38, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act4_scene7', 0, 'Enter Fluellen and Gower.'), ('henry_v_act4_scene7', 42, 'Alarum. Enter King Henry and forces; Warwick, Gloucester, Exeter, and others.'), ('henry_v_act4_scene7', 53, 'Enter Montjoy.'), ('henry_v_act4_scene7', 101, 'Points to Williams. Exeunt Heralds with Montjoy.'), ('henry_v_act4_scene7', 126, 'Exit.'), ('henry_v_act4_scene7', 140, 'Exit.'), ('henry_v_act4_scene7', 154, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act4_scene8', 0, 'Enter Gower and Williams.'), ('henry_v_act4_scene8', 1, 'Enter Fluellen.'), ('henry_v_act4_scene8', 6, 'Strikes him.'), ('henry_v_act4_scene8', 13, 'Enter Warwick and Gloucester.'), ('henry_v_act4_scene8', 17, 'Enter King Henry and Exeter.'), ('henry_v_act4_scene8', 57, 'Enter an English Herald.'), ('henry_v_act4_scene8', 110, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act5_chorus', 0, 'Enter Chorus.'), ('henry_v_act5_chorus', 0, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act5_scene1', 0, 'Enter Fluellen and Gower.'), ('henry_v_act5_scene1', 11, 'Enter Pistol.'), ('henry_v_act5_scene1', 25, 'Strikes him.'), ('henry_v_act5_scene1', 31, 'Strikes him.'), ('henry_v_act5_scene1', 52, 'Exit.'), ('henry_v_act5_scene1', 61, 'Exit.'), ('henry_v_act5_scene1', 71, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_act5_scene2', 0, 'Enter, at one door, King Henry, Exeter, Bedford, Gloucester, Warwick, Westmoreland, and other Lords; at another, the French King, Queen Isabel, the Princess Katharine, Alice, and other Ladies; the Duke of Burgundy, and his train.'), ('henry_v_act5_scene2', 96, 'Exeunt all except Henry, Katharine, and Alice.'), ('henry_v_act5_scene2', 243, 'Reenter the French King and his Queen, Burgundy, and other Lords.'), ('henry_v_act5_scene2', 304, 'Flourish.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_epilogue', 0, 'Enter Chorus.'), ('henry_v_epilogue', 0, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('henry_v_prologue', 0, 'Enter Chorus.'), ('henry_v_prologue', 0, 'Exit.');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act1_scene1_gloss1', 'henry_v_act1_scene1', 1, 'self bill', 'same bill — a parliamentary measure that would strip the Church of lands'), ('henry_v_act1_scene1_gloss2', 'henry_v_act1_scene1', 4, 'scambling', 'turbulent; disorderly'), ('henry_v_act1_scene1_gloss3', 'henry_v_act1_scene1', 9, 'temporal lands', 'secular holdings — Church-owned estates granted to the Crown'), ('henry_v_act1_scene1_gloss4', 'henry_v_act1_scene1', 13, 'full fifteen earls', 'enough to support fifteen earls'), ('henry_v_act1_scene1_gloss5', 'henry_v_act1_scene1', 69, 'mitigation', 'softening; relief'), ('henry_v_act1_scene1_gloss6', 'henry_v_act1_scene1', 23, 'true lover of the Holy Church', 'a sincere defender of the Church — part of the play''s early portrait of a reformed Henry'), ('henry_v_act1_scene1_gloss7', 'henry_v_act1_scene1', 28, 'Consideration', 'moral reflection'), ('henry_v_act1_scene1_gloss8', 'henry_v_act1_scene1', 35, 'Hydra-headed wilfulness', 'a wilfulness with many heads like the Lernaean Hydra — stubbornness that grows back when cut off'), ('henry_v_act1_scene1_gloss9', 'henry_v_act1_scene1', 46, 'Gordian knot', 'famously intricate knot cut by Alexander the Great — an image of a problem solved by force rather than untangling'), ('henry_v_act1_scene1_gloss10', 'henry_v_act1_scene1', 45, 'cause of policy', 'matter of statecraft'), ('henry_v_act1_scene1_gloss11', 'henry_v_act1_scene1', 53, 'grace', 'divine favor'), ('henry_v_act1_scene1_gloss12', 'henry_v_act1_scene1', 65, 'crescive in his faculty', 'growing through its own capacity — the medieval idea that souls develop by their own principle'), ('henry_v_act1_scene1_gloss13', 'henry_v_act1_scene1', 84, 'fain', 'gladly'), ('henry_v_act1_scene1_gloss14', 'henry_v_act1_scene1', 91, 'audience', 'formal hearing with the King');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act1_scene2_gloss1', 'henry_v_act1_scene2', 1, 'Where is my gracious Lord of Canterbury', 'Henry summons the Archbishop — the scene''s legal consultation begins'), ('henry_v_act1_scene2_gloss2', 'henry_v_act1_scene2', 4, 'resolved', 'fully informed; settled in mind'), ('henry_v_act1_scene2_gloss3', 'henry_v_act1_scene2', 10, 'justly and religiously', 'in accordance with law and conscience'), ('henry_v_act1_scene2_gloss4', 'henry_v_act1_scene2', 11, 'law Salique', 'Salic Law — the Frankish legal tradition used to bar royal inheritance through the female line, invoked here against Henry''s claim'), ('henry_v_act1_scene2_gloss5', 'henry_v_act1_scene2', 14, 'fashion', 'shape; misrepresent'), ('henry_v_act1_scene2_gloss6', 'henry_v_act1_scene2', 15, 'Or nicely charge your understanding soul', 'or subtly burden your conscience'), ('henry_v_act1_scene2_gloss7', 'henry_v_act1_scene2', 21, 'impawn', 'pledge; stake'), ('henry_v_act1_scene2_gloss8', 'henry_v_act1_scene2', 19, 'approbation', 'authoritative sanction'), ('henry_v_act1_scene2_gloss9', 'henry_v_act1_scene2', 28, 'waste in brief mortality', 'is quickly spent in short human lives'), ('henry_v_act1_scene2_gloss10', 'henry_v_act1_scene2', 29, 'conjuration', 'solemn appeal'), ('henry_v_act1_scene2_gloss11', 'henry_v_act1_scene2', 38, 'In terram Salicam mulieres ne succedant', 'Latin: ''Into the Salic land let no women succeed'' — the legal tag at the heart of Canterbury''s speech'), ('henry_v_act1_scene2_gloss12', 'henry_v_act1_scene2', 37, 'Pharamond', 'legendary founding king of the Franks, to whom the Salic Law was fictitiously attributed'), ('henry_v_act1_scene2_gloss13', 'henry_v_act1_scene2', 45, 'the floods of Sala and of Elbe', 'the Saale and Elbe rivers — German waterways central to Canterbury''s geography lesson'), ('henry_v_act1_scene2_gloss14', 'henry_v_act1_scene2', 46, 'Charles the Great', 'Charlemagne (742–814) — king of the Franks and Holy Roman Emperor'), ('henry_v_act1_scene2_gloss15', 'henry_v_act1_scene2', 69, 'Hugh Capet', 'founder of the Capetian dynasty of French kings (d. 996)'), ('henry_v_act1_scene2_gloss16', 'henry_v_act1_scene2', 69, 'usurp’d the crown', 'took the throne unlawfully — Canterbury is systematically questioning French royal legitimacy'), ('henry_v_act1_scene2_gloss17', 'henry_v_act1_scene2', 77, 'Lewis the Tenth', 'Louis X of France (r. 1314–1316) — Canterbury''s test case for inherited female right'), ('henry_v_act1_scene2_gloss18', 'henry_v_act1_scene2', 65, 'Pepin', 'Pepin the Short — Charlemagne''s father, another Carolingian claim cited'), ('henry_v_act1_scene2_gloss19', 'henry_v_act1_scene2', 98, 'Book of Numbers', 'Old Testament citation (Numbers 27:8) permitting daughters to inherit in the absence of sons — Canterbury''s biblical trump card'), ('henry_v_act1_scene2_gloss20', 'henry_v_act1_scene2', 100, 'Gracious lord', 'formal address to the King'), ('henry_v_act1_scene2_gloss21', 'henry_v_act1_scene2', 116, 'puissant', 'mighty'), ('henry_v_act1_scene2_gloss22', 'henry_v_act1_scene2', 244, 'Edward the Third', 'English king (r. 1327–1377) whose French claim is the historical basis for Henry''s'), ('henry_v_act1_scene2_gloss23', 'henry_v_act1_scene2', 105, 'Black Prince', 'Edward of Woodstock, Edward III''s eldest son — hero of Crécy (1346) and Poitiers (1356)'), ('henry_v_act1_scene2_gloss24', 'henry_v_act1_scene2', 138, 'Scot', 'Scottish raider — Canterbury shifts to the problem of border defense'), ('henry_v_act1_scene2_gloss25', 'henry_v_act1_scene2', 169, 'weasel Scot', 'the Scots pictured as a weasel — a small predator that attacks while the lion is away'), ('henry_v_act1_scene2_gloss26', 'henry_v_act1_scene2', 168, 'eagle England', 'England as an eagle — imperial, predatory'), ('henry_v_act1_scene2_gloss27', 'henry_v_act1_scene2', 171, 'cat', 'Canterbury''s proverb: when the cat''s away, the mice will play — if the king goes to France, the Scots will invade'), ('henry_v_act1_scene2_gloss28', 'henry_v_act1_scene2', 186, 'honey-bees', 'Exeter''s famous extended simile of the commonwealth as a beehive — kingdom ordered like a hive'), ('henry_v_act1_scene2_gloss29', 'henry_v_act1_scene2', 190, 'magistrates', 'officials administering justice'), ('henry_v_act1_scene2_gloss30', 'henry_v_act1_scene2', 199, 'mechanic porters', 'manual laborers; common workmen'), ('henry_v_act1_scene2_gloss31', 'henry_v_act1_scene2', 195, 'tent-royal', 'royal pavilion — here, the queen bee''s central cell'), ('henry_v_act1_scene2_gloss32', 'henry_v_act1_scene2', 241, 'Dauphin', 'title of the French crown prince (pronounced DOH-fan) — equivalent to the English Prince of Wales'), ('henry_v_act1_scene2_gloss33', 'henry_v_act1_scene2', 251, 'tun of treasure', 'a cask of valuables — the gift from the Dauphin, which turns out to be insulting'), ('henry_v_act1_scene2_gloss34', 'henry_v_act1_scene2', 254, 'tennis-balls', 'the Dauphin''s mocking gift — Henry''s youthful reputation reduced to a children''s game'), ('henry_v_act1_scene2_gloss35', 'henry_v_act1_scene2', 262, 'chases', 'tennis term — a point remembered but not yet scored, awaiting a second stroke; Henry turns the Dauphin''s taunt back on him'), ('henry_v_act1_scene2_gloss36', 'henry_v_act1_scene2', 260, 'wrangler', 'disputant; opponent'), ('henry_v_act1_scene2_gloss37', 'henry_v_act1_scene2', 278, 'gun-stones', 'cannonballs — the tennis balls reimagined as weapons'), ('henry_v_act1_scene2_gloss38', 'henry_v_act1_scene2', 275, 'dazzle all the eyes of France', 'blind the French with English arms'), ('henry_v_act1_scene2_gloss39', 'henry_v_act1_scene2', 282, 'mock mothers from their sons', 'widow them of their children by war'), ('henry_v_act1_scene2_gloss40', 'henry_v_act1_scene2', 289, 'well-hallow’d cause', 'holy justification — Henry takes the Dauphin''s mockery as moral license');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act2_chorus_gloss1', 'henry_v_act2_chorus', 1, 'youth of England are on fire', 'the young men of England are aflame with martial enthusiasm'), ('henry_v_act2_chorus_gloss2', 'henry_v_act2_chorus', 2, 'silken dalliance', 'soft, idle love-making — silken courtly pleasure'), ('henry_v_act2_chorus_gloss3', 'henry_v_act2_chorus', 3, 'armourers', 'makers and repairers of armour — the war-industry booms'), ('henry_v_act2_chorus_gloss4', 'henry_v_act2_chorus', 5, 'sell the pasture now to buy the horse', 'sell farmland to buy warhorses — economic re-tooling for war'), ('henry_v_act2_chorus_gloss5', 'henry_v_act2_chorus', 6, 'mirror of all Christian kings', 'the model of Christian kingship — Henry as the era''s royal paragon'), ('henry_v_act2_chorus_gloss6', 'henry_v_act2_chorus', 7, 'winged heels', 'winged feet — the attribute of Mercury, the Roman messenger god'), ('henry_v_act2_chorus_gloss7', 'henry_v_act2_chorus', 7, 'English Mercuries', 'Englishmen imagined as Mercury — swift and divinely errand-bound'), ('henry_v_act2_chorus_gloss8', 'henry_v_act2_chorus', 8, 'Expectation', 'personified anticipation — the air of coming battle'), ('henry_v_act2_chorus_gloss9', 'henry_v_act2_chorus', 10, 'crowns imperial, crowns and coronets', 'the three ranks of royal headgear — imperial crowns, kingly crowns, noble coronets'), ('henry_v_act2_chorus_gloss10', 'henry_v_act2_chorus', 14, 'pale policy', 'cowardly statecraft — ''pale'' = fearful'), ('henry_v_act2_chorus_gloss11', 'henry_v_act2_chorus', 17, 'Like little body with a mighty heart', 'small in body but great in spirit — the emerging myth of England''s scale'), ('henry_v_act2_chorus_gloss12', 'henry_v_act2_chorus', 21, 'nest of hollow bosoms', 'a colony of hollow (treacherous) hearts — the traitors'), ('henry_v_act2_chorus_gloss13', 'henry_v_act2_chorus', 22, 'treacherous crowns', 'French gold coins paid as bribes — ''crowns'' puns on coins and kingly heads'), ('henry_v_act2_chorus_gloss14', 'henry_v_act2_chorus', 23, 'Richard Earl of Cambridge', 'the first traitor, Richard of Conisburgh — historically motivated by the Mortimer claim, not the French bribe the play emphasizes'), ('henry_v_act2_chorus_gloss15', 'henry_v_act2_chorus', 24, 'Henry Lord Scroop of Masham', 'the second traitor — Henry''s former intimate'), ('henry_v_act2_chorus_gloss16', 'henry_v_act2_chorus', 25, 'Sir Thomas Grey', 'the third traitor — a Northumberland knight'), ('henry_v_act2_chorus_gloss17', 'henry_v_act2_chorus', 26, 'gilt of France', 'France''s gold — with a pun on ''guilt'' in the next line'), ('henry_v_act2_chorus_gloss18', 'henry_v_act2_chorus', 28, 'grace of kings', 'Henry, the ornament of kings'), ('henry_v_act2_chorus_gloss19', 'henry_v_act2_chorus', 31, 'digest', 'arrange; compose'), ('henry_v_act2_chorus_gloss20', 'henry_v_act2_chorus', 32, 'abuse of distance', 'the stage-trick of violating real geography'), ('henry_v_act2_chorus_gloss21', 'henry_v_act2_chorus', 34, 'set from London', 'departed from London'), ('henry_v_act2_chorus_gloss22', 'henry_v_act2_chorus', 36, 'playhouse', 'the theatrical space — now imaginatively relocated to Southampton'), ('henry_v_act2_chorus_gloss23', 'henry_v_act2_chorus', 38, 'charming the narrow seas', 'magically calming the Channel — a theatrical spell'), ('henry_v_act2_chorus_gloss24', 'henry_v_act2_chorus', 40, 'offend one stomach', 'cause any seasickness — the Chorus jokes about the stage''s imagined Channel crossing'), ('henry_v_act2_chorus_gloss25', 'henry_v_act2_chorus', 42, 'shift our scene', 'change the location of the action');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act2_scene1_gloss1', 'henry_v_act2_scene1', 1, 'Corporal Nym', '''Nym'' means ''to take/filch'' in Elizabethan slang — his name is a joke about petty theft'), ('henry_v_act2_scene1_gloss2', 'henry_v_act2_scene1', 2, 'Ancient Pistol', '''Ancient'' = ensign, the lowest commissioned officer; Pistol''s name signals noisy bombast'), ('henry_v_act2_scene1_gloss3', 'henry_v_act2_scene1', 5, 'wink', 'shut my eyes'), ('henry_v_act2_scene1_gloss4', 'henry_v_act2_scene1', 5, 'hold out mine iron', 'keep my sword out — Nym''s comic threat'), ('henry_v_act2_scene1_gloss5', 'henry_v_act2_scene1', 7, 'toast cheese', 'the sword is fit only for toasting cheese — a pathetic weapon'), ('henry_v_act2_scene1_gloss6', 'henry_v_act2_scene1', 10, 'sworn brothers', 'men joined by oath in military fellowship'), ('henry_v_act2_scene1_gloss7', 'henry_v_act2_scene1', 14, 'my rest', 'my decision; my settled resolve — gambling term, ''the stakes I reserve'''), ('henry_v_act2_scene1_gloss8', 'henry_v_act2_scene1', 14, 'rendezvous', 'ultimate destination; final resort'), ('henry_v_act2_scene1_gloss9', 'henry_v_act2_scene1', 16, 'Nell Quickly', 'the Hostess of the Boar''s Head tavern, familiar from the Henry IV plays'), ('henry_v_act2_scene1_gloss10', 'henry_v_act2_scene1', 17, 'troth-plight', 'betrothed; formally engaged by oath'), ('henry_v_act2_scene1_gloss11', 'henry_v_act2_scene1', 21, 'patience be a tired mare, yet she will plod', 'Nym''s proverbial locution: even an exhausted horse keeps going'), ('henry_v_act2_scene1_gloss12', 'henry_v_act2_scene1', 24, 'mine host', 'my innkeeper — Bardolph''s familiar address insults Pistol''s new domestic role'), ('henry_v_act2_scene1_gloss13', 'henry_v_act2_scene1', 24, 'Base tike', 'low-bred cur; contemptible dog'), ('henry_v_act2_scene1_gloss14', 'henry_v_act2_scene1', 29, 'keep a bawdy house', 'run a brothel — the Hostess''s anxious euphemism'), ('henry_v_act2_scene1_gloss15', 'henry_v_act2_scene1', 31, 'drawn', 'with sword drawn'), ('henry_v_act2_scene1_gloss16', 'henry_v_act2_scene1', 33, 'Pish!', 'expression of contempt — a hiss of dismissal'), ('henry_v_act2_scene1_gloss17', 'henry_v_act2_scene1', 34, 'Iceland dog', 'a breed of long-haired lap-dog — Pistol insults Nym as a yappy, effete cur'), ('henry_v_act2_scene1_gloss18', 'henry_v_act2_scene1', 34, 'prick-ear’d cur', 'sharp-eared mongrel'), ('henry_v_act2_scene1_gloss19', 'henry_v_act2_scene1', 36, 'shog off', 'clear off; buzz off — Nym''s low slang'), ('henry_v_act2_scene1_gloss20', 'henry_v_act2_scene1', 36, 'solus', 'Latin: ''alone'' — Nym wants a private duel; Pistol mishears it as an insult'), ('henry_v_act2_scene1_gloss21', 'henry_v_act2_scene1', 37, 'egregious', 'outstandingly bad; conspicuous in wickedness'), ('henry_v_act2_scene1_gloss22', 'henry_v_act2_scene1', 38, 'mervailous', 'marvellous — Pistol''s inflated diction'), ('henry_v_act2_scene1_gloss23', 'henry_v_act2_scene1', 40, 'maw', 'stomach; gullet'), ('henry_v_act2_scene1_gloss24', 'henry_v_act2_scene1', 40, 'perdy', 'by God (par Dieu) — mild oath'), ('henry_v_act2_scene1_gloss25', 'henry_v_act2_scene1', 42, 'retort the “solus” in thy bowels', 'hurl the word back into Pistol''s guts — Pistolian bombast'), ('henry_v_act2_scene1_gloss26', 'henry_v_act2_scene1', 43, 'Pistol’s cock is up', 'my pistol''s cocked and ready to fire — with bawdy double-meaning Pistol cultivates'), ('henry_v_act2_scene1_gloss27', 'henry_v_act2_scene1', 45, 'Barbason', 'a demon''s name from contemporary demonology — Nym refuses to be ''conjured'' like a devil'), ('henry_v_act2_scene1_gloss28', 'henry_v_act2_scene1', 45, 'humour', 'Nym''s catchphrase — ''mood'', ''inclination''; he over-uses it comically throughout the scene'), ('henry_v_act2_scene1_gloss29', 'henry_v_act2_scene1', 47, 'scour you with my rapier', 'run you through with my sword — ''scour'' = cleanse by piercing'), ('henry_v_act2_scene1_gloss30', 'henry_v_act2_scene1', 51, 'wight', 'creature; fellow (archaic)'), ('henry_v_act2_scene1_gloss31', 'henry_v_act2_scene1', 53, 'exhale', 'draw (your sword) — Pistol''s Latinate way of saying ''unsheathe'''), ('henry_v_act2_scene1_gloss32', 'henry_v_act2_scene1', 57, 'mickle', 'great; much (archaic/dialect)'), ('henry_v_act2_scene1_gloss33', 'henry_v_act2_scene1', 57, 'fury shall abate', 'my anger will lessen'), ('henry_v_act2_scene1_gloss34', 'henry_v_act2_scene1', 61, 'Couple a gorge', 'Pistol''s butchery of the French ''couper la gorge'' — ''cut the throat'''), ('henry_v_act2_scene1_gloss35', 'henry_v_act2_scene1', 63, 'hound of Crete', 'mock-epic insult — Cretan hounds were proverbially fierce'), ('henry_v_act2_scene1_gloss36', 'henry_v_act2_scene1', 64, 'spital', 'hospital — especially one for the diseased poor, often the pox'), ('henry_v_act2_scene1_gloss37', 'henry_v_act2_scene1', 65, 'powdering-tub of infamy', 'the sweating-tub used to treat venereal disease; by extension, a house of ill repute'), ('henry_v_act2_scene1_gloss38', 'henry_v_act2_scene1', 66, 'lazar', 'leprous beggar; diseased wretch'), ('henry_v_act2_scene1_gloss39', 'henry_v_act2_scene1', 66, 'Cressid’s kind', 'descendants of Cressida — who in Elizabethan tradition ends as a leprous beggar; slang for syphilitic women'), ('henry_v_act2_scene1_gloss40', 'henry_v_act2_scene1', 67, 'Doll Tearsheet', 'a notorious prostitute from Henry IV Part 2 — Pistol re-names the Hostess into her world'), ('henry_v_act2_scene1_gloss41', 'henry_v_act2_scene1', 68, 'quondam Quickly', 'the former Quickly — Latin ''quondam'' = formerly; she is now Pistol''s wife'), ('henry_v_act2_scene1_gloss42', 'henry_v_act2_scene1', 69, 'pauca', 'Latin: ''few (words)'' — enough said'), ('henry_v_act2_scene1_gloss43', 'henry_v_act2_scene1', 73, 'warming-pan', 'a long-handled pan of hot coals to warm a bed — the Boy''s crude joke about Bardolph''s face'), ('henry_v_act2_scene1_gloss44', 'henry_v_act2_scene1', 75, 'yield the crow a pudding', 'give the crow his meal — i.e. die, so the crows can feed on him'), ('henry_v_act2_scene1_gloss45', 'henry_v_act2_scene1', 80, 'eight shillings', 'the debt Pistol owes Nym from a wager — the quarrel''s actual trigger'), ('henry_v_act2_scene1_gloss46', 'henry_v_act2_scene1', 81, 'Base is the slave that pays', 'Pistol''s motto: only slaves pay their debts; gentlemen don''t'), ('henry_v_act2_scene1_gloss47', 'henry_v_act2_scene1', 83, 'As manhood shall compound', 'let our manhood settle it; let swordplay decide'), ('henry_v_act2_scene1_gloss48', 'henry_v_act2_scene1', 90, 'noble', 'a gold coin worth roughly six shillings eightpence'), ('henry_v_act2_scene1_gloss49', 'henry_v_act2_scene1', 94, 'sutler', 'army camp-follower who sells food and drink to soldiers'), ('henry_v_act2_scene1_gloss50', 'henry_v_act2_scene1', 99, 'burning quotidian tertian', 'the Hostess''s malapropism — ''quotidian'' (daily fever) and ''tertian'' (every third day) are contradictory; she means he has a raging fever'), ('henry_v_act2_scene1_gloss51', 'henry_v_act2_scene1', 103, 'fracted and corroborate', 'broken and corroborated (confirmed) — Pistol means ''broken''; he doesn''t know what ''corroborate'' means'), ('henry_v_act2_scene1_gloss52', 'henry_v_act2_scene1', 105, 'passes some humours and careers', 'gives vent to some moods and outbursts — Nym jargon; ''careers'' = runs'), ('henry_v_act2_scene1_gloss53', 'henry_v_act2_scene1', 106, 'condole', 'sympathize with; mourn for'), ('henry_v_act2_scene1_gloss54', 'henry_v_act2_scene1', 106, 'lambkins', 'little lambs — Pistol''s incongruously tender address');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act2_scene2_gloss1', 'henry_v_act2_scene2', 6, 'note', 'knowledge; information'), ('henry_v_act2_scene2_gloss2', 'henry_v_act2_scene2', 7, 'interception', 'letters secretly intercepted by Henry''s agents'), ('henry_v_act2_scene2_gloss3', 'henry_v_act2_scene2', 8, 'bedfellow', 'intimate companion — in period, sharing a bed denoted extraordinary closeness; Scroop had been Henry''s confidant'), ('henry_v_act2_scene2_gloss4', 'henry_v_act2_scene2', 9, 'dull’d and cloy’d', 'surfeited; satiated to dullness'), ('henry_v_act2_scene2_gloss5', 'henry_v_act2_scene2', 10, 'foreign purse', 'bribery from abroad — French gold'), ('henry_v_act2_scene2_gloss6', 'henry_v_act2_scene2', 12, 'Now sits the wind fair', 'the wind is favorable — naval idiom for good sailing weather'), ('henry_v_act2_scene2_gloss7', 'henry_v_act2_scene2', 12, 'aboard', 'onto the ship'), ('henry_v_act2_scene2_gloss8', 'henry_v_act2_scene2', 19, 'liege', 'lord to whom allegiance is owed'), ('henry_v_act2_scene2_gloss9', 'henry_v_act2_scene2', 33, 'office of our hand', 'duty of our hand — kingly reward-giving'), ('henry_v_act2_scene2_gloss10', 'henry_v_act2_scene2', 34, 'quittance of desert and merit', 'repayment of what is deserved'), ('henry_v_act2_scene2_gloss11', 'henry_v_act2_scene2', 36, 'steeled sinews', 'muscles hardened like steel'), ('henry_v_act2_scene2_gloss12', 'henry_v_act2_scene2', 40, 'Enlarge', 'set free; release from custody'), ('henry_v_act2_scene2_gloss13', 'henry_v_act2_scene2', 41, 'rail’d against our person', 'cursed the king aloud'), ('henry_v_act2_scene2_gloss14', 'henry_v_act2_scene2', 44, 'too much security', 'too much freedom from consequence'), ('henry_v_act2_scene2_gloss15', 'henry_v_act2_scene2', 46, 'Breed, by his sufferance, more of such a kind', 'let his being spared breed more like him'), ('henry_v_act2_scene2_gloss16', 'henry_v_act2_scene2', 53, 'heavy orisons', 'weighty prayers — ''orisons'' = prayers (already glossed in Hamlet)'), ('henry_v_act2_scene2_gloss17', 'henry_v_act2_scene2', 54, 'distemper', 'temporary illness of mood; here, drunkenness'), ('henry_v_act2_scene2_gloss18', 'henry_v_act2_scene2', 55, 'wink’d at', 'overlooked; ignored'), ('henry_v_act2_scene2_gloss19', 'henry_v_act2_scene2', 61, 'late commissioners', 'officials recently appointed'), ('henry_v_act2_scene2_gloss20', 'henry_v_act2_scene2', 64, 'Richard Earl of Cambridge', 'the traitor named in the Act II chorus — given his ''commission'' papers by Henry'), ('henry_v_act2_scene2_gloss21', 'henry_v_act2_scene2', 70, 'lose so much complexion', 'lose so much color from your faces'), ('henry_v_act2_scene2_gloss22', 'henry_v_act2_scene2', 72, 'Their cheeks are paper', 'their faces have turned white as paper'), ('henry_v_act2_scene2_gloss23', 'henry_v_act2_scene2', 73, 'cowarded and chased your blood', 'frightened your blood out of your faces'), ('henry_v_act2_scene2_gloss24', 'henry_v_act2_scene2', 87, 'light crowns', 'light-weight gold coins — punning on lightness of mind; a trifling sum'), ('henry_v_act2_scene2_gloss25', 'henry_v_act2_scene2', 88, 'practices of France', 'secret schemes of France'), ('henry_v_act2_scene2_gloss26', 'henry_v_act2_scene2', 89, 'Hampton', 'Southampton — Henry''s staging-port for the invasion'), ('henry_v_act2_scene2_gloss27', 'henry_v_act2_scene2', 93, 'Ingrateful', 'ungrateful'), ('henry_v_act2_scene2_gloss28', 'henry_v_act2_scene2', 95, 'bottom of my soul', 'deepest recesses of my spirit'), ('henry_v_act2_scene2_gloss29', 'henry_v_act2_scene2', 96, 'coin’d me into gold', 'stamped me as a coin — used me as a mint for his own enrichment'), ('henry_v_act2_scene2_gloss30', 'henry_v_act2_scene2', 104, 'yoke-devils', 'devils paired in harness — treason and murder as twin oxen'), ('henry_v_act2_scene2_gloss31', 'henry_v_act2_scene2', 106, 'admiration did not whoop at them', 'astonishment did not hoot at them — they worked so smoothly that nothing cried out'), ('henry_v_act2_scene2_gloss32', 'henry_v_act2_scene2', 110, 'preposterously', 'against natural order; perversely'), ('henry_v_act2_scene2_gloss33', 'henry_v_act2_scene2', 111, 'got the voice in hell for excellence', 'been voted hell''s prize for performance'), ('henry_v_act2_scene2_gloss34', 'henry_v_act2_scene2', 115, 'glistering semblances of piety', 'shining appearances of holiness — false-religious disguises'), ('henry_v_act2_scene2_gloss35', 'henry_v_act2_scene2', 116, 'temper’d thee', 'tuned you like a musical instrument; shaped your mind'), ('henry_v_act2_scene2_gloss36', 'henry_v_act2_scene2', 117, 'no instance', 'no reason; no pretext'), ('henry_v_act2_scene2_gloss37', 'henry_v_act2_scene2', 121, 'vasty Tartar', 'the vast underworld — Tartarus, the classical hell'), ('henry_v_act2_scene2_gloss38', 'henry_v_act2_scene2', 123, 'easy as that Englishman’s', 'as easy to win as that Englishman''s soul — Henry''s bitter irony'), ('henry_v_act2_scene2_gloss39', 'henry_v_act2_scene2', 125, 'sweetness of affiance', 'sweetness of trust; the pleasure of confiding'), ('henry_v_act2_scene2_gloss40', 'henry_v_act2_scene2', 129, 'spare in diet', 'moderate in eating — a mark of discipline'), ('henry_v_act2_scene2_gloss41', 'henry_v_act2_scene2', 132, 'Garnish’d and deck’d in modest complement', 'adorned and decorated with modest bearing'), ('henry_v_act2_scene2_gloss42', 'henry_v_act2_scene2', 134, 'purged judgement', 'purified, disciplined judgment'), ('henry_v_act2_scene2_gloss43', 'henry_v_act2_scene2', 135, 'finely bolted', 'finely sifted — ''bolting'' = sieving flour'), ('henry_v_act2_scene2_gloss44', 'henry_v_act2_scene2', 137, 'full-fraught man', 'the fully-accomplished man — loaded with virtues like a cargo ship'), ('henry_v_act2_scene2_gloss45', 'henry_v_act2_scene2', 137, 'best indued', 'most richly endowed'), ('henry_v_act2_scene2_gloss46', 'henry_v_act2_scene2', 140, 'Another fall of man', 'a second Fall — Scroop''s betrayal echoes Adam''s; Henry invokes Christian original sin'), ('henry_v_act2_scene2_gloss47', 'henry_v_act2_scene2', 143, 'I arrest thee of high treason', 'formal arrest-phrase — ''of'' means ''on the charge of'''), ('henry_v_act2_scene2_gloss48', 'henry_v_act2_scene2', 164, 'golden earnest', 'gold given as down-payment; bribe money'), ('henry_v_act2_scene2_gloss49', 'henry_v_act2_scene2', 170, 'tender', 'care for; protect'), ('henry_v_act2_scene2_gloss50', 'henry_v_act2_scene2', 183, 'every rub is smoothed', 'every obstacle is removed — ''rub'' = impediment, originally from bowls'), ('henry_v_act2_scene2_gloss51', 'henry_v_act2_scene2', 185, 'puissance', 'military power (as in the Prologue)'), ('henry_v_act2_scene2_gloss52', 'henry_v_act2_scene2', 186, 'in expedition', 'in motion; mobilized'), ('henry_v_act2_scene2_gloss53', 'henry_v_act2_scene2', 188, 'No king of England, if not king of France', 'if I can''t be king of France, I''m not really king of England — Henry''s aggressive closing oath');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act2_scene3_gloss1', 'henry_v_act2_scene3', 1, 'Staines', 'a town on the Thames west of London — stop on the road to Southampton'), ('henry_v_act2_scene3_gloss2', 'henry_v_act2_scene3', 2, 'manly heart doth yearn', 'Pistol''s grief — ''yearn'' here = ache with sorrow'), ('henry_v_act2_scene3_gloss3', 'henry_v_act2_scene3', 3, 'vaunting veins', 'boastful blood-vessels — Pistol''s bombastic diction'), ('henry_v_act2_scene3_gloss4', 'henry_v_act2_scene3', 4, 'Falstaff he is dead', 'Sir John Falstaff''s death — imported from the end of Henry IV Part 2; reported, not staged'), ('henry_v_act2_scene3_gloss5', 'henry_v_act2_scene3', 7, 'Arthur’s bosom', 'the Hostess''s malapropism for ''Abraham''s bosom'' (Luke 16:22) — the resting-place of the righteous after death'), ('henry_v_act2_scene3_gloss6', 'henry_v_act2_scene3', 8, 'a finer end', 'a better death'), ('henry_v_act2_scene3_gloss7', 'henry_v_act2_scene3', 9, 'christom child', 'the Hostess''s malapropism for ''chrisom child'' — a baby in its christening-cloth, proverbial for innocence'), ('henry_v_act2_scene3_gloss8', 'henry_v_act2_scene3', 10, 'turning o’ the tide', 'the moment of tidal change — old folk-belief held that dying men passed with the tide'), ('henry_v_act2_scene3_gloss9', 'henry_v_act2_scene3', 11, 'fumble with the sheets', 'pluck absently at the bed-linen — a classical sign of the dying'), ('henry_v_act2_scene3_gloss10', 'henry_v_act2_scene3', 13, 'nose was as sharp as a pen', 'his nose had grown pointed and thin — a traditional symptom of approaching death'), ('henry_v_act2_scene3_gloss11', 'henry_v_act2_scene3', 14, 'babbled of green fields', 'famous textual crux — Theobald''s emendation of the Folio''s nonsense; conveys Falstaff in delirium remembering pastoral scenes'), ('henry_v_act2_scene3_gloss12', 'henry_v_act2_scene3', 15, 'God, God, God', 'Falstaff''s deathbed cry — the Hostess misunderstands, thinking he needs comforting away from religion'), ('henry_v_act2_scene3_gloss13', 'henry_v_act2_scene3', 24, 'cried out of sack', 'spoke with regret of sack — the sweet sherry Falstaff was famous for loving'), ('henry_v_act2_scene3_gloss14', 'henry_v_act2_scene3', 28, 'carnation', 'the color carnation/flesh-pink — the Hostess puns on ''carnal''; she insists Falstaff never cared for that color'), ('henry_v_act2_scene3_gloss15', 'henry_v_act2_scene3', 31, 'rheumatic', 'the Hostess''s malapropism — she means ''lunatic'' or ''choleric''; ''rheumatic'' = catarrhal, not relevant'), ('henry_v_act2_scene3_gloss16', 'henry_v_act2_scene3', 31, 'whore of Babylon', 'apocalyptic image from Revelation 17 — Protestant rhetoric used it for the Catholic Church'), ('henry_v_act2_scene3_gloss17', 'henry_v_act2_scene3', 33, 'black soul burning in hellfire', 'Falstaff''s joke about Bardolph''s notoriously red nose — a flea on it burns like a damned soul'), ('henry_v_act2_scene3_gloss18', 'henry_v_act2_scene3', 36, 'shog', 'get going; move off (dialect)'), ('henry_v_act2_scene3_gloss19', 'henry_v_act2_scene3', 39, 'Pitch and Pay', 'pay cash; literally ''throw down the money'' — Pistol''s motto for tavern credit'), ('henry_v_act2_scene3_gloss20', 'henry_v_act2_scene3', 41, 'oaths are straws', 'promises are worthless as straws in the wind'), ('henry_v_act2_scene3_gloss21', 'henry_v_act2_scene3', 41, 'wafer-cakes', 'flimsy as communion wafers — faith is fragile'), ('henry_v_act2_scene3_gloss22', 'henry_v_act2_scene3', 42, 'holdfast', 'gripping tightly — ''the only dog'' proverbially means the one virtue to keep'), ('henry_v_act2_scene3_gloss23', 'henry_v_act2_scene3', 43, 'Caveto', 'Latin: ''beware'' — Pistol''s Latinate motto for caution'), ('henry_v_act2_scene3_gloss24', 'henry_v_act2_scene3', 44, 'clear thy crystals', 'wipe your eyes — ''crystals'' = crystalline tears/eyes'), ('henry_v_act2_scene3_gloss25', 'henry_v_act2_scene3', 44, 'Yoke-fellows in arms', 'yoked together in military service'), ('henry_v_act2_scene3_gloss26', 'henry_v_act2_scene3', 45, 'horse-leeches', 'large bloodsucking worms — Pistol''s image of army camp-followers as parasites'), ('henry_v_act2_scene3_gloss27', 'henry_v_act2_scene3', 49, 'adieu', 'French: goodbye — a mildly affected farewell'), ('henry_v_act2_scene3_gloss28', 'henry_v_act2_scene3', 50, 'housewifery', 'proper wifely management — Pistol orders the Hostess to keep house while he''s at war');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act2_scene4_gloss1', 'henry_v_act2_scene4', 4, 'Dukes of Berri and of Brittagne', 'Jean Duke of Berry and Jean Duke of Brittany — senior French royals commanded to muster'), ('henry_v_act2_scene4_gloss2', 'henry_v_act2_scene4', 5, 'Brabant and of Orleans', 'the Dukes of Brabant and Orléans — more French peers'), ('henry_v_act2_scene4_gloss3', 'henry_v_act2_scene4', 7, 'line and new repair', 'reinforce and refurbish — fortify'), ('henry_v_act2_scene4_gloss4', 'henry_v_act2_scene4', 8, 'means defendant', 'defensive supplies and provisions'), ('henry_v_act2_scene4_gloss5', 'henry_v_act2_scene4', 10, 'sucking of a gulf', 'the pull of a whirlpool — England draws men to war as a gulf sucks water'), ('henry_v_act2_scene4_gloss6', 'henry_v_act2_scene4', 11, 'provident', 'foresighted'), ('henry_v_act2_scene4_gloss7', 'henry_v_act2_scene4', 13, 'fatal and neglected English', 'deadly English, ignored at our peril'), ('henry_v_act2_scene4_gloss8', 'henry_v_act2_scene4', 14, 'redoubted', 'deeply respected; feared'), ('henry_v_act2_scene4_gloss9', 'henry_v_act2_scene4', 15, 'meet', 'fitting; appropriate'), ('henry_v_act2_scene4_gloss10', 'henry_v_act2_scene4', 18, 'musters', 'assemblies of troops; roll-calls'), ('henry_v_act2_scene4_gloss11', 'henry_v_act2_scene4', 25, 'Whitsun morris-dance', 'folk-dance performed at Whitsuntide — the Dauphin reduces England to village dancing'), ('henry_v_act2_scene4_gloss12', 'henry_v_act2_scene4', 26, 'idly king’d', 'badly governed; ruled by an idle king — the Dauphin''s insult'), ('henry_v_act2_scene4_gloss13', 'henry_v_act2_scene4', 28, 'humorous youth', 'a young man ruled by his moods; volatile'), ('henry_v_act2_scene4_gloss14', 'henry_v_act2_scene4', 31, 'late ambassadors', 'the recently returned ambassadors who carried the tennis-balls insult'), ('henry_v_act2_scene4_gloss15', 'henry_v_act2_scene4', 34, 'modest in exception', 'restrained when taking offence'), ('henry_v_act2_scene4_gloss16', 'henry_v_act2_scene4', 37, 'Roman Brutus', 'Lucius Junius Brutus — who feigned stupidity to mask the wit that would overthrow the Tarquins'), ('henry_v_act2_scene4_gloss17', 'henry_v_act2_scene4', 39, 'ordure', 'manure; excrement used as fertilizer'), ('henry_v_act2_scene4_gloss18', 'henry_v_act2_scene4', 41, 'high constable', 'the Constable of France — supreme commander of the French army'), ('henry_v_act2_scene4_gloss19', 'henry_v_act2_scene4', 46, 'niggardly projection', 'stingy planning'), ('henry_v_act2_scene4_gloss20', 'henry_v_act2_scene4', 47, 'miser, spoil his coat with scanting', 'a miser ruins his own coat by scrimping on the cloth'), ('henry_v_act2_scene4_gloss21', 'henry_v_act2_scene4', 50, 'flesh’d upon us', 'has tasted our blood — ''flesh''d'' = initiated to meat, as with hunting dogs'), ('henry_v_act2_scene4_gloss22', 'henry_v_act2_scene4', 51, 'bred out of that bloody strain', 'descended from that bloody stock — Henry''s warrior lineage'), ('henry_v_act2_scene4_gloss23', 'henry_v_act2_scene4', 54, 'Cressy battle', 'the Battle of Crécy, 1346 — Edward III''s great victory over the French'), ('henry_v_act2_scene4_gloss24', 'henry_v_act2_scene4', 56, 'Edward, Black Prince of Wales', 'Edward of Woodstock — hero of Crécy, already invoked in 1.2'), ('henry_v_act2_scene4_gloss25', 'henry_v_act2_scene4', 57, 'mountain sire, on mountain standing', 'Edward III, watching from a hilltop — the French King''s image of the Plantagenet king surveying his son''s victory'), ('henry_v_act2_scene4_gloss26', 'henry_v_act2_scene4', 60, 'Mangle the work of nature', 'slaughter what nature had made — the French forces cut down by the English'), ('henry_v_act2_scene4_gloss27', 'henry_v_act2_scene4', 68, 'chase is hotly follow’d', 'hunting-metaphor: the pursuit is pressing'), ('henry_v_act2_scene4_gloss28', 'henry_v_act2_scene4', 69, 'coward dogs', 'timid hounds — the Dauphin''s insult to those who fear Henry'), ('henry_v_act2_scene4_gloss29', 'henry_v_act2_scene4', 70, 'spend their mouths', 'bay loudly — hunting term for dogs barking'), ('henry_v_act2_scene4_gloss30', 'henry_v_act2_scene4', 72, 'Take up the English short', 'cut the English off curtly'), ('henry_v_act2_scene4_gloss31', 'henry_v_act2_scene4', 78, 'divest yourself', 'strip yourself of — of the French crown'), ('henry_v_act2_scene4_gloss32', 'henry_v_act2_scene4', 79, 'borrow’d glories', 'Henry''s claim: the French crown is held on loan, unlawfully'), ('henry_v_act2_scene4_gloss33', 'henry_v_act2_scene4', 85, 'sinister nor no awkward claim', 'neither an illegitimate nor an irregular claim'), ('henry_v_act2_scene4_gloss34', 'henry_v_act2_scene4', 86, 'wormholes of long-vanish’d days', 'dusty, worm-eaten historical records'), ('henry_v_act2_scene4_gloss35', 'henry_v_act2_scene4', 88, 'memorable line', 'notable pedigree — a genealogical chart of Edward III''s descent'), ('henry_v_act2_scene4_gloss36', 'henry_v_act2_scene4', 95, 'native and true challenger', 'the natural and rightful claimant'), ('henry_v_act2_scene4_gloss37', 'henry_v_act2_scene4', 97, 'Bloody constraint', 'violent compulsion — i.e. war'), ('henry_v_act2_scene4_gloss38', 'henry_v_act2_scene4', 100, 'thunder and in earthquake, like a Jove', 'like Jove (Jupiter) — the Roman king of the gods, wielding thunder'), ('henry_v_act2_scene4_gloss39', 'henry_v_act2_scene4', 102, 'bowels of the Lord', 'biblical idiom (Philippians 1:8) for ''the tender mercy of Christ'''), ('henry_v_act2_scene4_gloss40', 'henry_v_act2_scene4', 105, 'vasty jaws', 'vast jaws — war personified as a devouring mouth'), ('henry_v_act2_scene4_gloss41', 'henry_v_act2_scene4', 117, 'Scorn and defiance', 'Henry''s answer to the Dauphin personally — a formal challenge'), ('henry_v_act2_scene4_gloss42', 'henry_v_act2_scene4', 118, 'misbecome', 'be unbecoming to'), ('henry_v_act2_scene4_gloss43', 'henry_v_act2_scene4', 124, 'womby vaultages', 'cavernous vaults — France''s own caves will echo Henry''s cannon-fire back'), ('henry_v_act2_scene4_gloss44', 'henry_v_act2_scene4', 126, 'second accent of his ordinance', 'the echo/reply of his artillery — ''ordinance'' = ordnance, cannon'), ('henry_v_act2_scene4_gloss45', 'henry_v_act2_scene4', 131, 'Paris balls', 'the tennis balls the Dauphin sent — named for Paris as their origin'), ('henry_v_act2_scene4_gloss46', 'henry_v_act2_scene4', 132, 'Paris Louvre', 'the Louvre — the royal palace at Paris (before it was a museum)'), ('henry_v_act2_scene4_gloss47', 'henry_v_act2_scene4', 136, 'promise of his greener days', 'the potential of his earlier, unripe years — the wildness of Prince Hal in Henry IV'), ('henry_v_act2_scene4_gloss48', 'henry_v_act2_scene4', 137, 'weighs time / Even to the utmost grain', 'reckons time to the smallest measure — Henry now disciplined and precise'), ('henry_v_act2_scene4_gloss49', 'henry_v_act2_scene4', 143, 'footed in this land', 'already set foot on French soil — Henry''s landing is imminent or accomplished');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act3_chorus_gloss1', 'henry_v_act3_chorus', 1, 'imagined wing', 'the audience''s imagination as wings — the Chorus continues its central metaphor'), ('henry_v_act3_chorus_gloss2', 'henry_v_act3_chorus', 2, 'celerity', 'swiftness; speed'), ('henry_v_act3_chorus_gloss3', 'henry_v_act3_chorus', 4, 'well-appointed', 'properly equipped and fitted out for war'), ('henry_v_act3_chorus_gloss4', 'henry_v_act3_chorus', 4, 'Hampton pier', 'Southampton''s dock — the embarkation port'), ('henry_v_act3_chorus_gloss5', 'henry_v_act3_chorus', 6, 'silken streamers', 'silk pennants fluttering from the masts'), ('henry_v_act3_chorus_gloss6', 'henry_v_act3_chorus', 6, 'young Phoebus fanning', 'the streamers fanning the rising sun — Phoebus Apollo is the sun-god'), ('henry_v_act3_chorus_gloss7', 'henry_v_act3_chorus', 8, 'hempen tackle', 'the hemp ropes of the ship''s rigging'), ('henry_v_act3_chorus_gloss8', 'henry_v_act3_chorus', 9, 'shrill whistle', 'the boatswain''s pipe — signalling orders'), ('henry_v_act3_chorus_gloss9', 'henry_v_act3_chorus', 10, 'threaden sails', 'canvas sails — ''threaden'' = made of thread/cloth'), ('henry_v_act3_chorus_gloss10', 'henry_v_act3_chorus', 12, 'huge bottoms', 'large ship hulls'), ('henry_v_act3_chorus_gloss11', 'henry_v_act3_chorus', 13, 'Breasting the lofty surge', 'cutting through tall waves chest-first'), ('henry_v_act3_chorus_gloss12', 'henry_v_act3_chorus', 14, 'rivage', 'shore; coastline (French loan-word)'), ('henry_v_act3_chorus_gloss13', 'henry_v_act3_chorus', 15, 'inconstant billows', 'restless waves'), ('henry_v_act3_chorus_gloss14', 'henry_v_act3_chorus', 17, 'Harfleur', 'the French port town Henry besieges — modern Le Havre is built beside it'), ('henry_v_act3_chorus_gloss15', 'henry_v_act3_chorus', 18, 'Grapple your minds to sternage of this navy', 'hook your imagination to the stern of this fleet — ''sternage'' = the fleet''s stern, the following ships'), ('henry_v_act3_chorus_gloss16', 'henry_v_act3_chorus', 20, 'grandsires, babies and old women', 'England''s wartime skeleton population — the able-bodied are abroad'), ('henry_v_act3_chorus_gloss17', 'henry_v_act3_chorus', 21, 'pith and puissance', 'vigor and military power'), ('henry_v_act3_chorus_gloss18', 'henry_v_act3_chorus', 24, 'cull’d and choice-drawn cavaliers', 'picked, handpicked horsemen — an elite selection'), ('henry_v_act3_chorus_gloss19', 'henry_v_act3_chorus', 26, 'ordnance on their carriages', 'cannons mounted on wheeled carriages'), ('henry_v_act3_chorus_gloss20', 'henry_v_act3_chorus', 27, 'fatal mouths gaping on girded Harfleur', 'deadly cannon mouths aimed at besieged Harfleur — ''girded'' = surrounded by a ring of troops'), ('henry_v_act3_chorus_gloss21', 'henry_v_act3_chorus', 30, 'Katharine his daughter', 'the French princess whose betrothal to Henry is offered as a peace-bribe — prefigures Act 5'), ('henry_v_act3_chorus_gloss22', 'henry_v_act3_chorus', 31, 'petty and unprofitable dukedoms', 'worthless small fiefs — Henry''s scornful view of the French dowry offer'), ('henry_v_act3_chorus_gloss23', 'henry_v_act3_chorus', 32, 'likes not', 'does not please; is unwelcome'), ('henry_v_act3_chorus_gloss24', 'henry_v_act3_chorus', 32, 'nimble gunner', 'the quick-handed artilleryman'), ('henry_v_act3_chorus_gloss25', 'henry_v_act3_chorus', 33, 'linstock', 'a forked staff holding the lighted match used to fire a cannon'), ('henry_v_act3_chorus_gloss26', 'henry_v_act3_chorus', 35, 'eke out our performance with your mind', 'supplement our staging with your imagination — the Chorus''s signature plea');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act3_scene1_gloss1', 'henry_v_act3_scene1', 1, 'Once more unto the breach', 'once again into the gap in the walls — soldiers must renew the assault through the opening a siege-cannon has torn'), ('henry_v_act3_scene1_gloss2', 'henry_v_act3_scene1', 2, 'close the wall up with our English dead', 'fill the breach with our corpses — either break through or die in the gap'), ('henry_v_act3_scene1_gloss3', 'henry_v_act3_scene1', 4, 'modest stillness and humility', 'quiet restraint — Henry''s theory of peacetime virtue'), ('henry_v_act3_scene1_gloss4', 'henry_v_act3_scene1', 5, 'blast of war', 'trumpet-call of war; the din of battle'), ('henry_v_act3_scene1_gloss5', 'henry_v_act3_scene1', 6, 'imitate the action of the tiger', 'become predatory and ferocious — the speech''s keynote'), ('henry_v_act3_scene1_gloss6', 'henry_v_act3_scene1', 7, 'Stiffen the sinews', 'harden the muscles and tendons'), ('henry_v_act3_scene1_gloss7', 'henry_v_act3_scene1', 8, 'Disguise fair nature with hard-favour’d rage', 'mask your gentle face with ugly fury'), ('henry_v_act3_scene1_gloss8', 'henry_v_act3_scene1', 9, 'terrible aspect', 'fearsome expression'), ('henry_v_act3_scene1_gloss9', 'henry_v_act3_scene1', 10, 'portage of the head', 'the skull''s openings (eye-sockets) treated like gun-ports in a ship'), ('henry_v_act3_scene1_gloss10', 'henry_v_act3_scene1', 11, 'brass cannon', 'the eye as an artillery piece — warlike metamorphosis of the body'), ('henry_v_act3_scene1_gloss11', 'henry_v_act3_scene1', 12, 'galled rock', 'a cliff weathered by the sea'), ('henry_v_act3_scene1_gloss12', 'henry_v_act3_scene1', 13, 'jutty his confounded base', 'project over its eroded footing — ''jutty'' = overhang'), ('henry_v_act3_scene1_gloss13', 'henry_v_act3_scene1', 14, 'Swill’d with the wild and wasteful ocean', 'drenched by the destructive sea'), ('henry_v_act3_scene1_gloss14', 'henry_v_act3_scene1', 18, 'fet from fathers of war-proof', 'drawn from battle-tested fathers — ''fet'' = fetched; ''war-proof'' = proven in war'), ('henry_v_act3_scene1_gloss15', 'henry_v_act3_scene1', 19, 'Alexanders', 'Alexander the Great — Macedonian conqueror; the play''s first of three invocations'), ('henry_v_act3_scene1_gloss16', 'henry_v_act3_scene1', 20, 'from morn till even', 'from morning until evening'), ('henry_v_act3_scene1_gloss17', 'henry_v_act3_scene1', 21, 'sheathed their swords for lack of argument', 'put their swords away for want of an opponent to fight'), ('henry_v_act3_scene1_gloss18', 'henry_v_act3_scene1', 23, 'those whom you call’d fathers did beget you', 'the men you call father really did father you — prove your paternity in battle'), ('henry_v_act3_scene1_gloss19', 'henry_v_act3_scene1', 24, 'copy now to men of grosser blood', 'a model for coarser-blooded men'), ('henry_v_act3_scene1_gloss20', 'henry_v_act3_scene1', 25, 'yeomen', 'free-born English commoners of the farming class — the backbone of the English army and longbow'), ('henry_v_act3_scene1_gloss21', 'henry_v_act3_scene1', 27, 'mettle of your pasture', 'the quality of your home soil — show what English ground produces'), ('henry_v_act3_scene1_gloss22', 'henry_v_act3_scene1', 29, 'mean and base', 'humble and low-born'), ('henry_v_act3_scene1_gloss23', 'henry_v_act3_scene1', 30, 'noble lustre', 'the shine of nobility in your eyes — social elevation via valour'), ('henry_v_act3_scene1_gloss24', 'henry_v_act3_scene1', 31, 'greyhounds in the slips', 'greyhounds in their leashes — hunting dogs straining at the start'), ('henry_v_act3_scene1_gloss25', 'henry_v_act3_scene1', 32, 'Straining upon the start', 'pulling against the leash at the starting line'), ('henry_v_act3_scene1_gloss26', 'henry_v_act3_scene1', 32, 'game’s afoot', 'the quarry is up and running — hunting idiom, later made famous by Sherlock Holmes'), ('henry_v_act3_scene1_gloss27', 'henry_v_act3_scene1', 34, 'God for Harry, England, and Saint George', 'the English war-cry — St. George is England''s patron saint and the Garter''s namesake');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act3_scene2_gloss1', 'henry_v_act3_scene2', 2, 'knocks', 'blows; cannon-shots'), ('henry_v_act3_scene2_gloss2', 'henry_v_act3_scene2', 3, 'case of lives', 'a pair of lives — Nym complains he has only one'), ('henry_v_act3_scene2_gloss3', 'henry_v_act3_scene2', 4, 'plainsong', 'the unembellished melody; the plain truth — musical metaphor for bluntness'), ('henry_v_act3_scene2_gloss4', 'henry_v_act3_scene2', 6, 'God’s vassals', 'God''s subjects — soldiers as servants of providence'), ('henry_v_act3_scene2_gloss5', 'henry_v_act3_scene2', 10, 'alehouse in London', 'a London pub — the Boy''s wish for home and safety'), ('henry_v_act3_scene2_gloss6', 'henry_v_act3_scene2', 15, 'hie', 'hurry; go quickly'), ('henry_v_act3_scene2_gloss7', 'henry_v_act3_scene2', 17, 'avaunt', 'begone! get out of here!'), ('henry_v_act3_scene2_gloss8', 'henry_v_act3_scene2', 17, 'cullions', 'rascals; base fellows (also a crude term for testicles)'), ('henry_v_act3_scene2_gloss9', 'henry_v_act3_scene2', 18, 'men of mould', 'men of earth; mortal clay — Pistol''s inflated plea'), ('henry_v_act3_scene2_gloss10', 'henry_v_act3_scene2', 21, 'bawcock', 'fine fellow (from French ''beau coq'' — fine cock)'), ('henry_v_act3_scene2_gloss11', 'henry_v_act3_scene2', 21, 'lenity', 'mildness; mercy'), ('henry_v_act3_scene2_gloss12', 'henry_v_act3_scene2', 21, 'sweet chuck', 'term of endearment — ''chuck'' = chicken, dear'), ('henry_v_act3_scene2_gloss13', 'henry_v_act3_scene2', 23, 'swashers', 'swaggering braggarts'), ('henry_v_act3_scene2_gloss14', 'henry_v_act3_scene2', 26, 'antics', 'clowns; grotesques'), ('henry_v_act3_scene2_gloss15', 'henry_v_act3_scene2', 27, 'white-livered', 'cowardly — a pale liver was thought to indicate cowardice'), ('henry_v_act3_scene2_gloss16', 'henry_v_act3_scene2', 27, 'faces it out', 'brazens it out with his face; bluffs'), ('henry_v_act3_scene2_gloss17', 'henry_v_act3_scene2', 28, 'killing tongue and a quiet sword', 'deadly in speech, silent in arms — all bluster'), ('henry_v_act3_scene2_gloss18', 'henry_v_act3_scene2', 29, 'breaks words, and keeps whole weapons', 'uses up words, not weapons'), ('henry_v_act3_scene2_gloss19', 'henry_v_act3_scene2', 35, 'call it purchase', 'theft renamed as acquisition'), ('henry_v_act3_scene2_gloss20', 'henry_v_act3_scene2', 36, 'lute-case', 'instrument-case — Bardolph''s petty theft'), ('henry_v_act3_scene2_gloss21', 'henry_v_act3_scene2', 36, 'twelve leagues', 'about 36 miles — a league is roughly 3 miles'), ('henry_v_act3_scene2_gloss22', 'henry_v_act3_scene2', 37, 'Calais', 'English-held port on the French Channel coast from 1347–1558'), ('henry_v_act3_scene2_gloss23', 'henry_v_act3_scene2', 38, 'fire-shovel', 'a shovel for moving coals on a hearth — pettiest possible theft'), ('henry_v_act3_scene2_gloss24', 'henry_v_act3_scene2', 39, 'carry coals', 'endure indignity — proverbial for demeaning work (same as R&J 1.1)'), ('henry_v_act3_scene2_gloss25', 'henry_v_act3_scene2', 42, 'pocketing up of wrongs', 'tucking away of grievances — pun on literal pocket-picking'), ('henry_v_act3_scene2_gloss26', 'henry_v_act3_scene2', 44, 'cast it up', 'vomit; throw it up — the Boy rejects the thieves'' company'), ('henry_v_act3_scene2_gloss27', 'henry_v_act3_scene2', 45, 'presently', 'immediately; right now'), ('henry_v_act3_scene2_gloss28', 'henry_v_act3_scene2', 45, 'mines', 'tunnels dug beneath siege walls to collapse them'), ('henry_v_act3_scene2_gloss29', 'henry_v_act3_scene2', 49, 'disciplines of the war', 'Fluellen''s pedantic catchphrase — the classical ''military science'' he keeps citing'), ('henry_v_act3_scene2_gloss30', 'henry_v_act3_scene2', 49, 'concavities', 'the hollow excavations — the mine-tunnels'), ('henry_v_act3_scene2_gloss31', 'henry_v_act3_scene2', 50, 'th’ athversary', 'the adversary, in Fluellen''s Welsh accent — ''th'' for ''the''; dialect marker, not a typo'), ('henry_v_act3_scene2_gloss32', 'henry_v_act3_scene2', 51, 'digt himself', 'dug himself — Welsh-dialect form, preserved as characterization'), ('henry_v_act3_scene2_gloss33', 'henry_v_act3_scene2', 51, 'countermines', 'counter-tunnels dug to intercept enemy mines'), ('henry_v_act3_scene2_gloss34', 'henry_v_act3_scene2', 52, 'Cheshu', 'Fluellen''s Welsh oath ''Jesu'' — ''Cheshu'' = Jesus; dialect marker throughout'), ('henry_v_act3_scene2_gloss35', 'henry_v_act3_scene2', 55, 'Irishman', 'Captain Macmorris — Shakespeare''s only Irish character; the four-captains scene stages the emerging British Isles identity'), ('henry_v_act3_scene2_gloss36', 'henry_v_act3_scene2', 57, 'Captain Macmorris', 'the Irish captain; his accent (''ish'' for ''is'') is Shakespeare''s only extended Irish dialect'), ('henry_v_act3_scene2_gloss37', 'henry_v_act3_scene2', 64, 'falorous', 'valorous, in Fluellen''s pronunciation'), ('henry_v_act3_scene2_gloss38', 'henry_v_act3_scene2', 65, 'aunchient', 'ancient — Fluellen''s pronunciation; used as noun = ensign (lowest officer)'), ('henry_v_act3_scene2_gloss39', 'henry_v_act3_scene2', 68, 'pristine wars of the Romans', 'the wars of ancient Rome — Fluellen''s obsession with classical military theory'), ('henry_v_act3_scene2_gloss40', 'henry_v_act3_scene2', 68, 'gud-day', '''good day'' in Jamy''s Scottish accent — another dialect marker'), ('henry_v_act3_scene2_gloss41', 'henry_v_act3_scene2', 69, 'God-den', '''good-even'', contracted — Fluellen''s return greeting'), ('henry_v_act3_scene2_gloss42', 'henry_v_act3_scene2', 70, 'pioneers', 'military engineers who dig trenches and tunnels'), ('henry_v_act3_scene2_gloss43', 'henry_v_act3_scene2', 71, 'By Chrish', '''by Christ'' in Macmorris''s Irish pronunciation — dialect marker'), ('henry_v_act3_scene2_gloss44', 'henry_v_act3_scene2', 71, 'tish ill done', '''it is ill done'' — ''tish'' = ''tis, with Irish intonation'), ('henry_v_act3_scene2_gloss45', 'henry_v_act3_scene2', 72, 'trompet', 'trumpet (dialect spelling)'), ('henry_v_act3_scene2_gloss46', 'henry_v_act3_scene2', 77, 'voutsafe', 'vouchsafe; grant — Fluellen''s pronunciation'), ('henry_v_act3_scene2_gloss47', 'henry_v_act3_scene2', 80, 'friendly communication', 'Fluellen''s comic formality — he is asking to quarrel theoretically'), ('henry_v_act3_scene2_gloss48', 'henry_v_act3_scene2', 83, 'sall', 'shall, in Jamy''s Scottish accent'), ('henry_v_act3_scene2_gloss49', 'henry_v_act3_scene2', 83, 'gud feith', '''good faith'' — Jamy''s Scottish oath'), ('henry_v_act3_scene2_gloss50', 'henry_v_act3_scene2', 94, 'By the mess', 'by the mass — mild Scottish oath'), ('henry_v_act3_scene2_gloss51', 'henry_v_act3_scene2', 95, 'ay’ll de gud service', '''I''ll do good service'' — Jamy''s Scots'), ('henry_v_act3_scene2_gloss52', 'henry_v_act3_scene2', 95, 'lig i’ the grund', 'lie in the ground — Scottish dialect for ''die'''), ('henry_v_act3_scene2_gloss53', 'henry_v_act3_scene2', 98, 'wad full fain heard', 'would very much like to have heard — Scottish dialect'), ('henry_v_act3_scene2_gloss54', 'henry_v_act3_scene2', 98, 'tway', 'two — Scottish dialect'), ('henry_v_act3_scene2_gloss55', 'henry_v_act3_scene2', 101, 'What ish my nation?', 'Macmorris''s defensive outburst — the play''s most-discussed Irish line; a challenge to Fluellen''s presumption about ''his nation'''), ('henry_v_act3_scene2_gloss56', 'henry_v_act3_scene2', 105, 'peradventure', 'perhaps'), ('henry_v_act3_scene2_gloss57', 'henry_v_act3_scene2', 106, 'affability', 'friendly courtesy'), ('henry_v_act3_scene2_gloss58', 'henry_v_act3_scene2', 108, 'derivation of my birth', 'pedigree; ancestry'), ('henry_v_act3_scene2_gloss59', 'henry_v_act3_scene2', 110, 'cut off your head', 'Macmorris''s blunt threat — the captains'' scholarly dispute collapses into violence'), ('henry_v_act3_scene2_gloss60', 'henry_v_act3_scene2', 112, 'parley', 'trumpet-call for a negotiation truce — signals the Harfleur governor''s offer to talk'), ('henry_v_act3_scene2_gloss61', 'henry_v_act3_scene2', 116, 'there is an end', 'Fluellen''s dignified close — ''that''s that''');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act3_scene3_gloss1', 'henry_v_act3_scene3', 1, 'resolves', 'decides; answers'), ('henry_v_act3_scene3_gloss2', 'henry_v_act3_scene3', 1, 'governor', 'the town''s military commander, empowered to surrender'), ('henry_v_act3_scene3_gloss3', 'henry_v_act3_scene3', 2, 'latest parle', 'last parley — the final chance to negotiate before assault'), ('henry_v_act3_scene3_gloss4', 'henry_v_act3_scene3', 3, 'to our best mercy give yourselves', 'surrender unconditionally to our mercy'), ('henry_v_act3_scene3_gloss5', 'henry_v_act3_scene3', 4, 'proud of destruction', 'prideful in wanting their own destruction'), ('henry_v_act3_scene3_gloss6', 'henry_v_act3_scene3', 7, 'battery', 'artillery bombardment'), ('henry_v_act3_scene3_gloss7', 'henry_v_act3_scene3', 8, 'half-achieved', 'half-taken; half-conquered'), ('henry_v_act3_scene3_gloss8', 'henry_v_act3_scene3', 9, 'in her ashes she lie buried', 'until the town is burnt and buried in its own ashes'), ('henry_v_act3_scene3_gloss9', 'henry_v_act3_scene3', 10, 'gates of mercy shall be all shut up', 'mercy will be withdrawn — the speech''s opening premise'), ('henry_v_act3_scene3_gloss10', 'henry_v_act3_scene3', 11, 'flesh’d soldier', 'soldier accustomed to killing — ''flesh''d'' = blooded, habituated to slaughter'), ('henry_v_act3_scene3_gloss11', 'henry_v_act3_scene3', 12, 'liberty of bloody hand', 'free licence to kill — the abandonment of military restraint'), ('henry_v_act3_scene3_gloss12', 'henry_v_act3_scene3', 13, 'conscience wide as hell', 'a conscience as vast and permissive as hell itself'), ('henry_v_act3_scene3_gloss13', 'henry_v_act3_scene3', 13, 'mowing like grass', 'cutting down as a scythe cuts grass — slaughter as harvest'), ('henry_v_act3_scene3_gloss14', 'henry_v_act3_scene3', 14, 'fresh-fair virgins and your flowering infants', 'the young women and small children — named explicitly as targets'), ('henry_v_act3_scene3_gloss15', 'henry_v_act3_scene3', 15, 'impious War', 'war personified as unholy — ''impious'' = sacrilegious'), ('henry_v_act3_scene3_gloss16', 'henry_v_act3_scene3', 16, 'prince of fiends', 'Satan'), ('henry_v_act3_scene3_gloss17', 'henry_v_act3_scene3', 17, 'smirch’d complexion', 'soot-blackened face — war imagined as a fire-blackened demon'), ('henry_v_act3_scene3_gloss18', 'henry_v_act3_scene3', 17, 'fell feats', 'cruel deeds — ''fell'' = savage, deadly'), ('henry_v_act3_scene3_gloss19', 'henry_v_act3_scene3', 18, 'Enlink’d to waste and desolation', 'linked to destruction and ruin'), ('henry_v_act3_scene3_gloss20', 'henry_v_act3_scene3', 20, 'pure maidens', 'chaste young women'), ('henry_v_act3_scene3_gloss21', 'henry_v_act3_scene3', 21, 'hot and forcing violation', 'heated, forcible rape — the threat named directly'), ('henry_v_act3_scene3_gloss22', 'henry_v_act3_scene3', 22, 'licentious wickedness', 'lawless evil — soldiers'' unchained lust and rage'), ('henry_v_act3_scene3_gloss23', 'henry_v_act3_scene3', 23, 'holds his fierce career', 'runs his headlong course — ''career'' = gallop'), ('henry_v_act3_scene3_gloss24', 'henry_v_act3_scene3', 24, 'bootless', 'pointless; useless'), ('henry_v_act3_scene3_gloss25', 'henry_v_act3_scene3', 26, 'precepts to the leviathan', 'commands to the great sea-monster — Henry''s image for impossibility'), ('henry_v_act3_scene3_gloss26', 'henry_v_act3_scene3', 29, 'Whiles yet my soldiers are in my command', 'while I can still control them — the threat''s pivot: after a certain point, he cannot restrain them'), ('henry_v_act3_scene3_gloss27', 'henry_v_act3_scene3', 30, 'cool and temperate wind of grace', 'the mild breeze of mercy'), ('henry_v_act3_scene3_gloss28', 'henry_v_act3_scene3', 31, 'O’erblows', 'blows away'), ('henry_v_act3_scene3_gloss29', 'henry_v_act3_scene3', 32, 'heady murder', 'impulsive, headlong killing'), ('henry_v_act3_scene3_gloss30', 'henry_v_act3_scene3', 34, 'blind and bloody soldier', 'the soldier who kills indiscriminately'), ('henry_v_act3_scene3_gloss31', 'henry_v_act3_scene3', 35, 'Defile the locks of your shrill-shrieking daughters', 'rape your daughters — ''defile the locks'' = tear at their hair as they are assaulted'), ('henry_v_act3_scene3_gloss32', 'henry_v_act3_scene3', 36, 'silver beards', 'the grey beards of the old men — dragged by the elders'), ('henry_v_act3_scene3_gloss33', 'henry_v_act3_scene3', 37, 'reverend heads dash’d to the walls', 'old men''s venerable heads smashed against the walls'), ('henry_v_act3_scene3_gloss34', 'henry_v_act3_scene3', 38, 'naked infants spitted upon pikes', 'babies impaled on long pole-weapons — the speech''s most infamous image, left unambiguous on the page'), ('henry_v_act3_scene3_gloss35', 'henry_v_act3_scene3', 40, 'wives of Jewry', 'the women of Judea — biblical reference to Matthew 2, Herod''s massacre of the infants at Bethlehem'), ('henry_v_act3_scene3_gloss36', 'henry_v_act3_scene3', 41, 'Herod’s bloody-hunting slaughtermen', 'Herod''s soldiers hunting babies — the Massacre of the Innocents, the benchmark Henry''s threat invokes'), ('henry_v_act3_scene3_gloss37', 'henry_v_act3_scene3', 43, 'guilty in defence', 'responsible, by defending the town, for what follows'), ('henry_v_act3_scene3_gloss38', 'henry_v_act3_scene3', 45, 'succours', 'reinforcements; relief'), ('henry_v_act3_scene3_gloss39', 'henry_v_act3_scene3', 46, 'powers are yet not ready', 'the Dauphin''s army is not yet mustered'), ('henry_v_act3_scene3_gloss40', 'henry_v_act3_scene3', 47, 'raise so great a siege', 'break so large a siege'), ('henry_v_act3_scene3_gloss41', 'henry_v_act3_scene3', 48, 'We yield our town', 'Harfleur''s formal surrender'), ('henry_v_act3_scene3_gloss42', 'henry_v_act3_scene3', 50, 'defensible', 'able to hold out'), ('henry_v_act3_scene3_gloss43', 'henry_v_act3_scene3', 52, 'fortify it strongly', 'garrison and reinforce the captured town'), ('henry_v_act3_scene3_gloss44', 'henry_v_act3_scene3', 53, 'Use mercy to them all', 'spare the citizens — Henry pivots instantly from threat to mercy, having achieved surrender'), ('henry_v_act3_scene3_gloss45', 'henry_v_act3_scene3', 54, 'winter coming on and sickness growing', 'dysentery ravaged the English army after the siege — Henry''s march to Calais is forced by attrition'), ('henry_v_act3_scene3_gloss46', 'henry_v_act3_scene3', 55, 'retire to Calais', 'withdraw to the English-held port, ~100 miles north'), ('henry_v_act3_scene3_gloss47', 'henry_v_act3_scene3', 57, 'addrest', 'ready; prepared (archaic)');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act3_scene4_gloss1', 'henry_v_act3_scene4', 1, 'Alice, tu as été en Angleterre', 'French: ''Alice, you have been in England'' — Katherine begins the scene asking about Alice''s English'), ('henry_v_act3_scene4_gloss2', 'henry_v_act3_scene4', 1, 'tu parles bien le langage', 'French: ''you speak the language well'' — prompts Alice to give a lesson'), ('henry_v_act3_scene4_gloss3', 'henry_v_act3_scene4', 2, 'Un peu, madame', 'French: ''A little, madam'' — Alice''s modest reply'), ('henry_v_act3_scene4_gloss4', 'henry_v_act3_scene4', 3, 'm’enseignez', 'French: ''teach me'' — Katherine requests tuition'), ('henry_v_act3_scene4_gloss5', 'henry_v_act3_scene4', 3, 'j’apprenne à parler', 'French: ''I must learn to speak'' — signals the political motive: she is being readied for marriage to an English king'), ('henry_v_act3_scene4_gloss6', 'henry_v_act3_scene4', 3, 'Comment appelez-vous la main en Anglois', 'French: ''What do you call the hand in English?'' — the lesson''s first question'), ('henry_v_act3_scene4_gloss7', 'henry_v_act3_scene4', 5, 'elle est appelée de hand', 'French: ''it is called hand'' — Alice teaches ''hand'' as the English word'), ('henry_v_act3_scene4_gloss8', 'henry_v_act3_scene4', 6, 'De hand', 'Katherine''s attempted pronunciation of English ''hand'' — dialect-accurate; do not correct to ''the hand'''), ('henry_v_act3_scene4_gloss9', 'henry_v_act3_scene4', 6, 'Et les doigts', 'French: ''And the fingers?'' — next body-part question'), ('henry_v_act3_scene4_gloss10', 'henry_v_act3_scene4', 7, 'ma foi', 'French: ''my faith'' — mild oath, roughly ''goodness'''), ('henry_v_act3_scene4_gloss11', 'henry_v_act3_scene4', 7, 'j’oublie', 'French: ''I forget'' — Alice confesses a memory lapse'), ('henry_v_act3_scene4_gloss12', 'henry_v_act3_scene4', 8, 'de fingres', 'Katherine''s attempted ''fingers'' — French-accented English; a dialect trace'), ('henry_v_act3_scene4_gloss13', 'henry_v_act3_scene4', 10, 'le bon écolier', 'French: ''a good pupil'' — Katherine congratulates herself'), ('henry_v_act3_scene4_gloss14', 'henry_v_act3_scene4', 10, 'j’ai gagné deux mots d’Anglois vîtement', 'French: ''I have earned two English words quickly'' — playful pride'), ('henry_v_act3_scene4_gloss15', 'henry_v_act3_scene4', 11, 'les ongles', 'French: ''the nails'' (fingernails) — next vocabulary item'), ('henry_v_act3_scene4_gloss16', 'henry_v_act3_scene4', 12, 'de nails', 'Katherine''s attempt at ''nails'' — French-accented English'), ('henry_v_act3_scene4_gloss17', 'henry_v_act3_scene4', 13, 'Écoutez', 'French: ''Listen'' — Alice''s instruction'), ('henry_v_act3_scene4_gloss18', 'henry_v_act3_scene4', 14, 'C’est bien dit, madame; il est fort bon Anglois', 'French: ''Well said, madam; it is very good English'''), ('henry_v_act3_scene4_gloss19', 'henry_v_act3_scene4', 15, 'le bras', 'French: ''the arm'' — next item'), ('henry_v_act3_scene4_gloss20', 'henry_v_act3_scene4', 20, 'De arm', 'Katherine''s attempt at ''arm'' — the ''De'' repeats her French-accented article habit'), ('henry_v_act3_scene4_gloss21', 'henry_v_act3_scene4', 16, 'le coude', 'French: ''the elbow'' — next item'), ('henry_v_act3_scene4_gloss22', 'henry_v_act3_scene4', 17, 'De elbow', 'Katherine''s attempt at ''elbow'''), ('henry_v_act3_scene4_gloss23', 'henry_v_act3_scene4', 17, 'Je m’en fais la répétition', 'French: ''I''m going to repeat'' — Katherine recites to fix the lesson'), ('henry_v_act3_scene4_gloss24', 'henry_v_act3_scene4', 19, 'Il est trop difficile', 'French: ''It is too difficult'' — Alice''s gentle protest'), ('henry_v_act3_scene4_gloss25', 'henry_v_act3_scene4', 20, 'Excusez-moi', 'French: ''Pardon me'' — Katherine presses on'), ('henry_v_act3_scene4_gloss26', 'henry_v_act3_scene4', 20, 'de bilbow', 'Katherine''s mistake for ''elbow'' — she has slipped; ''bilbow'' = sword'), ('henry_v_act3_scene4_gloss27', 'henry_v_act3_scene4', 22, 'O Seigneur Dieu, je m’en oublie', 'French: ''O Lord God, I''m forgetting it'' — her frustration'), ('henry_v_act3_scene4_gloss28', 'henry_v_act3_scene4', 22, 'le col', 'French: ''the neck'''), ('henry_v_act3_scene4_gloss29', 'henry_v_act3_scene4', 23, 'De neck', 'Alice''s English'), ('henry_v_act3_scene4_gloss30', 'henry_v_act3_scene4', 25, 'De nick', 'Katherine''s attempt at ''neck'' — ''nick'' is her approximation'), ('henry_v_act3_scene4_gloss31', 'henry_v_act3_scene4', 25, 'le menton', 'French: ''the chin'''), ('henry_v_act3_scene4_gloss32', 'henry_v_act3_scene4', 24, 'De chin', 'Alice''s English for chin'), ('henry_v_act3_scene4_gloss33', 'henry_v_act3_scene4', 25, 'De sin', 'Katherine''s attempt at ''chin'' — ''sin'' is her approximation; builds the comic crescendo toward the indecent words'), ('henry_v_act3_scene4_gloss34', 'henry_v_act3_scene4', 26, 'Sauf votre honneur, en vérité', 'French: ''Saving your honour, truly'' — Alice''s courtly compliment'), ('henry_v_act3_scene4_gloss35', 'henry_v_act3_scene4', 27, 'les natifs d’Angleterre', 'French: ''natives of England'''), ('henry_v_act3_scene4_gloss36', 'henry_v_act3_scene4', 28, 'Je ne doute point d’apprendre', 'French: ''I don''t doubt I''ll learn'''), ('henry_v_act3_scene4_gloss37', 'henry_v_act3_scene4', 28, 'par la grâce de Dieu', 'French: ''by the grace of God'''), ('henry_v_act3_scene4_gloss38', 'henry_v_act3_scene4', 29, 'N’avez-vous pas déjà oublié', 'French: ''Haven''t you already forgotten'' — Alice tests her'), ('henry_v_act3_scene4_gloss39', 'henry_v_act3_scene4', 30, 'je réciterai à vous promptement', 'French: ''I''ll recite to you promptly'''), ('henry_v_act3_scene4_gloss40', 'henry_v_act3_scene4', 30, 'de mails', 'Katherine''s slip — she means ''nails'''), ('henry_v_act3_scene4_gloss41', 'henry_v_act3_scene4', 32, 'Sauf votre honneur', 'French: ''Saving your honour'' — Alice''s polite correction opener'), ('henry_v_act3_scene4_gloss42', 'henry_v_act3_scene4', 33, 'Ainsi dis-je', 'French: ''So I say'''), ('henry_v_act3_scene4_gloss43', 'henry_v_act3_scene4', 34, 'pied et la robe', 'French: ''foot and the dress'' — Katherine asks the English for these, but ''robe'' is a mishearing; she probably means ''gown'''), ('henry_v_act3_scene4_gloss44', 'henry_v_act3_scene4', 35, 'De foot', 'English ''foot'' — sounds like French ''foutre'' (obscenity)'), ('henry_v_act3_scene4_gloss45', 'henry_v_act3_scene4', 35, 'de coun', 'Alice''s attempt at ''gown'' — sounds like French ''con'' (obscenity). The scene''s comic climax: English body-words become scandalous French'), ('henry_v_act3_scene4_gloss46', 'henry_v_act3_scene4', 35, 'O Seigneur Dieu', 'French: ''O Lord God'' — Katherine''s scandalized reaction'), ('henry_v_act3_scene4_gloss47', 'henry_v_act3_scene4', 36, 'son mauvais, corruptible, gros, et impudique', 'French: ''bad-sounding, corrupting, coarse, and immodest'' — her list of objections'), ('henry_v_act3_scene4_gloss48', 'henry_v_act3_scene4', 36, 'les dames d’honneur d’user', 'French: ''for ladies of honour to use'' — what they should not say'), ('henry_v_act3_scene4_gloss49', 'henry_v_act3_scene4', 37, 'les seigneurs de France', 'French: ''the lords of France'' — before whom she dare not speak these words'), ('henry_v_act3_scene4_gloss50', 'henry_v_act3_scene4', 38, 'pour tout le monde', 'French: ''for anything in the world'' — idiomatic ''for anything'''), ('henry_v_act3_scene4_gloss51', 'henry_v_act3_scene4', 38, 'Foh', 'French: exclamation of disgust — ''ugh'''), ('henry_v_act3_scene4_gloss52', 'henry_v_act3_scene4', 38, 'Néanmoins', 'French: ''nevertheless'' — she perseveres'), ('henry_v_act3_scene4_gloss53', 'henry_v_act3_scene4', 39, 'ma leçon ensemble', 'French: ''my lesson all together'''), ('henry_v_act3_scene4_gloss54', 'henry_v_act3_scene4', 41, 'Excellent, madame', 'French: ''Excellent, madam'''), ('henry_v_act3_scene4_gloss55', 'henry_v_act3_scene4', 42, 'C’est assez pour une fois', 'French: ''That''s enough for one time'''), ('henry_v_act3_scene4_gloss56', 'henry_v_act3_scene4', 42, 'allons-nous à dîner', 'French: ''let''s go to dinner'' — scene closes on a domestic cadence');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act3_scene5_gloss1', 'henry_v_act3_scene5', 1, 'river Somme', 'the river Henry had to cross before turning north to Calais — historically a difficult crossing'), ('henry_v_act3_scene5_gloss2', 'henry_v_act3_scene5', 2, 'fought withal', 'given battle against'), ('henry_v_act3_scene5_gloss3', 'henry_v_act3_scene5', 4, 'barbarous people', 'barbaric people — the Constable''s view of the English'), ('henry_v_act3_scene5_gloss4', 'henry_v_act3_scene5', 5, 'O Dieu vivant', 'French: ''O living God'' — exclamation of aristocratic dismay'), ('henry_v_act3_scene5_gloss5', 'henry_v_act3_scene5', 5, 'sprays of us', 'offshoots of us — the French see the English as scions of their Norman stock'), ('henry_v_act3_scene5_gloss6', 'henry_v_act3_scene5', 6, 'emptying of our fathers’ luxury', 'the dregs of our ancestors'' lust — Dauphin''s gross image'), ('henry_v_act3_scene5_gloss7', 'henry_v_act3_scene5', 7, 'scions', 'young shoots grafted onto another stock'), ('henry_v_act3_scene5_gloss8', 'henry_v_act3_scene5', 7, 'wild and savage stock', 'English soil as uncultivated root-stock — French Normans grafted onto it'), ('henry_v_act3_scene5_gloss9', 'henry_v_act3_scene5', 8, 'Spirt up', 'sprout up; shoot up'), ('henry_v_act3_scene5_gloss10', 'henry_v_act3_scene5', 9, 'overlook their grafters', 'stand taller than those who grafted them — the English outdo the Norman ancestors'), ('henry_v_act3_scene5_gloss11', 'henry_v_act3_scene5', 9, 'Normans, but bastard Normans, Norman bastards', 'Bourbon''s insult — Anglo-Normans as illegitimate descendants'), ('henry_v_act3_scene5_gloss12', 'henry_v_act3_scene5', 10, 'Mort de ma vie', 'French: ''Death of my life'' — strong oath'), ('henry_v_act3_scene5_gloss13', 'henry_v_act3_scene5', 12, 'slobbery and a dirty farm', 'a muddy, filthy farm'), ('henry_v_act3_scene5_gloss14', 'henry_v_act3_scene5', 13, 'nook-shotten isle of Albion', 'angular, crook-cornered island — ''Albion'' is the classical name for Britain; ''nook-shotten'' = having many corners or bays'), ('henry_v_act3_scene5_gloss15', 'henry_v_act3_scene5', 14, 'Dieu de batailles', 'French: ''God of battles'''), ('henry_v_act3_scene5_gloss16', 'henry_v_act3_scene5', 14, 'mettle', 'spirit; temperament — metallurgical metaphor'), ('henry_v_act3_scene5_gloss17', 'henry_v_act3_scene5', 15, 'foggy, raw, and dull', 'damp, cold, and sluggish — stereotype of English climate'), ('henry_v_act3_scene5_gloss18', 'henry_v_act3_scene5', 17, 'sodden water', 'boiled water — for making beer'), ('henry_v_act3_scene5_gloss19', 'henry_v_act3_scene5', 18, 'drench for sur-rein’d jades', 'medicinal drink for over-worked horses — the Constable''s contempt for English ale'), ('henry_v_act3_scene5_gloss20', 'henry_v_act3_scene5', 18, 'barley-broth', 'beer — the thin barley beer of the English'), ('henry_v_act3_scene5_gloss21', 'henry_v_act3_scene5', 19, 'Decoct their cold blood', 'boil up their cold blood into heat — cooking metaphor for the English paradox'), ('henry_v_act3_scene5_gloss22', 'henry_v_act3_scene5', 20, 'spirited with wine', 'animated by wine — French aristocratic drink versus English beer'), ('henry_v_act3_scene5_gloss23', 'henry_v_act3_scene5', 22, 'roping icicles', 'icicles hanging like ropes'), ('henry_v_act3_scene5_gloss24', 'henry_v_act3_scene5', 25, 'Poor we may call them in their native lords', 'we may call the English poor in their own nobility — i.e., lacking the French refinement'), ('henry_v_act3_scene5_gloss25', 'henry_v_act3_scene5', 27, 'madams', 'Frenchwomen — ''our ladies'''), ('henry_v_act3_scene5_gloss26', 'henry_v_act3_scene5', 28, 'mettle is bred out', 'our valour has died out by over-breeding'), ('henry_v_act3_scene5_gloss27', 'henry_v_act3_scene5', 30, 'new-store France with bastard warriors', 'repopulate France with the illegitimate children of English soldiers — Dauphin''s humiliation fantasy'), ('henry_v_act3_scene5_gloss28', 'henry_v_act3_scene5', 31, 'English dancing-schools', 'Dauphin reduces French war to training in English dance-halls'), ('henry_v_act3_scene5_gloss29', 'henry_v_act3_scene5', 32, 'lavoltas', 'the lavolta — a fashionable 16th-century dance involving a high leap'), ('henry_v_act3_scene5_gloss30', 'henry_v_act3_scene5', 32, 'corantos', 'the coranto — a quick court dance with running steps'), ('henry_v_act3_scene5_gloss31', 'henry_v_act3_scene5', 33, 'grace is only in our heels', 'our grace lies only in running away'), ('henry_v_act3_scene5_gloss32', 'henry_v_act3_scene5', 34, 'lofty runaways', 'high-class fugitives — self-flattering cowardice'), ('henry_v_act3_scene5_gloss33', 'henry_v_act3_scene5', 35, 'Montjoy the herald', 'the French royal herald — titular name, not personal; he will be the French emissary to Henry'), ('henry_v_act3_scene5_gloss34', 'henry_v_act3_scene5', 39, 'Charles Delabreth', 'Charles d''Albret — the historical Constable of France, killed at Agincourt'), ('henry_v_act3_scene5_gloss35', 'henry_v_act3_scene5', 42, 'Rambures, Vaudemont', 'French nobles named in the historical record of Agincourt'), ('henry_v_act3_scene5_gloss36', 'henry_v_act3_scene5', 48, 'pennons painted in the blood of Harfleur', 'banners dyed red with Harfleur''s blood'), ('henry_v_act3_scene5_gloss37', 'henry_v_act3_scene5', 51, 'void his rheum', 'spit his phlegm — the Alps spitting on the valleys below'), ('henry_v_act3_scene5_gloss38', 'henry_v_act3_scene5', 53, 'captive chariot', 'a chariot transporting a prisoner — the French King imagines Henry led in triumph'), ('henry_v_act3_scene5_gloss39', 'henry_v_act3_scene5', 53, 'Rouen', 'capital of Normandy — a French seat of power'), ('henry_v_act3_scene5_gloss40', 'henry_v_act3_scene5', 58, 'sink of fear', 'the pit of his fear — ''sink'' = drain, cesspool'), ('henry_v_act3_scene5_gloss41', 'henry_v_act3_scene5', 59, 'for achievement offer us his ransom', 'in exchange for safe-passage, offer his ransom money — the French expect Henry to buy his way out');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act3_scene6_gloss1', 'henry_v_act3_scene6', 1, 'bridge', 'a contested bridge on the march to Calais — Exeter holds it'), ('henry_v_act3_scene6_gloss2', 'henry_v_act3_scene6', 4, 'Agamemnon', 'Greek king who led the expedition against Troy — Fluellen''s classical flattery of Exeter'), ('henry_v_act3_scene6_gloss3', 'henry_v_act3_scene6', 8, 'aunchient lieutenant', 'ensign-lieutenant — Pistol''s rank (pronounced Fluellen-style)'), ('henry_v_act3_scene6_gloss4', 'henry_v_act3_scene6', 9, 'pridge', 'bridge, in Fluellen''s Welsh pronunciation — dialect marker, not a typo'), ('henry_v_act3_scene6_gloss5', 'henry_v_act3_scene6', 10, 'Mark Antony', 'Roman general renowned for loyalty and martial skill — another classical flattery from Fluellen'), ('henry_v_act3_scene6_gloss6', 'henry_v_act3_scene6', 11, 'no estimation in the world', 'no reputation — Fluellen''s accurate judgment of Pistol''s social standing, mixed with praise for his soldiering'), ('henry_v_act3_scene6_gloss7', 'henry_v_act3_scene6', 19, 'buxom valour', 'vigorous courage — ''buxom'' originally = pliant, lively'), ('henry_v_act3_scene6_gloss8', 'henry_v_act3_scene6', 20, 'giddy Fortune’s furious fickle wheel', 'Fortune''s spinning wheel — medieval allegorical image; Pistol inflates it with alliteration'), ('henry_v_act3_scene6_gloss9', 'henry_v_act3_scene6', 21, 'goddess blind', 'Fortune personified as blindfolded — the conventional medieval figure'), ('henry_v_act3_scene6_gloss10', 'henry_v_act3_scene6', 23, 'Fortune is painted blind, with a muffler afore his eyes', 'Fluellen''s scholarly elaboration of the Fortune-allegory Pistol began — she wears a blindfold'), ('henry_v_act3_scene6_gloss11', 'henry_v_act3_scene6', 27, 'foot, look you, is fixed upon a spherical stone', 'Fortune''s traditional emblem — she balances on a sphere that keeps her unstable'), ('henry_v_act3_scene6_gloss12', 'henry_v_act3_scene6', 32, 'pax', 'a small tablet or medallion (typically metal or wood) kissed during the Mass — Bardolph stole one from a church'), ('henry_v_act3_scene6_gloss13', 'henry_v_act3_scene6', 35, 'hemp', 'the rope of the hangman — ''hemp''s windpipe'' = be hanged'), ('henry_v_act3_scene6_gloss14', 'henry_v_act3_scene6', 36, 'doom of death', 'sentence of death'), ('henry_v_act3_scene6_gloss15', 'henry_v_act3_scene6', 40, 'penny cord', 'cheap rope — the hangman''s noose'), ('henry_v_act3_scene6_gloss16', 'henry_v_act3_scene6', 41, 'requite', 'repay; reward'), ('henry_v_act3_scene6_gloss17', 'henry_v_act3_scene6', 46, 'discipline ought to be used', 'military discipline must be enforced — Fluellen refuses to intercede; Bardolph hangs'), ('henry_v_act3_scene6_gloss18', 'henry_v_act3_scene6', 48, 'figo', 'fig (Spanish/Italian) — an obscene gesture of contempt, thumb thrust between fingers'), ('henry_v_act3_scene6_gloss19', 'henry_v_act3_scene6', 49, 'fig of Spain', 'same obscene gesture, named as a Spanish import — Pistol at full bombast'), ('henry_v_act3_scene6_gloss20', 'henry_v_act3_scene6', 51, 'arrant', 'absolute; downright (intensifier)'), ('henry_v_act3_scene6_gloss21', 'henry_v_act3_scene6', 51, 'bawd', 'pimp; brothel-keeper'), ('henry_v_act3_scene6_gloss22', 'henry_v_act3_scene6', 51, 'cutpurse', 'pickpocket'), ('henry_v_act3_scene6_gloss23', 'henry_v_act3_scene6', 52, 'prave', 'brave, in Fluellen''s Welsh accent — dialect marker'), ('henry_v_act3_scene6_gloss24', 'henry_v_act3_scene6', 56, 'gull', 'dupe; fool (derived from the gull-bird, said to be easily caught)'), ('henry_v_act3_scene6_gloss25', 'henry_v_act3_scene6', 59, 'by rote', 'by memorized routine'), ('henry_v_act3_scene6_gloss26', 'henry_v_act3_scene6', 60, 'sconce', 'small fortification; also, slang for ''head'''), ('henry_v_act3_scene6_gloss27', 'henry_v_act3_scene6', 63, 'trick up', 'dress up; embellish falsely'), ('henry_v_act3_scene6_gloss28', 'henry_v_act3_scene6', 64, 'horrid suit of the camp', 'soldier''s uniform worn to impress civilians'), ('henry_v_act3_scene6_gloss29', 'henry_v_act3_scene6', 65, 'foaming bottles and ale-washed wits', 'drunken, beery wits — tavern audience for Pistol''s battle-tales'), ('henry_v_act3_scene6_gloss30', 'henry_v_act3_scene6', 70, 'hole in his coat', 'fault; flaw — Fluellen will watch for a pretext to act'), ('henry_v_act3_scene6_gloss31', 'henry_v_act3_scene6', 77, 'enforced to retire', 'forced to withdraw'), ('henry_v_act3_scene6_gloss32', 'henry_v_act3_scene6', 82, 'one that is like to be executed for robbing a church', 'Bardolph — his sentence; Fluellen reports it to Henry'), ('henry_v_act3_scene6_gloss33', 'henry_v_act3_scene6', 84, 'bubukles, and whelks, and knobs', 'pimples, pustules, and swellings — Fluellen''s clinical catalogue of Bardolph''s inflamed nose'), ('henry_v_act3_scene6_gloss34', 'henry_v_act3_scene6', 85, 'coal of fire', 'a burning ember — Bardolph''s famously red nose'), ('henry_v_act3_scene6_gloss35', 'henry_v_act3_scene6', 86, 'plue', 'blue, in Fluellen''s Welsh accent'), ('henry_v_act3_scene6_gloss36', 'henry_v_act3_scene6', 88, 'We would have all such offenders so cut off', 'Henry endorses the execution — no favouritism for an old Eastcheap companion'), ('henry_v_act3_scene6_gloss37', 'henry_v_act3_scene6', 90, 'compelled from the villages', 'taken from the villages by force — Henry forbids plunder'), ('henry_v_act3_scene6_gloss38', 'henry_v_act3_scene6', 91, 'lenity and cruelty play for a kingdom', 'when mercy and cruelty are both competing for a kingdom'), ('henry_v_act3_scene6_gloss39', 'henry_v_act3_scene6', 92, 'gentler gamester is the soonest winner', 'the milder gambler wins fastest — Henry''s governance maxim'), ('henry_v_act3_scene6_gloss40', 'henry_v_act3_scene6', 93, 'habit', 'costume; clothing — Montjoy is identified by his herald''s tabard'), ('henry_v_act3_scene6_gloss41', 'henry_v_act3_scene6', 99, 'bruise an injury till it were full ripe', 'strike at a wound only when it is fully developed — French strategic rationalization'), ('henry_v_act3_scene6_gloss42', 'henry_v_act3_scene6', 100, 'speak upon our cue', 'now is our moment to speak — theatrical image'), ('henry_v_act3_scene6_gloss43', 'henry_v_act3_scene6', 100, 'voice is imperial', 'we speak with royal authority'), ('henry_v_act3_scene6_gloss44', 'henry_v_act3_scene6', 101, 'admire our sufferance', 'marvel at our patience'), ('henry_v_act3_scene6_gloss45', 'henry_v_act3_scene6', 102, 'consider of his ransom', 'think about what he will pay to avoid battle'), ('henry_v_act3_scene6_gloss46', 'henry_v_act3_scene6', 104, 'pettiness would bow under', 'his small person would buckle under the weight'), ('henry_v_act3_scene6_gloss47', 'henry_v_act3_scene6', 105, 'exchequer', 'treasury'), ('henry_v_act3_scene6_gloss48', 'henry_v_act3_scene6', 112, 'Montjoy', 'the herald''s titular name — the office of principal king-of-arms in France, renewed with each officeholder'), ('henry_v_act3_scene6_gloss49', 'henry_v_act3_scene6', 116, 'Without impeachment', 'without hindrance; unopposed'), ('henry_v_act3_scene6_gloss50', 'henry_v_act3_scene6', 116, 'say the sooth', 'tell the truth'), ('henry_v_act3_scene6_gloss51', 'henry_v_act3_scene6', 118, 'craft and vantage', 'cunning and advantage'), ('henry_v_act3_scene6_gloss52', 'henry_v_act3_scene6', 125, 'This your air of France', 'this French air — Henry blames Continental atmosphere for his boasting'), ('henry_v_act3_scene6_gloss53', 'henry_v_act3_scene6', 128, 'frail and worthless trunk', 'my weak body — Henry''s self-deprecation; ''trunk'' = body'), ('henry_v_act3_scene6_gloss54', 'henry_v_act3_scene6', 131, 'such another neighbour', 'an enemy as great as France itself'), ('henry_v_act3_scene6_gloss55', 'henry_v_act3_scene6', 135, 'tawny ground with your red blood', 'the sunburnt French soil stained red with French blood'), ('henry_v_act3_scene6_gloss56', 'henry_v_act3_scene6', 143, 'We are in God’s hands', 'Henry''s keynote piety — the providentialism that frames his Agincourt victory');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act3_scene7_gloss1', 'henry_v_act3_scene7', 2, 'let my horse have his due', 'credit my horse as well — Orleans begins the scene''s running horse-bragging'), ('henry_v_act3_scene7_gloss2', 'henry_v_act3_scene7', 8, 'pasterns', 'the part of a horse''s leg between the fetlock and hoof — ''he treads on four pasterns'' = he''s a true horse'), ('henry_v_act3_scene7_gloss3', 'henry_v_act3_scene7', 8, 'Ça, ha', 'French exclamation of delight — ''Ah, there!'''), ('henry_v_act3_scene7_gloss4', 'henry_v_act3_scene7', 9, 'le cheval volant', 'French: ''the flying horse'' — mythical Pegasus'), ('henry_v_act3_scene7_gloss5', 'henry_v_act3_scene7', 10, 'Pegasus', 'the winged horse of Greek myth, born from the blood of Medusa'), ('henry_v_act3_scene7_gloss6', 'henry_v_act3_scene7', 10, 'qui a les narines de feu', 'French: ''which has nostrils of fire'''), ('henry_v_act3_scene7_gloss7', 'henry_v_act3_scene7', 11, 'he trots the air', 'he trots through the sky'), ('henry_v_act3_scene7_gloss8', 'henry_v_act3_scene7', 13, 'pipe of Hermes', 'the pipe Hermes used to charm Argus to sleep — Dauphin''s mythological flattery of his horse'), ('henry_v_act3_scene7_gloss9', 'henry_v_act3_scene7', 14, 'colour of the nutmeg', 'the tan-brown of a nutmeg'), ('henry_v_act3_scene7_gloss10', 'henry_v_act3_scene7', 15, 'beast for Perseus', 'a mount fit for Perseus — the Greek hero who rode Pegasus'), ('henry_v_act3_scene7_gloss11', 'henry_v_act3_scene7', 16, 'pure air and fire', 'composed only of the two lighter, nobler classical elements'), ('henry_v_act3_scene7_gloss12', 'henry_v_act3_scene7', 19, 'jades', 'worn-out or ordinary horses'), ('henry_v_act3_scene7_gloss13', 'henry_v_act3_scene7', 21, 'palfrey', 'a lady''s riding horse — the Dauphin strangely feminizes his war-mount'), ('henry_v_act3_scene7_gloss14', 'henry_v_act3_scene7', 21, 'bidding of a monarch', 'command of a king — the horse''s whinny'), ('henry_v_act3_scene7_gloss15', 'henry_v_act3_scene7', 24, 'rising of the lark to the lodging of the lamb', 'from dawn to night — ''lark'' sings at sunrise, ''lamb'' lies down at dusk'), ('henry_v_act3_scene7_gloss16', 'henry_v_act3_scene7', 31, 'sonnet in his praise', 'the Dauphin wrote a love-sonnet to his horse — the joke''s pivot'), ('henry_v_act3_scene7_gloss17', 'henry_v_act3_scene7', 33, 'sonnet begin so to one’s mistress', 'the customary target of such verse — Orleans catches the Dauphin writing his horse as his lover'), ('henry_v_act3_scene7_gloss18', 'henry_v_act3_scene7', 35, 'bears well', 'carries the rider well — Orleans picks up the double meaning: bears (tolerates) and bears (carries)'), ('henry_v_act3_scene7_gloss19', 'henry_v_act3_scene7', 37, 'shrewdly shook your back', 'severely jarred your back — with crude double meaning about sexual activity'), ('henry_v_act3_scene7_gloss20', 'henry_v_act3_scene7', 38, 'bridled', 'controlled — bawdy pun'), ('henry_v_act3_scene7_gloss21', 'henry_v_act3_scene7', 40, 'kern of Ireland', 'an Irish light-armed foot-soldier, proverbially bare-legged'), ('henry_v_act3_scene7_gloss22', 'henry_v_act3_scene7', 40, 'French hose off', 'without breeches — mocking the rider''s undress'), ('henry_v_act3_scene7_gloss23', 'henry_v_act3_scene7', 40, 'strait strossers', 'tight trousers/hose; here, nothing — ''strossers'' = trousers'), ('henry_v_act3_scene7_gloss24', 'henry_v_act3_scene7', 45, 'jade', 'a nag; also slang for a loose woman — Constable sustains the Dauphin''s mistress/horse conceit in the crudest direction'), ('henry_v_act3_scene7_gloss25', 'henry_v_act3_scene7', 46, 'wears his own hair', 'has her own hair (not a wig) — Dauphin''s proud claim for his horse'), ('henry_v_act3_scene7_gloss26', 'henry_v_act3_scene7', 49, 'Le chien est retourné à son propre vomissement', 'French: ''The dog is returned to his own vomit'' — from 2 Peter 2:22 / Proverbs 26:11; the Dauphin quotes scripture to insult the Constable'), ('henry_v_act3_scene7_gloss27', 'henry_v_act3_scene7', 49, 'la truie lavée au bourbier', 'French: ''the washed sow to the mire'' — second half of the same biblical proverb'), ('henry_v_act3_scene7_gloss28', 'henry_v_act3_scene7', 54, 'stars or suns', 'heraldic devices on the armour — the banter segues from horses to escutcheons'), ('henry_v_act3_scene7_gloss29', 'henry_v_act3_scene7', 58, 'superfluously', 'more than necessary; extravagantly'), ('henry_v_act3_scene7_gloss30', 'henry_v_act3_scene7', 67, 'fain be about the ears of the English', 'gladly be at grips with the English'), ('henry_v_act3_scene7_gloss31', 'henry_v_act3_scene7', 68, 'hazard', 'dice-gambling — a popular Elizabethan game of chance'), ('henry_v_act3_scene7_gloss32', 'henry_v_act3_scene7', 70, '’Tis midnight', 'the hour before Agincourt; the French still boast while the English pray'), ('henry_v_act3_scene7_gloss33', 'henry_v_act3_scene7', 74, 'Swear by her foot, that she may tread out the oath', 'Constable''s indecent joke about the mistress''s foot'), ('henry_v_act3_scene7_gloss34', 'henry_v_act3_scene7', 85, 'hooded valour', 'courage kept hooded like a hawk — invisible until release, implied useless'), ('henry_v_act3_scene7_gloss35', 'henry_v_act3_scene7', 86, 'bate', 'hawking term: a hawk ''bates'' when it beats its wings; also ''diminish'' — Constable''s pun'), ('henry_v_act3_scene7_gloss36', 'henry_v_act3_scene7', 87, 'flattery in friendship', 'Orleans''s proverb; Constable caps it'), ('henry_v_act3_scene7_gloss37', 'henry_v_act3_scene7', 91, 'fool’s bolt is soon shot', 'proverbial: a fool spends his wit quickly — fools have little ammunition'), ('henry_v_act3_scene7_gloss38', 'henry_v_act3_scene7', 99, 'mope with his fat-brained followers', 'sulk among his dull-witted men'), ('henry_v_act3_scene7_gloss39', 'henry_v_act3_scene7', 101, 'intellectual armour', 'mental armour — brains that would explain their thick helmets'), ('henry_v_act3_scene7_gloss40', 'henry_v_act3_scene7', 103, 'mastiffs', 'English mastiff dogs, proverbially courageous — Rambures''s back-handed compliment'), ('henry_v_act3_scene7_gloss41', 'henry_v_act3_scene7', 104, 'Russian bear', 'proverbially fierce — the bear-baiting image, English mastiffs charging in'), ('henry_v_act3_scene7_gloss42', 'henry_v_act3_scene7', 108, 'sympathize with the mastiffs', 'share the nature of mastiffs — English men like their dogs'), ('henry_v_act3_scene7_gloss43', 'henry_v_act3_scene7', 110, 'meals of beef and iron and steel', 'beef and sword-steel — Elizabethan cliché of English diet and arms'), ('henry_v_act3_scene7_gloss44', 'henry_v_act3_scene7', 112, 'shrewdly out of beef', 'severely short of beef — the English army is starving'), ('henry_v_act3_scene7_gloss45', 'henry_v_act3_scene7', 114, 'come, shall we about it', 'let''s get to arming — scene breaks toward battle');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act4_chorus_gloss1', 'henry_v_act4_chorus', 1, 'entertain conjecture', 'receive a guess; imagine'), ('henry_v_act4_chorus_gloss2', 'henry_v_act4_chorus', 2, 'creeping murmur', 'quiet, spreading sound'), ('henry_v_act4_chorus_gloss3', 'henry_v_act4_chorus', 2, 'poring dark', 'brooding, dense darkness — ''poring'' = staring intently'), ('henry_v_act4_chorus_gloss4', 'henry_v_act4_chorus', 3, 'wide vessel of the universe', 'the whole cosmos as a vast container'), ('henry_v_act4_chorus_gloss5', 'henry_v_act4_chorus', 4, 'foul womb of night', 'night as a dark womb — productive image for the coming day''s slaughter'), ('henry_v_act4_chorus_gloss6', 'henry_v_act4_chorus', 5, 'stilly sounds', 'quietly sounds'), ('henry_v_act4_chorus_gloss7', 'henry_v_act4_chorus', 6, 'fix’d sentinels', 'posted guards'), ('henry_v_act4_chorus_gloss8', 'henry_v_act4_chorus', 8, 'paly flames', 'pale, wan flames — campfires seen from a distance'), ('henry_v_act4_chorus_gloss9', 'henry_v_act4_chorus', 9, 'umber’d face', 'shadowed, darkened face — ''umber'' is a brown-earth pigment'), ('henry_v_act4_chorus_gloss10', 'henry_v_act4_chorus', 10, 'Steed threatens steed', 'warhorse challenges warhorse — the horses are more active than the men'), ('henry_v_act4_chorus_gloss11', 'henry_v_act4_chorus', 12, 'armourers, accomplishing the knights', 'armour-smiths finishing the knights'' equipment — the stanza''s trademark image'), ('henry_v_act4_chorus_gloss12', 'henry_v_act4_chorus', 13, 'closing rivets up', 'hammering the last rivets into armour-joints'), ('henry_v_act4_chorus_gloss13', 'henry_v_act4_chorus', 14, 'dreadful note of preparation', 'fearsome sound of readiness for battle'), ('henry_v_act4_chorus_gloss14', 'henry_v_act4_chorus', 18, 'over-lusty French', 'excessively high-spirited French'), ('henry_v_act4_chorus_gloss15', 'henry_v_act4_chorus', 19, 'low-rated English play at dice', 'dice for the undervalued English — they gamble for prisoners before the battle'), ('henry_v_act4_chorus_gloss16', 'henry_v_act4_chorus', 20, 'cripple tardy-gaited night', 'lame, slow-walking night — the French curse its slowness'), ('henry_v_act4_chorus_gloss17', 'henry_v_act4_chorus', 21, 'foul and ugly witch', 'night as a hag who limps away — classic misogynist personification'), ('henry_v_act4_chorus_gloss18', 'henry_v_act4_chorus', 23, 'Like sacrifices', 'like beasts prepared for sacrifice — the English pictured as victims'), ('henry_v_act4_chorus_gloss19', 'henry_v_act4_chorus', 24, 'inly ruminate', 'inwardly meditate'), ('henry_v_act4_chorus_gloss20', 'henry_v_act4_chorus', 26, 'Investing lank-lean cheeks', 'clothing their gaunt, thin cheeks'), ('henry_v_act4_chorus_gloss21', 'henry_v_act4_chorus', 26, 'war-worn coats', 'battle-worn uniforms'), ('henry_v_act4_chorus_gloss22', 'henry_v_act4_chorus', 28, 'horrid ghosts', 'frightful spectres — the moonlit English look already dead'), ('henry_v_act4_chorus_gloss23', 'henry_v_act4_chorus', 29, 'royal captain of this ruin’d band', 'Henry, king of this wrecked company'), ('henry_v_act4_chorus_gloss24', 'henry_v_act4_chorus', 31, 'Praise and glory on his head', 'the Chorus''s own benediction, overheard by the audience'), ('henry_v_act4_chorus_gloss25', 'henry_v_act4_chorus', 36, 'enrounded him', 'surrounded him'), ('henry_v_act4_chorus_gloss26', 'henry_v_act4_chorus', 37, 'Nor doth he dedicate one jot of colour', 'he doesn''t lose a particle of his complexion — showing no fear'), ('henry_v_act4_chorus_gloss27', 'henry_v_act4_chorus', 39, 'overbears attaint', 'overpowers (the appearance of) exhaustion — ''attaint'' = infection, weariness'), ('henry_v_act4_chorus_gloss28', 'henry_v_act4_chorus', 43, 'largess universal like the sun', 'bounty given to all, as the sun gives light'), ('henry_v_act4_chorus_gloss29', 'henry_v_act4_chorus', 44, 'liberal eye', 'generous gaze'), ('henry_v_act4_chorus_gloss30', 'henry_v_act4_chorus', 45, 'mean and gentle', 'low-born and high-born alike'), ('henry_v_act4_chorus_gloss31', 'henry_v_act4_chorus', 47, 'A little touch of Harry in the night', 'a brief passing contact with Henry in the dark — the stanza''s famous phrase, and the scene''s set-up for 4.1'), ('henry_v_act4_chorus_gloss32', 'henry_v_act4_chorus', 50, 'four or five most vile and ragged foils', 'a handful of shabby stage-swords — the Chorus''s self-deprecating confession that the battle cannot be staged'), ('henry_v_act4_chorus_gloss33', 'henry_v_act4_chorus', 52, 'name of Agincourt', 'the name we will honour despite the stage''s failure'), ('henry_v_act4_chorus_gloss34', 'henry_v_act4_chorus', 53, 'Minding true things by what their mock’ries be', 'remembering true events through their theatrical imitation — the Chorus''s final aesthetic plea');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act4_scene1_gloss1', 'henry_v_act4_scene1', 4, 'some soul of goodness in things evil', 'even in bad things there is a seed of good — Henry''s habit of redeeming adversity'), ('henry_v_act4_scene1_gloss2', 'henry_v_act4_scene1', 5, 'observingly distil it out', 'carefully extract the good — alchemical metaphor'), ('henry_v_act4_scene1_gloss3', 'henry_v_act4_scene1', 6, 'bad neighbour makes us early stirrers', 'a dangerous neighbour makes us rise early — the French force vigilance on Henry''s men'), ('henry_v_act4_scene1_gloss4', 'henry_v_act4_scene1', 7, 'good husbandry', 'good management; thriftiness'), ('henry_v_act4_scene1_gloss5', 'henry_v_act4_scene1', 8, 'outward consciences', 'external conscience; moral reminders'), ('henry_v_act4_scene1_gloss6', 'henry_v_act4_scene1', 10, 'dress us fairly for our end', 'prepare ourselves properly for death'), ('henry_v_act4_scene1_gloss7', 'henry_v_act4_scene1', 11, 'gather honey from the weed', 'extract sweetness even from useless plants — proverbial optimism'), ('henry_v_act4_scene1_gloss8', 'henry_v_act4_scene1', 77, 'Erpingham', 'Sir Thomas Erpingham — the old knight who commanded the English archers; a historical figure'), ('henry_v_act4_scene1_gloss9', 'henry_v_act4_scene1', 15, 'love their present pains', 'learn to love current hardship — stoic endurance'), ('henry_v_act4_scene1_gloss10', 'henry_v_act4_scene1', 20, 'casted slough and fresh legerity', 'shed skin (like a snake) and new nimbleness — image of renewal'), ('henry_v_act4_scene1_gloss11', 'henry_v_act4_scene1', 21, 'cloak', 'Erpingham''s cloak — Henry uses it to disguise himself as a common officer'), ('henry_v_act4_scene1_gloss12', 'henry_v_act4_scene1', 27, 'I and my bosom must debate', 'I and my heart must argue — solo self-examination'), ('henry_v_act4_scene1_gloss13', 'henry_v_act4_scene1', 30, 'God-a-mercy', '''God have mercy''; thanks'), ('henry_v_act4_scene1_gloss14', 'henry_v_act4_scene1', 30, 'Qui vas là?', 'French: ''Who goes there?'' — Pistol''s attempt at a sentry''s challenge'), ('henry_v_act4_scene1_gloss15', 'henry_v_act4_scene1', 31, 'Discuss unto me', 'tell me — Pistolian inflation of ''say'''), ('henry_v_act4_scene1_gloss16', 'henry_v_act4_scene1', 32, 'base, common and popular', 'low-born, ordinary, or of the people'), ('henry_v_act4_scene1_gloss17', 'henry_v_act4_scene1', 33, 'gentleman of a company', 'a gentleman attached to a company of soldiers — roughly officer-rank'), ('henry_v_act4_scene1_gloss18', 'henry_v_act4_scene1', 34, 'Trail’st thou the puissant pike', 'do you carry the mighty pike? — a foot-soldier''s weapon'), ('henry_v_act4_scene1_gloss19', 'henry_v_act4_scene1', 37, 'bawcock', 'fine fellow (French ''beau coq'' — already glossed at 3.2)'), ('henry_v_act4_scene1_gloss20', 'henry_v_act4_scene1', 38, 'imp of fame', 'offspring of fame — ''imp'' = scion, noble graft'), ('henry_v_act4_scene1_gloss21', 'henry_v_act4_scene1', 41, 'bully', 'here a term of affection — ''fine fellow''; not yet the modern pejorative'), ('henry_v_act4_scene1_gloss22', 'henry_v_act4_scene1', 42, 'Harry le Roy', 'Henry the King — Henry''s French-disguised name; Pistol thinks it''s Cornish'), ('henry_v_act4_scene1_gloss23', 'henry_v_act4_scene1', 43, 'Cornish', 'from Cornwall — ''le Roy'' was a common Cornish surname'), ('henry_v_act4_scene1_gloss24', 'henry_v_act4_scene1', 46, 'knock his leek about his pate', 'smack his leek about his head — the leek is Fluellen''s emblem, and Pistol promises to assault him with it; sets up 5.1'), ('henry_v_act4_scene1_gloss25', 'henry_v_act4_scene1', 47, 'Saint Davy’s day', 'St. David''s Day (March 1) — the Welsh national saint''s day'), ('henry_v_act4_scene1_gloss26', 'henry_v_act4_scene1', 50, 'figo', 'obscene Spanish fig-gesture (already glossed in 3.6)'), ('henry_v_act4_scene1_gloss27', 'henry_v_act4_scene1', 52, 'sorts well with your fierceness', 'suits your aggressive name; goes well with your bluster'), ('henry_v_act4_scene1_gloss28', 'henry_v_act4_scene1', 55, 'prerogatifes', 'prerogatives, in Fluellen''s accent — ancient military privileges'), ('henry_v_act4_scene1_gloss29', 'henry_v_act4_scene1', 57, 'Pompey the Great', 'Pompey Magnus — Roman general and rival of Julius Caesar; Fluellen''s model of military order'), ('henry_v_act4_scene1_gloss30', 'henry_v_act4_scene1', 58, 'tiddle taddle nor pibble pabble', 'Fluellen''s nonce-words for idle chatter'), ('henry_v_act4_scene1_gloss31', 'henry_v_act4_scene1', 63, 'enemy is loud', 'the French camp is noisy — contrasts with the quiet English'), ('henry_v_act4_scene1_gloss32', 'henry_v_act4_scene1', 66, 'prating coxcomb', 'babbling fool — ''coxcomb'' = fool''s cap / fool'), ('henry_v_act4_scene1_gloss33', 'henry_v_act4_scene1', 72, 'no great cause to desire the approach of day', 'Bates doesn''t look forward to dawn — the soldiers dread battle'), ('henry_v_act4_scene1_gloss34', 'henry_v_act4_scene1', 71, 'Williams', 'Michael Williams — the soldier whose argument with Henry becomes the play''s most sustained critique of kingship'), ('henry_v_act4_scene1_gloss35', 'henry_v_act4_scene1', 80, 'wrecked upon a sand', 'shipwrecked on a sandbar — awaiting the next tide to sweep them off'), ('henry_v_act4_scene1_gloss36', 'henry_v_act4_scene1', 82, 'told his thought', 'shared his private fear'), ('henry_v_act4_scene1_gloss37', 'henry_v_act4_scene1', 84, 'the king is but a man', 'Henry''s opening premise — the speech that attempts to demystify kingship to Williams and Bates'), ('henry_v_act4_scene1_gloss38', 'henry_v_act4_scene1', 85, 'violet smells to him as it doth to me', 'his senses are the same as ours — the body, not the office'), ('henry_v_act4_scene1_gloss39', 'henry_v_act4_scene1', 86, 'element shows to him as it doth to me', 'the sky looks the same to him as to me — ''element'' = sky'), ('henry_v_act4_scene1_gloss40', 'henry_v_act4_scene1', 87, 'ceremonies laid by', 'set aside his ceremonial dignities'), ('henry_v_act4_scene1_gloss41', 'henry_v_act4_scene1', 88, 'affections are higher mounted', 'his passions fly higher — but they stoop like hawks, like ours'), ('henry_v_act4_scene1_gloss42', 'henry_v_act4_scene1', 91, 'relish', 'taste; quality'), ('henry_v_act4_scene1_gloss43', 'henry_v_act4_scene1', 94, 'outward courage', 'the courage one shows on the surface'), ('henry_v_act4_scene1_gloss44', 'henry_v_act4_scene1', 95, 'Thames up to the neck', 'immersed in the Thames — wishing himself at home, cold and safe'), ('henry_v_act4_scene1_gloss45', 'henry_v_act4_scene1', 97, 'at all adventures', 'whatever the consequences; come what may'), ('henry_v_act4_scene1_gloss46', 'henry_v_act4_scene1', 101, 'ransomed', 'paid for his release — kings captured in battle were normally ransomed, not killed'), ('henry_v_act4_scene1_gloss47', 'henry_v_act4_scene1', 105, 'his cause being just and his quarrel honourable', 'Henry''s insistence — the condition he keeps returning to; it is the condition Williams will challenge'), ('henry_v_act4_scene1_gloss48', 'henry_v_act4_scene1', 106, 'That’s more than we know', 'Williams''s decisive skeptical reply — the audience cannot verify royal justifications'), ('henry_v_act4_scene1_gloss49', 'henry_v_act4_scene1', 109, 'obedience to the king wipes the crime of it out of us', 'Bates''s doctrine of passive obedience — our duty is to obey, not to judge the war''s justice'), ('henry_v_act4_scene1_gloss50', 'henry_v_act4_scene1', 111, 'cause be not good', 'if the war is not just'), ('henry_v_act4_scene1_gloss51', 'henry_v_act4_scene1', 112, 'heavy reckoning to make', 'a terrible account to give (to God, on Judgment Day)'), ('henry_v_act4_scene1_gloss52', 'henry_v_act4_scene1', 113, 'latter day', 'Judgment Day; the Last Judgment'), ('henry_v_act4_scene1_gloss53', 'henry_v_act4_scene1', 116, 'children rawly left', 'children left destitute (''raw'' = unprotected)'), ('henry_v_act4_scene1_gloss54', 'henry_v_act4_scene1', 117, 'die well that die in a battle', 'soldiers rarely die ''well'' — i.e., in the state of Christian grace — since battle gives no time to settle affairs or repent'), ('henry_v_act4_scene1_gloss55', 'henry_v_act4_scene1', 120, 'black matter for the king', 'a serious moral indictment of the king — Williams holds Henry responsible'), ('henry_v_act4_scene1_gloss56', 'henry_v_act4_scene1', 121, 'disobey were against all proportion of subjection', 'yet refusing to fight would violate the duty of a subject — Williams sees the trap'), ('henry_v_act4_scene1_gloss57', 'henry_v_act4_scene1', 122, 'son that is by his father sent about merchandise', 'Henry''s analogy — a son sent to trade who sins on the way; the father isn''t damned for the son''s sins'), ('henry_v_act4_scene1_gloss58', 'henry_v_act4_scene1', 132, 'arbitrement of swords', 'decision by combat; the judgment of battle'), ('henry_v_act4_scene1_gloss59', 'henry_v_act4_scene1', 135, 'broken seals of perjury', 'seduction under false promise of marriage'), ('henry_v_act4_scene1_gloss60', 'henry_v_act4_scene1', 135, 'wars their bulwark', 'using the army as a refuge'), ('henry_v_act4_scene1_gloss61', 'henry_v_act4_scene1', 137, 'defeated the law and outrun native punishment', 'escaped civil justice at home'), ('henry_v_act4_scene1_gloss62', 'henry_v_act4_scene1', 139, 'beadle', 'a minor parish officer who administered whippings; war as God''s whip'), ('henry_v_act4_scene1_gloss63', 'henry_v_act4_scene1', 143, 'unprovided', 'spiritually unprepared; unconfessed'), ('henry_v_act4_scene1_gloss64', 'henry_v_act4_scene1', 145, 'every subject’s soul is his own', 'Henry''s rhetorical pivot — the king answers for the justice of the war, not the state of each soul'), ('henry_v_act4_scene1_gloss65', 'henry_v_act4_scene1', 147, 'wash every mote out of his conscience', 'clean every speck from his conscience — a soldier''s pre-battle spiritual hygiene'), ('henry_v_act4_scene1_gloss66', 'henry_v_act4_scene1', 156, 'determine to fight lustily', 'resolve to fight vigorously'), ('henry_v_act4_scene1_gloss67', 'henry_v_act4_scene1', 157, 'king say he would not be ransomed', 'Henry''s pledge never to be captured — he fights or dies'), ('henry_v_act4_scene1_gloss68', 'henry_v_act4_scene1', 158, 'when our throats are cut, he may be ransomed', 'Williams''s bitter skepticism — the dead can''t check on the king''s promises'), ('henry_v_act4_scene1_gloss69', 'henry_v_act4_scene1', 161, 'perilous shot out of an elder-gun', 'a dangerous pop from a pop-gun (elder-wood toy) — Williams mocks the commoner''s leverage over the king'), ('henry_v_act4_scene1_gloss70', 'henry_v_act4_scene1', 164, 'peacock’s feather', 'a feeble means — fanning the sun with a feather'), ('henry_v_act4_scene1_gloss71', 'henry_v_act4_scene1', 166, 'Your reproof is something too round', 'your rebuke is too direct'), ('henry_v_act4_scene1_gloss72', 'henry_v_act4_scene1', 168, 'quarrel between us, if you live', 'Williams proposes a personal duel after the battle if Henry survives — the glove plot begins'), ('henry_v_act4_scene1_gloss73', 'henry_v_act4_scene1', 170, 'gage', 'pledge of combat — typically a glove thrown down'), ('henry_v_act4_scene1_gloss74', 'henry_v_act4_scene1', 171, 'bonnet', 'soft cap'), ('henry_v_act4_scene1_gloss75', 'henry_v_act4_scene1', 177, 'box on the ear', 'a slap on the side of the head — Williams''s promised response to Henry''s reappearance'), ('henry_v_act4_scene1_gloss76', 'henry_v_act4_scene1', 184, 'twenty French crowns to one', '20-to-1 odds; a French gold coin is also called a ''crown'''), ('henry_v_act4_scene1_gloss77', 'henry_v_act4_scene1', 186, 'cut French crowns', 'pun: clip gold coins (illegal coin-cutting) OR cut French heads — Henry''s morbid joke'), ('henry_v_act4_scene1_gloss78', 'henry_v_act4_scene1', 187, 'clipper', 'coin-clipper, but here the king himself will be ''clipping'' French heads with the sword'), ('henry_v_act4_scene1_gloss79', 'henry_v_act4_scene1', 193, 'God of battles', 'the Old Testament God of Hosts — Henry''s invocation before Agincourt'), ('henry_v_act4_scene1_gloss80', 'henry_v_act4_scene1', 195, 'sense of reckoning', 'the counting of odds — Henry prays his men won''t register how outnumbered they are'), ('henry_v_act4_scene1_gloss81', 'henry_v_act4_scene1', 197, 'fault my father made in compassing the crown', 'Henry IV''s usurpation of Richard II''s throne — the dynastic sin Henry V has inherited'), ('henry_v_act4_scene1_gloss82', 'henry_v_act4_scene1', 199, 'Richard’s body have interred new', 'Henry V reburied Richard II at Westminster Abbey (1413) — historical fact'), ('henry_v_act4_scene1_gloss83', 'henry_v_act4_scene1', 202, 'Five hundred poor I have in yearly pay', '500 poor people on annual stipend to pray for Richard'), ('henry_v_act4_scene1_gloss84', 'henry_v_act4_scene1', 205, 'Two chantries', 'two chapels endowed for perpetual prayer — Henry''s further atonement for his father''s usurpation'), ('henry_v_act4_scene1_gloss85', 'henry_v_act4_scene1', 208, 'penitence comes after all', 'my repentance comes after the deed — Henry knows his atonement can''t truly erase the sin');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act4_scene2_gloss1', 'henry_v_act4_scene2', 1, 'gild our armour', 'gilds our armour — the sun turns the French armour golden'), ('henry_v_act4_scene2_gloss2', 'henry_v_act4_scene2', 2, 'Monte à cheval', 'French: ''Mount on horse'' — the Dauphin''s cry for his mount'), ('henry_v_act4_scene2_gloss3', 'henry_v_act4_scene2', 2, 'varlet! laquais', 'French: ''knave! lackey!'' — the Dauphin calling servants'), ('henry_v_act4_scene2_gloss4', 'henry_v_act4_scene2', 3, 'Via', 'Italian/French exclamation — ''off we go'', ''away'''), ('henry_v_act4_scene2_gloss5', 'henry_v_act4_scene2', 3, 'les eaux et la terre', 'French: ''the waters and the earth'' — mock-elemental dialogue'), ('henry_v_act4_scene2_gloss6', 'henry_v_act4_scene2', 4, 'Rien puis? l’air et le feu', 'French: ''Nothing more? The air and fire'' — Orleans adds the other two elements; the four classical elements ascribed playfully to their horses'), ('henry_v_act4_scene2_gloss7', 'henry_v_act4_scene2', 4, 'Ciel, cousin Orleans', 'French: ''Heaven, cousin Orleans'' — the Dauphin tops him'), ('henry_v_act4_scene2_gloss8', 'henry_v_act4_scene2', 6, 'incision in their hides', 'cut the horses'' hides — the Dauphin''s grotesque fantasy of the horses weeping blood'), ('henry_v_act4_scene2_gloss9', 'henry_v_act4_scene2', 8, 'dout them with superfluous courage', 'extinguish (English eyes) with excess courage — ''dout'' = do out, extinguish'), ('henry_v_act4_scene2_gloss10', 'henry_v_act4_scene2', 10, 'natural tears', 'Rambures''s deflation — if the horses weep blood now, they have nothing left for natural grief'), ('henry_v_act4_scene2_gloss11', 'henry_v_act4_scene2', 11, 'embattled', 'drawn up in battle array'), ('henry_v_act4_scene2_gloss12', 'henry_v_act4_scene2', 14, 'suck away their souls', 'the mere sight of the French army will drain English morale'), ('henry_v_act4_scene2_gloss13', 'henry_v_act4_scene2', 15, 'shales and husks', 'empty shells and chaff — what will remain of the English'), ('henry_v_act4_scene2_gloss14', 'henry_v_act4_scene2', 18, 'curtle-axe', 'cutlass; short broad sword — ''curtle'' = short'), ('henry_v_act4_scene2_gloss15', 'henry_v_act4_scene2', 21, 'vapour of our valour', 'the breath of our courage — will blow the English over'), ('henry_v_act4_scene2_gloss16', 'henry_v_act4_scene2', 23, 'superfluous lackeys', 'surplus servants — French camp-followers, more than needed'), ('henry_v_act4_scene2_gloss17', 'henry_v_act4_scene2', 25, 'squares of battle', 'the square formations of troops'), ('henry_v_act4_scene2_gloss18', 'henry_v_act4_scene2', 26, 'hilding foe', 'worthless, cowardly foe — ''hilding'' = good-for-nothing'), ('henry_v_act4_scene2_gloss19', 'henry_v_act4_scene2', 28, 'idle speculation', 'mere watching — ''we wouldn''t even have to fight, just observe'''), ('henry_v_act4_scene2_gloss20', 'henry_v_act4_scene2', 32, 'tucket sonance', 'a trumpet fanfare — ''tucket'' = flourish, ''sonance'' = sound'), ('henry_v_act4_scene2_gloss21', 'henry_v_act4_scene2', 36, 'Yond island carrions', 'those English island-carcasses — ''carrion'' = dead flesh'), ('henry_v_act4_scene2_gloss22', 'henry_v_act4_scene2', 38, 'ragged curtains', 'tattered banners'), ('henry_v_act4_scene2_gloss23', 'henry_v_act4_scene2', 40, 'Big Mars seems bankrupt', 'Mars, god of war, looks ruined — the English have no martial splendour'), ('henry_v_act4_scene2_gloss24', 'henry_v_act4_scene2', 41, 'rusty beaver', 'rust-stained visor — ''beaver'' = the lower face-guard of a helmet'), ('henry_v_act4_scene2_gloss25', 'henry_v_act4_scene2', 42, 'fixed candlesticks', 'motionless candlesticks — the English riders don''t move'), ('henry_v_act4_scene2_gloss26', 'henry_v_act4_scene2', 43, 'torch-staves', 'torch-poles — their weapons look ornamental, not deadly'), ('henry_v_act4_scene2_gloss27', 'henry_v_act4_scene2', 44, 'Lob down their heads', 'droop their heads heavily'), ('henry_v_act4_scene2_gloss28', 'henry_v_act4_scene2', 45, 'gum down-roping', 'mucus hanging in strings — sick horses'), ('henry_v_act4_scene2_gloss29', 'henry_v_act4_scene2', 46, 'gimmal bit', 'a jointed horse-bit with two rings'), ('henry_v_act4_scene2_gloss30', 'henry_v_act4_scene2', 48, 'executors, the knavish crows', 'the crows as the horses'' death-executors — already circling'), ('henry_v_act4_scene2_gloss31', 'henry_v_act4_scene2', 54, 'send them dinners and fresh suits', 'Dauphin''s gibe — we might as well feed them before killing them'), ('henry_v_act4_scene2_gloss32', 'henry_v_act4_scene2', 57, 'guidon', 'a small pennant carried by a cavalry unit'), ('henry_v_act4_scene2_gloss33', 'henry_v_act4_scene2', 60, 'outwear the day', 'waste the daylight');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act4_scene3_gloss1', 'henry_v_act4_scene3', 3, 'threescore thousand', 'sixty thousand — Westmoreland''s wildly inflated estimate of the French; the historical English/French ratio was closer to 1:4 or 1:5'), ('henry_v_act4_scene3_gloss2', 'henry_v_act4_scene3', 4, 'five to one', 'five-to-one odds — Exeter''s calculation; historically the French outnumbered the English roughly 3–5 to 1'), ('henry_v_act4_scene3_gloss3', 'henry_v_act4_scene3', 5, 'fearful odds', 'terrifying numerical disadvantage'), ('henry_v_act4_scene3_gloss4', 'henry_v_act4_scene3', 14, 'framed of the firm truth of valour', 'made of solid, unflinching valour'), ('henry_v_act4_scene3_gloss5', 'henry_v_act4_scene3', 17, 'ten thousand of those men in England', 'Westmoreland wishes for reinforcements — the play''s set-up line for Henry''s reply'), ('henry_v_act4_scene3_gloss6', 'henry_v_act4_scene3', 20, 'mark’d to die', 'marked out for death'), ('henry_v_act4_scene3_gloss7', 'henry_v_act4_scene3', 20, 'enow', 'enough'), ('henry_v_act4_scene3_gloss8', 'henry_v_act4_scene3', 22, 'fewer men, the greater share of honour', 'Henry''s keynote — fewer sharers means each gets more glory'), ('henry_v_act4_scene3_gloss9', 'henry_v_act4_scene3', 24, 'By Jove', 'by Jupiter — mild classical oath'), ('henry_v_act4_scene3_gloss10', 'henry_v_act4_scene3', 26, 'yearns me not', 'doesn''t grieve me — ''yearn'' = grieve'), ('henry_v_act4_scene3_gloss11', 'henry_v_act4_scene3', 28, 'sin to covet honour', 'if wanting honour is a sin — Henry''s self-confessed ambition, the speech''s personal note'), ('henry_v_act4_scene3_gloss12', 'henry_v_act4_scene3', 30, 'coz', 'cousin — affectionate contraction'), ('henry_v_act4_scene3_gloss13', 'henry_v_act4_scene3', 34, 'proclaim it, Westmoreland', 'Henry invites anyone unwilling to leave — a daring morale-setting gambit'), ('henry_v_act4_scene3_gloss14', 'henry_v_act4_scene3', 35, 'hath no stomach to this fight', 'has no appetite (or courage) for the battle'), ('henry_v_act4_scene3_gloss15', 'henry_v_act4_scene3', 36, 'passport shall be made', 'traveling documents will be provided — formal permission to leave'), ('henry_v_act4_scene3_gloss16', 'henry_v_act4_scene3', 37, 'crowns for convoy', 'money for the journey home — ''crowns'' = coins'), ('henry_v_act4_scene3_gloss17', 'henry_v_act4_scene3', 40, 'feast of Crispian', 'St. Crispin''s Day, October 25 — the date of Agincourt, 1415; Crispin and Crispianus (or Crispinian) were twin 3rd-century cobbler-saints martyred under Diocletian'), ('henry_v_act4_scene3_gloss18', 'henry_v_act4_scene3', 42, 'Will stand a tip-toe', 'will stand up on tiptoe (with pride) when this day is mentioned'), ('henry_v_act4_scene3_gloss19', 'henry_v_act4_scene3', 45, 'vigil', 'the eve of a feast — the day before'), ('henry_v_act4_scene3_gloss20', 'henry_v_act4_scene3', 47, 'strip his sleeve and show his scars', 'the retired soldier''s boast — the speech''s physical gesture'), ('henry_v_act4_scene3_gloss21', 'henry_v_act4_scene3', 50, 'remember with advantages', 'remember with exaggerations — Henry''s realism about aging memory'), ('henry_v_act4_scene3_gloss22', 'henry_v_act4_scene3', 52, 'Familiar in his mouth as household words', 'spoken as routinely as everyday expressions — the source of ''household words'''), ('henry_v_act4_scene3_gloss23', 'henry_v_act4_scene3', 53, 'Harry the king, Bedford and Exeter', 'Henry names his own company — binding them to himself in memory'), ('henry_v_act4_scene3_gloss24', 'henry_v_act4_scene3', 55, 'flowing cups freshly remember’d', 'remembered anew over the cups — the veterans drinking together'), ('henry_v_act4_scene3_gloss25', 'henry_v_act4_scene3', 57, 'Crispin Crispian', 'the twin saints'' names paired — the speech''s liturgical cadence'), ('henry_v_act4_scene3_gloss26', 'henry_v_act4_scene3', 60, 'We few, we happy few, we band of brothers', 'the speech''s most-quoted line — ''band of brothers'' becomes the foundational phrase of Anglo-American military fraternity (used for the WWII 101st Airborne, later the HBO series)'), ('henry_v_act4_scene3_gloss27', 'henry_v_act4_scene3', 61, 'sheds his blood with me', 'fights alongside me and bleeds with me'), ('henry_v_act4_scene3_gloss28', 'henry_v_act4_scene3', 62, 'vile', 'low-born; socially base — ''vile'' in this period means low in rank, not morally evil'), ('henry_v_act4_scene3_gloss29', 'henry_v_act4_scene3', 63, 'gentle his condition', 'raise him to the rank of gentleman; make him noble — the promise of social elevation through shared combat, the speech''s operative pledge'), ('henry_v_act4_scene3_gloss30', 'henry_v_act4_scene3', 64, 'gentlemen in England now abed', 'the nobles at home in bed — safe, and (Henry implies) less manly'), ('henry_v_act4_scene3_gloss31', 'henry_v_act4_scene3', 65, 'accursed they were not here', 'they will curse themselves for missing this battle'), ('henry_v_act4_scene3_gloss32', 'henry_v_act4_scene3', 66, 'hold their manhoods cheap', 'they will feel their masculinity is worth less'), ('henry_v_act4_scene3_gloss33', 'henry_v_act4_scene3', 67, 'Saint Crispin’s day', 'October 25 — the battle''s date, now bound to the speech'), ('henry_v_act4_scene3_gloss34', 'henry_v_act4_scene3', 70, 'expedience', 'speed'), ('henry_v_act4_scene3_gloss35', 'henry_v_act4_scene3', 72, 'Perish the man whose mind is backward now', 'cursed be anyone who now hesitates'), ('henry_v_act4_scene3_gloss36', 'henry_v_act4_scene3', 76, 'unwish’d five thousand men', 'wished away 5,000 men by reducing the wished-for number'), ('henry_v_act4_scene3_gloss37', 'henry_v_act4_scene3', 82, 'gulf', 'abyss; whirlpool'), ('henry_v_act4_scene3_gloss38', 'henry_v_act4_scene3', 83, 'englutted', 'swallowed up'), ('henry_v_act4_scene3_gloss39', 'henry_v_act4_scene3', 84, 'mind / Thy followers of repentance', 'remind your soldiers to repent — Montjoy''s grim courtesy before battle'), ('henry_v_act4_scene3_gloss40', 'henry_v_act4_scene3', 91, 'achieve me and then sell my bones', 'defeat me first, then profit from my corpse — Henry''s sardonic answer'), ('henry_v_act4_scene3_gloss41', 'henry_v_act4_scene3', 93, 'sell the lion’s skin / While the beast lived', 'proverb — from Aesop''s fable; don''t count your victory before winning it'), ('henry_v_act4_scene3_gloss42', 'henry_v_act4_scene3', 97, 'witness live in brass of this day’s work', 'brass monuments will testify to this day''s deeds'), ('henry_v_act4_scene3_gloss43', 'henry_v_act4_scene3', 101, 'draw their honours reeking up to heaven', 'raise their smoking honours to heaven — ''reeking'' = steaming, smoking'), ('henry_v_act4_scene3_gloss44', 'henry_v_act4_scene3', 103, 'smell whereof shall breed a plague', 'English corpses rotting will poison France — a grotesque threat'), ('henry_v_act4_scene3_gloss45', 'henry_v_act4_scene3', 105, 'bullet’s grazing', 'a cannonball skipping along the ground and bouncing up to kill again'), ('henry_v_act4_scene3_gloss46', 'henry_v_act4_scene3', 107, 'Killing in relapse of mortality', 'killing twice — once dying, once after death'), ('henry_v_act4_scene3_gloss47', 'henry_v_act4_scene3', 109, 'warriors for the working-day', 'workaday soldiers — Henry contrasts his ragged men with parade-ground finery'), ('henry_v_act4_scene3_gloss48', 'henry_v_act4_scene3', 110, 'gayness and our gilt are all besmirch’d', 'our bright colours and gilding are all tarnished'), ('henry_v_act4_scene3_gloss49', 'henry_v_act4_scene3', 114, 'worn us into slovenry', 'worn our appearance into slovenliness'), ('henry_v_act4_scene3_gloss50', 'henry_v_act4_scene3', 115, 'hearts are in the trim', 'hearts are in fighting condition — ''trim'' = order, readiness'), ('henry_v_act4_scene3_gloss51', 'henry_v_act4_scene3', 121, 'Herald, save thou thy labour', 'spare yourself the trouble; no more negotiations'), ('henry_v_act4_scene3_gloss52', 'henry_v_act4_scene3', 130, 'leading of the vaward', 'command of the vanguard — the front division in battle');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act4_scene4_gloss1', 'henry_v_act4_scene4', 1, 'cur', 'mongrel dog — Pistol''s insult to his prisoner'), ('henry_v_act4_scene4_gloss2', 'henry_v_act4_scene4', 2, 'Je pense que vous êtes le gentilhomme de bonne qualité', 'French: ''I think you are a gentleman of good quality'' — the soldier''s appeal to be spared'), ('henry_v_act4_scene4_gloss3', 'henry_v_act4_scene4', 3, 'Qualité calmie custore me', 'Pistol''s garbled mishearing of the soldier''s French — he has no idea what was said'), ('henry_v_act4_scene4_gloss4', 'henry_v_act4_scene4', 4, 'O Seigneur Dieu', 'French: ''O Lord God'' — the soldier''s exclamation'), ('henry_v_act4_scene4_gloss5', 'henry_v_act4_scene4', 5, 'Signieur Dew', 'Pistol treats the French ''Seigneur Dieu'' as the soldier''s name — ''Mister Dew'''), ('henry_v_act4_scene4_gloss6', 'henry_v_act4_scene4', 6, 'Perpend', 'weigh carefully; consider — Pistol''s affected Latinism'), ('henry_v_act4_scene4_gloss7', 'henry_v_act4_scene4', 7, 'point of fox', 'sword-point — ''fox'' was slang for a sword, from a fox-head maker''s mark'), ('henry_v_act4_scene4_gloss8', 'henry_v_act4_scene4', 9, 'Egregious ransom', 'outstanding (large) ransom — ''egregious'' retains its older sense of ''conspicuous'''), ('henry_v_act4_scene4_gloss9', 'henry_v_act4_scene4', 10, 'prenez miséricorde', 'French: ''take mercy'' — ''have mercy'''), ('henry_v_act4_scene4_gloss10', 'henry_v_act4_scene4', 10, 'ayez pitié de moi', 'French: ''have pity on me'''), ('henry_v_act4_scene4_gloss11', 'henry_v_act4_scene4', 11, 'Moy shall not serve', 'Pistol hears French ''moi'' as a unit of measure — thinks the soldier is offering a small amount and demands forty'), ('henry_v_act4_scene4_gloss12', 'henry_v_act4_scene4', 12, 'rim', 'the lining of the belly; entrails'), ('henry_v_act4_scene4_gloss13', 'henry_v_act4_scene4', 14, 'Est-il impossible d’échapper la force de ton bras', 'French: ''Is it impossible to escape the force of your arm?'''), ('henry_v_act4_scene4_gloss14', 'henry_v_act4_scene4', 15, 'Brass, cur!', 'Pistol mishears ''bras'' (arm) as ''brass'' (the metal) — thinks the soldier is insulting his honour by offering base metal'), ('henry_v_act4_scene4_gloss15', 'henry_v_act4_scene4', 16, 'luxurious mountain goat', 'lecherous mountain goat — Pistol''s absurd epithet'), ('henry_v_act4_scene4_gloss16', 'henry_v_act4_scene4', 17, 'O pardonnez-moi', 'French: ''O pardon me'''), ('henry_v_act4_scene4_gloss17', 'henry_v_act4_scene4', 18, 'ton of moys', 'a ton of (the things he calls ''moys'') — Pistol''s continued mis-hearing of ''moi'''), ('henry_v_act4_scene4_gloss18', 'henry_v_act4_scene4', 20, 'Écoutez: comment êtes-vous appelé', 'French: ''Listen: what are you called?'' — the Boy translating'), ('henry_v_act4_scene4_gloss19', 'henry_v_act4_scene4', 21, 'Monsieur le Fer', 'French: ''Mr. the Iron'' — his surname Le Fer means ''the iron'''), ('henry_v_act4_scene4_gloss20', 'henry_v_act4_scene4', 23, 'fer him, and firk him, and ferret him', 'Pistol''s triple pun — ''fer'' plays on the name, ''firk'' = beat/trounce (also sexually), ''ferret'' = harass'), ('henry_v_act4_scene4_gloss21', 'henry_v_act4_scene4', 27, 'Que dit-il, monsieur', 'French: ''What does he say, sir?'''), ('henry_v_act4_scene4_gloss22', 'henry_v_act4_scene4', 28, 'Il me commande de vous dire', 'French: ''He orders me to tell you'' — the Boy translates the threat back'), ('henry_v_act4_scene4_gloss23', 'henry_v_act4_scene4', 28, 'vous faites vous prêt', 'French: ''make yourself ready'''), ('henry_v_act4_scene4_gloss24', 'henry_v_act4_scene4', 29, 'couper votre gorge', 'French: ''cut your throat'' — Pistol''s famous ''couple a gorge'' now in actual French'), ('henry_v_act4_scene4_gloss25', 'henry_v_act4_scene4', 30, 'Owy, cuppele gorge, permafoy', 'Pistol''s attempt at French — ''oui, couper la gorge, par ma foi'''), ('henry_v_act4_scene4_gloss26', 'henry_v_act4_scene4', 33, 'je vous supplie, pour l’amour de Dieu', 'French: ''I beg you, for the love of God'''), ('henry_v_act4_scene4_gloss27', 'henry_v_act4_scene4', 34, 'le gentilhomme de bonne maison', 'French: ''a gentleman of good family'''), ('henry_v_act4_scene4_gloss28', 'henry_v_act4_scene4', 35, 'deux cents écus', 'French: ''two hundred crowns'' — the ransom offered'), ('henry_v_act4_scene4_gloss29', 'henry_v_act4_scene4', 40, 'Petit monsieur, que dit-il', 'French: ''Little sir, what does he say?'''), ('henry_v_act4_scene4_gloss30', 'henry_v_act4_scene4', 41, 'Encore qu’il est contre son jurement', 'French: ''Although it is against his oath'' — the Boy translates Pistol''s grand face-saving reply'), ('henry_v_act4_scene4_gloss31', 'henry_v_act4_scene4', 43, 'la liberté, le franchisement', 'French: ''liberty, freedom'' — the prisoner''s release'), ('henry_v_act4_scene4_gloss32', 'henry_v_act4_scene4', 44, 'mille remercîments', 'French: ''a thousand thanks'''), ('henry_v_act4_scene4_gloss33', 'henry_v_act4_scene4', 45, 'entre les mains d’un chevalier', 'French: ''into the hands of a knight'''), ('henry_v_act4_scene4_gloss34', 'henry_v_act4_scene4', 46, 'plus brave, vaillant, et très distingué seigneur d’Angleterre', 'French: ''most brave, valorous, and most distinguished lord of England'' — the Boy will translate this back literally'), ('henry_v_act4_scene4_gloss35', 'henry_v_act4_scene4', 52, 'Suivez-vous le grand capitaine', 'French: ''Follow the great captain'' — the Boy telling the prisoner to go with Pistol'), ('henry_v_act4_scene4_gloss36', 'henry_v_act4_scene4', 54, 'empty vessel makes the greatest sound', 'proverb (from the Bible-era: ''empty vessels make most sound'') — Pistol is noise without substance'), ('henry_v_act4_scene4_gloss37', 'henry_v_act4_scene4', 55, 'roaring devil i’ the old play', 'the devil from medieval mystery plays — a traditional noisy stock-villain who could be beaten with a wooden dagger by any comic'), ('henry_v_act4_scene4_gloss38', 'henry_v_act4_scene4', 56, 'pare his nails with a wooden dagger', 'the Vice-character''s typical stage-business; a toothless threat'), ('henry_v_act4_scene4_gloss39', 'henry_v_act4_scene4', 58, 'stay with the lackeys, with the luggage', 'the boys guarded the baggage — a detail that becomes fatal in 4.7 when the French sack the camp and kill the boys');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act4_scene5_gloss1', 'henry_v_act4_scene5', 1, 'O diable', 'French: ''O devil'' — the Constable''s cry as the French collapse'), ('henry_v_act4_scene5_gloss2', 'henry_v_act4_scene5', 2, 'O seigneur! le jour est perdu, tout est perdu', 'French: ''O lord! the day is lost, all is lost'''), ('henry_v_act4_scene5_gloss3', 'henry_v_act4_scene5', 3, 'Mort de ma vie', 'French: ''Death of my life'' (already glossed in 3.5)'), ('henry_v_act4_scene5_gloss4', 'henry_v_act4_scene5', 3, 'all is confounded', 'all is ruined'), ('henry_v_act4_scene5_gloss5', 'henry_v_act4_scene5', 4, 'Reproach and everlasting shame', 'the Dauphin collapses into shame-language'), ('henry_v_act4_scene5_gloss6', 'henry_v_act4_scene5', 5, 'Sits mocking in our plumes', 'mocking shame rides in the plumes of our helmets'), ('henry_v_act4_scene5_gloss7', 'henry_v_act4_scene5', 5, 'méchante fortune', 'French: ''wicked fortune'''), ('henry_v_act4_scene5_gloss8', 'henry_v_act4_scene5', 7, 'perdurable shame', 'lasting, eternal shame'), ('henry_v_act4_scene5_gloss9', 'henry_v_act4_scene5', 7, 'let’s stab ourselves', 'the Dauphin''s despairing suicide-impulse'), ('henry_v_act4_scene5_gloss10', 'henry_v_act4_scene5', 8, 'wretches that we play’d at dice for', 'the English we gambled prisoner-rights over last night — recall 3.7 and 4 Chorus'), ('henry_v_act4_scene5_gloss11', 'henry_v_act4_scene5', 11, 'die in honour', 'Bourbon''s rallying cry — fall back into the battle to die well'), ('henry_v_act4_scene5_gloss12', 'henry_v_act4_scene5', 14, 'pandar', 'pimp; procurer'), ('henry_v_act4_scene5_gloss13', 'henry_v_act4_scene5', 15, 'no gentler than my dog', 'as common as any dog'), ('henry_v_act4_scene5_gloss14', 'henry_v_act4_scene5', 17, 'Disorder, that hath spoil’d us, friend us now', 'disorder ruined us — let chaos help us in our last charge'), ('henry_v_act4_scene5_gloss15', 'henry_v_act4_scene5', 18, 'on heaps go offer up our lives', 'in disorganized masses, sacrifice our lives'), ('henry_v_act4_scene5_gloss16', 'henry_v_act4_scene5', 20, 'smother up the English in our throngs', 'overwhelm the English with our sheer numbers'), ('henry_v_act4_scene5_gloss17', 'henry_v_act4_scene5', 23, 'shame will be too long', 'if we live long, our shame will last longer');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act4_scene6_gloss1', 'henry_v_act4_scene6', 2, 'keep the French the field', 'the French still hold part of the battlefield — the battle isn''t over'), ('henry_v_act4_scene6_gloss2', 'henry_v_act4_scene6', 3, 'Duke of York', 'Edward, 2nd Duke of York — historically killed at Agincourt, possibly suffocated in his armour; the senior English casualty'), ('henry_v_act4_scene6_gloss3', 'henry_v_act4_scene6', 5, 'thrice up again, and fighting', 'rose three times after being knocked down'), ('henry_v_act4_scene6_gloss4', 'henry_v_act4_scene6', 6, 'From helmet to the spur all blood', 'covered in blood head to foot'), ('henry_v_act4_scene6_gloss5', 'henry_v_act4_scene6', 8, 'Larding the plain', 'enriching the plain with his flesh — ''larding'' = basting with fat'), ('henry_v_act4_scene6_gloss6', 'henry_v_act4_scene6', 9, 'Yoke-fellow to his honour-owing wounds', 'paired with York by wounds deservingly won'), ('henry_v_act4_scene6_gloss7', 'henry_v_act4_scene6', 10, 'Earl of Suffolk', 'Michael de la Pole, 3rd Earl of Suffolk — also killed at Agincourt'), ('henry_v_act4_scene6_gloss8', 'henry_v_act4_scene6', 11, 'haggled over', 'hacked to pieces'), ('henry_v_act4_scene6_gloss9', 'henry_v_act4_scene6', 12, 'in gore he lay insteep’d', 'drenched in his own blood'), ('henry_v_act4_scene6_gloss10', 'henry_v_act4_scene6', 16, 'My soul shall thine keep company to heaven', 'York''s vow to die alongside Suffolk — a deathbed companionship'), ('henry_v_act4_scene6_gloss11', 'henry_v_act4_scene6', 19, 'chivalry', 'knightly fellowship'), ('henry_v_act4_scene6_gloss12', 'henry_v_act4_scene6', 21, 'raught', 'reached (archaic)'), ('henry_v_act4_scene6_gloss13', 'henry_v_act4_scene6', 22, 'feeble gripe', 'weak grasp'), ('henry_v_act4_scene6_gloss14', 'henry_v_act4_scene6', 24, 'over Suffolk’s neck / He threw his wounded arm', 'homoerotic tableau of the two earls dying embraced — a heightened chivalric intimacy'), ('henry_v_act4_scene6_gloss15', 'henry_v_act4_scene6', 26, 'espoused to death', 'married to death — the two earls wedded to each other in dying'), ('henry_v_act4_scene6_gloss16', 'henry_v_act4_scene6', 27, 'testament of noble-ending love', 'a will (testament) sealed in blood — affirming their comradely love'), ('henry_v_act4_scene6_gloss17', 'henry_v_act4_scene6', 31, 'all my mother came into mine eyes', 'my feminine (motherly) emotional side welled up — Exeter confesses tears'), ('henry_v_act4_scene6_gloss18', 'henry_v_act4_scene6', 33, 'compound / With mistful eyes', 'negotiate with misty eyes — Henry has to deal with his tears too'), ('henry_v_act4_scene6_gloss19', 'henry_v_act4_scene6', 35, 'new alarum', 'a fresh alarm — trumpet signal of a new French push'), ('henry_v_act4_scene6_gloss20', 'henry_v_act4_scene6', 36, 'reinforced their scatter’d men', 'the French have regrouped their scattered forces'), ('henry_v_act4_scene6_gloss21', 'henry_v_act4_scene6', 37, 'every soldier kill his prisoners', 'Henry''s order to kill the French prisoners — historically attested; controversial even in its own time. The scene presents it flatly, without commentary; the text leaves the ethics for the reader'), ('henry_v_act4_scene6_gloss22', 'henry_v_act4_scene6', 38, 'Give the word through', 'pass the order along');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act4_scene7_gloss1', 'henry_v_act4_scene7', 1, 'Kill the poys and the luggage', '''kill the boys and the [plunder the] luggage'' — Fluellen reports the French raid on the English camp, the crime that (in the play''s chronology) provides cover for Henry''s order to kill prisoners'), ('henry_v_act4_scene7_gloss2', 'henry_v_act4_scene7', 1, 'law of arms', 'the accepted rules of war — killing non-combatant boys violated the chivalric code'), ('henry_v_act4_scene7_gloss3', 'henry_v_act4_scene7', 7, 'cut his prisoner’s throat', 'Gower''s interpretation of Henry''s order — retaliation for the French killing the camp-boys. The play hedges the timing'), ('henry_v_act4_scene7_gloss4', 'henry_v_act4_scene7', 9, 'porn at Monmouth', 'born at Monmouth (Welsh pronunciation) — Henry''s birthplace, in Wales'), ('henry_v_act4_scene7_gloss5', 'henry_v_act4_scene7', 10, 'Alexander the Pig', 'Fluellen''s blunder for ''Alexander the Big'' — he means ''great'' but the Welsh word ''pig'' slips in; the error becomes the scene''s joke'), ('henry_v_act4_scene7_gloss6', 'henry_v_act4_scene7', 11, 'Alexander the Great', 'Alexander III of Macedon — classical conqueror; Fluellen''s chosen parallel to Henry'), ('henry_v_act4_scene7_gloss7', 'henry_v_act4_scene7', 15, 'born in Macedon', 'the Macedonian capital — Gower''s correct version'), ('henry_v_act4_scene7_gloss8', 'henry_v_act4_scene7', 16, 'Philip of Macedon', 'Philip II — Alexander''s father'), ('henry_v_act4_scene7_gloss9', 'henry_v_act4_scene7', 20, 'river in Macedon', 'Fluellen''s parallel of Monmouth''s River Wye with an unnamed Macedonian river'), ('henry_v_act4_scene7_gloss10', 'henry_v_act4_scene7', 22, 'Wye', 'the river at Monmouth — a real Welsh river'), ('henry_v_act4_scene7_gloss11', 'henry_v_act4_scene7', 26, 'figures in all things', 'typological parallels in everything — Fluellen''s Renaissance rhetoric of correspondences'), ('henry_v_act4_scene7_gloss12', 'henry_v_act4_scene7', 31, 'Cleitus', 'Alexander''s friend and general, killed by Alexander in a drunken rage (328 BCE) — a notorious ancient example of tyrant-error'), ('henry_v_act4_scene7_gloss13', 'henry_v_act4_scene7', 38, 'fat knight with the great belly doublet', 'Sir John Falstaff — Fluellen''s parallel: as Alexander killed Cleitus drunk, Henry ''turned away'' Falstaff sober. The rejection at the end of Henry IV Part 2'), ('henry_v_act4_scene7_gloss14', 'henry_v_act4_scene7', 40, 'Sir John Falstaff', 'the plump companion of Henry''s wild youth, rejected at Henry''s coronation; his death was reported in 2.3'), ('henry_v_act4_scene7_gloss15', 'henry_v_act4_scene7', 49, 'skirr away', 'flee swiftly; scatter'), ('henry_v_act4_scene7_gloss16', 'henry_v_act4_scene7', 50, 'Assyrian slings', 'the slings of ancient Assyrian warriors — proverbial for speed and force'), ('henry_v_act4_scene7_gloss17', 'henry_v_act4_scene7', 51, 'cut the throats of those we have', 'Henry renews the threat to kill prisoners — note the double mention; the play makes this choice unavoidable'), ('henry_v_act4_scene7_gloss18', 'henry_v_act4_scene7', 57, 'fined these bones of mine for ransom', 'paid my ransom with my own bones — Henry''s pledge to die on the field, not be ransomed'), ('henry_v_act4_scene7_gloss19', 'henry_v_act4_scene7', 59, 'charitable license', 'Montjoy asks permission to bury the French dead — the battle is over'), ('henry_v_act4_scene7_gloss20', 'henry_v_act4_scene7', 61, 'book our dead', 'register our dead (in a book)'), ('henry_v_act4_scene7_gloss21', 'henry_v_act4_scene7', 62, 'sort our nobles from our common men', 'separate the nobles from the common dead for different burials — rank held even in death'), ('henry_v_act4_scene7_gloss22', 'henry_v_act4_scene7', 64, 'mercenary blood', 'the blood of hirelings — a French nobleman has been killed beside commoners'), ('henry_v_act4_scene7_gloss23', 'henry_v_act4_scene7', 67, 'fetlock deep in gore', 'horses'' ankles submerged in blood'), ('henry_v_act4_scene7_gloss24', 'henry_v_act4_scene7', 68, 'Yerk out their armed heels', 'kick out with their shod hooves'), ('henry_v_act4_scene7_gloss25', 'henry_v_act4_scene7', 69, 'Killing them twice', 'the horses trample their own fallen masters — killing what is already dead'), ('henry_v_act4_scene7_gloss26', 'henry_v_act4_scene7', 76, 'What is this castle call’d', 'Henry asks the name of the nearest castle — the question that gives the battle its name'), ('henry_v_act4_scene7_gloss27', 'henry_v_act4_scene7', 77, 'Agincourt', 'Azincourt — a small village near the battlefield; Henry names the battle on the spot'), ('henry_v_act4_scene7_gloss28', 'henry_v_act4_scene7', 79, 'Crispin Crispianus', 'the two Crispin saints (see 4.3) — Henry formally consecrates the day to them'), ('henry_v_act4_scene7_gloss29', 'henry_v_act4_scene7', 81, 'Plack Prince of Wales', 'Black Prince of Wales (Fluellen''s Welsh pronunciation) — Edward III''s son, hero of Crécy'), ('henry_v_act4_scene7_gloss30', 'henry_v_act4_scene7', 85, 'garden where leeks did grow', 'legendary Welsh battlefield where Welsh soldiers wore leeks to identify each other — the origin of the Welsh leek-badge'), ('henry_v_act4_scene7_gloss31', 'henry_v_act4_scene7', 86, 'Monmouth caps', 'knitted woollen caps traditionally made at Monmouth — worn by Welsh soldiers'), ('henry_v_act4_scene7_gloss32', 'henry_v_act4_scene7', 88, 'Saint Tavy’s day', 'St. David''s Day, March 1 — Welsh national day (Fluellen''s pronunciation of ''Davy'')'), ('henry_v_act4_scene7_gloss33', 'henry_v_act4_scene7', 90, 'I am Welsh', 'Henry''s affirmation — he was born at Monmouth and is proud of his Welsh blood'), ('henry_v_act4_scene7_gloss34', 'henry_v_act4_scene7', 91, 'water in Wye', 'the River Wye — cannot wash out his Welshness'), ('henry_v_act4_scene7_gloss35', 'henry_v_act4_scene7', 92, 'Got pless it', '''God bless it'' in Fluellen''s Welsh accent'), ('henry_v_act4_scene7_gloss36', 'henry_v_act4_scene7', 95, 'By Jeshu', 'by Jesus (Fluellen''s Welsh oath)'), ('henry_v_act4_scene7_gloss37', 'henry_v_act4_scene7', 104, 'gage', 'pledge/glove from Williams; Henry re-opens the 4.1 plot'), ('henry_v_act4_scene7_gloss38', 'henry_v_act4_scene7', 108, 'box o’ th’ ear', 'a slap on the ear (Williams''s promised retribution)'), ('henry_v_act4_scene7_gloss39', 'henry_v_act4_scene7', 115, 'from the answer of his degree', 'socially too high to be challenged by a commoner'), ('henry_v_act4_scene7_gloss40', 'henry_v_act4_scene7', 117, 'Lucifier and Belzebub', 'Lucifer and Beelzebub — chief devils; Fluellen''s rhetorical flourish'), ('henry_v_act4_scene7_gloss41', 'henry_v_act4_scene7', 119, 'Jacksauce', 'impudent fellow — ''Jack'' + ''sauce'''), ('henry_v_act4_scene7_gloss42', 'henry_v_act4_scene7', 128, 'when Alençon and myself were down together', 'Henry had been in single combat with the Duke of Alençon — historically attested; Alençon died'), ('henry_v_act4_scene7_gloss43', 'henry_v_act4_scene7', 134, 'aggriefed', 'aggrieved, in Fluellen''s accent'), ('henry_v_act4_scene7_gloss44', 'henry_v_act4_scene7', 151, 'hot as gunpowder', 'Fluellen''s quick temper — sets up the 4.8 payoff');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act4_scene8_gloss1', 'henry_v_act4_scene8', 1, 'knight you', 'Williams thinks Fluellen is being summoned for knighthood'), ('henry_v_act4_scene8_gloss2', 'henry_v_act4_scene8', 5, 'Know the glove! I know the glove is a glove', 'Fluellen''s comic tautology'), ('henry_v_act4_scene8_gloss3', 'henry_v_act4_scene8', 7, '’Sblood', '''by God''s blood'' — a strong oath'), ('henry_v_act4_scene8_gloss4', 'henry_v_act4_scene8', 10, 'treason his payment into plows', 'punish treason with blows — Fluellen''s ''plows'' = ''blows'''), ('henry_v_act4_scene8_gloss5', 'henry_v_act4_scene8', 26, 'saving your majesty’s manhood', 'not to impugn your majesty''s courage — Fluellen''s polite hedge as he insults the ''traitor'''), ('henry_v_act4_scene8_gloss6', 'henry_v_act4_scene8', 27, 'beggarly, lousy knave', 'poverty-stricken, lice-ridden scoundrel'), ('henry_v_act4_scene8_gloss7', 'henry_v_act4_scene8', 28, 'avouchment', 'affirmation; certification — Fluellen''s mock-legal word'), ('henry_v_act4_scene8_gloss8', 'henry_v_act4_scene8', 32, 'most bitter terms', 'Henry admits Williams spoke harshly to him in 4.1 — plays at being offended'), ('henry_v_act4_scene8_gloss9', 'henry_v_act4_scene8', 33, 'let his neck answer for it', 'hang him, in Fluellen''s view'), ('henry_v_act4_scene8_gloss10', 'henry_v_act4_scene8', 36, 'All offences, my lord, come from the heart', 'Williams''s moral defence — no offence was intended'), ('henry_v_act4_scene8_gloss11', 'henry_v_act4_scene8', 38, 'came not like yourself', 'you appeared as a common soldier, not a king — Williams''s self-defence'), ('henry_v_act4_scene8_gloss12', 'henry_v_act4_scene8', 39, 'garments, your lowliness', 'your borrowed cloak and lowly bearing'), ('henry_v_act4_scene8_gloss13', 'henry_v_act4_scene8', 44, 'fill this glove with crowns', 'a purse in the shape of a glove — Henry''s way of rewarding Williams''s honesty'), ('henry_v_act4_scene8_gloss14', 'henry_v_act4_scene8', 50, 'twelve pence', 'a shilling — Fluellen''s small personal gift to Williams'), ('henry_v_act4_scene8_gloss15', 'henry_v_act4_scene8', 51, 'prawls, and prabbles', 'brawls and brabbles (squabbles), in Fluellen''s accent — dialect preserved'), ('henry_v_act4_scene8_gloss16', 'henry_v_act4_scene8', 56, 'pashful', 'bashful, in Fluellen''s accent'), ('henry_v_act4_scene8_gloss17', 'henry_v_act4_scene8', 56, 'silling', 'shilling, in Fluellen''s accent'), ('henry_v_act4_scene8_gloss18', 'henry_v_act4_scene8', 59, 'number of the slaughter’d French', 'the casualty list — Henry will read it aloud, producing the play''s roll-call of dead nobles'), ('henry_v_act4_scene8_gloss19', 'henry_v_act4_scene8', 61, 'Charles Duke of Orleans', 'Charles d''Orléans — captured at Agincourt, held in England for 25 years; a noted poet in captivity'), ('henry_v_act4_scene8_gloss20', 'henry_v_act4_scene8', 62, 'John Duke of Bourbon', 'John I, Duke of Bourbon — captured at Agincourt; died in English captivity 1434'), ('henry_v_act4_scene8_gloss21', 'henry_v_act4_scene8', 62, 'Lord Bouciqualt', 'Boucicaut — Marshal of France; captured at Agincourt, died in English captivity'), ('henry_v_act4_scene8_gloss22', 'henry_v_act4_scene8', 65, 'ten thousand French', 'the play''s inflated casualty figure — the historical estimate is ~6,000–10,000 French dead at Agincourt'), ('henry_v_act4_scene8_gloss23', 'henry_v_act4_scene8', 68, 'One hundred twenty-six', 'the number of French princes, dukes and banner-bearing nobles dead — precision lends the catalogue authority'), ('henry_v_act4_scene8_gloss24', 'henry_v_act4_scene8', 71, 'yesterday dubb’d knights', '500 who had been newly knighted on the eve of battle — all killed'), ('henry_v_act4_scene8_gloss25', 'henry_v_act4_scene8', 73, 'sixteen hundred mercenaries', '1,600 of the dead were hired soldiers — the rest aristocrats, a deliberate inversion of normal casualty ratios'), ('henry_v_act4_scene8_gloss26', 'henry_v_act4_scene8', 77, 'Charles Delabreth', 'Charles d''Albret — Constable of France, killed at Agincourt (already in 3.5)'), ('henry_v_act4_scene8_gloss27', 'henry_v_act4_scene8', 78, 'Jacques of Chatillon', 'Admiral of France — killed'), ('henry_v_act4_scene8_gloss28', 'henry_v_act4_scene8', 80, 'Guichard Dolphin', 'Guichard Dauphin — ''Great Master of France''; killed'), ('henry_v_act4_scene8_gloss29', 'henry_v_act4_scene8', 81, 'John, Duke of Alençon', 'French duke killed by Henry personally — note, Alençon as Henry''s own kill'), ('henry_v_act4_scene8_gloss30', 'henry_v_act4_scene8', 82, 'Brother to the Duke of Burgundy', 'the Duke of Brabant — related to the Duke of Burgundy (who was not at Agincourt)'), ('henry_v_act4_scene8_gloss31', 'henry_v_act4_scene8', 86, 'royal fellowship of death', 'an assembly of nobility united only by dying — Henry''s phrase for the catalogue'), ('henry_v_act4_scene8_gloss32', 'henry_v_act4_scene8', 89, 'Sir Richard Ketly, Davy Gam', 'Kettle/Kethele and Dafydd Gam — actual English casualties, one Welsh; ''Davy Gam'' = the historical David Gam, killed saving Henry''s life (per Tudor chroniclers)'), ('henry_v_act4_scene8_gloss33', 'henry_v_act4_scene8', 90, 'None else of name', 'no other English nobles dead — the vanishingly small English loss'), ('henry_v_act4_scene8_gloss34', 'henry_v_act4_scene8', 91, 'five and twenty', '25 English dead (common soldiers) — historically an understatement, but propaganda had already inflated the French dead and deflated the English'), ('henry_v_act4_scene8_gloss35', 'henry_v_act4_scene8', 91, 'thy arm was here', 'God''s arm fought for us — Henry''s providentialism'), ('henry_v_act4_scene8_gloss36', 'henry_v_act4_scene8', 93, 'without stratagem', 'without trickery; in straight combat'), ('henry_v_act4_scene8_gloss37', 'henry_v_act4_scene8', 94, 'plain shock and even play of battle', 'straightforward clash of arms'), ('henry_v_act4_scene8_gloss38', 'henry_v_act4_scene8', 100, 'boast of this or take that praise from God', 'Henry forbids boasting — all credit to God; proclamation on pain of death'), ('henry_v_act4_scene8_gloss39', 'henry_v_act4_scene8', 107, 'Non nobis', 'Latin Psalm 115 — ''Non nobis, Domine'': ''Not unto us, O Lord, but unto thy name give glory.'' Traditional English battle-thanksgiving'), ('henry_v_act4_scene8_gloss40', 'henry_v_act4_scene8', 107, 'Te Deum', '''Te Deum laudamus'' — the ancient Latin hymn of thanksgiving to God'), ('henry_v_act4_scene8_gloss41', 'henry_v_act4_scene8', 108, 'charity enclosed in clay', 'buried charitably in the earth'), ('henry_v_act4_scene8_gloss42', 'henry_v_act4_scene8', 109, 'Calais', 'the English-held Channel port — Henry''s destination, already planned at the end of 3.3');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act5_chorus_gloss1', 'henry_v_act5_chorus', 1, 'Vouchsafe', 'grant permission; be so good as to allow'), ('henry_v_act5_chorus_gloss2', 'henry_v_act5_chorus', 4, 'of time, of numbers and due course of things', 'constraints of time, population size, and the proper sequence of events — the Chorus apologizes for compression'), ('henry_v_act5_chorus_gloss3', 'henry_v_act5_chorus', 7, 'Calais', 'Henry''s staging port for the return crossing'), ('henry_v_act5_chorus_gloss4', 'henry_v_act5_chorus', 8, 'Heave him away upon your winged thoughts', 'lift him on your imagination''s wings'), ('henry_v_act5_chorus_gloss5', 'henry_v_act5_chorus', 9, 'Athwart the sea', 'across the sea — the English Channel'), ('henry_v_act5_chorus_gloss6', 'henry_v_act5_chorus', 10, 'Pales in the flood', 'encloses the flood with a fence of people — the crowds line the shore'), ('henry_v_act5_chorus_gloss7', 'henry_v_act5_chorus', 11, 'out-voice the deep-mouth’d sea', 'drown out the booming sea'), ('henry_v_act5_chorus_gloss8', 'henry_v_act5_chorus', 12, 'whiffler', 'an armed official who cleared the way in processions — ''whiffler'' = herald/marshal'), ('henry_v_act5_chorus_gloss9', 'henry_v_act5_chorus', 16, 'Blackheath', 'an open area south-east of London where royal entries traditionally assembled'), ('henry_v_act5_chorus_gloss10', 'henry_v_act5_chorus', 18, 'bruised helmet and his bended sword', 'Henry''s battered Agincourt arms — which his lords want to parade'), ('henry_v_act5_chorus_gloss11', 'henry_v_act5_chorus', 19, 'forbids it', 'Henry refuses the triumphal display — his modesty claim'), ('henry_v_act5_chorus_gloss12', 'henry_v_act5_chorus', 20, 'vainness and self-glorious pride', 'vanity and boastful pride'), ('henry_v_act5_chorus_gloss13', 'henry_v_act5_chorus', 21, 'signal and ostent', 'show and outward display'), ('henry_v_act5_chorus_gloss14', 'henry_v_act5_chorus', 23, 'quick forge and working-house of thought', 'the active smithy of the mind — the Chorus''s image for rapid imaginative scene-change'), ('henry_v_act5_chorus_gloss15', 'henry_v_act5_chorus', 25, 'mayor and all his brethren', 'the Lord Mayor of London and his aldermen'), ('henry_v_act5_chorus_gloss16', 'henry_v_act5_chorus', 26, 'senators of the antique Rome', 'senators of ancient Rome — the Chorus elevates London''s civic reception to a Roman triumph'), ('henry_v_act5_chorus_gloss17', 'henry_v_act5_chorus', 27, 'plebeians', 'common people — completes the Roman parallel'), ('henry_v_act5_chorus_gloss18', 'henry_v_act5_chorus', 28, 'conquering Caesar', 'Henry as returning Caesar — the triumphal image'), ('henry_v_act5_chorus_gloss19', 'henry_v_act5_chorus', 29, 'lower but loving likelihood', 'a humbler but affectionate parallel — the Chorus draws a current analogy'), ('henry_v_act5_chorus_gloss20', 'henry_v_act5_chorus', 30, 'general of our gracious empress', 'the Earl of Essex — Queen Elizabeth''s favorite, then leading troops in Ireland; the play''s rare topical reference, datable to spring 1599'), ('henry_v_act5_chorus_gloss21', 'henry_v_act5_chorus', 32, 'rebellion broached on his sword', 'rebellion impaled on his sword — the hoped-for Irish campaign victory that did not actually happen'), ('henry_v_act5_chorus_gloss22', 'henry_v_act5_chorus', 35, 'Now in London place him', 'imagine Henry in London now'), ('henry_v_act5_chorus_gloss23', 'henry_v_act5_chorus', 38, 'emperor’s coming in behalf of France', 'Emperor Sigismund came to England (1416) to mediate peace — a historical episode the Chorus skips over'), ('henry_v_act5_chorus_gloss24', 'henry_v_act5_chorus', 40, 'All the occurrences, whatever chanced', 'everything that happened — omitted for compression'), ('henry_v_act5_chorus_gloss25', 'henry_v_act5_chorus', 41, 'Harry’s back-return again to France', 'Henry''s second invasion of France (1417–1420), which led to the Treaty of Troyes'), ('henry_v_act5_chorus_gloss26', 'henry_v_act5_chorus', 42, 'play’d / The interim', 'acted (out) the intervening years — the Chorus as time-compressor'), ('henry_v_act5_chorus_gloss27', 'henry_v_act5_chorus', 44, 'brook abridgement', 'tolerate the shortening');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act5_scene1_gloss1', 'henry_v_act5_scene1', 1, 'Saint Davy’s day is past', 'March 1 (the Welsh national day) has already passed — why still wearing the leek? (see 4.1 and 4.7)'), ('henry_v_act5_scene1_gloss2', 'henry_v_act5_scene1', 2, 'occasions and causes why and wherefore', 'Fluellen''s pedantic triple-phrase for ''reasons'''), ('henry_v_act5_scene1_gloss3', 'henry_v_act5_scene1', 3, 'scauld', 'scabby; scurvy (dialect)'), ('henry_v_act5_scene1_gloss4', 'henry_v_act5_scene1', 4, 'pragging', 'bragging, in Fluellen''s Welsh accent — dialect marker'), ('henry_v_act5_scene1_gloss5', 'henry_v_act5_scene1', 4, 'Pistol, which you and yourself and all the world', 'Fluellen''s over-emphatic rhetoric'), ('henry_v_act5_scene1_gloss6', 'henry_v_act5_scene1', 6, 'prings me pread', 'brings me bread (Welsh ''b'' → ''p''); dialect preserved'), ('henry_v_act5_scene1_gloss7', 'henry_v_act5_scene1', 7, 'bid me eat my leek', 'Pistol earlier mocked the leek in front of Fluellen; now Fluellen will make him eat it, literally'), ('henry_v_act5_scene1_gloss8', 'henry_v_act5_scene1', 12, 'swelling like a turkey-cock', 'puffed up like a turkey — Gower''s classic English image of pomposity'), ('henry_v_act5_scene1_gloss9', 'henry_v_act5_scene1', 13, 'God pless you', '''God bless you'' in Welsh accent (sarcastic)'), ('henry_v_act5_scene1_gloss10', 'henry_v_act5_scene1', 15, 'bedlam', 'from ''Bethlem Hospital'' — madhouse; Pistol calls Fluellen mad'), ('henry_v_act5_scene1_gloss11', 'henry_v_act5_scene1', 15, 'base Trojan', 'vile scoundrel — Pistolese inflation'), ('henry_v_act5_scene1_gloss12', 'henry_v_act5_scene1', 16, 'fold up Parca’s fatal web', 'close up Fate''s doomed tapestry — ''Parcae'' = the three Roman Fates'), ('henry_v_act5_scene1_gloss13', 'henry_v_act5_scene1', 17, 'qualmish', 'nauseated'), ('henry_v_act5_scene1_gloss14', 'henry_v_act5_scene1', 18, 'peseech you heartily', 'beseech you (Welsh ''b'' → ''p'')'), ('henry_v_act5_scene1_gloss15', 'henry_v_act5_scene1', 20, 'affections and your appetites', 'Fluellen''s catalogue style — listing inclinations exhaustively'), ('henry_v_act5_scene1_gloss16', 'henry_v_act5_scene1', 23, 'Cadwallader', 'the last British-Welsh king before the Saxons (7th century) — Pistol swears by a Welsh legend'), ('henry_v_act5_scene1_gloss17', 'henry_v_act5_scene1', 24, 'one goat for you', 'Fluellen strikes Pistol with a cudgel; ''goat'' plays on Pistol''s ''goats'''), ('henry_v_act5_scene1_gloss18', 'henry_v_act5_scene1', 28, 'mountain-squire', 'mountain gentleman — a contemptuous term for a Welshman; Pistol had used it'), ('henry_v_act5_scene1_gloss19', 'henry_v_act5_scene1', 29, 'squire of low degree', 'lowly gentleman — Fluellen''s deflating retort; a 15th-century romance title'), ('henry_v_act5_scene1_gloss20', 'henry_v_act5_scene1', 33, 'peat his pate four days', 'beat your head for four days (Welsh ''b'' → ''p'')'), ('henry_v_act5_scene1_gloss21', 'henry_v_act5_scene1', 34, 'ploody coxcomb', 'bloody head (Welsh dialect); ''coxcomb'' = head'), ('henry_v_act5_scene1_gloss22', 'henry_v_act5_scene1', 39, 'not enough leek to swear by', 'there''s not enough leek left to use as an oath — Fluellen will keep feeding him'), ('henry_v_act5_scene1_gloss23', 'henry_v_act5_scene1', 40, 'cudgel', 'stout stick'), ('henry_v_act5_scene1_gloss24', 'henry_v_act5_scene1', 45, 'groat', 'a fourpenny coin — small money'), ('henry_v_act5_scene1_gloss25', 'henry_v_act5_scene1', 51, 'woodmonger', 'a seller of firewood — Fluellen will only pay him in cudgels'), ('henry_v_act5_scene1_gloss26', 'henry_v_act5_scene1', 54, 'counterfeit cowardly knave', 'fake, cowardly scoundrel — Gower''s dressing-down of Pistol'), ('henry_v_act5_scene1_gloss27', 'henry_v_act5_scene1', 56, 'predeceased valour', 'the valour of earlier generations'), ('henry_v_act5_scene1_gloss28', 'henry_v_act5_scene1', 57, 'gleeking and galling', 'mocking and jeering'), ('henry_v_act5_scene1_gloss29', 'henry_v_act5_scene1', 59, 'English in the native garb', 'English in the native manner — the ''standard'' accent'), ('henry_v_act5_scene1_gloss30', 'henry_v_act5_scene1', 60, 'Welsh correction teach you a good English condition', 'Welsh discipline will teach you English manners — Gower''s closing hit'), ('henry_v_act5_scene1_gloss31', 'henry_v_act5_scene1', 62, 'huswife', 'harlot; strumpet — Pistol pictures Fortune as a whore who betrayed him'), ('henry_v_act5_scene1_gloss32', 'henry_v_act5_scene1', 63, 'my Doll is dead i’ the spital', 'Doll Tearsheet has died in the hospital — ''my Doll''; the Hostess died of the same disease as was rumored'), ('henry_v_act5_scene1_gloss33', 'henry_v_act5_scene1', 64, 'malady of France', 'syphilis — euphemistically called ''the French disease'''), ('henry_v_act5_scene1_gloss34', 'henry_v_act5_scene1', 65, 'rendezvous', 'refuge; retreat (French term Pistol re-uses from 2.1)'), ('henry_v_act5_scene1_gloss35', 'henry_v_act5_scene1', 67, 'bawd I’ll turn', 'I''ll become a pimp — Pistol''s decline to outright criminality'), ('henry_v_act5_scene1_gloss36', 'henry_v_act5_scene1', 68, 'lean to cutpurse', 'incline toward pickpocketing'), ('henry_v_act5_scene1_gloss37', 'henry_v_act5_scene1', 70, 'patches will I get unto these cudgell’d scars', 'I''ll disguise my beating-bruises as war-wounds'), ('henry_v_act5_scene1_gloss38', 'henry_v_act5_scene1', 71, 'Gallia wars', 'the French wars — ''Gallia'' = ancient Gaul');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act5_scene2_gloss1', 'henry_v_act5_scene2', 1, 'wherefore we are met', 'for which we are gathered — Henry opens with formal diplomatic language'), ('henry_v_act5_scene2_gloss2', 'henry_v_act5_scene2', 2, 'brother France', 'fellow king of France — ''brother'' is the standard royal address between kings'), ('henry_v_act5_scene2_gloss3', 'henry_v_act5_scene2', 2, 'sister', 'Queen Isabel of Bavaria, Charles VI''s wife'), ('henry_v_act5_scene2_gloss4', 'henry_v_act5_scene2', 4, 'cousin Katharine', 'Princess Catherine of Valois — the betrothed'), ('henry_v_act5_scene2_gloss5', 'henry_v_act5_scene2', 7, 'Duke of Burgundy', 'Philip III ''the Good'' of Burgundy — historically not at Troyes; Shakespeare conflates him with his father John the Fearless'), ('henry_v_act5_scene2_gloss6', 'henry_v_act5_scene2', 12, 'issue', 'outcome; offspring — Queen Isabel''s diplomatic pun'), ('henry_v_act5_scene2_gloss7', 'henry_v_act5_scene2', 17, 'fatal balls of murdering basilisks', 'deadly cannonballs of killing serpents — a basilisk is both a mythical serpent whose look kills AND a large cannon'), ('henry_v_act5_scene2_gloss8', 'henry_v_act5_scene2', 18, 'venom of such looks', 'the poison of such glances — continuing the basilisk image'), ('henry_v_act5_scene2_gloss9', 'henry_v_act5_scene2', 27, 'bar', 'court-of-justice / meeting-place'), ('henry_v_act5_scene2_gloss10', 'henry_v_act5_scene2', 31, 'congreeted', 'greeted each other (a Shakespearean coinage)'), ('henry_v_act5_scene2_gloss11', 'henry_v_act5_scene2', 33, 'rub or what impediment', 'obstacle or hindrance — ''rub'' from bowls, already used in 2.2'), ('henry_v_act5_scene2_gloss12', 'henry_v_act5_scene2', 34, 'naked, poor and mangled Peace', 'Peace personified as a ravaged woman — Burgundy''s celebrated pastoral lament'), ('henry_v_act5_scene2_gloss13', 'henry_v_act5_scene2', 35, 'Dear nurse of arts', 'Peace nurses the arts, agriculture, and childbirth'), ('henry_v_act5_scene2_gloss14', 'henry_v_act5_scene2', 36, 'best garden of the world', 'France as Eden — the phrase the Epilogue will echo with bitter irony'), ('henry_v_act5_scene2_gloss15', 'henry_v_act5_scene2', 40, 'Corrupting in it own fertility', 'rotting in its own abundance — neglected farmland goes to weed'), ('henry_v_act5_scene2_gloss16', 'henry_v_act5_scene2', 42, 'hedges even-pleach’d', 'hedges evenly braided (maintained by pleaching) — but now overgrown'), ('henry_v_act5_scene2_gloss17', 'henry_v_act5_scene2', 44, 'fallow leas', 'fallow fields; unploughed meadows'), ('henry_v_act5_scene2_gloss18', 'henry_v_act5_scene2', 45, 'darnel, hemlock and rank fumitory', 'weeds — rye-grass (darnel), poisonous hemlock, smoky-looking fumitory; Shakespeare''s catalogue of agricultural neglect'), ('henry_v_act5_scene2_gloss19', 'henry_v_act5_scene2', 46, 'coulter', 'the blade of a plough that cuts the furrow'), ('henry_v_act5_scene2_gloss20', 'henry_v_act5_scene2', 47, 'deracinate', 'uproot; eradicate — a Latinate verb'), ('henry_v_act5_scene2_gloss21', 'henry_v_act5_scene2', 48, 'even mead', 'level meadow'), ('henry_v_act5_scene2_gloss22', 'henry_v_act5_scene2', 49, 'freckled cowslip, burnet and green clover', 'wildflowers and pasture-grass — what the meadow used to produce'), ('henry_v_act5_scene2_gloss23', 'henry_v_act5_scene2', 52, 'docks, rough thistles, kecksies, burs', 'weeds replacing wildflowers; ''kecksies'' = dry hollow stalks of cow-parsley'), ('henry_v_act5_scene2_gloss24', 'henry_v_act5_scene2', 59, 'grow like savages', 'grow wild, uncivilized — the soldier becomes the barbarian'), ('henry_v_act5_scene2_gloss25', 'henry_v_act5_scene2', 60, 'meditate on blood', 'think only of bloodshed'), ('henry_v_act5_scene2_gloss26', 'henry_v_act5_scene2', 61, 'diffused attire', 'disordered, slovenly clothing'), ('henry_v_act5_scene2_gloss27', 'henry_v_act5_scene2', 65, 'let', 'obstacle; hindrance (archaic)'), ('henry_v_act5_scene2_gloss28', 'henry_v_act5_scene2', 73, 'enscheduled', 'listed in a schedule; written in document form'), ('henry_v_act5_scene2_gloss29', 'henry_v_act5_scene2', 77, 'cursorary', 'cursory; hasty (archaic variant)'), ('henry_v_act5_scene2_gloss30', 'henry_v_act5_scene2', 82, 'peremptory answer', 'definitive, final answer'), ('henry_v_act5_scene2_gloss31', 'henry_v_act5_scene2', 95, 'capital demand', 'chief/principal demand — Katherine heads the list of terms'), ('henry_v_act5_scene2_gloss32', 'henry_v_act5_scene2', 96, 'fore-rank', 'front rank; first place in a list'), ('henry_v_act5_scene2_gloss33', 'henry_v_act5_scene2', 98, 'vouchsafe to teach a soldier terms', 'Henry''s wooing opener — he frames himself as a plain soldier rather than a court poet'), ('henry_v_act5_scene2_gloss34', 'henry_v_act5_scene2', 101, 'Your majesty shall mock me', 'Katherine''s worry — she thinks the king is mocking her broken English'), ('henry_v_act5_scene2_gloss35', 'henry_v_act5_scene2', 105, 'Pardonnez-moi', 'French: ''Forgive me'' — Katherine''s polite refusal phrase'), ('henry_v_act5_scene2_gloss36', 'henry_v_act5_scene2', 105, 'vat is “like me”', 'Katherine mishears ''do you like me'' as a pronoun — her comic misunderstanding drives the wooing'), ('henry_v_act5_scene2_gloss37', 'henry_v_act5_scene2', 107, 'Que dit-il? Que je suis semblable à les anges?', 'French: ''What does he say? That I am similar to the angels?'''), ('henry_v_act5_scene2_gloss38', 'henry_v_act5_scene2', 108, 'Oui, vraiment, sauf votre grâce, ainsi dit-il', 'French: ''Yes, truly, with all respect, that''s what he says'' — Alice''s courtly confirmation'), ('henry_v_act5_scene2_gloss39', 'henry_v_act5_scene2', 110, 'O bon Dieu! les langues des hommes sont pleines de tromperies', 'French: ''O good God! the tongues of men are full of deceits'''), ('henry_v_act5_scene2_gloss40', 'henry_v_act5_scene2', 112, 'dat de tongues of de mans is be full of deceits', 'Alice''s French-accented English — a back-translation joke'), ('henry_v_act5_scene2_gloss41', 'henry_v_act5_scene2', 116, 'plain king', 'a straightforward king — Henry''s rhetorical pose throughout the scene'), ('henry_v_act5_scene2_gloss42', 'henry_v_act5_scene2', 117, 'sold my farm to buy my crown', 'bought a throne by selling a farm — Henry''s mock-commoner identification'), ('henry_v_act5_scene2_gloss43', 'henry_v_act5_scene2', 118, 'mince it in love', 'speak delicately about love'), ('henry_v_act5_scene2_gloss44', 'henry_v_act5_scene2', 123, 'Marry', 'mild oath (from ''by the Virgin Mary'') — ''why, indeed'''), ('henry_v_act5_scene2_gloss45', 'henry_v_act5_scene2', 127, 'leap-frog', 'the children''s game — Henry offers athletic courtship'), ('henry_v_act5_scene2_gloss46', 'henry_v_act5_scene2', 129, 'buffet for my love', 'box (fight with fists) for love'), ('henry_v_act5_scene2_gloss47', 'henry_v_act5_scene2', 130, 'bound my horse', 'make my horse leap'), ('henry_v_act5_scene2_gloss48', 'henry_v_act5_scene2', 131, 'lay on like a butcher', 'lay into it like a butcher at work'), ('henry_v_act5_scene2_gloss49', 'henry_v_act5_scene2', 131, 'jack-an-apes', 'a monkey — ''Jack-an-apes'' was a common fairground monkey-in-costume'), ('henry_v_act5_scene2_gloss50', 'henry_v_act5_scene2', 132, 'look greenly', 'look love-sick; turn pale-green with longing'), ('henry_v_act5_scene2_gloss51', 'henry_v_act5_scene2', 132, 'gasp out my eloquence', 'deliver rehearsed flourishes of speech — Henry disclaims courtly poetry'), ('henry_v_act5_scene2_gloss52', 'henry_v_act5_scene2', 135, 'fellow of this temper', 'man of this disposition'), ('henry_v_act5_scene2_gloss53', 'henry_v_act5_scene2', 137, 'let thine eye be thy cook', 'let your eye doctor up my appearance — make me look tasty to you'), ('henry_v_act5_scene2_gloss54', 'henry_v_act5_scene2', 138, 'plain soldier', 'Henry''s self-ascribed register — the speech''s governing pose, simultaneously sincere and rhetorical'), ('henry_v_act5_scene2_gloss55', 'henry_v_act5_scene2', 142, 'uncoined constancy', 'unminted (unforged) fidelity — plain sincerity, not the currency of court'), ('henry_v_act5_scene2_gloss56', 'henry_v_act5_scene2', 143, 'fellows of infinite tongue', 'men of unending talk — Henry dismisses courtly lovers'), ('henry_v_act5_scene2_gloss57', 'henry_v_act5_scene2', 145, 'speaker is but a prater', 'a talker is just a chatter'), ('henry_v_act5_scene2_gloss58', 'henry_v_act5_scene2', 146, 'rhyme is but a ballad', 'rhyming verse is just a popular song'), ('henry_v_act5_scene2_gloss59', 'henry_v_act5_scene2', 147, 'curled pate will grow bald', 'curly hair will fall out — the catalogue of age''s ruin'), ('henry_v_act5_scene2_gloss60', 'henry_v_act5_scene2', 148, 'full eye will wax hollow', 'bright eye will grow sunken with age'), ('henry_v_act5_scene2_gloss61', 'henry_v_act5_scene2', 155, 'enemy of France', 'Katherine''s key question — can she love France''s conqueror? The political and personal merge'), ('henry_v_act5_scene2_gloss62', 'henry_v_act5_scene2', 158, 'not part with a village of it', 'Henry jokes he loves France so much he won''t give up any of it — fuses conquest with romance'), ('henry_v_act5_scene2_gloss63', 'henry_v_act5_scene2', 163, 'hang upon my tongue like a new-married wife', 'cling to my tongue like a bride to her husband'), ('henry_v_act5_scene2_gloss64', 'henry_v_act5_scene2', 164, 'Je quand sur le possession de France', 'Henry''s bungled French for ''when I am in possession of France'' — the comedy of his ''plain soldier'' pose'), ('henry_v_act5_scene2_gloss65', 'henry_v_act5_scene2', 166, 'Saint Denis', 'St. Denis — patron saint of France; Henry''s apotropaic invocation'), ('henry_v_act5_scene2_gloss66', 'henry_v_act5_scene2', 166, 'donc votre est France et vous êtes mienne', 'Henry''s bad French for ''so yours is France and you are mine'' — grammatically tangled, as he admits'), ('henry_v_act5_scene2_gloss67', 'henry_v_act5_scene2', 170, 'le françois que vous parlez, il est meilleur que l’Anglois lequel je parle', 'French: ''the French you speak is better than the English I speak'' — Katherine''s gallant courtesy'), ('henry_v_act5_scene2_gloss68', 'henry_v_act5_scene2', 173, 'truly-falsely', 'true-ly false-ly — Henry''s coinage for bilingual lovers'' half-accurate speech'), ('henry_v_act5_scene2_gloss69', 'henry_v_act5_scene2', 178, 'closet', 'private chamber'), ('henry_v_act5_scene2_gloss70', 'henry_v_act5_scene2', 183, 'get thee with scambling', 'conceive a child by rough wooing — ''scambling'' = disorderly, struggling'), ('henry_v_act5_scene2_gloss71', 'henry_v_act5_scene2', 184, 'Saint Denis and Saint George', 'French and English patron saints — the mixed-blood son''s dual patronage'), ('henry_v_act5_scene2_gloss72', 'henry_v_act5_scene2', 185, 'boy, half French, half English', 'the future Henry VI — born 1421; Henry predicts him to Katherine here'), ('henry_v_act5_scene2_gloss73', 'henry_v_act5_scene2', 186, 'take the Turk by the beard', 'humble the Turks (a dig at the Ottoman Empire) — Henry fantasizes a crusade against Constantinople'), ('henry_v_act5_scene2_gloss74', 'henry_v_act5_scene2', 187, 'flower-de-luce', 'fleur-de-lis — the heraldic lily of French royalty'), ('henry_v_act5_scene2_gloss75', 'henry_v_act5_scene2', 190, 'English moiety', 'English half'), ('henry_v_act5_scene2_gloss76', 'henry_v_act5_scene2', 191, 'la plus belle Katherine du monde', 'French: ''the most beautiful Katherine in the world'''), ('henry_v_act5_scene2_gloss77', 'henry_v_act5_scene2', 192, 'mon très cher et divin déesse', 'French: ''my most dear and divine goddess'' — ''déesse'' is feminine, though Henry''s grammar is imperfect'), ('henry_v_act5_scene2_gloss78', 'henry_v_act5_scene2', 193, 'Your majestee ave fausse French enough to deceive de most sage demoiselle', 'Katherine''s broken English: ''your majesty has false French enough to deceive the wisest young lady'''), ('henry_v_act5_scene2_gloss79', 'henry_v_act5_scene2', 198, 'beshrew my father’s ambition', 'curse my father''s political ambition — Henry blames Henry IV''s scheming for his unromantic appearance'), ('henry_v_act5_scene2_gloss80', 'henry_v_act5_scene2', 200, 'aspect of iron', 'iron-like expression'), ('henry_v_act5_scene2_gloss81', 'henry_v_act5_scene2', 203, 'ill layer up of beauty', 'poor preserver of beauty — old age doesn''t preserve well'), ('henry_v_act5_scene2_gloss82', 'henry_v_act5_scene2', 209, 'Harry of England, I am thine', 'the formula Henry wants Katherine to speak — formally yielding'), ('henry_v_act5_scene2_gloss83', 'henry_v_act5_scene2', 211, 'England is thine, Ireland is thine, France is thine', 'Henry''s dowry list — the three kingdoms he wishes to settle on her'), ('henry_v_act5_scene2_gloss84', 'henry_v_act5_scene2', 214, 'broken music', 'music played on incomplete consorts — ''broken'' = mixed instruments; Henry puns on Katherine''s broken English'), ('henry_v_act5_scene2_gloss85', 'henry_v_act5_scene2', 218, 'Dat is as it shall please le roi mon père', 'Katherine''s broken English with French: ''that is as it shall please the king my father'''), ('henry_v_act5_scene2_gloss86', 'henry_v_act5_scene2', 220, 'Den it sall also content me', 'Katherine''s broken English: ''then it shall also content me'' — her assent'), ('henry_v_act5_scene2_gloss87', 'henry_v_act5_scene2', 222, 'Laissez, mon seigneur', 'French: ''Let be, my lord'' — Katherine politely refuses the hand-kiss'), ('henry_v_act5_scene2_gloss88', 'henry_v_act5_scene2', 223, 'vous abaissiez votre grandeur', 'French: ''you lower your greatness'''), ('henry_v_act5_scene2_gloss89', 'henry_v_act5_scene2', 226, 'Les dames et demoiselles pour être baisées devant leurs noces', 'French: ''ladies and maidens to be kissed before their wedding'' — Katherine cites French marriage custom'), ('henry_v_act5_scene2_gloss90', 'henry_v_act5_scene2', 228, 'pour les ladies of France', 'Alice''s French-English mix: ''for the ladies of France'''), ('henry_v_act5_scene2_gloss91', 'henry_v_act5_scene2', 229, 'baiser en Anglish', 'Alice''s mix: ''to kiss in English'' — she doesn''t know the English word'), ('henry_v_act5_scene2_gloss92', 'henry_v_act5_scene2', 230, 'Your majestee entend bettre que moi', 'Alice''s broken English: ''Your majesty understands better than me'''), ('henry_v_act5_scene2_gloss93', 'henry_v_act5_scene2', 234, 'nice customs curtsy to great kings', 'fussy etiquette bows to royal prerogative — Henry''s smooth, self-authorizing logic'), ('henry_v_act5_scene2_gloss94', 'henry_v_act5_scene2', 235, 'weak list of a country’s fashion', 'the flimsy limit of a country''s convention'), ('henry_v_act5_scene2_gloss95', 'henry_v_act5_scene2', 236, 'makers of manners', 'Henry''s regal claim — kings don''t follow custom, they create it'), ('henry_v_act5_scene2_gloss96', 'henry_v_act5_scene2', 239, 'You have witchcraft in your lips', 'Henry''s flattery — after kissing her'), ('henry_v_act5_scene2_gloss97', 'henry_v_act5_scene2', 249, 'conjure up the spirit of love', 'summon the love-spirit — Burgundy will run this ritual-magic joke'), ('henry_v_act5_scene2_gloss98', 'henry_v_act5_scene2', 254, 'naked and blind', 'the iconography of Cupid — naked, blindfolded'), ('henry_v_act5_scene2_gloss99', 'henry_v_act5_scene2', 255, 'ros’d over with the virgin crimson of modesty', 'blushed over with virginal pink modesty — Burgundy''s courtly euphemism'), ('henry_v_act5_scene2_gloss100', 'henry_v_act5_scene2', 258, 'they do wink and yield', 'close their eyes and give in — the courtly cliché of female consent');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_act5_scene2_gloss101', 'henry_v_act5_scene2', 262, 'well summered and warm kept', 'kept warm through summer — ripening'), ('henry_v_act5_scene2_gloss102', 'henry_v_act5_scene2', 263, 'flies at Bartholomew-tide', 'flies in late August — drowsy, easy to catch; Bartholomew''s Day = August 24'), ('henry_v_act5_scene2_gloss103', 'henry_v_act5_scene2', 274, 'girdled with maiden walls', 'encircled with virgin walls — French cities still unentered, compared to Katherine'), ('henry_v_act5_scene2_gloss104', 'henry_v_act5_scene2', 287, 'Notre très-cher fils Henri, Roi d’Angleterre, Héritier de France', 'French: ''Our most dear son Henry, King of England, Heir of France'' — the key clause of the Treaty of Troyes (1420), making Henry heir to the French throne'), ('henry_v_act5_scene2_gloss105', 'henry_v_act5_scene2', 288, 'Praeclarissimus filius noster Henricus', 'Latin: ''Our most illustrious son Henry'' — parallel Latin text of the same article'), ('henry_v_act5_scene2_gloss106', 'henry_v_act5_scene2', 295, 'contending kingdoms', 'the rival kingdoms of France and England'), ('henry_v_act5_scene2_gloss107', 'henry_v_act5_scene2', 308, 'spousal', 'marriage'), ('henry_v_act5_scene2_gloss108', 'henry_v_act5_scene2', 311, 'paction', 'covenant; pact'), ('henry_v_act5_scene2_gloss109', 'henry_v_act5_scene2', 312, 'incorporate league', 'unified alliance — one body politic'), ('henry_v_act5_scene2_gloss110', 'henry_v_act5_scene2', 317, 'take your oath', 'the formal swearing of treaty-oaths — Henry''s political closing'), ('henry_v_act5_scene2_gloss111', 'henry_v_act5_scene2', 320, 'Sennet', 'a set of notes played on a trumpet, often signaling entry/exit of a royal party');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_epilogue_gloss1', 'henry_v_epilogue', 1, 'rough and all-unable pen', 'clumsy and inadequate pen — the author''s conventional modesty'), ('henry_v_epilogue_gloss2', 'henry_v_epilogue', 2, 'bending author', 'the stooping author — ''bending'' = bowing under the weight of his subject'), ('henry_v_epilogue_gloss3', 'henry_v_epilogue', 3, 'In little room confining mighty men', 'cramping great men into a small space — the theatre''s physical constraint echoed from the Prologue'), ('henry_v_epilogue_gloss4', 'henry_v_epilogue', 4, 'Mangling by starts', 'hacking apart in fits and starts — the play''s abridgement acknowledged'), ('henry_v_epilogue_gloss5', 'henry_v_epilogue', 5, 'Small time, but in that small most greatly lived', 'a short life, but within it lived most greatly — Henry V died at 35, nine years after Agincourt'), ('henry_v_epilogue_gloss6', 'henry_v_epilogue', 6, 'star of England', 'Henry as England''s brightest star'), ('henry_v_epilogue_gloss7', 'henry_v_epilogue', 6, 'Fortune made his sword', 'Fortune smithed his sword — his victories attributed to luck as much as virtue'), ('henry_v_epilogue_gloss8', 'henry_v_epilogue', 7, 'world’s best garden', 'France — the same phrase Burgundy used in 5.2; here edged with irony'), ('henry_v_epilogue_gloss9', 'henry_v_epilogue', 8, 'son imperial lord', 'his son Henry VI — infant heir to both thrones'), ('henry_v_epilogue_gloss10', 'henry_v_epilogue', 9, 'Henry the Sixth', 'Henry V''s son, born December 1421; crowned King of England as an infant in 1422, and (claimed) King of France as a child in 1431'), ('henry_v_epilogue_gloss11', 'henry_v_epilogue', 9, 'infant bands', 'swaddling-bands — Henry VI was nine months old when he inherited'), ('henry_v_epilogue_gloss12', 'henry_v_epilogue', 11, 'Whose state so many had the managing', 'so many regents and councils governed his state — the turmoil of the protectorate'), ('henry_v_epilogue_gloss13', 'henry_v_epilogue', 12, 'lost France and made his England bleed', 'under Henry VI, England lost all its French territories (by 1453) and was consumed by the Wars of the Roses (1455–1485)'), ('henry_v_epilogue_gloss14', 'henry_v_epilogue', 13, 'Which oft our stage hath shown', 'Shakespeare''s own Henry VI Parts 1–3 and Richard III, written earlier — the Epilogue cross-references the earlier tetralogy'), ('henry_v_epilogue_gloss15', 'henry_v_epilogue', 14, 'In your fair minds let this acceptance take', 'accept this in your kind imagination — the final petition, echoing the Prologue''s opening plea');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('henry_v_prologue_gloss1', 'henry_v_prologue', 1, 'Muse of fire', 'highest of the classical Muses — associated with inspired, elevated poetry; the element of fire was thought the most noble'), ('henry_v_prologue_gloss2', 'henry_v_prologue', 1, 'ascend', 'rise up to'), ('henry_v_prologue_gloss3', 'henry_v_prologue', 2, 'brightest heaven of invention', 'the highest realm of creative imagination — ''invention'' means poetic creation'), ('henry_v_prologue_gloss4', 'henry_v_prologue', 3, 'A kingdom for a stage', 'a whole kingdom to serve as the playing space — the wish for scale the theatre can''t supply'), ('henry_v_prologue_gloss5', 'henry_v_prologue', 5, 'warlike Harry', 'Henry V — ''Harry'' is the familiar form of Henry throughout the play'), ('henry_v_prologue_gloss6', 'henry_v_prologue', 6, 'port of Mars', 'bearing of Mars — the Roman god of war'), ('henry_v_prologue_gloss7', 'henry_v_prologue', 7, 'Leash’d in like hounds', 'held in check as if leashed — war''s catastrophes are Henry''s hunting dogs'), ('henry_v_prologue_gloss8', 'henry_v_prologue', 7, 'famine, sword and fire', 'the three calamities of invasion — starvation, slaughter, and burning'), ('henry_v_prologue_gloss9', 'henry_v_prologue', 8, 'Crouch for employment', 'wait ready to be unleashed'), ('henry_v_prologue_gloss10', 'henry_v_prologue', 8, 'gentles all', 'gentlemen all — formal address to the audience'), ('henry_v_prologue_gloss11', 'henry_v_prologue', 9, 'flat unraised spirits', 'unglorified, ordinary souls — the actors'' apology for their own plainness'), ('henry_v_prologue_gloss12', 'henry_v_prologue', 10, 'unworthy scaffold', 'the stage, humbly described — ''scaffold'' here = raised platform, not gallows'), ('henry_v_prologue_gloss13', 'henry_v_prologue', 11, 'cockpit', 'small enclosed arena — either a pit for cockfighting or the round theatre itself'), ('henry_v_prologue_gloss14', 'henry_v_prologue', 12, 'vasty fields of France', 'the enormous French battlefields — ''vasty'' = vast'), ('henry_v_prologue_gloss15', 'henry_v_prologue', 13, 'wooden O', 'the Globe Theatre — Shakespeare''s round wooden playhouse'), ('henry_v_prologue_gloss16', 'henry_v_prologue', 13, 'casques', 'helmets'), ('henry_v_prologue_gloss17', 'henry_v_prologue', 14, 'Agincourt', 'the 1415 battle where Henry defeated a much larger French army'), ('henry_v_prologue_gloss18', 'henry_v_prologue', 15, 'crooked figure', 'a zero — a curved numeral that multiplies when placed after a digit'), ('henry_v_prologue_gloss19', 'henry_v_prologue', 16, 'Attest in little place a million', 'stand in a small space for a great sum — the zero''s mathematical trick'), ('henry_v_prologue_gloss20', 'henry_v_prologue', 17, 'ciphers', 'zeros; also, insignificant things'), ('henry_v_prologue_gloss21', 'henry_v_prologue', 17, 'accompt', 'account; reckoning'), ('henry_v_prologue_gloss22', 'henry_v_prologue', 18, 'imaginary forces', 'the powers of your imagination'), ('henry_v_prologue_gloss23', 'henry_v_prologue', 19, 'girdle', 'belt; encircling boundary — i.e. the theatre''s walls'), ('henry_v_prologue_gloss24', 'henry_v_prologue', 21, 'abutting fronts', 'facing coastlines — England and France stare at each other across the Channel'), ('henry_v_prologue_gloss25', 'henry_v_prologue', 22, 'perilous narrow ocean', 'the dangerous, narrow sea — the English Channel'), ('henry_v_prologue_gloss26', 'henry_v_prologue', 23, 'Piece out our imperfections', 'fill in what the stage lacks'), ('henry_v_prologue_gloss27', 'henry_v_prologue', 25, 'puissance', 'military might; armed force'), ('henry_v_prologue_gloss28', 'henry_v_prologue', 27, 'Printing their proud hoofs i’ the receiving earth', 'stamping their hooves on the soft ground — one of the play''s defining verbal images of imagined spectacle'), ('henry_v_prologue_gloss29', 'henry_v_prologue', 28, 'deck', 'adorn; clothe in splendor'), ('henry_v_prologue_gloss30', 'henry_v_prologue', 29, 'jumping o’er times', 'skipping across years — the chorus announces its freedom with chronology'), ('henry_v_prologue_gloss31', 'henry_v_prologue', 31, 'hourglass', 'the running-time of a stage performance'), ('henry_v_prologue_gloss32', 'henry_v_prologue', 32, 'Admit me Chorus', 'accept me as the Chorus — the classical Greek convention of a narrating voice'), ('henry_v_prologue_gloss33', 'henry_v_prologue', 33, 'prologue-like', 'in the manner of a prologue'), ('henry_v_prologue_gloss34', 'henry_v_prologue', 34, 'Gently to hear, kindly to judge', 'to listen patiently and judge with sympathy — the standard petition for indulgence');
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act1_scene1_ann1', 'henry_v_act1_scene1', 1, 19, 'Henry V 1.1.1–19', 'historical', 'The bill that starts the war', 'The scene opens on a parliamentary threat: a bill, first proposed in the reign of Henry IV and now revived, would strip the English Church of temporal lands worth more than half its possessions. Canterbury''s calculation is precise — the confiscated revenues would maintain fifteen earls, fifteen hundred knights, six thousand two hundred esquires, a hundred almshouses, and would put £1,000 a year into the royal treasury. These figures are drawn from Raphael Holinshed''s Chronicles (1587), Shakespeare''s principal source. The historical bill, first raised in 1404 and revived in 1410 and 1414, was real, and so was the political logic: an ambitious Church-stripping measure was a durable threat to clerical wealth. Canterbury''s counter-move — to engage the king''s ambition so thoroughly in a French war that the bill cannot reach a vote — reads as realpolitik. Shakespeare shows the Church actively procuring the war. This is a materially more compromising portrait of the invasion''s origins than anything Henry himself will admit in the scenes that follow.', ARRAY['Raphael Holinshed, Chronicles of England, Scotland, and Ireland (1587)','Gary Taylor (ed.), The Oxford Shakespeare: Henry V (1982), introduction']::TEXT[]), ('henry_v_act1_scene1_ann2', 'henry_v_act1_scene1', 24, 45, 'Henry V 1.1.24–45', 'thematic', 'The conversion narrative — Hal to Henry', 'Canterbury''s account of Henry''s transformation — wildness that died with his father, Consideration whipping ''the offending Adam'' out of him, the king now full of divinity, policy, and theology — compresses the arc of the Henry IV plays into forty lines. It is also strategically self-serving: Canterbury is flattering the king in advance of asking him to hear the Church''s war-argument. Whether Henry''s piety is real or performed is one of the play''s open questions. The scene leaves it ambiguous on purpose: Canterbury''s ''miracle'' rhetoric sits beside Ely''s more coolly political observation that they still need to act to prevent the bill. Audiences who have read the Henry IV plays know that Prince Hal''s transformation at his coronation was public theatre; audiences who haven''t hear Canterbury''s speech as sincere wonder. Both readings remain available.', ARRAY['Stephen Greenblatt, ''Invisible Bullets,'' Shakespearean Negotiations (1988)','Alexander Leggatt, Shakespeare''s Political Drama (1988)']::TEXT[]), ('henry_v_act1_scene1_ann3', 'henry_v_act1_scene1', 70, 102, 'Henry V 1.1.70–102', 'structural', 'Canterbury''s motive, made explicit', 'The scene''s most important structural feature is that Canterbury lays out his plan to divert the king before the king appears. By the time Henry enters in 1.2 and solicits Canterbury''s legal judgement on the French claim, we already know the Archbishop has an institutional interest in encouraging the war. This changes what we hear in the next scene. When Canterbury speaks for forty lines about the Salic Law, we are not watching a disinterested legal consultation; we are watching a bought advocate. Shakespeare does not belabour the point, but he stages the causal sequence clearly: Church threat, political maneuver, war-justification. The play''s later emphasis on Henry''s providentialism and the God-fought nature of Agincourt must be read against this opening frame. The fact that the soldiers themselves debate the war''s justice in 4.1 (Williams''s challenge) is thus not a late innovation; the play has been keeping the question open from its first scene.', ARRAY['A. R. Humphreys, The Arden Shakespeare: Henry V (1968)','Andrew Gurr (ed.), King Henry V (New Cambridge Shakespeare, 1992)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act1_scene2_ann1', 'henry_v_act1_scene2', 34, 100, 'Henry V 1.2.34–100', 'historical', 'The Salic Law speech — historical fact, satirical stagecraft', 'Canterbury''s sixty-line disquisition on the Salic Law is drawn directly, and in places verbatim, from Holinshed''s Chronicles, which quotes the speech that Archbishop Chichele (the historical Canterbury) delivered to Parliament in 1414. Historically, the Salic Law — a 6th-century Frankish rule of inheritance — was invoked by 14th-century French jurists to bar inheritance of the French crown through the female line and thus to deny Edward III''s claim. Canterbury''s counter-argument is that the Salic Law applied only to the German Salian region, not to France, and that in any event the French themselves had repeatedly inherited through the female line. Whether he is right or tendentious is a genuine scholarly question; the historical arguments were and are real. But Shakespeare stages the exposition satirically. Canterbury speaks for sixty lines of tangled dynastic geography — Pharamond, Pepin, Hugh Capet, Lewis the Tenth, Louis the Ninth — and by line 88 Henry has to press him: ''May I with right and conscience make this claim?'' The absurd scholarly cascade enacts the process by which a war of conquest is equipped with legal justification: laboriously, in learned Latin and medieval chronology, under pressure from a king who wants a yes.', ARRAY['Raphael Holinshed, Chronicles (1587)','Gary Taylor (ed.), The Oxford Shakespeare: Henry V (1982), introduction and 1.2 commentary','Jonathan Bate, The Genius of Shakespeare (1997)']::TEXT[]), ('henry_v_act1_scene2_ann2', 'henry_v_act1_scene2', 184, 220, 'Henry V 1.2.184–220', 'close_reading', 'Exeter''s honeybee speech — the commonwealth as hive', 'Exeter''s extended simile of the kingdom as a beehive — with its magistrates, merchants, sad-eyed executioners, and idle drones all ordered under the queen bee — is a set-piece of Elizabethan political theory in verse. The hive was a commonplace figure for the ordered commonwealth, drawn from Virgil''s Georgics Book IV and transmitted through Renaissance emblem books and courtesy literature. Shakespeare''s particular version works as an argument: a kingdom can sustain both domestic governance and foreign expedition simultaneously, because each order of subject has its own proper work. This answers Canterbury''s earlier warning about the Scots invading if the army crosses to France. The simile matters because it is the play''s fullest positive vision of political order — a kind of counter-argument to the mess and improvisation that every other scene shows. Shakespeare places it here, at the war''s planning moment, as if to say: this is the ideal the expedition claims to embody. Whether the play endorses the ideal or merely displays it is, again, left open.', ARRAY['Virgil, Georgics IV','Frank Kermode, Shakespeare''s Language (2000)','Pauline Croft, King James (2003), on hive imagery in early modern political writing']::TEXT[]), ('henry_v_act1_scene2_ann3', 'henry_v_act1_scene2', 245, 300, 'Henry V 1.2.245–300', 'historical', 'The tennis-balls episode — a legendary insult', 'The Dauphin''s mocking gift of tennis balls, and Henry''s elaborate in-kind reply, is one of the play''s most famous set-pieces. It is also on historically shaky ground. The story appears in several 15th-century chronicles, including the First English Life of Henry V (c. 1513–14) and a ballad tradition that predates the chronicles themselves. But it is not in the most contemporary French sources. Most modern historians treat it as legend — a crystallizing narrative device for a diplomatic insult whose actual form, if any, is lost. What Shakespeare does with the episode is, however, historically precise in another way: he turns Henry''s answer into a prophetic catalogue of French suffering (''mock mothers from their sons, / Mock castles down…''), and he locates the conversion of the insult into a war-justification at the crown-coronation moment of the play. ''His jest shall savour but of shallow wit, / When thousands weep more than did laugh at it'' (lines 296–297): Henry transforms personal insult into collective retribution. Readers should notice how comfortably the rhetoric of wounded royal honour does this work — and how the Dauphin is made, in effect, to authorize the war.', ARRAY['The First English Life of King Henry the Fifth, ed. C. L. Kingsford (1911)','Anne Curry, Agincourt: A New History (2005)','A. R. Humphreys, The Arden Shakespeare: Henry V (1968)']::TEXT[]), ('henry_v_act1_scene2_ann4', 'henry_v_act1_scene2', 300, 312, 'Henry V 1.2.300–312', 'thematic', '''Well-hallow''d cause'' — how a claim becomes a crusade', 'Henry''s closing line — ''But this lies all within the will of God, / To whom I do appeal'' — places the war under divine sanction. This is the characteristic rhetorical move of Henry''s speeches throughout the play, and by this point in the scene we have watched it be manufactured: Canterbury''s compromised legal opinion, the Church''s institutional interest, the sixty lines of Salic genealogy, the lords'' eager endorsement, and finally the Dauphin''s tennis-balls giving Henry the moral licence to call it an affront. What begins in 1.1 as a bill against Church lands ends in 1.2 as a ''well-hallow''d cause'' with God on its side. The play does not tell us that this is cynical; it merely stages the process with unusual clarity. The same providentialism will return after Agincourt, when Henry forbids any soldier to claim credit for the victory on pain of death. Readers may notice that the same rhetorical apparatus that sanctifies conquest in 1.2 will sanctify victory in 4.8.', ARRAY['Stephen Greenblatt, Shakespearean Negotiations (1988)','Norman Rabkin, ''Either/Or,'' in Shakespeare and the Problem of Meaning (1981)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act2_chorus_ann1', 'henry_v_act2_chorus', 1, 14, 'Henry V 2 Chorus.1–14', 'structural', 'The economy of war — England retooling', 'The Chorus''s opening economic image — selling the pasture to buy the horse — is one of the play''s most materially specific lines. It captures the Tudor understanding of an expeditionary war: livestock and arable land converted to cavalry; armourers prospering; silk and leisure (''silken dalliance'') stored away; the young men mobilized. The Chorus frames this as moral elevation (honour ''reigns solely in the breast of every man''), but the economic mechanism remains visible. ''Now thrive the armourers'' is not incidental — Shakespeare is telling us that war is industry. The speech''s buoyant tone contrasts sharply with the tavern scene that follows (2.1), in which the war''s actual recruits are low-life quarrellers preparing to go pillage for a living. The juxtaposition is deliberate. The Chorus speaks for official England; the play gives us the other England in counterpoint.', ARRAY['Andrew Gurr (ed.), King Henry V (New Cambridge Shakespeare, 1992)','Thomas Healy, Shakespeare, Alienation and the Early Modern Stage (1994)']::TEXT[]), ('henry_v_act2_chorus_ann2', 'henry_v_act2_chorus', 20, 30, 'Henry V 2 Chorus.20–30', 'historical', 'The three traitors of Southampton', 'The Chorus names the Southampton plotters — Richard Earl of Cambridge, Henry Lord Scroop of Masham, and Sir Thomas Grey of Northumberland — and attributes their treason simply to French gold. Historically, the situation was more complicated. Cambridge''s real motive was dynastic: he was married to the Mortimer line, whose claim to the English throne was arguably stronger than the Lancastrian Henry''s. His plot aimed to put his brother-in-law, Edmund Mortimer, Earl of March, on the throne. The play suppresses this because it would introduce the Lancastrian usurpation problem that Henry V itself wants to keep offstage. By reducing the motive to ''the gilt of France,'' the Chorus and the later scene collapse a dynastic conspiracy into a simple bribery narrative. This is a characteristic move: the play manages the awkward question of Henry''s legitimacy throughout, and the Chorus''s simplification is one of its key instruments.', ARRAY['Gary Taylor (ed.), The Oxford Shakespeare: Henry V (1982)','Anne Curry, Agincourt: A New History (2005)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act2_scene1_ann1', 'henry_v_act2_scene1', 1, 50, 'Henry V 2.1.1–50', 'thematic', 'The other England — Eastcheap after Falstaff', 'The Eastcheap scene that opens Act II introduces the remnants of Falstaff''s old company — Bardolph, Nym, Pistol — and installs them as the play''s recurring comic counterpoint to the official war. Their world is petty theft, doubtful marriages, and sword-quarrels about eight-shilling debts. Shakespeare is doing something structurally specific here: he is showing us who Henry''s war actually sweeps up. The Chorus has just named England''s ''youth on fire'' and ''the mirror of all Christian kings''; the scene immediately undercuts the image by staging Nym''s plodding cowardice and Pistol''s inflated bombast as the mobilization''s reality on the ground. The contrast is not sentimental — Shakespeare is not asking us to love Pistol — but it is structural: the play''s official voice and its low-comic undervoice alternate throughout, and this is the first such alternation.', ARRAY['C. L. Barber, Shakespeare''s Festive Comedy (1959)','Robert Weimann, Shakespeare and the Popular Tradition in the Theater (1978)']::TEXT[]), ('henry_v_act2_scene1_ann2', 'henry_v_act2_scene1', 60, 100, 'Henry V 2.1.60–100', 'linguistic', 'Pistol''s diction — mock-heroic as a character', 'Pistol is Shakespeare''s most fully realized parody of a certain kind of Elizabethan actor — the roaring, classically-allusive, stage-villain whose speech is studded with half-digested Latin, misquoted classical mythology, and oaths designed to sound imposing. His vocabulary is a running pastiche: ''Couple a gorge'' (bungled French), ''quondam Quickly'' (Latinate pretension), ''pauca'' (schoolboy Latin), ''Cressid''s kind'' (misused Troy-matter). His rhythmic, near-blank-verse inflections parody the high style of earlier Elizabethan drama (especially Marlowe). The comedy depends on our hearing the rhetorical mode Pistol is imitating. Importantly, Pistol''s inflation is not just funny: it is a window into what soldier-theatre could sound like in 1599, and the play will later (5.1) strip away the inflated pose entirely, showing us the ordinary scrounger underneath.', ARRAY['M. M. Mahood, Shakespeare''s Wordplay (1957)','Emrys Jones, Scenic Form in Shakespeare (1971)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act2_scene2_ann1', 'henry_v_act2_scene2', 39, 85, 'Henry V 2.2.39–85', 'close_reading', 'The trap sprung — Henry''s performance of mercy', 'Henry stages the traitors'' entrapment with theatrical care. He first proposes releasing a drunken man who railed against him; the three traitors pile on insisting the king be harsher; Henry gently overrules them and grants mercy. Only then does he hand them the papers that, as they read them, reveal their own treason. The trap''s elegance is the point: the traitors have just demanded strict punishment, and Henry will now apply to them the logic they themselves urged. ''The mercy that was quick in us but late, / By your own counsel is suppress''d and kill''d'' (lines 77–78). This is the kind of monarch Henry has become: one who makes his enemies condemn themselves with their own argument. Readers may recall Prince Hal in Henry IV Part 2, who famously banishes Falstaff at his coronation with calculated public timing. The political method is the same. What looks like improvised royal authority is in fact carefully rehearsed dramaturgy.', ARRAY['Alexander Leggatt, Shakespeare''s Political Drama (1988)','Stephen Greenblatt, Shakespearean Negotiations (1988)']::TEXT[]), ('henry_v_act2_scene2_ann2', 'henry_v_act2_scene2', 92, 140, 'Henry V 2.2.92–140', 'thematic', 'Scroop and the Second Fall', 'Henry''s long reproach to Scroop in particular — ''Thou that didst bear the key of all my counsels'' — is the most emotionally charged thing Henry says in the play up to this point. Scroop was his intimate, his ''bedfellow'' in the period''s sense of confidant. His betrayal is framed as ''another fall of man,'' a second Eden. The theological vocabulary is deliberate: Henry''s scandal is not merely political but cosmological. A trusted companion who was ''spare in diet, / Free from gross passion,'' ''garnish''d and deck''d in modest complement'' — exactly the virtues Canterbury earlier attributed to Henry himself in 1.1 — has proven hollow. The passage resonates with the Henry IV plays'' preoccupation with false appearances and feigned loyalty. It is also the moment the play comes closest to expressing genuine anguish from Henry; he announces it himself (''I will weep for thee''). The anguish is rhetorical as well as felt; it is the only proper setting in which to pronounce a capital sentence against a man who once ate at your table.', ARRAY['Harold Bloom, Shakespeare: The Invention of the Human (1998)','Graham Holderness, Shakespeare: The Histories (2000)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act2_scene3_ann1', 'henry_v_act2_scene3', 1, 35, 'Henry V 2.3.1–35', 'biographical', 'Falstaff''s death — narrative necessity', 'The death of Falstaff, reported with unguarded tenderness by the Hostess, is one of the most-loved passages in Shakespeare and one of the most necessary. Sir John Falstaff had been the comic center of Henry IV Parts 1 and 2 — the fat knight whose drunken wit made Prince Hal''s youth recognizably human. At the end of Part 2, Henry (now crowned) publicly rejected him. Part of that play''s bargain with the audience was the Epilogue''s promise that Falstaff would return in Henry V. Shakespeare went back on that promise: Falstaff does not appear. The reasons are speculative — possibly a dispute with the actor Will Kemp, possibly a recognition that Falstaff''s comic register is incompatible with the martial tone of Henry V. Whatever the cause, Shakespeare had to remove the character, and he does it with exquisite misdirection: the Hostess''s mangled syntax, the famous ''babbled of green fields,'' the detail of Falstaff fumbling with the sheets at the turning of the tide. Falstaff dies in the play''s wings; the audience inherits the grief without ever seeing the body.', ARRAY['J. Dover Wilson, The Fortunes of Falstaff (1943)','Harold Bloom, Shakespeare: The Invention of the Human (1998)','René Weis, Shakespeare Unbound (2007)']::TEXT[]), ('henry_v_act2_scene3_ann2', 'henry_v_act2_scene3', 9, 15, 'Henry V 2.3.9–15', 'textual', '''A'' babbled of green fields'' — Theobald''s textual miracle', 'The phrase ''a'' babbled of green fields,'' one of the most resonant lines in Shakespeare, does not appear in any original text. The First Folio (1623) reads ''a Table of greene fields,'' which is nonsense. The eighteenth-century editor Lewis Theobald conjectured in 1733 that a compositor had misread Shakespeare''s ''a bablde'' (abbreviated for ''a babbled'') as ''a Table.'' Theobald''s emendation is so accepted that modern editions simply print it; few lines of Shakespeare are so universally cited and so purely editorial. The reading gives us a dying Falstaff in delirious peace, remembering pastoral — an image that retroactively humanizes the whole Eastcheap world. It is worth noting that this is what textual editing, at its best, can do: it can recover a line that makes a whole scene sing.', ARRAY['Lewis Theobald, Shakespeare Restored (1726)','Stanley Wells & Gary Taylor, William Shakespeare: A Textual Companion (1987)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act2_scene4_ann1', 'henry_v_act2_scene4', 25, 48, 'Henry V 2.4.25–48', 'thematic', 'The French divided — two views of Henry', 'The French council scene stages a revealing internal disagreement. The Dauphin — ''idly king''d'' Henry is a ''vain, giddy, shallow, humorous youth'' — dismisses the English threat as a Whitsun morris-dance (folk-dance of village England). The Constable (a more serious figure) rebukes him: Henry''s reputation for wildness is the ''outside of the Roman Brutus,'' a discretion disguised as folly. The Constable''s parallel is literary — he invokes Lucius Junius Brutus, the founder of the Roman Republic, who feigned stupidity to mask the wit that would later overthrow the Tarquins. The French court is divided not over strategy but over Henry''s character, and the Dauphin is on the wrong side. This prepares us for the Dauphin''s eventual humiliation and the Constable''s death at Agincourt: the serious reader of Henry is right, and he dies for his accuracy; the reductive reader of Henry is wrong, and he is disgraced.', ARRAY['Gary Taylor (ed.), The Oxford Shakespeare: Henry V (1982)','Joel Altman, ''Vile Participation: The Amplification of Violence in the Theater of Henry V,'' Shakespeare Quarterly 42 (1991)']::TEXT[]), ('henry_v_act2_scene4_ann2', 'henry_v_act2_scene4', 78, 112, 'Henry V 2.4.78–112', 'structural', 'Exeter''s delivery — the formal demand', 'Exeter''s speech to the French king frames the English claim in the most aggressive possible diplomatic language: ''divest yourself … of the borrow''d glories … unto the crown of France.'' The threat escalates from ''bloody constraint'' (line 97) to biblical thunder (''in thunder and in earthquake, like a Jove'') to a grotesque inventory of the war''s human cost — widows, orphans, maidens'' groans for husbands, fathers, and betrothed lovers. The rhetorical work Exeter performs here is to make Henry''s claim both total and inevitable. The French king answers with courtly delay (''Tomorrow shall you bear our full intent back''); the Dauphin cannot help himself and provokes Exeter further, earning a sharper secondary threat. The scene closes with Exeter''s warning that Henry ''is footed in this land already'' — i.e. the invasion is not a threat but an accomplished fact. Diplomacy here is theatre, with the outcome already decided.', ARRAY['Andrew Gurr (ed.), King Henry V (New Cambridge Shakespeare, 1992)','Robert Shaughnessy, Shakespeare in the 21st Century (2012), on diplomatic staging']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act3_chorus_ann1', 'henry_v_act3_chorus', 1, 18, 'Henry V 3 Chorus.1–18', 'close_reading', '''A city on th'' inconstant billows dancing'' — the fleet as sea-borne metropolis', 'The Act 3 Chorus is one of Shakespeare''s great occasional poems in miniature. Its core image — the English fleet observed from shore, ''a city on th'' inconstant billows dancing'' — has been admired since the Romantics. The stanza does several things at once: it persuades the audience to visualize a vast invasion fleet the Globe cannot stage; it dignifies the expedition with civic grandeur (''so appears this fleet majestical''); and it uses shore-based spectatorship (''you stand upon the rivage'') to make the audience an onlooker rather than a participant. Notice the verbs: ''grapple your minds to sternage of this navy,'' ''Work, work your thoughts.'' The Chorus demands work from us; the language is almost nautical labor. And the stanza''s closing image — ''the nimble gunner / With linstock now the devilish cannon touches / And down goes all before them'' — dispatches Harfleur''s fall in a single graceful sentence, letting the imagination accomplish what the stage cannot.', ARRAY['Samuel Taylor Coleridge, Lectures on Shakespeare (1818)','Frank Kermode, Shakespeare''s Language (2000)']::TEXT[]), ('henry_v_act3_chorus_ann2', 'henry_v_act3_chorus', 28, 35, 'Henry V 3 Chorus.28–35', 'thematic', 'The Katherine offer — dowry as deflection', 'The Chorus introduces an offstage diplomatic detail: the French king has offered Katharine as Henry''s bride, together with ''some petty and unprofitable dukedoms,'' as a settlement. ''The offer likes not'' — Henry refuses. Why this matters: it tells the audience that a marriage-solution to the war existed and was declined. When Act 5 finally stages the wooing scene, the audience should remember that Katherine was offered to Henry before Harfleur, before Agincourt, before the thousands of French dead. Henry accepted her only after taking France at sword-point. The Chorus''s brief couplet — dowry proposal, Henry refuses, ''nimble gunner … devilish cannon touches'' — is a compressed argument about what this war is actually buying.', ARRAY['Graham Holderness, Shakespeare: The Histories (2000)','Andrew Gurr (ed.), King Henry V (New Cambridge Shakespeare, 1992)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act3_scene1_ann1', 'henry_v_act3_scene1', 1, 17, 'Henry V 3.1.1–17', 'close_reading', 'The rhetorical architecture of ''Once more unto the breach''', 'Henry''s speech to the soldiers at the Harfleur breach is a masterclass in siege oratory. Its structure is rigorously controlled. Lines 1–2 give the imperative and its stakes (return to the breach, or die filling it). Lines 3–5 mark the ethical pivot: what virtue is in peace is not what virtue is in war. Lines 6–14 supply the key metamorphic command: imitate the tiger, stiffen sinews, summon blood, disguise fair nature with hard-favour''d rage. The body-language is physical: teeth set, nostrils stretched, breath held, every spirit bent up. The rhetorical technique is transformation — Henry is not asking the soldiers to be braver; he is prescribing a bodily and facial reconfiguration that will make them killers. The speech is also addressed in two registers: first to the noblest (''you noblest English / Whose blood is fet from fathers of war-proof''), then to the yeomen (''good yeomen / Whose limbs were made in England''), closing with the single collective war-cry. The rhetorical care is near-liturgical.', ARRAY['Madeleine Doran, Shakespeare''s Dramatic Language (1976)','Brian Vickers, The Artistry of Shakespeare''s Prose (1968)']::TEXT[]), ('henry_v_act3_scene1_ann2', 'henry_v_act3_scene1', 17, 34, 'Henry V 3.1.17–34', 'thematic', 'Class-addressed oratory — the yeomen and the game', 'Henry''s speech explicitly addresses the yeomen — the free-born English farming commoners who made up the archer corps — and praises ''the mettle of your pasture.'' This acknowledges a military reality: the longbow, which would decide Agincourt, was the yeoman''s weapon, not the knight''s. The speech flatters the social group that would actually win the battle. The closing image — ''I see you stand like greyhounds in the slips, / Straining upon the start. The game''s afoot'' — converts the army into a hunting pack and the French into quarry. ''The game''s afoot'' has become proverbial (and famously re-used by Arthur Conan Doyle''s Sherlock Holmes). In context, it is the speech''s decisive detheologizing move: what began as a siege-ethic ends as a blood-sport. The breach-ethic is not ''kill in the name of God'' but ''chase the prey.'' The closing invocation ''God for Harry, England, and Saint George'' nominally rebalances this, but the hunt-image lingers.', ARRAY['Juliet Barker, Agincourt: The King, the Campaign, the Battle (2005)','Emrys Jones, Scenic Form in Shakespeare (1971)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act3_scene2_ann1', 'henry_v_act3_scene2', 23, 44, 'Henry V 3.2.23–44', 'structural', 'The Boy''s soliloquy — the war seen from below', 'The Boy''s long speech assessing Pistol, Bardolph, and Nym is one of the play''s most important counter-frames. The Chorus has just shown us ''our swift scene'' flying ''with imagined wing'' to Harfleur; Henry has just delivered the breach oration. The Boy, aged perhaps twelve, walks onstage and gives us an adult appraisal: the three older men who are his masters are cowards, thieves, and frauds. The speech is clear-eyed (''I must leave them, and seek some better service''); it is also delivered directly to the audience, without irony. Later, at 4.4 and 4.7, the Boy will be revealed to have been left with the camp''s luggage and killed by the French during their raid. The play thus frames the war with the perspective of an intelligent child whom the play allows to speak truly once, and then allows to die. Readers should notice whom Shakespeare trusts with clarity and whom he rewards with survival.', ARRAY['C. L. Barber, Shakespeare''s Festive Comedy (1959)','Thomas Healy, Shakespeare, Alienation and the Early Modern Stage (1994)']::TEXT[]), ('henry_v_act3_scene2_ann2', 'henry_v_act3_scene2', 68, 110, 'Henry V 3.2.68–110', 'thematic', 'The four captains — a British Isles tableau, under stress', 'This is Shakespeare''s four-captains scene: Gower (English), Fluellen (Welsh), Jamy (Scottish), and Macmorris (Irish) serving together before Harfleur. It stages the emerging idea of a British Isles identity united in foreign war — the nationalist premise that would later underwrite the Stuart union of crowns. But the scene does not smooth the union. Fluellen''s classical pedantry, Jamy''s Scots-cadenced courtesy, and Macmorris''s explosive defensiveness — ''What ish my nation? Who talks of my nation?'' — stage the identity as contested at the moment of its formation. Macmorris is Shakespeare''s only Irish character in the canon, and this is the most-discussed Irish line in Renaissance drama. It can be read as comic (an Irishman over-reacting to a routine Welsh observation) or as politically serious (an Irishman interrupting the construction of ''Britishness'' to demand whose nation is being talked about). Modern productions and critics (especially post-1980 Irish scholarship) tend to the latter. The scene''s unresolved tension — the parley sounds and the captains have to abandon their dispute — is the point: British identity is assembled under the pressure of a common French enemy, and unresolved by the assembly.', ARRAY['David Cairns & Shaun Richards, Writing Ireland (1988)','Philip Edwards, Threshold of a Nation (1979)','Andrew Murphy, But the Irish Sea Betwixt Us (1999)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act3_scene3_ann1', 'henry_v_act3_scene3', 1, 43, 'Henry V 3.3.1–43', 'thematic', 'The threat to Harfleur — what is actually on the page', 'Henry''s speech to the governor of Harfleur is the play''s hardest passage. The Chorus does not prepare us for it; the action scene does not euphemize it. In order, Henry threatens: the enraged soldiery in ''liberty of bloody hand,'' with ''conscience wide as hell,'' mowing virgins and infants like grass (lines 11–14); fire and desolation (15–18); the ''hot and forcing violation'' of pure maidens — that is, the mass rape of the town''s women (19–21); the defiling of ''shrill-shrieking daughters'' and the dashing of old men''s heads against the walls (34–37); and, most unmistakably, ''Your naked infants spitted upon pikes'' (38). Henry compares the coming scene to Herod''s massacre of the innocents at Bethlehem (40–41), thus locating his threat inside the Christian catalogue of atrocities. This is not a bluff; it is the standard early-modern rhetoric of siege warfare, in which credible threats of sack were conventional tools for forcing surrender. But Shakespeare''s version is unusually specific and unusually sustained. Forty-three lines of threat, naming sexual violence and infanticide explicitly. Readers cannot honestly say Henry is a simple hero and hold these lines in mind at the same time. The play makes us hold both.', ARRAY['Theodor Meron, Bloody Constraint: War and Chivalry in Shakespeare (1998)','Norman Rabkin, ''Either/Or: Responding to Henry V,'' Shakespeare and the Problem of Meaning (1981)','Juliet Barker, Agincourt: The King, the Campaign, the Battle (2005)']::TEXT[]), ('henry_v_act3_scene3_ann2', 'henry_v_act3_scene3', 44, 57, 'Henry V 3.3.44–57', 'structural', 'Henry''s pivot from threat to mercy', 'The governor surrenders, and Henry pivots instantly: ''Use mercy to them all'' (line 53). The same man who forty lines earlier was promising pikes through infants is now commanding his uncle Exeter to garrison Harfleur gently. The speed of the pivot is the point. Henry''s threat worked: the town yielded ''our town and lives to thy soft mercy'' rather than endure sack. The play thus invites two readings simultaneously. (1) Henry is a cunning military psychologist who knows the conventions of siege warfare: make the threat credible enough and the city surrenders, sparing both sides. No rape happens; no infant is spitted. The threat is instrumental. (2) Henry is a rhetorician who can summon the imagery of atrocity without hesitation and withdraw it without explanation; what matters is what he was willing to promise. The scene refuses to decide. The structural fact — threat, surrender, mercy — is historically accurate and morally unresolved.', ARRAY['Meron, Bloody Constraint (1998)','Rabkin, ''Either/Or'' (1981)']::TEXT[]), ('henry_v_act3_scene3_ann3', 'henry_v_act3_scene3', 54, 57, 'Henry V 3.3.54–57', 'historical', 'The march to Calais — forced by dysentery', 'Henry''s closing announcement — ''The winter coming on and sickness growing / Upon our soldiers, we will retire to Calais'' — corresponds to a historical fact the play slightly softens. The English army was ravaged by dysentery during and after the siege of Harfleur; thousands of men died of the ''bloody flux''; Henry''s best estimate of his effective force by the time of Agincourt was a fraction of what had landed. The march to Calais was not a strategic decision but a desperate one, undertaken with depleted forces through hostile territory. Historically this is the situation that made the victory at Agincourt so improbable and so mythologized afterwards. The play will register the depletion (Henry to Montjoy in 3.6: ''My people are with sickness much enfeebled''), but it presents the retirement to Calais as a poised royal choice rather than an epidemiological emergency.', ARRAY['Anne Curry, Agincourt: A New History (2005)','Juliet Barker, Agincourt: The King, the Campaign, the Battle (2005)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act3_scene4_ann1', 'henry_v_act3_scene4', 1, 47, 'Henry V 3.4.1–47', 'structural', 'Katherine''s English lesson — the play''s quietest political scene', 'Act 3.4 is an entire scene in French, broken only by Katherine''s attempted English vocabulary words. It is a self-contained interlude: the princess of France, at her father''s palace, systematically learning the body-words of the language of the man who is besieging her country. ''Le bras, le coude, le col, le menton, le pied'' — the English-lesson is a domestic activity, but every word is a preparation for marriage. The scene works on two registers. The comic register is real: the accidental obscenities (''foot'' and ''coun'' — close to ''foutre'' and ''con'' in French) scandalize Katherine into an instruction-manual denial. The political register is that Katherine is being prepared for a conquest that has not yet happened but is already being arranged in the royal court. Shakespeare gives the scene no commentary, no choral frame, no English voice. It is pure preparation. When Henry finally woos her in 5.2, we will have already watched her assemble the vocabulary.', ARRAY['Patricia Parker, Shakespeare from the Margins (1996)','Karen Newman, Fashioning Femininity and English Renaissance Drama (1991)']::TEXT[]), ('henry_v_act3_scene4_ann2', 'henry_v_act3_scene4', 33, 42, 'Henry V 3.4.33–42', 'linguistic', 'The deliberate obscene pun — ''foot'' and ''coun''', 'The comic climax of the lesson is Katherine''s shocked reaction to ''foot'' (which sounds like the French ''foutre'' — a crude word for sex) and ''coun'' (Alice''s attempt at English ''gown,'' which sounds like the French ''con'' — a crude word for female genitalia). Katherine''s response is a full-scale courtly protest: these are ''mots de son mauvais, corruptible, gros, et impudique, et non pour les dames d''honneur d''user'' — words of bad sound, corrupting, coarse, and immodest, not for ladies of honour to use. But she recites them anyway in her summary. The joke is that the English vocabulary of marriage-preparation is, from a French ear, a catalogue of obscenities. Shakespeare is making a very specific cross-linguistic observation about how sexual vocabulary hides in innocent words across languages. It is also a quiet comment on what marriage to the enemy king may bring.', ARRAY['Margaret Jones-Davies, ''Shakespeare''s French,'' in Shakespeare and the Middle Ages (2009)','Juliet Dusinberre, Shakespeare and the Nature of Women (1975)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act3_scene5_ann1', 'henry_v_act3_scene5', 5, 34, 'Henry V 3.5.5–34', 'thematic', 'The French self-diagnosis — Norman bastards and cold blood', 'The Dauphin and Bourbon''s speech about the English is one of the most politically revealing moments in the play. Their complaint is genealogical: the English are ''Normans, but bastard Normans, Norman bastards,'' i.e. the French admit that the English invaders are descendants of their own Norman ancestors (via 1066), degraded by mixing with the ''wild and savage stock'' of England. The Constable''s speech that follows elaborates this into a climatic argument: how can a foggy, raw, cold country, living on beer (''sur-rein''d jades'' drench), produce warriors hot enough to fight? The passage is doing work on two levels. Internally, it is French panic expressed as ethnic self-regard. Externally, Shakespeare is flattering his English audience: the French themselves admit that English valour is a mystery. The anxiety about mass rape (''our mettle is bred out, and they will give / Their bodies to the lust of English youth / To new-store France with bastard warriors'') is especially striking: it inverts and acknowledges the Harfleur threat. The French fear what Henry just threatened.', ARRAY['Andrew Gurr (ed.), King Henry V (New Cambridge Shakespeare, 1992)','Willy Maley, Nation, State, and Empire in English Renaissance Literature (2003)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act3_scene6_ann1', 'henry_v_act3_scene6', 32, 90, 'Henry V 3.6.32–90', 'thematic', 'Bardolph''s execution — Henry''s old companion killed, without comment', 'The execution of Bardolph for stealing a pax (a small altar object) from a French church is one of the play''s most pointed structural decisions. Bardolph had been Falstaff''s companion throughout the Henry IV plays and one of Prince Hal''s Eastcheap drinking-crew; he is an old familiar face, a man Henry knew well in his youth. Fluellen reports the execution almost incidentally: ''one Bardolph, if your majesty know the man: his face is all bubukles, and whelks, and knobs, and flames o'' fire...'' Henry answers, ''We would have all such offenders so cut off'' — a single line, no recognition, no hesitation. Compare Hal''s immediate, raw grief when he thought Falstaff was dead in Henry IV Part 1, 5.4. The Henry V who executes Bardolph has successfully eliminated the Prince Hal who knew him. Readers should register the absence of emotion as itself the scene''s moral statement. And Henry''s follow-on speech forbidding English plunder in the villages — ''the gentler gamester is the soonest winner'' — is the same speech that just refused to protect an old companion from the hanging-tree. The morality is consistent, but only if you accept that Henry''s conversion from Hal to king was complete.', ARRAY['Harold Bloom, Shakespeare: The Invention of the Human (1998)','Stephen Greenblatt, Will in the World (2004)','Graham Holderness, Shakespeare: The Histories (2000)']::TEXT[]), ('henry_v_act3_scene6_ann2', 'henry_v_act3_scene6', 113, 140, 'Henry V 3.6.113–140', 'close_reading', 'Henry''s ''plain soldier'' frankness with Montjoy', 'When Montjoy the French herald arrives, Henry''s answer is unusually direct: ''My people are with sickness much enfeebled, / My numbers lessened, and those few I have / Almost no better than so many French.'' This is a private admission of weakness delivered to the enemy, and it is unexpected. The strategic calculation is one thing: Montjoy will report the English army as a ragged band, inviting the French to attack en masse rather than let the sick English march quietly to Calais. But there is also a rhetorical honesty here that Henry does not display elsewhere in the play. He even apologizes for boasting (''forgive me, God, / That I do brag thus''). The passage prepares us for the Henry of the night before Agincourt — the king who will walk among his men disguised and hear their complaints. The ''plain soldier'' pose that dominates the wooing scene is already being rehearsed.', ARRAY['Anne Barton, ''The King Disguised,'' in The Triple Bond (1975)','Andrew Gurr (ed.), King Henry V (New Cambridge Shakespeare, 1992)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act3_scene7_ann1', 'henry_v_act3_scene7', 1, 46, 'Henry V 3.7.1–46', 'thematic', 'The French nobles and their horses — the play''s critique of aristocratic vanity', 'The extended discussion of horses and armour among the French nobles the night before Agincourt is the play''s sharpest piece of character-comedy. The Dauphin''s description of his horse (''pure air and fire,'' ''le cheval volant,'' the Pegasus-comparison, ''my horse is my mistress'') is over-refined to the point of absurdity. The Constable''s needling about the Dauphin''s sonnet-to-his-horse is a scholarly joke — sonnets are properly addressed to mistresses. The scene stages the French aristocracy as over-cultivated, effeminate (they prefer horses to women), and over-confident. This is not neutral characterization. Shakespeare is shaping the English self-image by contrast: the English are starving, dirty, and silent; the French are ornate, voluble, and dissipated. Historically, the French nobility at Agincourt were heavily armoured knights who were indeed beaten by English yeoman archers. The play translates that military reality into a cultural one. Virgil asks the modern reader to notice this: the comic French scenes are ideological work, not decoration. The culture being defeated is coded as feminine and aesthetic; the culture doing the defeating is coded as plain and masculine.', ARRAY['Lisa Jardine, Still Harping on Daughters (1983)','Janet Adelman, Suffocating Mothers (1992)','Graham Holderness, Shakespeare: The Histories (2000)']::TEXT[]), ('henry_v_act3_scene7_ann2', 'henry_v_act3_scene7', 95, 117, 'Henry V 3.7.95–117', 'close_reading', 'The mastiffs and the poor English army', 'The French nobles'' contempt for the English army is characterized with precision at the scene''s close. Rambures compares the English to their ''mastiffs'' — courageous but stupid dogs — and Orleans develops the simile: ''Foolish curs, that run winking into the mouth of a Russian bear / And have their heads crushed like rotten apples.'' The Constable caps it: the English ''leave their wits with their wives, … give them great meals of beef and iron and steel, / They will eat like wolves and fight like devils.'' Then the final deflation: ''Ay, but these English are shrewdly out of beef.'' This is a clean dramatic irony. The audience knows the English have just been starved by the march; the French think they know the same and consider it the guarantee of victory. Tomorrow the army will win Agincourt. The scene is structured so that the French express their strategic assessment with perfect cultural snobbery and complete confidence, the audience hears it without commentary, and the play proceeds to falsify every word.', ARRAY['Emrys Jones, Scenic Form in Shakespeare (1971)','Andrew Gurr, The Shakespearean Stage (1992)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act4_chorus_ann1', 'henry_v_act4_chorus', 1, 28, 'Henry V 4 Chorus.1–28', 'close_reading', 'The atmospheric masterwork — night between two armies', 'The Act 4 Chorus is, for many critics, the single greatest poetic passage in Shakespeare''s histories. It does not narrate events; it builds an atmosphere. The opening triplet — ''creeping murmur,'' ''poring dark,'' ''wide vessel of the universe'' — establishes a nocturnal stillness in which the two armies are close enough to hear each other (''the fix''d sentinels almost receive / The secret whispers of each other''s watch''). The visual poetry that follows — ''fire answers fire,'' ''paly flames,'' ''umber''d face,'' ''steed threatens steed'' — gives the reader a cinematic image of two camps facing each other across a dark field. The sound-world is tight: hammers closing rivets, cocks crowing, clocks tolling the third hour. The Chorus uses the stillness to set up the contrast: the ''over-lusty'' French playing at dice, the ''poor condemned English'' sitting like sacrifices by their watchful fires. No battle has yet begun; everything about the outcome is already ambient.', ARRAY['Frank Kermode, Shakespeare''s Language (2000)','Emrys Jones, Scenic Form in Shakespeare (1971)','Stephen Greenblatt, Will in the World (2004)']::TEXT[]), ('henry_v_act4_chorus_ann2', 'henry_v_act4_chorus', 29, 47, 'Henry V 4 Chorus.29–47', 'thematic', '''A little touch of Harry in the night'' — the king as moral presence', 'The Chorus''s portrait of Henry walking among his soldiers — ''bids them good morrow with a modest smile / And calls them brothers, friends, and countrymen'' — is the play''s official version of the event. Henry is generous, his liberal eye a ''largess universal like the sun''; wretches ''pluck comfort from his looks.'' The tableau is hagiographic. The famous phrase ''a little touch of Harry in the night'' has a tender, almost monastic cadence. But the Chorus is about to hand over to the actual 4.1 scene, which will show us Henry doing what the Chorus has described — except with a specific and conflictual encounter: the Williams debate. The Chorus and the scene do not contradict each other exactly, but the Chorus''s radiant-royal generosity and the scene''s soldier''s critique of royal responsibility do not occupy the same moral universe. Again, both are the play; readers should hold both.', ARRAY['Anne Barton, ''The King Disguised,'' in The Triple Bond (1975)','Norman Rabkin, ''Either/Or'' (1981)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act4_scene1_ann1', 'henry_v_act4_scene1', 1, 30, 'Henry V 4.1.1–30', 'thematic', 'Henry''s philosophy of hardship — ''soul of goodness in things evil''', 'The scene opens with Henry''s characteristic alchemical language: ''There is some soul of goodness in things evil, / Would men observingly distil it out.'' The formulation is Stoic in its lineage — the philosopher''s counsel that what cannot be avoided can be repurposed. Henry extends it: the ''bad neighbour'' (the French army) is their ''outward conscience,'' preaching ''that we should dress us fairly for our end.'' What is unusual here is the private nature of the speech. Henry is speaking to his brothers and Erpingham before the sun is up; there is no crowd to impress, no audience to persuade. The speech is not performance; it is what the king actually thinks. This matters when we turn to the Chorus''s heroic portrait and the Williams dialogue that follows: Henry genuinely believes hardship has spiritual value, and he genuinely believes a king''s work is to model that belief to his men. The rhetorical question the play keeps asking is whether this private piety changes anything about the political and moral compromises Henry has already made.', ARRAY['A. C. Bradley, Shakespearean Tragedy (1904)','Harold Bloom, Shakespeare: The Invention of the Human (1998)']::TEXT[]), ('henry_v_act4_scene1_ann2', 'henry_v_act4_scene1', 69, 70, 'Henry V 4.1.69–70', 'close_reading', 'Henry''s aside on Fluellen', 'In the brief moment after overhearing Fluellen rebuking Gower for loud speech at night, Henry says: ''Though it appear a little out of fashion, / There is much care and valour in this Welshman.'' It is a small line, but important. Henry is watching a subordinate whom the audience has been permitted to find comic, and he sees something genuine in him. The line is evidence that Henry''s generosity is not only rhetorical — and it anticipates Henry''s public affirmation in 4.7 (''I am Welsh, you know, good countryman'') that binds the king to the Welsh soldiery. A king who can hear out-of-fashion manners and still see care and valour in them is a king the play takes seriously. This is one of the small ways Shakespeare earns our ambivalence: not every Henry-moment is a calculation.', ARRAY['Andrew Gurr (ed.), King Henry V (New Cambridge Shakespeare, 1992)','Peter Saccio, Shakespeare''s English Kings (2nd ed., 2000)']::TEXT[]), ('henry_v_act4_scene1_ann3', 'henry_v_act4_scene1', 106, 145, 'Henry V 4.1.106–145', 'thematic', 'The Williams debate — royal responsibility on trial', 'The dialogue between Henry (disguised) and the soldier Michael Williams is the play''s most sustained philosophical passage. Williams''s argument is precise: if the king''s cause is unjust, his soldiers die damned; if they die damned, ''it will be a black matter for the king that led them to it.'' Henry''s reply is the long merchant/servant analogy (lines 122–145): a father who sends a son to sea does not damn himself if the son sins on the journey; a master who sends a servant with money is not damned if the servant is killed by robbers. The argument''s logic is: each subject''s soul is his own; the king is not responsible for the spiritual state of his soldiers at the moment of death. This is internally coherent theology. But it is also a careful evasion of Williams''s real question, which is about the justness of the cause itself. Henry''s reply does not engage the premise (''if the cause be not good''); it sidesteps it by asserting the separability of king''s judgement and subject''s soul. Williams''s concession (''Ay, he said so, to make us fight cheerfully'') suggests the soldier is not fully persuaded. The scene refuses to vindicate either voice. It is the play''s most direct staging of the critique that the Chorus''s rhetoric wants to suppress.', ARRAY['Norman Rabkin, ''Either/Or'' (1981)','Graham Holderness, Shakespeare: The Histories (2000)','Alexander Leggatt, Shakespeare''s Political Drama (1988)']::TEXT[]), ('henry_v_act4_scene1_ann4', 'henry_v_act4_scene1', 193, 209, 'Henry V 4.1.193–209', 'historical', '''Not today, O Lord'' — Henry IV''s usurpation and the guilty crown', 'Henry''s prayer alone before dawn — ''Not today, O Lord, / O, not today, think not upon the fault / My father made in compassing the crown'' — is one of the play''s most historically rich moments. Henry IV had seized the throne from his cousin Richard II in 1399, forcing Richard''s abdication and later condoning his murder. This dynastic sin has shadowed the Lancastrian line throughout the first tetralogy (Henry VI Parts 1–3) and the second (Richard II, Henry IV Parts 1–2). Henry V''s reburial of Richard II at Westminster Abbey (historically attested, 1413) and his endowment of two chantries for Richard''s soul are acts of atonement specifically. Henry''s prayer is honest about this: ''all that I can do is nothing worth, / Since that my penitence comes after all.'' The Lancastrian curse — that usurpation poisons the crown and will eventually bring civil war — is acknowledged by the king himself in solitude. The Epilogue will return to it: Henry VI will lose France and England will bleed in the Wars of the Roses that end the tetralogy Shakespeare had already written.', ARRAY['Peter Saccio, Shakespeare''s English Kings (2nd ed., 2000)','Nigel Saul, Richard II (1997)','Gary Taylor (ed.), Henry V (1982)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act4_scene2_ann1', 'henry_v_act4_scene2', 35, 53, 'Henry V 4.2.35–53', 'close_reading', 'Grandpré''s mocking survey — English as dead meat', 'Lord Grandpré''s speech describing the English army before battle is a small masterpiece of contemptuous portraiture. The English are ''island carrions'' — dead flesh — ''desperate of their bones,'' their tattered banners hanging limp, ''Big Mars seems bankrupt in their beggar''d host.'' The horses ''Lob down their heads,'' their bits fouled with chewed grass; the crows are the horses'' ''executors,'' impatient for the hour. It is a memorable image and (like 3.7) an intensifier of the battle''s dramatic irony: the French look at this army and see food for carrion-birds. The English will win in a few hours. Notice also that Grandpré''s contempt is specifically for the English army''s ragged appearance, not for its fighting quality — he doesn''t understand that the longbow will make appearance irrelevant. The scene closes with the Constable reaching for his guidon: the battle starts at the end of this speech.', ARRAY['Juliet Barker, Agincourt: The King, the Campaign, the Battle (2005)','Emrys Jones, Scenic Form in Shakespeare (1971)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act4_scene3_ann1', 'henry_v_act4_scene3', 18, 39, 'Henry V 4.3.18–39', 'close_reading', 'The speech''s opening inversion — fewer, not more', 'The Crispin''s Day oration begins with a reversal that does most of the speech''s political work. Westmoreland wishes for reinforcements; Henry answers by wishing for even fewer men. ''If we are mark''d to die, we are enow / To do our country loss; and if to live, / The fewer men, the greater share of honour.'' The rhetorical move is calculated: by publicly welcoming under-numbering, Henry takes the army''s greatest liability (numerical inferiority) and converts it into the army''s greatest asset (concentrated glory). The premise is that honour is a finite resource divided among the survivors, so a smaller share-base produces more per head. This is mathematically absurd and rhetorically irresistible. Westmoreland is immediately converted (line 74: ''Would you and I alone, / Without more help, could fight this royal battle!''). Henry now offers passports and pocket money to any man unwilling to fight; none leave. The opening inversion is the gate of the speech, and the audience feels it work.', ARRAY['Madeleine Doran, Shakespeare''s Dramatic Language (1976)','Gary Taylor (ed.), Henry V (1982)']::TEXT[]), ('henry_v_act4_scene3_ann2', 'henry_v_act4_scene3', 40, 67, 'Henry V 4.3.40–67', 'thematic', '''Band of brothers'' and the politics of fraternity', 'The core of the Crispin''s Day speech — ''We few, we happy few, we band of brothers; / For he today that sheds his blood with me / Shall be my brother; be he ne''er so vile, / This day shall gentle his condition'' — makes two enormous promises at once. The first is fraternity: the king will call the meanest soldier ''brother.'' The second is social elevation: ''vile'' here means low-born (not morally evil in this period), and ''gentle his condition'' means to raise him to the rank of gentleman. Henry is offering, in effect, that shared combat will dissolve class distinction. The promise is explosive; it is also, historically, not kept. Agincourt''s low-born survivors returned to England as commoners; very few were raised in rank. But the speech''s rhetorical power is not damaged by its promise''s thin fulfilment: the ''band of brothers'' phrase has become foundational to English and American military rhetoric, used for the WWII 101st Airborne (''Easy Company''), later the HBO miniseries title, and across innumerable commemorations. The speech keeps working on any reading of Henry — patriotic or critical — because the promise of shared sacrifice and honour is, in the moment of battle, genuinely mobilizing. The fact that the speech works on the ''cynical'' Henry as well as the ''heroic'' one is itself part of the play''s argument about rhetoric and power.', ARRAY['Norman Rabkin, ''Either/Or'' (1981)','Stephen Ambrose, Band of Brothers (1992)','Graham Holderness, Shakespeare: The Histories (2000)']::TEXT[]), ('henry_v_act4_scene3_ann3', 'henry_v_act4_scene3', 85, 130, 'Henry V 4.3.85–130', 'close_reading', 'Henry''s answer to Montjoy — the second, private oration', 'After the public Crispin''s Day speech, Montjoy returns for one more attempt at ransom, and Henry delivers what is effectively a second oration, less quoted but equally tight. ''We are but warriors for the working-day; / Our gayness and our gilt are all besmirch''d / With rainy marching in the painful field.'' The tonal register is entirely different from the high-heroic ''band of brothers'' speech: plainer, grittier, almost proletarian (''working-day,'' ''slovenry,'' ''poor soldiers''). Henry offers the French the image of his army as an honest working crew in dirty uniforms. It is also a commitment not to be ransomed: ''they shall have none, I swear, but these my joints'' — his body is the only ransom. The combination — a public oration that promises nobility and a private answer that promises only labour and death — is rhetorically masterful. Readers should notice how many registers Henry can speak in and how each is pitched for its audience.', ARRAY['Brian Vickers, The Artistry of Shakespeare''s Prose (1968)','Emrys Jones, Scenic Form in Shakespeare (1971)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act4_scene4_ann1', 'henry_v_act4_scene4', 1, 50, 'Henry V 4.4.1–50', 'linguistic', 'Bilingual comedy — the mishearing scene', 'The capture of Monsieur Le Fer by Pistol and the Boy is built on sustained linguistic misunderstanding. Pistol hears the French ''Seigneur Dieu'' as the man''s name; he hears ''moi'' as a unit of currency (''forty moys''); he hears the soldier''s ''bras'' (arm) as English ''brass'' (the metal) and takes offence at being offered base metal. The Boy, who actually knows French, works as translator between them. The scene is funny, but it is doing important structural work: it gives us our last sustained look at Pistol, the Boy, and the Eastcheap group before the French raid the baggage camp and kill the Boy offstage (reported in 4.7). The Boy''s final soliloquy at lines 52–60 — that Pistol is a ''roaring devil in the old play'' with more noise than valour, and that he (the Boy) must stay with the luggage because the French could raid the camp — is the audience''s last notice of the Boy''s situation. By the next scene-but-one, he will be dead. Shakespeare lets the Boy earn the last word, and then has him killed for being in its way.', ARRAY['C. L. Barber, Shakespeare''s Festive Comedy (1959)','Patricia Parker, Shakespeare from the Margins (1996)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act4_scene5_ann1', 'henry_v_act4_scene5', 1, 23, 'Henry V 4.5.1–23', 'close_reading', 'The French collapse in twenty lines', 'Scene 4.5 is the shortest scene in the play. The French nobles — the same Dauphin, Bourbon, Orleans, and Constable whose horse-boasts filled 3.7 — now cry out ''O diable!'' and ''O seigneur! le jour est perdu, tout est perdu!'' The brevity is the point. Shakespeare does not stage a French defeat scene of equal weight to any English triumph scene. Instead, he gives us twenty-three lines of panic, and then moves to 4.6, where Henry names York''s death. The structural effect is fast and somewhat cruel: 3.7''s fifty-line horse-bragging is paid off with 4.5''s twenty-line collapse, and the ratio itself enacts the play''s judgment. Bourbon''s final line — ''The devil take order now! I''ll to the throng; / Let life be short; else shame will be too long'' — is the only dignified note. The rest is confusion. This is structural contempt rendered as pacing.', ARRAY['Emrys Jones, Scenic Form in Shakespeare (1971)','Andrew Gurr, The Shakespearean Stage (1992)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act4_scene6_ann1', 'henry_v_act4_scene6', 3, 32, 'Henry V 4.6.3–32', 'close_reading', 'The York-Suffolk death — chivalric tableau', 'Exeter''s thirty-line report of the deaths of the Duke of York and the Earl of Suffolk is the play''s most elaborate chivalric set-piece. The two earls die side by side, Suffolk first, then York ''all haggled over'' comes to him; York takes Suffolk''s beard, kisses the wounds on his face, and asks his soul to wait so they can fly to heaven together. The image of the two men ''espoused to death'' with ''a testament of noble-ending love'' is unmistakably homoerotic in its language and its staging — a male-male death-marriage. This is period chivalric idiom; it is also a tonal counterpoint to the harder action that is about to happen. Exeter''s admission that he wept (''all my mother came into mine eyes / And gave me up to tears'') is unusual for a commander; Henry''s answer (''I blame you not; / For, hearing this, I must perforce compound / With mistful eyes'') equally unusual for a king. The scene is building, in chivalric tears, an emotional charge that the next line — the order to kill the prisoners — will suddenly violate.', ARRAY['Bruce Smith, Homosexual Desire in Shakespeare''s England (1991)','Goran V. Stanivukovic (ed.), Ovidian Transversions (2020)']::TEXT[]), ('henry_v_act4_scene6_ann2', 'henry_v_act4_scene6', 35, 38, 'Henry V 4.6.35–38', 'historical', '''Then every soldier kill his prisoners'' — the play''s moral crux', 'Henry''s order to kill the French prisoners is the play''s single most controversial moment, and Shakespeare does not soften it. ''But hark! what new alarum is this same? / The French have reinforced their scatter''d men: / Then every soldier kill his prisoners; / Give the word through.'' Four lines. No debate, no hesitation, no later regret. Historically the order is attested: contemporary chroniclers (the Gesta Henrici Quinti and others) record that Henry gave this command when the baggage camp was attacked during the battle, fearing that the prisoners (who still had their weapons) would rise up and join their countrymen. The order was controversial even in its own time; some English knights refused to carry it out. The killing that followed was of noble prisoners who were, by the conventions of chivalric warfare, legally protected until ransomed. Shakespeare stages it flatly. The next scene (4.7) will let Gower interpret the order as retaliation for the French killing the camp-boys — but the play''s chronology is deliberately blurred; in the text, Henry gives the order before he has heard about the boys. The moral complexity is exactly this: is Henry responding to a tactical emergency (the reinforcement alarm he mentions), a strategic calculation about armed prisoners, or a breach of the laws of war? The play refuses to adjudicate. Readers should hold the flatness of the stage-moment against the weight of what has been ordered.', ARRAY['Gesta Henrici Quinti, ed. Frank Taylor & John S. Roskell (1975)','Anne Curry, Agincourt: A New History (2005)','Juliet Barker, Agincourt: The King, the Campaign, the Battle (2005)','Theodor Meron, Bloody Constraint (1998)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act4_scene7_ann1', 'henry_v_act4_scene7', 1, 8, 'Henry V 4.7.1–8', 'structural', 'The French raid on the boys — retroactive justification', 'Fluellen''s opening lines announce that the French have raided the English baggage camp and killed ''the poys'' (the boys, in Welsh pronunciation). Gower''s immediate interpretive move is to connect this atrocity to Henry''s prisoner-killing order of the previous scene: ''the king, most worthily, hath caused every soldier to cut his prisoner''s throat. O, ''tis a gallant king!'' But the textual chronology is reversed. In the play''s spoken sequence, Henry gave the order BEFORE the raid on the boys was reported. Gower is retroactively supplying a just-war justification that the moment of the order did not provide. The play keeps both framings visible. A reader can, with Gower, read the prisoner-killing as legitimate retaliation; a reader can, with the blunt text of 4.6, read it as a tactical decision with independent justification. The scene''s structural honesty is that it supplies Gower''s reading as reading, not as fact.', ARRAY['Rabkin, ''Either/Or'' (1981)','Anne Curry, Agincourt: A New History (2005)']::TEXT[]), ('henry_v_act4_scene7_ann2', 'henry_v_act4_scene7', 9, 41, 'Henry V 4.7.9–41', 'close_reading', 'Alexander the Pig — the play''s shrewdest parallel', 'Fluellen''s comparison of Henry to Alexander the Great is one of the play''s most quietly consequential passages. The comedy is Welsh-dialect: ''Alexander the Pig'' (for ''Big''), rivers in Macedon and Monmouth, ''salmons in both.'' But the parallel Fluellen draws is dangerous. He reminds Gower that Alexander, ''in his rages, and his furies,'' killed his best friend Cleitus. Gower objects: Our king is not like Alexander in that; Henry never killed any of his friends. Fluellen corrects him: ''as Alexander killed his friend Cleitus, being in his ales and his cups; so also Harry Monmouth, being in his right wits and his good judgements, turned away the fat knight with the great belly doublet.'' The fat knight is Falstaff. Fluellen is saying: Alexander-drunk killed Cleitus; Henry-sober rejected Falstaff; the parallel holds. This is the play''s clearest acknowledgement that Henry''s rejection of Falstaff was a moral action of the same order as Alexander''s murder of his friend. A Welshman in a military camp, in dialect-inflected comic cadence, delivers what is arguably the most damning critical observation the play ventures about Henry.', ARRAY['Harold Bloom, Shakespeare: The Invention of the Human (1998)','Stephen Greenblatt, ''Invisible Bullets'' (1985)','A. C. Bradley, ''The Rejection of Falstaff'' (1902)']::TEXT[]), ('henry_v_act4_scene7_ann3', 'henry_v_act4_scene7', 77, 102, 'Henry V 4.7.77–102', 'thematic', '''We call it Agincourt'' — naming the victory', 'When Montjoy returns with no more ransom-request but a plea for permission to bury the French dead, Henry asks the name of the nearest castle. Montjoy answers: ''Agincourt.'' Henry immediately christens the battle: ''Then call we this the field of Agincourt, / Fought on the day of Crispin Crispianus.'' The act of naming is the victory''s first rhetorical monument. The place-name is not yet a battle-name; Henry makes it one. Then follows the Welsh-leek exchange with Fluellen — ''I am Welsh, you know, good countryman'' — in which Henry publicly affirms his Welshness (he was born at Monmouth) and binds himself to the Welsh soldiery whose longbows had carried the day. This is Henry at his rhetorical best: naming the victory, crediting God, binding the army. It is also the moment the play''s highest civic music sounds. The play does not deflate it here; the Epilogue will.', ARRAY['Peter Saccio, Shakespeare''s English Kings (2nd ed., 2000)','Gwyn A. Williams, When Was Wales? (1985)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act4_scene8_ann1', 'henry_v_act4_scene8', 1, 50, 'Henry V 4.8.1–50', 'structural', 'The glove-plot pays off — Henry gives Williams crowns', 'The glove-exchange set up in 4.1 pays off here. Williams has punched Fluellen (believing the glove in Fluellen''s cap belongs to the arrogant soldier who insulted the king); Henry reveals that he was that soldier. Williams''s defense is disarmingly direct: ''Your majesty came not like yourself … had you been as I took you for, I made no offence.'' Henry''s response is generous: he fills Williams''s glove with crowns. What makes the sequence work is Williams''s refusal to apologize: the king in disguise invited the insult, and the responsibility is not on the soldier. Shakespeare does not flinch from having Williams win the argument. Henry rewards him with money, not with a title; Williams will go home as a commoner, which is the appropriate register. The king-in-disguise trope is a favorite of Elizabethan drama (it recurs in As You Like It and Measure for Measure); Shakespeare''s version here is unusual in that the commoner gets to keep his moral advantage.', ARRAY['Anne Barton, ''The King Disguised,'' in The Triple Bond (1975)','Kenneth Muir, The Sources of Shakespeare''s Plays (1977)']::TEXT[]), ('henry_v_act4_scene8_ann2', 'henry_v_act4_scene8', 58, 100, 'Henry V 4.8.58–100', 'historical', 'The catalogue of the dead — historical politics of a casualty report', 'Henry''s long recitation of the French noble dead is a set-piece of propagandist accounting. The numbers are unreliable: 10,000 French dead, 126 princes and banner-bearing nobles, 8,400 knights and gentlemen, 500 freshly-knighted — and only 25 common English dead plus four named nobles (York, Suffolk, Kettle, Davy Gam). Historical estimates of Agincourt casualties vary considerably, but modern historians generally put French losses at roughly 6,000–10,000 (heavily weighted toward the nobility, who led the fatal cavalry charge into the mud) and English losses at probably several hundred rather than 25. Shakespeare follows his source (Holinshed) but the source itself inherits the aftermath-propaganda. What the catalogue accomplishes dramatically is different from its historical accuracy: it stages an astonishing inversion of normal war-casualties (nobles killed in massive numbers, commoners almost untouched) and it invites the audience to hear ''God fought for us'' as both historically adequate (in the sense that such a disproportion is not ordinary) and theologically exorbitant (since attributing it wholly to God erases the strategic fact of the longbow). Henry''s immediate decree banning boasting on pain of death — ''be it death proclaimed through our host / To boast of this or take that praise from God / Which is his only'' — closes the catalogue by making providentialism state policy.', ARRAY['Anne Curry, Agincourt: A New History (2005)','Juliet Barker, Agincourt: The King, the Campaign, the Battle (2005)','Peter Saccio, Shakespeare''s English Kings (2nd ed., 2000)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act5_chorus_ann1', 'henry_v_act5_chorus', 9, 34, 'Henry V 5 Chorus.9–34', 'structural', 'London as Rome — the triumphal reception', 'The 5 Chorus describes Henry''s return to London in deliberately Roman terms: the mayor and aldermen ''Like to the senators of the antique Rome,'' the plebeians at their heels, going forth to fetch their ''conquering Caesar in.'' Henry''s refusal of the triumphal display — refusing to have his bruised helmet and bent sword carried before him — is registered as humility (''being free from vainness and self-glorious pride''). Readers should note the layered strategy: the Chorus Latinizes London, elevates the event to antique ceremony, and then has Henry decline the ceremony, giving him all the moral credit of humility while retaining all the classical grandeur the framing confers. This is rhetorical double-counting. The passage is also the point at which the Chorus''s voice sounds most frankly adulatory — and critics have often read this as the moment Shakespeare''s irony is least available. Whether one hears the Chorus-stanza as sincere or as over-freighted with praise is a test of how the whole play sounds to each reader.', ARRAY['Norman Rabkin, ''Either/Or'' (1981)','Andrew Gurr (ed.), King Henry V (New Cambridge Shakespeare, 1992)']::TEXT[]), ('henry_v_act5_chorus_ann2', 'henry_v_act5_chorus', 29, 34, 'Henry V 5 Chorus.29–34', 'historical', 'The Essex reference — the play''s one dating anchor', '''Were now the general of our gracious empress, / As in good time he may, from Ireland coming, / Bringing rebellion broached on his sword'' — this is Henry V''s only unambiguous topical reference, and its dating is important. The ''general of our gracious empress'' is the Earl of Essex, Queen Elizabeth I''s favorite, who set out for Ireland in late March 1599 to put down Hugh O''Neill''s rebellion. Essex returned in September 1599 without victory; his attempted rebellion and execution followed in 1601. This means Henry V was written and performed in the narrow window between roughly March and September 1599 — almost certainly for the opening of the Globe that summer. The reference is optimistic about Essex (''as in good time he may'') in a way that became impossible after his return. The line is thus historical evidence about both the play''s composition date and the political sympathies of the Chamberlain''s Men in the weeks before the Essex disaster. By the time the Folio was printed in 1623, Essex was twenty years dead; the line read (and reads) as the ghost of a hope.', ARRAY['Gary Taylor (ed.), The Oxford Shakespeare: Henry V (1982), introduction','Paul E. J. Hammer, The Polarisation of Elizabethan Politics (1999)','Andrew Gurr (ed.), King Henry V (New Cambridge Shakespeare, 1992)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act5_scene1_ann1', 'henry_v_act5_scene1', 1, 44, 'Henry V 5.1.1–44', 'structural', 'Fluellen forces Pistol to eat the leek — the cycle closes', 'The leek scene is long-setup comedy. At 4.1 Pistol mocked Fluellen''s leek (not knowing he was speaking to the king''s kinsman); at 5.1 Fluellen, now a veteran with Henry''s acknowledgement, beats Pistol with a cudgel and forces him to eat a raw leek bite by bite. The comedy is brutal: Pistol is a known coward and a known petty criminal, and the scene gives us the satisfaction of seeing his bombast physically collapsed. But there is also a social point. Fluellen, the Welsh captain whose dialect we have been permitted to laugh at for four acts, now enforces discipline on the English braggart, and Gower (the English captain) endorses the act at length: ''henceforth let a Welsh correction teach you a good English condition.'' The ethnic hierarchy the play has played with is, in this scene, upended: the Welshman teaches the Englishman manners. The scene also works as a final, unsentimental reckoning with the Eastcheap world. Pistol''s closing soliloquy — Doll is dead, the rendezvous is cut off, ''bawd I''ll turn, / And something lean to cutpurse of quick hand'' — announces that he will go home to England and live by crime, with his ''cudgell''d scars'' passed off as war-wounds. This is what the campaign has produced in the low-comic line: a criminal with a false story. The play does not soften it.', ARRAY['Robert Weimann, Shakespeare and the Popular Tradition in the Theater (1978)','Ann Rosalind Jones, ''The Ethnographic Present,'' in Shakespeare and the Early Modern (2002)']::TEXT[]), ('henry_v_act5_scene1_ann2', 'henry_v_act5_scene1', 62, 71, 'Henry V 5.1.62–71', 'thematic', 'Pistol''s homecoming as the play''s underfoot pay-off', 'Pistol''s short closing soliloquy is the play''s only honest post-war economic statement. He reports two facts: his wife Doll/Nell has died of the ''malady of France'' (syphilis), and his tavern-rendezvous is therefore cut off. His plan: steal his way home to England, become a pimp (''bawd'') and cut-purse, pass off his leek-beating bruises as war-wounds (''the Gallia wars''). The grim comedy is that Pistol will be one of the veterans of Agincourt the English streets soon see. The King''s ''band of brothers'' promise — that shared combat would ''gentle'' a low soldier''s condition — is falsified here by a low soldier making his own account. The speech is less than a dozen lines; it is what the victory looks like from the side of the army that had nothing to begin with. Readers should notice that Shakespeare ends his low-plot with this speech and not with the leek''s beating. The beating is the comic catharsis; the soliloquy is the audit.', ARRAY['C. L. Barber, Shakespeare''s Festive Comedy (1959)','Thomas Healy, Shakespeare, Alienation and the Early Modern Stage (1994)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_act5_scene2_ann1', 'henry_v_act5_scene2', 23, 67, 'Henry V 5.2.23–67', 'close_reading', 'Burgundy''s lament for France — the garden-pastoral as political argument', 'The Duke of Burgundy''s forty-five-line plea for peace is the scene''s opening rhetorical set-piece, and one of the play''s most celebrated passages. It is also a political argument disguised as pastoral description. Burgundy catalogues, at length, what war has done to the French countryside: the ''naked, poor and mangled Peace'' exiled; vines unpruned and dying; hedges grown wild; meadows overrun with weeds (''darnel, hemlock and rank fumitory''); and — extending the image — houses, children, and citizens ''grow like savages'' for want of the ''sciences that should become our country.'' The passage is beautiful and persuasive. It is also politically precise: Burgundy, historically a key mediator between the English and French crowns, is arguing that peace at any price is necessary for French civic life. This is the kind of speech Henry needs to hear in order to move forward with the treaty. The scene''s structural logic is that Burgundy''s lyrical diplomacy softens the French, and Henry can then extract his terms (marriage, heir-status to the crown, Katherine as capital demand) against a background of visibly ravaged France. The garden-pastoral rhetoric is not neutral; it is a lever.', ARRAY['Patricia Parker, Shakespeare from the Margins (1996)','Frank Kermode, Shakespeare''s Language (2000)','Peter Saccio, Shakespeare''s English Kings (2nd ed., 2000)']::TEXT[]), ('henry_v_act5_scene2_ann2', 'henry_v_act5_scene2', 97, 221, 'Henry V 5.2.97–221', 'thematic', 'The wooing scene — Henry''s ''plain soldier'' pose as political performance', 'Henry''s courtship of Katherine is the play''s longest sustained scene and its most heavily choreographed prose passage. Henry casts himself repeatedly as a ''plain soldier'' — unable to dance, unable to rhyme, unable to ''look greenly'' or ''gasp out [his] eloquence'' — and offers Katherine only ''downright oaths'' and a ''good heart.'' The rhetoric is, however, anything but plain. Henry delivers long, polished prose paragraphs; he demonstrates competent (if deliberately awkward) French; he cites Saint Denis and Saint George; he prophesies a ''boy, half French, half English'' who will ''take the Turk by the beard.'' The ''plain soldier'' pose is itself a carefully composed rhetorical mode — one more register in a king who has been speaking in different registers to different audiences throughout the play. At the same time, the scene has genuine local charm. Katherine''s ''Is it possible dat I sould love de enemy of France?'' (line 155) cuts through the flirtation to the unresolved political heart of the marriage. Henry''s answer is a conquering-king''s joke (''I love France so well that I will not part with a village of it; I will have it all mine''). The mixing of the political and the erotic is the point: Katherine is explicitly ''our capital demand,'' the head of the articles, and the wooing scene is a ceremony for terms already arranged. Readers should notice who does the talking (Henry almost entirely), how much of the scene is in Henry''s voice, and how carefully the ''plain soldier'' pose is kept up. The pose is convincing; it is also work.', ARRAY['Karen Newman, Fashioning Femininity and English Renaissance Drama (1991)','Juliet Dusinberre, Shakespeare and the Nature of Women (1975)','Lisa Jardine, Reading Shakespeare Historically (1996)']::TEXT[]), ('henry_v_act5_scene2_ann3', 'henry_v_act5_scene2', 233, 242, 'Henry V 5.2.233–242', 'close_reading', '''Nice customs curtsy to great kings'' — the wooing scene''s operative phrase', 'When Katherine politely cites the French custom that ladies are not kissed before their wedding, Henry''s response is one of the most quietly revealing lines in the play: ''O Kate, nice customs curtsy to great kings. Dear Kate, you and I cannot be confined within the weak list of a country''s fashion: we are the makers of manners, Kate; and the liberty that follows our places stops the mouth of all find-faults.'' The phrase ''makers of manners'' is operative. Henry is declaring that royal prerogative overrides national custom — his and Katherine''s, jointly. The line works as wooing (it assimilates Katherine to his royal freedom), as conquest (it overrides French custom with English-king prerogative), and as political theory (kings are not subject to cultural norms, they make them). The kiss that follows is both a romantic gesture and a small constitutional act. Critics sometimes hear the scene as charming; Shakespeare also gives us this line. Both hearings are correct; the scene is doing both kinds of work at once.', ARRAY['Stephen Greenblatt, Will in the World (2004)','Graham Holderness, Shakespeare: The Histories (2000)']::TEXT[]), ('henry_v_act5_scene2_ann4', 'henry_v_act5_scene2', 285, 302, 'Henry V 5.2.285–302', 'historical', 'The Treaty of Troyes — what the wooing scene is serving', 'The scene''s formal conclusion records the effective terms of the Treaty of Troyes (1420). Exeter reads out the one article the French king has balked at: Henry is to be named in all future French royal documents as ''Notre très-cher fils Henri, Roi d''Angleterre, Héritier de France'' — ''Our most dear son Henry, King of England, Heir of France.'' The French king is to disinherit his own son (the Dauphin of the play, historically the future Charles VII) and acknowledge Henry as heir to the French throne. This was the Treaty''s actual most important clause. The wooing scene is thus ornamental around this political fact: Katherine is given to Henry as the dynastic seal of an agreement that makes Henry the next king of France. Historically, the Treaty held for barely two years: Henry V died of dysentery in August 1422, and his infant son Henry VI''s regency promptly collapsed, enabling Charles VII''s eventual reconquest (the era of Joan of Arc) and the loss of all French territory by 1453. The play does not mention any of this within the scene — it is reserved for the Epilogue. But the reader who holds the Treaty''s actual history alongside Henry''s closing ''Prepare we for our marriage'' will hear the scene''s final lines differently from a reader who does not.', ARRAY['Anne Curry, The Hundred Years War (2nd ed., 2003)','Peter Saccio, Shakespeare''s English Kings (2nd ed., 2000)','Christopher Allmand, Henry V (1992)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_epilogue_ann1', 'henry_v_epilogue', 1, 14, 'Henry V Epilogue.1–14', 'structural', 'The Epilogue is a sonnet — the play''s final formal choice', 'The Epilogue is a complete English sonnet: three quatrains rhymed ABAB CDCD EFEF and a closing couplet GG. Shakespeare has chosen the sonnet form for his most loaded exit in the whole play. The form matters because a sonnet is a closed, resolved, satisfying poetic unit — it arrives at a couplet that ties it off. By using this form, the Epilogue claims the authority of aesthetic completion. But the content of the sonnet is the opposite of aesthetic completion: it announces that everything Henry built will be unmade within a generation. The formal closure and the historical dis-closure pull against each other. The result is that the play ends with a structure that says ''finished'' and a content that says ''collapsed.'' Readers should hear both at once. The choice of sonnet form also recalls the opening Chorus''s epic-invocation (lines 1–8) and the Prologue/Epilogue symmetry that frames the whole play: it begins with an aspiration to epic and ends with a sonnet naming dynastic failure. The arc from ''O for a Muse of fire'' to ''made his England bleed'' is deliberately undone.', ARRAY['Frank Kermode, Shakespeare''s Language (2000)','Helen Vendler, The Art of Shakespeare''s Sonnets (1997)']::TEXT[]), ('henry_v_epilogue_ann2', 'henry_v_epilogue', 5, 12, 'Henry V Epilogue.5–12', 'historical', 'The future-tense undoing — Henry VI and the loss of France', 'The sonnet''s eight middle lines describe what happens after the play ends. ''Small time'' — Henry V died in 1422, aged 35, nine years after Agincourt. ''Fortune made his sword'' — his victories are retrospectively attributed to luck (a less flattering gloss than the play has previously offered). ''The world''s best garden he achieved'' — echoes Burgundy''s image from 5.2, now tinged with bitter irony. ''And of it left his son imperial lord. / Henry the Sixth, in infant bands crown''d King / Of France and England, did this king succeed'' — the baby Henry VI inherited both crowns at nine months old. ''Whose state so many had the managing'' — refers to the factional regency, with multiple protectors jockeying for power. ''That they lost France and made his England bleed'' — the loss of France (complete by 1453) and the Wars of the Roses (1455–1485) that followed. The Epilogue compresses thirty years of civil-war collapse into two lines. The play''s triumph is systematically undone.', ARRAY['Peter Saccio, Shakespeare''s English Kings (2nd ed., 2000)','Anne Curry, The Hundred Years War (2nd ed., 2003)','Bertrand Wolffe, Henry VI (1981)']::TEXT[]), ('henry_v_epilogue_ann3', 'henry_v_epilogue', 13, 14, 'Henry V Epilogue.13–14', 'biographical', '''Which oft our stage hath shown'' — Shakespeare cross-referencing himself', 'The Epilogue''s penultimate line — ''Which oft our stage hath shown'' — is a direct reference to Shakespeare''s own earlier work. The Henry VI plays (Parts 1, 2, and 3) and Richard III were written in the early 1590s, years before Henry V (1599). Shakespeare had, in other words, already dramatized everything the Epilogue says will happen. The first tetralogy (Henry VI 1–3 and Richard III) showed the Wars of the Roses in considerable detail; the second tetralogy (Richard II, Henry IV 1–2, Henry V) now ends by pointing at the first. The chronological arc of the composition was reverse of the historical arc: Shakespeare had already written the later history, and Henry V is thus the prequel to a story whose ending he and his audience already knew. This is not an incidental detail. The Epilogue is effectively telling the audience: you know how this ends; you''ve seen it; accept the play''s triumph knowing what follows. It is the play''s final, quiet admission that the Agincourt victory it has just celebrated was historically followed by catastrophe — and that the playwright''s own earlier work testifies to that catastrophe.', ARRAY['Gary Taylor (ed.), The Oxford Shakespeare: Henry V (1982), introduction','Jean E. Howard & Phyllis Rackin, Engendering a Nation (1997)','Norman Rabkin, ''Either/Or'' (1981)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('henry_v_prologue_ann1', 'henry_v_prologue', 1, 8, 'Henry V Prologue.1–8', 'structural', 'The Muse-of-fire invocation and the epic tradition it claims', 'The opening eight lines place Henry V inside the classical epic tradition by imitating an epic invocation of the Muse — as Homer opens the Iliad, Virgil the Aeneid, Milton (later) Paradise Lost. By asking for ''a Muse of fire'' (the noblest of the four elements), a kingdom-sized stage, and princes and monarchs as its actors, the Chorus stakes a claim: this is not a comedy or an ordinary history play but a poem of national destiny. Yet the invocation is immediately undercut, in lines 8–14, by the humility trope that follows. The pattern — soaring request, swift retraction — is the Chorus''s governing rhythm throughout the play. It simultaneously asserts that Henry deserves epic treatment and apologizes for not being able to provide it. Readers should hear this as both reverence and knowing theatrical self-awareness: Shakespeare knows perfectly well his Globe can''t stage Agincourt; the Chorus is the play''s strategy for converting that limitation into a participatory virtue.', ARRAY['Anne Barton, ''The King Disguised,'' in The Triple Bond (1975)','A. R. Humphreys, The Arden Shakespeare: Henry V (1968)']::TEXT[]), ('henry_v_prologue_ann2', 'henry_v_prologue', 11, 14, 'Henry V Prologue.11–14', 'historical', 'The ''wooden O'' and the Globe''s constraints', '''This cockpit'' and ''this wooden O'' refer to the Globe Theatre, which opened in the summer of 1599 — the same season Henry V was first performed. The Chorus''s apology is literal: the Globe was a wooden polygon roughly 30 metres across, open to the sky, able to hold perhaps 3,000 spectators but offering a thrust stage with almost no scenery. The play''s siege at Harfleur, the night-before-battle panorama of the Act 4 Chorus, the Agincourt victory itself — none of it could be staged. Shakespeare''s solution is to write an anti-spectacle: he defers the seen to the imagined and demands the audience supply the missing armies, ships, and cavalry from their own minds. The ''crooked figure'' (line 15) — a zero — that can ''attest in little place a million'' is a mathematical image for this theatrical trick: the actors are ciphers that the audience must multiply. It is a rhetoric of co-production that, by 1599, had no recent precedent on the English stage.', ARRAY['Andrew Gurr, The Shakespearean Stage 1574–1642 (3rd ed., 1992)','Stephen Greenblatt, Shakespeare''s Freedom (2010)']::TEXT[]), ('henry_v_prologue_ann3', 'henry_v_prologue', 15, 25, 'Henry V Prologue.15–25', 'thematic', 'Imagination as the play''s working substance', 'The heart of the Prologue is its contract with the audience. The Chorus does not promise to show Agincourt; it asks us to make it. ''Piece out our imperfections with your thoughts,'' ''Into a thousand parts divide one man,'' ''Think, when we talk of horses, that you see them / Printing their proud hoofs i'' the receiving earth'' — these are not decorations but working instructions. Shakespeare is asking the audience to perform a continuous act of imaginative generosity, and the whole play will depend on our willingness. This has political implications too: a play that recruits its audience into the making of national glory is a play whose ideological work is necessarily collaborative. If we stop supplying the Chorus''s imagined horses, the English cause visibly shrinks to a few men in ragged costumes in a wooden ring. The play''s critics (starting with the 20th-century productions that refused to collaborate) have shown how readily the epic frame can be withdrawn once one simply declines to imagine it.', ARRAY['Norman Rabkin, ''Either/Or: Responding to Henry V,'' Shakespeare and the Problem of Meaning (1981)','Stephen Greenblatt, Shakespearean Negotiations (1988)']::TEXT[]), ('henry_v_prologue_ann4', 'henry_v_prologue', 32, 34, 'Henry V Prologue.32–34', 'thematic', 'The Chorus''s role — and the play''s central interpretive problem', '''Admit me Chorus to this history'' — the Chorus petitions the audience to be accepted as a narrative voice. This is the play''s unique structural feature: of all Shakespeare''s histories, only Henry V has a formal Chorus appearing six times (Prologue, before Acts II–V, and the Epilogue), relentlessly heroic and morally one-toned. Yet the action scenes the Chorus frames are frequently much darker than the Chorus prepares us for. The Prologue introduces Henry as ''warlike Harry, like himself'' assuming ''the port of Mars''; the following scenes show Canterbury manipulating the king toward a war of dynastic ambition. The Chorus celebrates ''brothers, friends and countrymen'' in the Act 4 Chorus; the Act 4 itself stages Williams''s challenge to royal responsibility and the killing of prisoners. Norman Rabkin''s 1981 essay ''Either/Or'' argues this double vision is the play''s point: the Chorus supplies the patriotic frame, the action supplies its critique, and Shakespeare refuses to adjudicate between them. Readers should hold both registers at once.', ARRAY['Norman Rabkin, ''Either/Or: Responding to Henry V,'' Shakespeare and the Problem of Meaning (1981)','Lawrence Danson, Tragic Alphabet (1974)','Gary Taylor (ed.), The Oxford Shakespeare: Henry V (1982)']::TEXT[]);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act1_scene1_q1', 'henry_v_act1_scene1', 'comprehension', 'What is the bill that Canterbury fears (lines 1–19)?', ARRAY['A law that would ban English bishops from holding office','A parliamentary bill that would strip the Church of temporal lands worth more than half its wealth','A tax on monastic buildings only','A requirement that the Church pay for royal wars']::TEXT[], 1, 15, 1, 19), ('henry_v_act1_scene1_q2', 'henry_v_act1_scene1', 'inference', 'Why does Canterbury encourage Henry''s war on France?', ARRAY['He believes Henry''s claim is legally irrefutable, regardless of self-interest','Because the war will absorb the king''s attention and political capital, preventing the bill from passing — he has an institutional motive','He personally hates the French King','Because Joan of Arc is expected to lead a counter-invasion']::TEXT[], 1, 25, 70, 102), ('henry_v_act1_scene1_q3', 'henry_v_act1_scene1', 'theme', 'Canterbury describes Henry''s transformation from ''wildness'' to kingly virtue. What dramatic history does this summary compress?', ARRAY['The events of Julius Caesar','Prince Hal''s development in Shakespeare''s earlier Henry IV Parts 1 and 2','Henry III''s relationship with the Church','The boyhood of Edward III']::TEXT[], 1, 20, 24, 45), ('henry_v_act1_scene1_q4', 'henry_v_act1_scene1', 'structural', 'How does 1.1 frame what happens in 1.2?', ARRAY['It introduces Henry in person','It establishes that Canterbury has a material interest in promoting the French war BEFORE he is asked to legally justify it — the audience hears the next scene''s legal opinion as compromised','It introduces the Dauphin','It sets up a love plot that the rest of the play will develop']::TEXT[], 1, 30, 70, 102);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act1_scene2_q1', 'henry_v_act1_scene2', 'comprehension', 'What is the ''Salic Law'' that Canterbury explicates at length?', ARRAY['A Frankish legal tradition cited by 14th-century French jurists to bar royal inheritance through the female line — which Canterbury argues does not apply to France','A tax on salt levied during Edward III''s reign','A treaty that ended the Hundred Years'' War in 1453','A ceremonial law requiring the king to be crowned at Rheims']::TEXT[], 0, 20, 34, 88), ('henry_v_act1_scene2_q2', 'henry_v_act1_scene2', 'inference', 'Why does Shakespeare stage Canterbury''s Salic Law speech at such exhausting length?', ARRAY['Because the Elizabethan audience wanted dynastic trivia','Because Holinshed''s Chronicles could not be abridged for legal reasons','The tangled scholarly exposition dramatizes the process by which a war of conquest is laboriously equipped with legal justification — the legalism is itself the satire','Because Canterbury is a bad speaker and Shakespeare wanted to show it']::TEXT[], 2, 30, 34, 100), ('henry_v_act1_scene2_q3', 'henry_v_act1_scene2', 'close_reading', 'Exeter''s ''honey-bees'' speech (lines 184–220) uses the beehive as a metaphor for —', ARRAY['The Elizabethan court''s intrigues','The ordered commonwealth — a kingdom in which magistrates, merchants, and laborers each have their proper work, an image drawn from Virgil''s Georgics','The Roman Catholic Church','The guild system of London']::TEXT[], 1, 25, 184, 220), ('henry_v_act1_scene2_q4', 'henry_v_act1_scene2', 'theme', 'The Dauphin''s gift of tennis balls is —', ARRAY['A well-documented historical event of 1414','A legendary insult — attested in some 15th-century chronicles but not in the contemporary French sources; Shakespeare inherited it from tradition','Shakespeare''s own invention, without precedent','An actual diplomatic document preserved in the British Library']::TEXT[], 1, 20, 258, 272), ('henry_v_act1_scene2_q5', 'henry_v_act1_scene2', 'close_reading', 'What rhetorical transformation does Henry perform in his reply to the tennis balls (lines 272–300)?', ARRAY['He forgives the insult and offers the Dauphin peace','He converts a personal jest into a prophecy of mass French suffering, using the Dauphin''s mockery to license collective retribution','He challenges the Dauphin to a game of tennis','He ignores the insult and goes to bed']::TEXT[], 1, 30, 272, 300), ('henry_v_act1_scene2_q6', 'henry_v_act1_scene2', 'theme', 'By the end of 1.2, how has the motive for war been framed?', ARRAY['As pure self-defense against an imminent French invasion','As a ''well-hallow''d cause'' under divine sanction — the scene has staged the process by which a dynastic claim, a compromised legal opinion, and a personal insult combine into a war blessed by God','As a trade dispute over cloth exports','As a response to the killing of an English ambassador']::TEXT[], 1, 30, 300, 312);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act2_chorus_q1', 'henry_v_act2_chorus', 'close_reading', 'What does ''They sell the pasture now to buy the horse'' (line 5) describe?', ARRAY['A farmer''s bad bargain','The economic mobilization of the English countryside for war — selling livestock-land to equip cavalry','The purchase of racehorses for Agincourt','A French trade embargo on English wool']::TEXT[], 1, 20, 5, 5), ('henry_v_act2_chorus_q2', 'henry_v_act2_chorus', 'inference', 'The Chorus attributes the traitors'' treason to ''the gilt of France.'' What does the play omit?', ARRAY['Nothing — the account is historically complete','That Cambridge''s actual motive was dynastic: his Mortimer marriage gave his brother-in-law a rival claim to Henry''s throne. The play simplifies the plot into bribery','That one of the traitors was secretly Welsh','That the plot also involved the Dauphin personally']::TEXT[], 1, 30, 22, 30), ('henry_v_act2_chorus_q3', 'henry_v_act2_chorus', 'theme', 'Why does the Chorus''s ''silken dalliance in the wardrobe lies'' image matter?', ARRAY['It is purely decorative','It registers the cultural cost of mobilization — ease, pleasure, and courtly idleness are stored away while the war industry thrives','It refers to a ceremonial robe worn at Henry''s coronation','It is an anti-Catholic jibe']::TEXT[], 1, 20, 2, 4);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act2_scene1_q1', 'henry_v_act2_scene1', 'structural', 'What is the structural function of the Eastcheap scene in Act II?', ARRAY['To introduce new characters for the wooing subplot','To provide comic relief with no thematic content','To show the actual human material of Henry''s ''youth of England on fire'' — low-comic scroungers preparing for pillage — as a counterpoint to the Chorus''s official rhetoric','To explain the Salic Law to the audience']::TEXT[], 2, 25, 1, 30), ('henry_v_act2_scene1_q2', 'henry_v_act2_scene1', 'close_reading', 'What does Pistol''s speech-register imitate?', ARRAY['Courtly French love-sonnets','Biblical Psalter translations','The mock-heroic, classically-allusive style of earlier Elizabethan stage-villains (especially the Marlovian bombastic tradition), full of misused Latin and over-inflated oaths','The Welsh dialect of Fluellen']::TEXT[], 2, 25, 37, 70), ('henry_v_act2_scene1_q3', 'henry_v_act2_scene1', 'comprehension', 'What is the actual quarrel between Pistol and Nym?', ARRAY['A matter of military honour','A religious dispute','An eight-shilling gambling debt — and Pistol''s having married Nym''s betrothed Nell Quickly','A disputed command at Harfleur']::TEXT[], 2, 20, 16, 80);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act2_scene2_q1', 'henry_v_act2_scene2', 'inference', 'Why does Henry first raise (and then grant) mercy for the drunkard before exposing the traitors?', ARRAY['Because he has forgotten about the traitors','To make the traitors commit themselves to strict punishment — using their own advocacy for severity against them when their treason is revealed','Because Exeter pressured him','Because the drunk was an old friend']::TEXT[], 1, 30, 40, 82), ('henry_v_act2_scene2_q2', 'henry_v_act2_scene2', 'close_reading', 'Henry''s reproach to Scroop frames the betrayal as ''another fall of man.'' Why this theological framing?', ARRAY['Because Scroop is a priest','Because Shakespeare needs to fill time','Because the betrayal of trusted intimacy is figured as a second Eden — a cosmic scandal, not just a political one. It also echoes the Henry IV plays'' preoccupation with false appearances','Because the Salic Law speech required biblical balance']::TEXT[], 2, 30, 139, 145), ('henry_v_act2_scene2_q3', 'henry_v_act2_scene2', 'comprehension', 'What does the scene end with?', ARRAY['Henry sparing the traitors at the last moment','A verdict of death for all three traitors, and Henry''s immediate sailing to France (''No king of England, if not king of France'')','A council deciding to delay the French invasion','The queen''s arrival from Cyprus']::TEXT[], 1, 20, 161, 188);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act2_scene3_q1', 'henry_v_act2_scene3', 'theme', 'Why does Falstaff not appear in Henry V, given he was the star of Henry IV Parts 1 and 2?', ARRAY['Shakespeare wrote him into the play but censors cut it','Because the martial register of Henry V has no place for his comic-unruly world — and his rejection at the end of Henry IV Part 2 had already severed him from the now-king. His death is reported, not staged','Because the actor who played Falstaff had died','Because the Queen disliked the character']::TEXT[], 1, 30, 1, 35), ('henry_v_act2_scene3_q2', 'henry_v_act2_scene3', 'close_reading', 'What is the textual status of ''a'' babbled of green fields'' (line 14)?', ARRAY['It appears in all original editions','The Folio (1623) has nonsense (''a Table of greene fields''); the famous line is an 18th-century editorial conjecture by Lewis Theobald that has become universally accepted','It is only in the First Quarto and cut from the Folio','It was added by Samuel Johnson in 1765']::TEXT[], 1, 30, 14, 14), ('henry_v_act2_scene3_q3', 'henry_v_act2_scene3', 'comprehension', 'The Hostess''s speech about Falstaff''s death is full of malapropisms. ''Arthur''s bosom'' is her version of what?', ARRAY['''Arthur''s cave''','''Abraham''s bosom'' — the biblical resting-place of the righteous after death (Luke 16:22)','''Arthur''s table''','''Aaron''s bosom''']::TEXT[], 1, 15, 7, 8);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act2_scene4_q1', 'henry_v_act2_scene4', 'comprehension', 'What literary parallel does the French Constable use for Henry (lines 36–38)?', ARRAY['Hannibal of Carthage','Alexander of Macedon','Lucius Junius Brutus — the Roman who feigned stupidity to mask the wit that would overthrow the Tarquin kings','Coriolanus']::TEXT[], 2, 20, 36, 40), ('henry_v_act2_scene4_q2', 'henry_v_act2_scene4', 'theme', 'The scene stages a disagreement between the Dauphin and the Constable. What does it tell us?', ARRAY['That the French court is internally divided on Henry''s character, and the Dauphin''s dismissive reading is the wrong one — which prefigures his humiliation and the Constable''s (accurate-but-fatal) respect','That the French are planning a peace treaty','That they intend to bribe the English army','That the Dauphin plans to flee France']::TEXT[], 0, 25, 25, 48), ('henry_v_act2_scene4_q3', 'henry_v_act2_scene4', 'close_reading', 'What does Exeter mean by Henry being ''footed in this land already'' (line 143)?', ARRAY['Henry is limping from an injury','Henry has already landed in France — the ''diplomatic'' demand is actually a formality delivered after the invasion','Henry has arrived at the French court in disguise','Henry has taken up residence in Paris']::TEXT[], 1, 25, 143, 143);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act3_chorus_q1', 'henry_v_act3_chorus', 'close_reading', 'The Chorus compares the English fleet at sea to —', ARRAY['An army on the march','A city on the inconstant billows dancing — civic grandeur conferred on the invasion by imagery','A forest of masts','A flock of migrating birds']::TEXT[], 1, 20, 13, 17), ('henry_v_act3_chorus_q2', 'henry_v_act3_chorus', 'theme', 'Why does the Chorus mention the French king''s offer of Katherine as a peace-settlement?', ARRAY['To introduce Katherine as a character for the first time','To indicate that a marriage-settlement was offered BEFORE the war and was declined — reminding us (when we reach Act 5) that Katherine was the price of conquest, not the reward of genuine love','To stage a French marriage proposal','To introduce the sub-plot of Alice the interpreter']::TEXT[], 1, 30, 28, 32), ('henry_v_act3_chorus_q3', 'henry_v_act3_chorus', 'structural', 'How does the Chorus handle the fall of Harfleur?', ARRAY['Stages the siege in detail','Skips it entirely without mention','Compresses it into a closing couplet — ''the nimble gunner / With linstock now the devilish cannon touches / And down goes all before them'' — leaving the imagination to do the work','Narrates it through a captured French soldier']::TEXT[], 2, 20, 32, 35);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act3_scene1_q1', 'henry_v_act3_scene1', 'close_reading', 'What does Henry command the soldiers to do in lines 6–14?', ARRAY['Withdraw to regroup','Undergo a bodily and facial metamorphosis — imitate the tiger, stiffen sinews, disguise fair nature with ''hard-favour''d rage'' — a physical re-engineering into killers','Pray for divine aid','Sing a battle-song']::TEXT[], 1, 25, 6, 14), ('henry_v_act3_scene1_q2', 'henry_v_act3_scene1', 'theme', 'Why does Henry explicitly address the yeomen?', ARRAY['They were the lowest social class present','Because the yeoman archers — commoners with longbows — were the army''s decisive force; the speech flatters the social group that will actually win the battle','Because only yeomen spoke English','Because the nobility had refused to fight']::TEXT[], 1, 30, 25, 30), ('henry_v_act3_scene1_q3', 'henry_v_act3_scene1', 'close_reading', 'What is the structural function of ''I see you stand like greyhounds in the slips'' (line 31)?', ARRAY['A reference to Henry''s hunting hobby','A closing simile that converts the army into a hunting pack and the French into quarry — ''The game''s afoot'' (line 32) makes the siege a blood-sport','A Welsh idiom from Fluellen','A misquotation of Ovid']::TEXT[], 1, 25, 31, 32), ('henry_v_act3_scene1_q4', 'henry_v_act3_scene1', 'comprehension', 'The speech''s final line invokes which three names?', ARRAY['God, Queen, and Country','God, Harry, England, and Saint George (the English patron saint)','Saint Denis, Saint George, and the Virgin','Henry, Exeter, and Canterbury']::TEXT[], 1, 10, 34, 34);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act3_scene2_q1', 'henry_v_act3_scene2', 'inference', 'What is the structural purpose of the Boy''s speech (lines 23–44)?', ARRAY['Pure comic relief','To introduce a child character who will survive the play','To provide a clear-eyed, adult-level critique of Pistol/Bardolph/Nym from below — delivered in the voice of a child the play will later permit to be killed offstage. The audience''s only fully honest narrator is disposable','To translate Fluellen''s Welsh for the audience']::TEXT[], 2, 30, 23, 44), ('henry_v_act3_scene2_q2', 'henry_v_act3_scene2', 'theme', 'Macmorris''s line ''What ish my nation? Who talks of my nation?'' is famous because —', ARRAY['It is a nonsense line inserted for comedy only','Macmorris is Shakespeare''s only Irish character; the line has become the most-cited Renaissance-drama passage in Irish studies, staging the contested nature of emergent British identity at the moment of its formation','It is a quotation from Holinshed','It is the longest line in the play']::TEXT[], 1, 30, 100, 103), ('henry_v_act3_scene2_q3', 'henry_v_act3_scene2', 'close_reading', 'Fluellen''s repeated phrase ''the disciplines of the war'' signals what?', ARRAY['His Welsh heritage','A serious critique of Henry''s strategy','His pedantic preoccupation with classical military theory — especially the ''Roman'' and ''pristine'' wars he keeps citing; the catchphrase becomes a running comic signature','His religious beliefs']::TEXT[], 2, 20, 49, 115);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act3_scene3_q1', 'henry_v_act3_scene3', 'close_reading', 'What, specifically, does Henry threaten if Harfleur does not surrender?', ARRAY['A long siege without casualties','The mass rape of the town''s women, the killing of its old men, and the impaling of its ''naked infants'' on pikes — with an explicit comparison to Herod''s massacre of the innocents','Economic sanctions','The removal of the town''s governor']::TEXT[], 1, 30, 19, 41), ('henry_v_act3_scene3_q2', 'henry_v_act3_scene3', 'theme', 'How should readers think about Henry''s threat?', ARRAY['As a pure expression of villainy','As the standard early-modern rhetoric of siege warfare, in which credible threats were conventional surrender-tools — but Shakespeare''s version is unusually specific and sustained, naming sexual violence and infanticide; the moral weight is on the page and is not euphemized','As a rhetorical flourish meant to impress the soldiers','As a passage unique to the Folio and cut from modern editions']::TEXT[], 1, 35, 1, 43), ('henry_v_act3_scene3_q3', 'henry_v_act3_scene3', 'structural', 'What happens immediately after Henry''s threat?', ARRAY['A bloody assault on Harfleur','The town surrenders, and Henry pivots instantly to ''Use mercy to them all'' — the scene stages threat, surrender, and sudden mercy in forty lines','The Dauphin arrives with reinforcements','Henry withdraws without taking the town']::TEXT[], 1, 25, 44, 57), ('henry_v_act3_scene3_q4', 'henry_v_act3_scene3', 'inference', 'Why does the scene end with Henry''s decision to march to Calais?', ARRAY['Because he has defeated the French entirely','The army has been ravaged by dysentery during the siege; the retreat is historically forced by disease, though the play presents it as a poised royal choice','Because he wants to visit English garrisons','Because Montjoy has offered a truce']::TEXT[], 1, 25, 54, 57);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act3_scene4_q1', 'henry_v_act3_scene4', 'structural', 'What is unusual about 3.4 as a scene?', ARRAY['It is in blank verse','It is performed entirely in French (with Katherine''s attempted English body-words), without English choral framing — an interlude preparing Katherine for a marriage Henry has not yet won','It has only one character','It is a sonnet, like the Prologue']::TEXT[], 1, 25, 1, 47), ('henry_v_act3_scene4_q2', 'henry_v_act3_scene4', 'close_reading', 'What is the source of Katherine''s comic shock at ''foot'' and ''coun'' (lines 34–38)?', ARRAY['She dislikes feet','The English words ''foot'' (close to French ''foutre'') and ''coun'' (close to French ''con'') sound obscene to French ears — a cross-linguistic sexual pun','She cannot pronounce them','Alice has taught her the wrong words']::TEXT[], 1, 25, 34, 42), ('henry_v_act3_scene4_q3', 'henry_v_act3_scene4', 'theme', 'What political work does the scene quietly do?', ARRAY['None — it is comic relief only','It stages Katherine''s preparation (vocabulary, by body-part) for a marriage to the conquering English king; when Henry woos her in 5.2, we have already watched her assemble the vocabulary','It introduces Alice as a new character for Act 4','It announces the French surrender at Agincourt']::TEXT[], 1, 30, 1, 47);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act3_scene5_q1', 'henry_v_act3_scene5', 'close_reading', 'What does the Constable claim distinguishes the English at line 15 onwards?', ARRAY['They have more men','That their cold, foggy climate and beer-fed diet should disqualify them as warriors — yet they fight hot and bravely, a paradox Constable finds shameful for France','Their cavalry is superior','They have better generals']::TEXT[], 1, 25, 14, 25), ('henry_v_act3_scene5_q2', 'henry_v_act3_scene5', 'theme', 'What does the Dauphin fear at lines 27–30?', ARRAY['A French retreat','That French women will give themselves to English soldiers and repopulate France with ''bastard warriors'' — mass rape as ethnic replacement, the very threat Henry made at Harfleur','That the Dauphin will be captured','That the English army lacks bread']::TEXT[], 1, 30, 27, 30);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act3_scene6_q1', 'henry_v_act3_scene6', 'inference', 'How does Henry respond to the news that his old Eastcheap companion Bardolph is to be executed?', ARRAY['With private grief','By pardoning Bardolph','With a single line endorsing the execution — ''We would have all such offenders so cut off'' — showing that Prince Hal has been successfully eliminated from the present king','By sending him back to England in chains']::TEXT[], 2, 30, 82, 90), ('henry_v_act3_scene6_q2', 'henry_v_act3_scene6', 'comprehension', 'What does Henry tell Montjoy about the English army''s condition?', ARRAY['That it is in full health','That the soldiers are enfeebled by sickness and reduced in numbers — a candid admission of weakness, delivered to the enemy','That reinforcements have just arrived from England','That the Dauphin has already surrendered']::TEXT[], 1, 25, 119, 122), ('henry_v_act3_scene6_q3', 'henry_v_act3_scene6', 'theme', 'Henry''s maxim ''the gentler gamester is the soonest winner'' (line 92) refers to —', ARRAY['A recommendation that soldiers play chess','His policy of forbidding plunder from French villages — strict discipline and payment for supplies, to conciliate the local population and speed the march','A proverb about card games','Instruction on how to treat horses']::TEXT[], 1, 25, 88, 92);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act3_scene7_q1', 'henry_v_act3_scene7', 'theme', 'How does the play characterize the French nobles at 3.7?', ARRAY['As sober military planners','As over-refined, voluble, effeminate — in love with their horses and armour, composing sonnets to their mounts; this is ideological work, not neutral comedy. The play is shaping the English self-image by cultural contrast','As honest peasants','As religious fanatics']::TEXT[], 1, 30, 1, 50), ('henry_v_act3_scene7_q2', 'henry_v_act3_scene7', 'close_reading', 'What is the joke of the Constable''s line ''I have heard a sonnet begin so to one''s mistress'' (line 33)?', ARRAY['It is a misquotation','Sonnets are properly addressed to mistresses; the Dauphin has written one to his horse — the Constable is accusing him of treating his horse as a lover. The Dauphin then doubles down: ''my horse is my mistress''','Orleans doesn''t understand sonnets','The sonnet is a recent invention in the play''s timeline']::TEXT[], 1, 25, 33, 36), ('henry_v_act3_scene7_q3', 'henry_v_act3_scene7', 'inference', 'What is the dramatic irony of the French nobles'' confidence in 3.7?', ARRAY['They don''t know that Henry has already left for Calais','They correctly assess the English army as starving and reduced, but conclude from this (wrongly) that victory is guaranteed — the audience knows Agincourt is tomorrow and the English will win','They are fooled by a false peace offer','The French king has died in the night']::TEXT[], 1, 30, 95, 117);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act4_chorus_q1', 'henry_v_act4_chorus', 'close_reading', 'What atmosphere does the Chorus build in lines 1–16?', ARRAY['A blazing daytime battlefield','A quiet night between two armies, close enough to hear each other''s sentinels — a cinematic stillness in which the hammers of armourers, the crowing of cocks, and the tolling of clocks all register','A stormy sea-crossing','A royal funeral']::TEXT[], 1, 25, 1, 16), ('henry_v_act4_chorus_q2', 'henry_v_act4_chorus', 'theme', 'What does ''A little touch of Harry in the night'' (line 47) do?', ARRAY['Introduces Harry as a character','Concludes the Chorus''s hagiographic portrait of Henry as a morally radiant presence among his men — just before the 4.1 scene will complicate that portrait with Williams''s challenge','Stages Henry''s nightmare','Describes a battle already underway']::TEXT[], 1, 25, 47, 47), ('henry_v_act4_chorus_q3', 'henry_v_act4_chorus', 'close_reading', 'How does the Chorus contrast the two armies at lines 17–28?', ARRAY['They are equally confident','The French ''over-lusty'' and ''secure in soul,'' playing at dice for English prisoners; the ''poor condemned English'' sitting ''like sacrifices'' by their fires, ''horrid ghosts'' in the moonlight','Both armies are asleep','The English play dice and the French pray']::TEXT[], 1, 25, 17, 28);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act4_scene1_q1', 'henry_v_act4_scene1', 'theme', 'What philosophical stance opens Henry''s speech to his brothers?', ARRAY['Pure fatalism','A stoic/alchemical stance: ''some soul of goodness in things evil'' — hardship can be distilled into spiritual preparation; the bad neighbour is an ''outward conscience'' teaching us to ''dress us fairly for our end''','Scepticism about prayer','A renunciation of kingship']::TEXT[], 1, 25, 3, 12), ('henry_v_act4_scene1_q2', 'henry_v_act4_scene1', 'close_reading', 'What is Williams''s central argument about royal responsibility?', ARRAY['That kings cannot be challenged under any circumstances','That if the king''s cause is unjust, his soldiers die in a state of unrepented sin — and therefore ''it will be a black matter for the king that led them to it.'' The king''s moral accountability is load-bearing','That soldiers should refuse to fight without pay','That Henry is a kind king and deserves no criticism']::TEXT[], 1, 30, 111, 121), ('henry_v_act4_scene1_q3', 'henry_v_act4_scene1', 'inference', 'How does Henry answer Williams''s challenge?', ARRAY['By agreeing entirely','With the father/son and master/servant analogies: each subject''s soul is his own; the king isn''t damned for the private state of each soldier. The reply is theologically coherent but sidesteps Williams''s actual question about the justice of the war','By threatening to have him executed','By revealing his identity as king on the spot']::TEXT[], 1, 30, 122, 152), ('henry_v_act4_scene1_q4', 'henry_v_act4_scene1', 'historical', 'What ''fault'' does Henry pray God to ''think not upon'' at line 198?', ARRAY['His own drunken youth','His father Henry IV''s usurpation of Richard II''s throne in 1399 — the dynastic sin Henry V has tried to atone for by reburying Richard and endowing chantries for his soul','The tennis-balls insult','The death of Falstaff']::TEXT[], 1, 30, 197, 209), ('henry_v_act4_scene1_q5', 'henry_v_act4_scene1', 'structural', 'What does the glove-exchange between Henry and Williams set up?', ARRAY['Nothing — it is a throwaway moment','A two-scene comic pay-off: Henry will give the glove to Fluellen in 4.7, Williams will punch Fluellen in 4.8, and Henry will reveal the trick and reward Williams with a glove full of crowns','A duel that actually happens during Agincourt','An engagement between Williams and Alice']::TEXT[], 1, 25, 170, 181);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act4_scene2_q1', 'henry_v_act4_scene2', 'close_reading', 'Grandpré describes the English army as —', ARRAY['A formidable force','''Island carrions, desperate of their bones'' — dead meat, with crows already circling as their ''executors'' — a contemptuous image that the battle is about to falsify','A disciplined Roman legion','A combined fleet']::TEXT[], 1, 20, 35, 48), ('henry_v_act4_scene2_q2', 'henry_v_act4_scene2', 'theme', 'What does the French attitude in 4.2 accomplish structurally?', ARRAY['It wastes time','It amplifies the dramatic irony of the coming victory: the French are certain, the audience knows Agincourt is minutes away, and the English (unseen) are already saying the prayer that 4.3 will stage','It introduces the wooing subplot','It previews Henry''s death']::TEXT[], 1, 25, 13, 34);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act4_scene3_q1', 'henry_v_act4_scene3', 'close_reading', 'What does Henry do with Westmoreland''s wish for ten thousand more men from England?', ARRAY['Grants it by sending a messenger','Inverts it — ''The fewer men, the greater share of honour'' — converting the army''s numerical liability into a rhetorical asset, then offering passports to anyone unwilling to fight','Rebukes Westmoreland publicly','Delays the battle to await reinforcements']::TEXT[], 1, 25, 18, 39), ('henry_v_act4_scene3_q2', 'henry_v_act4_scene3', 'theme', 'What does ''be he ne''er so vile, / This day shall gentle his condition'' (lines 62–63) promise?', ARRAY['That cowards will be pardoned','That a low-born man (''vile'' = socially base in period usage) who fights today will be raised to the rank of gentleman — a promise of social elevation through shared combat','That French prisoners will be treated well','That Henry''s brothers will be made dukes']::TEXT[], 1, 30, 62, 63), ('henry_v_act4_scene3_q3', 'henry_v_act4_scene3', 'theme', 'How does ''band of brothers'' work on the critical (as well as patriotic) reading of Henry?', ARRAY['It doesn''t — cynical readings make the speech ineffective','The speech remains effective on any reading; even a calculating or cynical Henry could deliver it, and the rhetorical power of shared sacrifice doesn''t depend on the speaker''s sincerity. This is itself part of the play''s argument about rhetoric and power','Only Olivier''s 1944 film supports the patriotic reading','The speech is absent from critical editions']::TEXT[], 1, 35, 60, 67), ('henry_v_act4_scene3_q4', 'henry_v_act4_scene3', 'close_reading', 'What register does Henry use in his answer to Montjoy (lines 108–125)?', ARRAY['Same as the Crispin''s Day oration','Plain, gritty, almost proletarian — ''warriors for the working-day,'' ''besmirch''d'' gilt, ''slovenry,'' ''poor soldiers.'' The tonal shift is pitched for the French herald','Outraged Latinate grandeur','Formal verse quatrains']::TEXT[], 1, 25, 108, 125), ('henry_v_act4_scene3_q5', 'henry_v_act4_scene3', 'comprehension', 'What date is St. Crispin''s Day, and why does it matter?', ARRAY['June 15 — the anniversary of Henry''s coronation','October 25 — the date of the Battle of Agincourt (1415); saints Crispin and Crispianus were 3rd-century martyred shoemakers','March 1 — St. David''s Day','April 23 — St. George''s Day']::TEXT[], 1, 20, 40, 48), ('henry_v_act4_scene3_q6', 'henry_v_act4_scene3', 'structural', 'Why is the Crispin''s Day speech preceded by a second Montjoy-embassy (lines 79–88)?', ARRAY['To give Montjoy more lines','To give Henry a second oration-audience: the French herald gets the ''working-day'' register, after the army has been given the ''band of brothers'' register. The two audiences receive different speeches','Because Westmoreland requested it','Because Montjoy has changed sides']::TEXT[], 1, 25, 79, 130);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act4_scene4_q1', 'henry_v_act4_scene4', 'close_reading', 'What drives the comedy of Pistol''s interrogation of the French soldier?', ARRAY['Pistol''s fluent French','A series of mishearings: ''Seigneur Dieu'' taken as a name, ''moi'' as a unit of currency, ''bras'' (arm) as ''brass'' (metal). The Boy mediates','The soldier''s refusal to speak','A trick by the Constable of France']::TEXT[], 1, 25, 3, 20), ('henry_v_act4_scene4_q2', 'henry_v_act4_scene4', 'structural', 'The Boy''s soliloquy at 4.4 lines 52–60 is the audience''s last extended look at him. What does he reveal?', ARRAY['That he''s plotting with the French','That he will stay with the luggage and lackeys (standard protocol for a boy non-combatant) because the French could easily raid the camp — foreshadowing his offstage death, reported in 4.7','That he wants to marry Alice','That he is Pistol''s cousin']::TEXT[], 1, 30, 52, 60);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act4_scene5_q1', 'henry_v_act4_scene5', 'structural', 'What is notable about the length of 4.5?', ARRAY['It is the longest scene in Act IV','It is the shortest scene in the play — 23 lines; the brevity is the point: 3.7''s long horse-bragging scene is paid off with a compressed collapse, the ratio enacting the play''s judgment','It has been cut in most modern productions','It is spoken in Latin']::TEXT[], 1, 20, 1, 23);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act4_scene6_q1', 'henry_v_act4_scene6', 'close_reading', 'How does Exeter describe the death of York and Suffolk?', ARRAY['A distant massacre','A chivalric death-marriage: the two earls ''espoused to death'' with York kissing Suffolk''s wounds; Exeter admits he wept; Henry admits he must ''compound / With mistful eyes'' — unusual emotional frankness before the next line''s order','A forgotten incident','A strategic retreat']::TEXT[], 1, 25, 8, 32), ('henry_v_act4_scene6_q2', 'henry_v_act4_scene6', 'theme', 'How does the play stage Henry''s order to kill the French prisoners?', ARRAY['With a long soliloquy justifying it','In four lines — ''hark! what new alarum is this same? / The French have reinforced their scatter''d men: / Then every soldier kill his prisoners; / Give the word through.'' No debate, no regret; the flatness itself is the play''s statement','As a deferred decision never actually carried out','Through Fluellen''s narration offstage']::TEXT[], 1, 35, 35, 38), ('henry_v_act4_scene6_q3', 'henry_v_act4_scene6', 'historical', 'Is Henry''s order historically attested?', ARRAY['No — it is Shakespeare''s invention','Yes — contemporary chroniclers (Gesta Henrici Quinti and others) record that Henry gave this command during the battle; it was controversial in its own time, with some English knights refusing to carry it out','Only in French sources hostile to Henry','Only in 19th-century retellings']::TEXT[], 1, 25, 37, 37), ('henry_v_act4_scene6_q4', 'henry_v_act4_scene6', 'inference', 'Why does the play deliberately blur the timing between Henry''s order and the French killing the camp-boys?', ARRAY['Sloppy writing','To leave the moral question open: 4.6 has Henry give the order in response to a ''new alarum'' of reinforcement, before any mention of the boys; 4.7 has Gower retroactively interpret the order as retaliation for the killed boys. The two framings are both on the page, neither adjudicated','The Folio printers made an error','Because Shakespeare wrote the scenes years apart']::TEXT[], 1, 30, 35, 38);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act4_scene7_q1', 'henry_v_act4_scene7', 'structural', 'What is the structural problem with Gower''s interpretation at 4.7 lines 4–8?', ARRAY['It is false historically','Gower retroactively interprets Henry''s prisoner-killing order as retaliation for the French raid on the boys — but in the text Henry gave the order BEFORE the raid was reported. The play keeps both framings visible, neither adjudicated','Gower is lying','Fluellen contradicts it immediately']::TEXT[], 1, 30, 4, 8), ('henry_v_act4_scene7_q2', 'henry_v_act4_scene7', 'close_reading', 'What parallel does Fluellen draw between Henry and Alexander the Great?', ARRAY['Both were born in Macedon','Alexander drunk killed his friend Cleitus; Henry sober rejected Falstaff — the parallel suggests the rejection was a moral action of the same kind. Delivered in Welsh-accented dialect, this is one of the play''s most damning critical observations about its king','Both conquered India','Both died at age 35']::TEXT[], 1, 35, 25, 41), ('henry_v_act4_scene7_q3', 'henry_v_act4_scene7', 'theme', 'Why does Henry''s exchange with Fluellen about the leek matter (lines 85–98)?', ARRAY['It''s a lunch break','It publicly affirms Henry''s Welshness (he was born at Monmouth) and binds him to the Welsh soldiery whose longbow archers won the battle — a rhetorical moment of unity after naming the victory ''Agincourt''','It prepares the wooing scene','It introduces Macmorris']::TEXT[], 1, 25, 85, 98);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act4_scene8_q1', 'henry_v_act4_scene8', 'structural', 'How does the glove-plot resolve?', ARRAY['Williams is imprisoned for striking Fluellen','Williams explains that the king''s disguise invited the insult; Henry, persuaded, fills Williams''s glove with crowns. Williams doesn''t apologize; the king doesn''t insist','Fluellen is rewarded with a dukedom','Both Williams and Fluellen are sent to Calais']::TEXT[], 1, 25, 37, 48), ('henry_v_act4_scene8_q2', 'henry_v_act4_scene8', 'comprehension', 'According to Henry''s list, how many common English soldiers died?', ARRAY['Five hundred','Twenty-five — an astonishingly low number that has been disputed by modern historians, who estimate several hundred','Ten thousand','None']::TEXT[], 1, 20, 88, 91), ('henry_v_act4_scene8_q3', 'henry_v_act4_scene8', 'theme', 'What does Henry do immediately after reciting the casualty catalogue?', ARRAY['Leads a prayer at the battlefield','Issues a decree — on pain of death — forbidding any soldier to boast of Agincourt or take credit from God. Providentialism becomes state policy','Orders the dead to be burned','Writes a personal letter to Katherine']::TEXT[], 1, 25, 98, 101), ('henry_v_act4_scene8_q4', 'henry_v_act4_scene8', 'historical', 'How should readers treat Henry''s casualty numbers?', ARRAY['As modern archaeology','As propaganda inherited from 15th-century sources (via Holinshed): the disproportion (French nobles killed in huge numbers, English commoners barely scratched) is extraordinary and real, but the specific numbers are likely inflated/deflated on both sides. Modern estimates differ substantially','As literal transcripts of French rolls','As inventions of Shakespeare with no historical basis']::TEXT[], 1, 30, 65, 91);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act5_chorus_q1', 'henry_v_act5_chorus', 'close_reading', 'How does the Chorus describe Henry''s return to London (lines 9–28)?', ARRAY['As a quiet homecoming','In Roman triumphal terms — the mayor and aldermen as ''senators of the antique Rome,'' Londoners as plebeians, Henry as ''conquering Caesar'' — but Henry declines the triumphal display, gaining the credit of humility while retaining the classical grandeur the framing supplies','As a disaster','As a secret arrival by night']::TEXT[], 1, 25, 9, 28), ('henry_v_act5_chorus_q2', 'henry_v_act5_chorus', 'historical', 'The reference at lines 29–34 to ''the general of our gracious empress … from Ireland coming'' dates the play how?', ARRAY['It cannot be dated','To late March–September 1599 — during the Earl of Essex''s Irish campaign, while hope for his success was still possible. After his return without victory (autumn 1599) and his execution (1601), the line could not have been written in that form','To 1603, after Elizabeth''s death','To 1595, before the Globe was built']::TEXT[], 1, 30, 29, 34);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act5_scene1_q1', 'henry_v_act5_scene1', 'structural', 'What does the leek scene accomplish?', ARRAY['Mere slapstick','A long-setup comic pay-off: Fluellen beats Pistol with a cudgel and forces him to eat a raw leek, inverting the play''s ethnic hierarchy — the Welshman corrects the English bombast, with Gower''s explicit endorsement','A political rebellion','A second glove-plot']::TEXT[], 1, 25, 1, 60), ('henry_v_act5_scene1_q2', 'henry_v_act5_scene1', 'theme', 'What does Pistol''s closing soliloquy reveal?', ARRAY['That he is reformed','That he will return to England as a pimp and cut-purse, passing off his leek-bruises as war-wounds. His honest post-war account falsifies Henry''s ''band of brothers'' promise of social elevation for low-born soldiers','That he plans to marry Alice','That he has enlisted again for France']::TEXT[], 1, 30, 62, 71), ('henry_v_act5_scene1_q3', 'henry_v_act5_scene1', 'comprehension', 'What has happened to Pistol''s wife?', ARRAY['She has returned to Eastcheap','She has died of the ''malady of France'' — syphilis — in the hospital','She is in Scotland','She has become a nun']::TEXT[], 1, 15, 63, 64);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_act5_scene2_q1', 'henry_v_act5_scene2', 'close_reading', 'What is Burgundy doing rhetorically in his long lament for France (lines 23–67)?', ARRAY['Genuinely grieving for French agriculture only','Delivering a political argument in pastoral disguise: the ''naked, poor and mangled Peace'' and the overgrown vineyards are a plea that justifies French concessions on any terms. The beauty of the rhetoric is the lever','Confessing to treason','Proposing a Crusade']::TEXT[], 1, 30, 23, 67), ('henry_v_act5_scene2_q2', 'henry_v_act5_scene2', 'theme', 'How should we read Henry''s ''plain soldier'' pose in the wooing scene?', ARRAY['As literally plain, unrehearsed speech','As a carefully composed rhetorical register — Henry delivers long polished prose paragraphs while claiming plainness; the pose is one more audience-calibrated register in a king whose speech varies by audience throughout the play','As evidence he had no eloquence','As a sign of his youthful nerves']::TEXT[], 1, 30, 114, 142), ('henry_v_act5_scene2_q3', 'henry_v_act5_scene2', 'close_reading', 'What is the force of Henry''s ''nice customs curtsy to great kings … we are the makers of manners'' (lines 234–236)?', ARRAY['A tactful compliment to French tradition','An assertion of royal prerogative over cultural norm: kings aren''t subject to custom, they create it. The line overrides Katherine''s objection to pre-marriage kissing and doubles as political theory','A quotation from Chaucer','A piece of Welsh dialect']::TEXT[], 1, 30, 234, 236), ('henry_v_act5_scene2_q4', 'henry_v_act5_scene2', 'historical', 'What does Exeter read out at lines 285–288?', ARRAY['A prayer in French','The key clause of the Treaty of Troyes (1420): that Henry is to be named ''Héritier de France'' — heir to the French throne — in all future French royal documents. The wooing scene ornaments this treaty-clause','Katherine''s dowry inventory','A list of French prisoners still held in England']::TEXT[], 1, 30, 285, 288), ('henry_v_act5_scene2_q5', 'henry_v_act5_scene2', 'inference', 'What does the wooing scene''s place in the play''s argument invite us to see?', ARRAY['That love conquers all political conflict','That the marriage is a dynastic settlement dressed as romance: Katherine is the ''capital demand'' of the treaty; the wooing scene is a ceremony for terms already arranged. Romance and conquest are not separable here','That Henry has given up his French claim','That Katherine was secretly Welsh']::TEXT[], 1, 30, 94, 96), ('henry_v_act5_scene2_q6', 'henry_v_act5_scene2', 'theme', 'Why does Katherine''s ''Is it possible dat I sould love de enemy of France?'' (line 155) matter?', ARRAY['It introduces Katherine as a minor character','It is the one moment the scene''s underlying political question surfaces in Katherine''s own voice. Henry''s reply — loving him means loving France''s conqueror, who will have ''all'' of it — doesn''t resolve the question so much as absorb it','It shows Katherine does not actually speak French','It is a quotation from Chaucer']::TEXT[], 1, 30, 155, 161);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_epilogue_q1', 'henry_v_epilogue', 'structural', 'What verse form is the Epilogue?', ARRAY['Free verse','An English sonnet (three quatrains plus a couplet) — the form''s closure pulls against the sonnet''s content, which is the collapse of Henry''s achievement','A ballad stanza','Heroic couplets']::TEXT[], 1, 25, 1, 14), ('henry_v_epilogue_q2', 'henry_v_epilogue', 'historical', 'What historical future does the Epilogue announce?', ARRAY['Henry V''s long and successful reign','Henry V''s early death; the succession of his infant son Henry VI to both crowns; the factional regency; the loss of France; the Wars of the Roses that ''made his England bleed''','A crusade to reconquer Jerusalem','A peaceful transition to the Tudor dynasty']::TEXT[], 1, 30, 5, 12), ('henry_v_epilogue_q3', 'henry_v_epilogue', 'theme', 'Why does the Epilogue mention ''Which oft our stage hath shown'' (line 13)?', ARRAY['As a general allusion to Elizabethan theatre','As a direct cross-reference to Shakespeare''s own Henry VI plays (1–3) and Richard III — written years earlier. Henry V is thus the prequel to a catastrophe the audience has already seen dramatized','To advertise a forthcoming play','As a line added by a later editor']::TEXT[], 1, 35, 13, 13), ('henry_v_epilogue_q4', 'henry_v_epilogue', 'inference', 'What is the effect of ending the play this way?', ARRAY['Pure triumphalism — the Epilogue celebrates Henry''s victory','A deliberate undoing: the sonnet''s formal closure frames content that says everything Henry built collapsed within a generation. The patriotic reading cannot be cleanly sustained against the Epilogue''s future-tense dis-closure','An uplifting glimpse of the Tudor future','A factual error by Shakespeare']::TEXT[], 1, 35, 5, 14);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('henry_v_prologue_q1', 'henry_v_prologue', 'structural', 'What is the Chorus''s opening request, and why?', ARRAY['A kingdom-sized stage and a Muse of fire — because the subject is too great for an ordinary theatre','A quiet setting — because the play is domestic','An end to dramatic convention — because the story is too true to stage','The closure of the theatres — because the play is a religious work']::TEXT[], 0, 15, 1, 8), ('henry_v_prologue_q2', 'henry_v_prologue', 'close_reading', 'What does the Chorus mean by ''this wooden O''?', ARRAY['The round letter O as a symbol of nothingness','A hollow crown','The Globe Theatre — Shakespeare''s round wooden playhouse','A siege-engine used at Agincourt']::TEXT[], 2, 10, 13, 13), ('henry_v_prologue_q3', 'henry_v_prologue', 'theme', 'What does the ''crooked figure'' that ''may attest in little place a million'' (lines 15–16) represent?', ARRAY['A dishonest accountant','A zero — a small numeral that multiplies larger numbers; image for how the actors, as ''ciphers,'' must be multiplied by the audience''s imagination','A bent sword unfit for battle','A star-shape on a military banner']::TEXT[], 1, 20, 15, 17), ('henry_v_prologue_q4', 'henry_v_prologue', 'comprehension', 'The Chorus asks the audience to do what specifically?', ARRAY['Remain silent throughout the performance','Imagine the missing armies, fleets, and battlefield in their own minds (''piece out our imperfections with your thoughts'')','Applaud only at the end of each act','Not bring weapons into the theatre']::TEXT[], 1, 15, 23, 27), ('henry_v_prologue_q5', 'henry_v_prologue', 'inference', 'Why does Shakespeare have the Prologue apologize so insistently for the theatre''s limitations?', ARRAY['He genuinely doubted the play would succeed','It was legally required by Elizabethan censors','The apologies recruit the audience into co-producing the play''s epic scale — a rhetorical strategy, not mere humility','He had been forced to cut most of the script before performance']::TEXT[], 2, 25, 15, 25), ('henry_v_prologue_q6', 'henry_v_prologue', 'theme', 'Critics often note that the Chorus presents Henry heroically while the action scenes sometimes undercut that portrait. What is this structural feature called in Norman Rabkin''s classic 1981 essay?', ARRAY['The tragic-comic blend','The ''Either/Or'' double vision — the play sustains both a patriotic and a critical reading at once','The choral interlude tradition','The deus-ex-machina effect']::TEXT[], 1, 30, 32, 34);
